// Translation is disabled — flip to `true` to re-enable the auto-translate
// pipeline and the Translate button on assignments. When false, all translation
// UI is hidden and no API calls are made (regardless of the API key).
const TRANSLATION_ENABLED = false;
// Text-only translation for short content (cleaner notes, task names).
// This is independent from TRANSLATION_ENABLED (which gates the full
// PDF/image document translation pipeline that's currently dormant).
// Text translation is cheap and useful so it's on by default; gates
// downstream still check for a valid API key.
const TEXT_TRANSLATION_ENABLED = true;

const isTranslateConfigured = () =>
  TRANSLATION_ENABLED &&
  GOOGLE_TRANSLATE_API_KEY &&
  GOOGLE_TRANSLATE_API_KEY !== 'PASTE_YOUR_GOOGLE_TRANSLATE_KEY_HERE' &&
  GOOGLE_TRANSLATE_API_KEY.length > 10;

// Lighter gate for short-text translation. Doesn't require the master
// document-translation flag, but still needs a real API key.
const isTextTranslateConfigured = () =>
  TEXT_TRANSLATION_ENABLED &&
  GOOGLE_TRANSLATE_API_KEY &&
  GOOGLE_TRANSLATE_API_KEY !== 'PASTE_YOUR_GOOGLE_TRANSLATE_KEY_HERE' &&
  GOOGLE_TRANSLATE_API_KEY.length > 10;

// Translate one or more strings via Google Cloud Translation API v2.
// Returns array of { translatedText, detectedSourceLanguage } in the same order.
async function translateText(strings, targetLang) {
  if (!isTextTranslateConfigured()) throw new Error('Translation is not configured.');
  const inputs = (Array.isArray(strings) ? strings : [strings]).filter(s => s && s.trim());
  if (inputs.length === 0) return [];
  const url = `https://translation.googleapis.com/language/translate/v2?key=${GOOGLE_TRANSLATE_API_KEY}`;
  const body = { q: inputs, target: targetLang, format: 'text' };
  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body)
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err?.error?.message || `Translation failed (${res.status})`);
  }
  const data = await res.json();
  return (data?.data?.translations || []).map(t => ({
    translatedText: t.translatedText,
    detectedSourceLanguage: t.detectedSourceLanguage,
  }));
}

// =================================================================
// LIVE PAGE TRANSLATION — Spanish toggle for cleaners.
// Walks the DOM, batch-translates text nodes via Google Translate
// API, caches in localStorage to avoid re-translating known strings.
// A MutationObserver re-runs on new content (route changes, modals).
// Locale persists in localStorage and is per-device, not per-user
// (matches the cleaner's preference, doesn't broadcast to PMs).
// =================================================================
const LocaleContext = React.createContext({ locale: 'en', setLocale: () => {} });
const PreviewContext = React.createContext(null);

function useLocale() {
  return React.useContext(LocaleContext);
}

// In-memory cache so we don't hit localStorage on every node check.
let _ttTranslationCache = null;
function loadTranslationCache() {
  if (_ttTranslationCache) return _ttTranslationCache;
  try {
    _ttTranslationCache = JSON.parse(localStorage.getItem('tidytrack_translations_es') || '{}');
  } catch { _ttTranslationCache = {}; }
  return _ttTranslationCache;
}
function saveTranslationCache(cache) {
  _ttTranslationCache = cache;
  try { localStorage.setItem('tidytrack_translations_es', JSON.stringify(cache)); } catch {}
}

function TranslationProvider({ children }) {
  const [locale, setLocaleState] = useState(() => {
    try {
      // Saved preference wins; otherwise sniff the device. We accept
      // 'es' / 'es-MX' / 'es-ES' / etc. as Spanish.
      const saved = localStorage.getItem('tidytrack_locale');
      if (saved) return saved;
      const nav = (typeof navigator !== 'undefined' && navigator.language) || 'en';
      if (nav.toLowerCase().startsWith('es')) return 'es';
      return 'en';
    } catch { return 'en'; }
  });

  // Expose locale globally so non-React helpers (tt() in AuthedShift)
  // can read the current language without prop drilling. The Spanish
  // micro-dictionary is populated below so the multi-cleaner prompts
  // ("All items done?", "Delete this photo?") translate.
  useEffect(() => {
    try {
      window.__tidytrack_locale = locale;
      window.__tidytrack_es = {
        // Multi-cleaner prompts (from leaveBlock + deletePhoto)
        'All items done at this bedroom. Finish the workblock?':
          'Todos los elementos están listos en este dormitorio. ¿Terminar el workblock?',
        'Delete this photo? This cannot be reversed.':
          '¿Eliminar esta foto? No se puede deshacer.',
        'You can only delete photos you took.':
          'Solo puedes eliminar fotos que tú tomaste.',
      };
    } catch {}
  }, [locale]);

  const setLocale = (newLocale) => {
    try { localStorage.setItem('tidytrack_locale', newLocale); } catch {}
    // Switching back to English: easiest reset is a reload, since we
    // mutated text nodes in place and can't reliably restore originals
    // after React re-renders.
    if (newLocale === 'en' && locale !== 'en') {
      window.location.reload();
      return;
    }
    setLocaleState(newLocale);
  };

  useEffect(() => {
    if (locale !== 'es') return;
    if (!isTextTranslateConfigured()) {
      console.warn('[translate] Spanish requested but Google Translate API key not configured');
      return;
    }

    // Don't translate text inside these elements — they're either
    // user-generated content that should stay raw (apartment labels,
    // proper names, IDs) or interactive form values.
    const SKIP_TAGS = new Set(['SCRIPT','STYLE','NOSCRIPT','TEXTAREA','INPUT','CODE','PRE']);
    // Common UI strings that are SHORT and ambiguous — skip to avoid
    // weird machine translations. Apartment labels like "B1-101" or
    // "Bedroom 2" are best left as-is.
    const SKIP_PATTERN = /^([A-Z]\d+-?\d*|[a-f0-9-]{8,}|\d+|\d+[:.]?\d*[ap]m?|[\s·•—|/]+)$/i;

    let pending = false;
    const translateVisibleNodes = async () => {
      if (pending) return;
      pending = true;
      try {
        const cache = loadTranslationCache();
        const nodes = [];
        const walker = document.createTreeWalker(
          document.body,
          NodeFilter.SHOW_TEXT,
          {
            acceptNode: (node) => {
              const text = node.nodeValue;
              if (!text || !text.trim()) return NodeFilter.FILTER_REJECT;
              if (node._ttDone) return NodeFilter.FILTER_REJECT;
              const parent = node.parentElement;
              if (!parent) return NodeFilter.FILTER_REJECT;
              if (SKIP_TAGS.has(parent.tagName)) return NodeFilter.FILTER_REJECT;
              if (parent.closest('[data-no-translate]')) return NodeFilter.FILTER_REJECT;
              const trimmed = text.trim();
              if (SKIP_PATTERN.test(trimmed)) return NodeFilter.FILTER_REJECT;
              // Skip strings shorter than 2 chars
              if (trimmed.length < 2) return NodeFilter.FILTER_REJECT;
              return NodeFilter.FILTER_ACCEPT;
            }
          }
        );
        while (walker.nextNode()) nodes.push(walker.currentNode);
        if (nodes.length === 0) return;

        const uniqueTexts = [];
        const seen = new Set();
        nodes.forEach(n => {
          const key = n.nodeValue.trim();
          if (!cache[key] && !seen.has(key)) {
            seen.add(key);
            uniqueTexts.push(key);
          }
        });

        if (uniqueTexts.length > 0) {
          // Batch up to ~100 strings per request (Google limit is 128)
          const BATCH = 100;
          for (let i = 0; i < uniqueTexts.length; i += BATCH) {
            const slice = uniqueTexts.slice(i, i + BATCH);
            try {
              const results = await translateText(slice, 'es');
              results.forEach((r, j) => {
                cache[slice[j]] = r.translatedText;
              });
            } catch (e) {
              console.warn('[translate] batch failed', e);
            }
          }
          saveTranslationCache(cache);
        }

        // Apply translations to all gathered nodes
        nodes.forEach(node => {
          const original = node.nodeValue.trim();
          const translated = cache[original];
          if (translated && translated !== original) {
            // Preserve leading/trailing whitespace from the original
            const leading = node.nodeValue.match(/^\s*/)[0];
            const trailing = node.nodeValue.match(/\s*$/)[0];
            node.nodeValue = leading + translated + trailing;
          }
          node._ttDone = true;
        });
      } finally {
        pending = false;
      }
    };

    // Initial translate
    translateVisibleNodes();

    // Re-run when DOM changes (route changes, modals, new content)
    let raf = null;
    const observer = new MutationObserver(() => {
      if (raf) cancelAnimationFrame(raf);
      raf = requestAnimationFrame(translateVisibleNodes);
    });
    observer.observe(document.body, { childList: true, subtree: true, characterData: true });

    return () => {
      observer.disconnect();
      if (raf) cancelAnimationFrame(raf);
    };
  }, [locale]);

  return (
    <LocaleContext.Provider value={{ locale, setLocale }}>
      {children}
    </LocaleContext.Provider>
  );
}

// Convert a fetched Blob to base64 (strips the data: prefix).
async function blobToBase64(blob) {
  return new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => {
      const result = r.result;
      // result is "data:<mime>;base64,<actual-base64>"
      const comma = result.indexOf(',');
      resolve(comma >= 0 ? result.slice(comma + 1) : result);
    };
    r.onerror = () => reject(new Error('Could not read file'));
    r.readAsDataURL(blob);
  });
}

// OCR an attachment via Google Cloud Vision API.
// Returns the extracted full text, or '' if nothing readable found.
// Throws on hard errors (network, auth, etc) so callers can handle.
async function extractTextFromAttachment(fileUrl, fileKind) {
  if (!isTranslateConfigured()) throw new Error('Translation is not configured.');
  // 1. Fetch the file as a Blob
  let resp;
  try {
    resp = await fetch(fileUrl);
  } catch (e) {
    throw new Error(`Could not fetch attachment from storage: ${e.message || 'network error'}`);
  }
  if (!resp.ok) throw new Error(`Could not fetch attachment (HTTP ${resp.status})`);
  const blob = await resp.blob();
  // Sanity cap — Cloud Vision has a 20MB limit for synchronous calls
  if (blob.size > 20 * 1024 * 1024) {
    throw new Error('Attachment too large for OCR (over 20MB).');
  }
  const base64 = await blobToBase64(blob);

  const isPdf = fileKind === 'pdf' || blob.type === 'application/pdf';

  if (isPdf) {
    // PDFs use the files:annotate endpoint with mimeType
    const url = `https://vision.googleapis.com/v1/files:annotate?key=${GOOGLE_TRANSLATE_API_KEY}`;
    const body = {
      requests: [{
        inputConfig: {
          content: base64,
          mimeType: 'application/pdf',
        },
        features: [{ type: 'DOCUMENT_TEXT_DETECTION' }],
        // Limit to first 5 pages to keep costs/time reasonable
        pages: [1, 2, 3, 4, 5],
      }]
    };
    const apiResp = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    if (!apiResp.ok) {
      const err = await apiResp.json().catch(() => ({}));
      throw new Error(err?.error?.message || `Vision API (PDF) failed (HTTP ${apiResp.status})`);
    }
    const data = await apiResp.json();
    // Response shape: data.responses[0].responses[] (one per page)
    const pages = data?.responses?.[0]?.responses || [];
    const allText = pages.map(p => p?.fullTextAnnotation?.text || '').filter(Boolean).join('\n\n');
    return allText;
  } else {
    // Images use the simpler images:annotate endpoint
    const url = `https://vision.googleapis.com/v1/images:annotate?key=${GOOGLE_TRANSLATE_API_KEY}`;
    const body = {
      requests: [{
        image: { content: base64 },
        features: [{ type: 'DOCUMENT_TEXT_DETECTION', maxResults: 1 }],
      }]
    };
    const apiResp = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    if (!apiResp.ok) {
      const err = await apiResp.json().catch(() => ({}));
      throw new Error(err?.error?.message || `Vision API failed (HTTP ${apiResp.status})`);
    }
    const data = await apiResp.json();
    const annotation = data?.responses?.[0]?.fullTextAnnotation;
    return annotation?.text || '';
  }
}

// Run the full auto-translation pipeline for an uploaded assignment:
//   fetch attachment → OCR → translate to Spanish → save back to DB.
// Called fire-and-forget after upload; never blocks the UI.
async function autoTranslateAssignment(assignmentId, fileUrl, fileKind) {
  if (!isTranslateConfigured()) {
    console.warn('[auto-translate] skipped — translation not configured');
    return;
  }
  console.log('[auto-translate] starting for', assignmentId, fileKind);
  try {
    await supabase.from('assignments')
      .update({ translation_status: 'processing' })
      .eq('id', assignmentId);
    console.log('[auto-translate] OCR step…');
    const text = await extractTextFromAttachment(fileUrl, fileKind);
    console.log('[auto-translate] OCR returned', text.length, 'chars');
    if (!text || text.trim().length < 3) {
      // Nothing readable in the attachment
      await supabase.from('assignments')
        .update({ extracted_text: text || '', translation_status: 'skipped' })
        .eq('id', assignmentId);
      return;
    }
    console.log('[auto-translate] translation step…');
    const translations = await translateText([text], 'es');
    const spanish = translations?.[0]?.translatedText || '';
    console.log('[auto-translate] saved Spanish version:', spanish.slice(0, 80) + '…');
    await supabase.from('assignments')
      .update({
        extracted_text: text,
        spanish_translation: spanish,
        translation_status: 'done',
        translation_error: null,
      })
      .eq('id', assignmentId);
  } catch (e) {
    console.error('[auto-translate] FAILED for assignment', assignmentId, e);
    try {
      await supabase.from('assignments')
        .update({
          translation_status: 'failed',
          translation_error: (e?.message || String(e)).slice(0, 500),
        })
        .eq('id', assignmentId);
    } catch {}
  }
}

// =================================================================
// useAssignmentSync — keep assignment views in sync.
// Subscribes to realtime changes on assignment_targets and assignments,
// and refreshes when the window/tab regains focus.
// Pass it a load() function to call when something changes.
// =================================================================
function useAssignmentSync(load, channelKey = 'asgn-sync') {
  const loadRef = useRef(load);
  loadRef.current = load;
  useEffect(() => {
    const debouncedLoad = (() => {
      let t = null;
      return () => {
        if (t) clearTimeout(t);
        t = setTimeout(() => loadRef.current && loadRef.current(), 250);
      };
    })();
    const channel = supabase.channel(channelKey + '-' + Math.random().toString(36).slice(2, 8))
      .on('postgres_changes', { event: '*', schema: 'public', table: 'assignment_targets' }, debouncedLoad)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'assignments' }, debouncedLoad)
      // Also listen for workblock activity. Without these subscriptions
      // a cleaner who has the Assignments / Suggested tab open won't
      // see that another cleaner just started a workblock until they
      // pull-to-refresh — which is exactly what the owner reported.
      // The debounced load coalesces back-to-back events into one fetch.
      .on('postgres_changes', { event: '*', schema: 'public', table: 'work_blocks' }, debouncedLoad)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'work_block_participants' }, debouncedLoad)
      // Tasks and photos changing inside an existing workblock should
      // also propagate — that's how a viewer of OtherWorkblocksHere
      // sees "Troy added a photo" or "Troy started cleaning the tub"
      // without manual refresh. Without these, the bullet list of
      // tasks in another cleaner's workblock card sat stale until
      // the user pulled-to-refresh.
      .on('postgres_changes', { event: '*', schema: 'public', table: 'tasks' }, debouncedLoad)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'photos' }, debouncedLoad)
      .subscribe();

    const onFocus = () => debouncedLoad();
    const onVisible = () => { if (!document.hidden) debouncedLoad(); };
    window.addEventListener('focus', onFocus);
    document.addEventListener('visibilitychange', onVisible);

    return () => {
      supabase.removeChannel(channel);
      window.removeEventListener('focus', onFocus);
      document.removeEventListener('visibilitychange', onVisible);
    };
    // eslint-disable-next-line
  }, [channelKey]);
}

// =================================================================
// IDLE DETECTOR — auto clock-out after 5 hours of inactivity.
// Shows a warning at the 2-hour mark giving them 3 hours to dismiss.
//
// Detects activity via pointer/keyboard/touch events. Debounces saves
// of `last_activity_at` to the database to once per minute max.
// When the app regains focus, checks if too much time has passed and
// triggers auto-clock-out retroactively using the saved last_activity_at.
//
// Returns: { showWarning, dismissWarning } — caller renders the warning UI.
// =================================================================
// Auto-clock-out behavior: warn at 45min of inactivity, force end at 1hr.
// 1 hour is the target (per owner preference) — the 45min warning gives
// the cleaner a chance to dismiss before time is lost.
const IDLE_WARN_MS = 45 * 60 * 1000;       // 45 minutes
const IDLE_LIMIT_MS = 60 * 60 * 1000;      // 1 hour
const ACTIVITY_SAVE_THROTTLE_MS = 60 * 1000; // save to DB at most once per minute

function useIdleDetector({ shift, onAutoClockOut, enabled = true }) {
  const [showWarning, setShowWarning] = useState(false);
  const lastActivityRef = useRef(Date.now());
  const lastSaveRef = useRef(0);
  const idleStartRef = useRef(null); // timestamp when current idle interval started
  const intervalRef = useRef(null);

  // Save activity timestamp to DB (throttled)
  const saveActivity = async (ts) => {
    if (!shift?.id) return;
    if (ts - lastSaveRef.current < ACTIVITY_SAVE_THROTTLE_MS) return;
    lastSaveRef.current = ts;
    try {
      await supabase.from('shifts')
        .update({ last_activity_at: new Date(ts).toISOString() })
        .eq('id', shift.id);
    } catch (e) { /* fail silent */ }
  };

  // Record an idle interval (when an idle gap is observed)
  const recordIdleInterval = async (startTs, endTs) => {
    if (!shift?.id) return;
    const seconds = Math.floor((endTs - startTs) / 1000);
    if (seconds < 60) return; // ignore gaps under 1 minute
    try {
      const { data: cur } = await supabase.from('shifts')
        .select('idle_seconds, idle_intervals')
        .eq('id', shift.id).maybeSingle();
      const existing = cur?.idle_intervals || [];
      const newIntervals = [...existing, {
        start: new Date(startTs).toISOString(),
        end: new Date(endTs).toISOString(),
        seconds
      }];
      const totalSec = (cur?.idle_seconds || 0) + seconds;
      await supabase.from('shifts').update({
        idle_seconds: totalSec,
        idle_intervals: newIntervals
      }).eq('id', shift.id);
    } catch (e) { /* fail silent */ }
  };

  // Activity marker
  const markActive = () => {
    const now = Date.now();
    const wasIdling = idleStartRef.current !== null;
    if (wasIdling) {
      // We were idle — log the gap
      const startedAt = idleStartRef.current;
      idleStartRef.current = null;
      // Only count it as a true idle gap if it exceeded the warn threshold (avoid noise)
      if (now - startedAt > IDLE_WARN_MS) {
        recordIdleInterval(startedAt, now);
      }
    }
    lastActivityRef.current = now;
    setShowWarning(false);
    saveActivity(now);
  };

  // Wire up activity listeners
  useEffect(() => {
    if (!enabled || !shift) return;
    const events = ['mousedown', 'touchstart', 'keydown', 'pointerdown'];
    const handler = () => markActive();
    events.forEach(e => window.addEventListener(e, handler, { passive: true }));
    // Initial activity stamp on enable
    markActive();
    return () => {
      events.forEach(e => window.removeEventListener(e, handler));
    };
    // eslint-disable-next-line
  }, [enabled, shift?.id]);

  // Tick: check idle status every 30 seconds
  useEffect(() => {
    if (!enabled || !shift) return;
    const tick = async () => {
      const now = Date.now();
      const sinceActive = now - lastActivityRef.current;

      if (sinceActive >= IDLE_LIMIT_MS) {
        // Past the limit — auto clock out
        if (intervalRef.current) clearInterval(intervalRef.current);
        // Record the idle gap up to the last activity
        if (idleStartRef.current === null) idleStartRef.current = lastActivityRef.current;
        await recordIdleInterval(idleStartRef.current, lastActivityRef.current + IDLE_WARN_MS);
        // Auto-clock-out via callback (caller handles UI + state cleanup)
        if (onAutoClockOut) onAutoClockOut(lastActivityRef.current);
        setShowWarning(false);
      } else if (sinceActive >= IDLE_WARN_MS) {
        // Warning zone — show the warning UI
        if (idleStartRef.current === null) idleStartRef.current = lastActivityRef.current;
        setShowWarning(true);
      }
    };
    intervalRef.current = setInterval(tick, 30 * 1000);
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
    // eslint-disable-next-line
  }, [enabled, shift?.id]);

  // On focus / visibility return: check if we should retroactively clock out
  useEffect(() => {
    if (!enabled || !shift) return;
    const check = async () => {
      // Pull fresh last_activity_at from DB
      const { data: s } = await supabase.from('shifts')
        .select('last_activity_at, end_time')
        .eq('id', shift.id).maybeSingle();
      if (!s || s.end_time) return; // already ended
      const lastTs = s.last_activity_at ? new Date(s.last_activity_at).getTime() : null;
      if (!lastTs) return;
      const now = Date.now();
      if (now - lastTs >= IDLE_LIMIT_MS) {
        // Retroactive clock-out
        await recordIdleInterval(lastTs, lastTs + IDLE_WARN_MS);
        if (onAutoClockOut) onAutoClockOut(lastTs);
      } else if (now - lastTs >= IDLE_WARN_MS) {
        setShowWarning(true);
      }
      lastActivityRef.current = lastTs; // reset local clock
    };
    const onFocus = () => check();
    const onVis = () => { if (!document.hidden) check(); };
    window.addEventListener('focus', onFocus);
    document.addEventListener('visibilitychange', onVis);
    return () => {
      window.removeEventListener('focus', onFocus);
      document.removeEventListener('visibilitychange', onVis);
    };
    // eslint-disable-next-line
  }, [enabled, shift?.id]);

  const dismissWarning = () => {
    lastActivityRef.current = Date.now();
    saveActivity(Date.now());
    idleStartRef.current = null;
    setShowWarning(false);
  };

  return { showWarning, dismissWarning };
}


const fmtTime = (ms) => {
  if (!ms || ms < 0) return '0:00:00';
  const total = Math.floor(ms / 1000);
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  return `${h}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
};
const fmtTimeShort = (ms) => {
  if (!ms || ms < 0) return '0m';
  const t = Math.floor(ms / 1000);
  const h = Math.floor(t / 3600);
  const m = Math.floor((t % 3600) / 60);
  return h > 0 ? `${h}h ${m}m` : `${m}m`;
};
const fmtMoney = (n) => {
  if (n == null || isNaN(n)) return '$0.00';
  return '$' + Number(n).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};
const fmtDate = (ts) => new Date(ts).toLocaleDateString('en-US', { month:'short', day:'numeric' });
const fmtDateLong = (ts) => new Date(ts).toLocaleDateString('en-US', { month:'long', day:'numeric', year:'numeric' });
const fmtDateWithDay = (ts) => new Date(ts).toLocaleDateString('en-US', { weekday:'short', month:'short', day:'numeric' });

// Format a 'YYYY-MM-DD' due date parsed in LOCAL time (avoids the
// UTC-midnight shift that makes date-only strings render a day early).
const fmtDueDate = (key) => {
  if (!key) return '';
  const d = new Date(String(key).slice(0, 10) + 'T00:00:00');
  return d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
};

// Due-date helpers for assignments. scheduled_date is 'YYYY-MM-DD'.
const localTodayKey = () => {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};
// 'overdue' | 'today' | 'upcoming' | null
const assignmentDueKind = (scheduledDate) => {
  if (!scheduledDate) return null;
  const today = localTodayKey();
  if (scheduledDate < today) return 'overdue';
  if (scheduledDate === today) return 'today';
  return 'upcoming';
};
// Sort rank: overdue first, then today, then undated, then upcoming.
const assignmentDueRank = (scheduledDate) => {
  const k = assignmentDueKind(scheduledDate);
  if (k === 'overdue') return 0;
  if (k === 'today') return 1;
  if (!k) return 2;
  return 3;
};
const fmtClock = (ts) => new Date(ts).toLocaleTimeString('en-US', { hour:'numeric', minute:'2-digit' });

// Time-of-day greeting helper. Returns "Good morning", "Good afternoon",
// or "Good evening" based on the current hour in the user's local time.
const greetingForTime = () => {
  const h = new Date().getHours();
  if (h < 12) return 'Good morning';
  if (h < 17) return 'Good afternoon';
  return 'Good evening';
};

// Compute billable milliseconds for a shift:
//   raw clocked-in time − idle_seconds + manual_adjustment_seconds
// Falls back to raw duration for shifts without these fields.
const shiftBillableMs = (shift) => {
  if (!shift?.start_time) return 0;
  const rawMs = (shift.end_time ? new Date(shift.end_time) : new Date()) - new Date(shift.start_time);
  const idleSec = shift.idle_seconds || 0;
  const adjSec = shift.manual_adjustment_seconds || 0;
  return Math.max(0, rawMs - idleSec * 1000 + adjSec * 1000);
};
const shiftBillableHours = (shift) => shiftBillableMs(shift) / (1000 * 60 * 60);


function useTick(active) {
  const [, setT] = useState(0);
  useEffect(() => {
    if (!active) return;
    const id = setInterval(() => setT(t => t + 1), 1000);
    return () => clearInterval(id);
  }, [active]);
}

// Natural sort: '1-101' before '1-102' before '2-101' before '10-101'
// Splits the label into number/non-number chunks and compares chunk by chunk.
function naturalCompare(a, b) {
  const ax = String(a).split(/(\d+)/).filter(Boolean);
  const bx = String(b).split(/(\d+)/).filter(Boolean);
  for (let i = 0; i < Math.max(ax.length, bx.length); i++) {
    if (ax[i] === undefined) return -1;
    if (bx[i] === undefined) return 1;
    const an = parseInt(ax[i], 10);
    const bn = parseInt(bx[i], 10);
    if (!isNaN(an) && !isNaN(bn)) {
      if (an !== bn) return an - bn;
    } else {
      const cmp = ax[i].localeCompare(bx[i]);
      if (cmp !== 0) return cmp;
    }
  }
  return 0;
}

// Extract the building prefix from a unit label like "B3-205" → "B3"
// Falls back to first non-numeric prefix, or null if no match.
function buildingFromLabel(label) {
  if (!label) return null;
  const m = String(label).match(/^([A-Za-z]+\d+)/);
  return m ? m[1] : null;
}

// Pull the floor number out of an apartment label. The first digit of
// the apartment portion is the floor (101 → 1, 204 → 2, 305 → 3).
// Returns null if no apartment number is detected.
function floorFromLabel(label) {
  if (!label) return null;
  // Match the apartment number portion — everything after the building
  // prefix (e.g. "B1-101" → "101", or just "101" if no prefix).
  const m = String(label).match(/(\d{3,})/);
  if (!m) return null;
  return parseInt(m[1].charAt(0), 10);
}

// Resolve which BUILDING a unit belongs to. Two ways:
//   1. If the label carries a prefix (e.g. "B2-305"), use it directly.
//   2. Otherwise derive it from the cumulative numbering scheme — units
//      run 4-per-floor per building, so on any floor units 1–4 are
//      building 1, 5–8 are building 2, 9–12 are building 3, etc.
//      101–104 → B1, 105–108 → B2, 305–308 → B2 (top floor), and so on.
// BLOCK_SIZE is the units-per-floor-per-building (4 here). Returns a
// stable key string like "B1" so we can group/compare by building.
const BUILDING_BLOCK_SIZE = 4;
function buildingKey(label, blockSize = BUILDING_BLOCK_SIZE) {
  const prefixed = buildingFromLabel(label);
  if (prefixed) return prefixed;
  const m = String(label || '').match(/(\d{3,})/);
  if (!m) return null;
  const num = parseInt(m[1], 10);
  const floor = parseInt(m[1].charAt(0), 10);
  const pos = num - floor * 100; // position across buildings on that floor
  if (pos < 1) return null;
  return 'B' + Math.ceil(pos / blockSize);
}

const sessionStore = {
  async get() {
    try { const v = localStorage.getItem('tidytrack_session'); return v ? JSON.parse(v) : null; }
    catch { return null; }
  },
  async set(v) { try { localStorage.setItem('tidytrack_session', JSON.stringify(v)); } catch {} },
  async clear() { try { localStorage.removeItem('tidytrack_session'); } catch {} }
};

// =================================================================
// Top-level App
// =================================================================
export default function App() {
  // Hash-based routing so we can have different routes (#/portal, #/staff, etc.)
  // without setting up react-router.
  const [route, setRoute] = useState(() => window.location.hash || '');

  useEffect(() => {
    const onHash = () => setRoute(window.location.hash || '');
    window.addEventListener('hashchange', onHash);
    return () => window.removeEventListener('hashchange', onHash);
  }, []);

  // Decide which screen to mount, then wrap in TranslationProvider so
  // the Spanish toggle works across every surface (cleaner, PM, owner).
  let inner;
  if (route.startsWith('#/portal') || route.startsWith('#portal')) {
    inner = <PortalApp />;
  } else if (route.startsWith('#/staff') || route.startsWith('#staff')) {
    inner = <StaffApp />;
  } else {
    inner = <RootRouter />;
  }
  return <TranslationProvider>{inner}</TranslationProvider>;
}

// Decides between LandingPage and StaffApp at the root URL based on remembered choice.
function RootRouter() {
  const [view, setView] = useState(null); // 'staff' | 'landing'

  useEffect(() => {
    try {
      const choice = localStorage.getItem('tt_role_choice');
      if (choice === 'staff') {
        setView('staff');
      } else {
        setView('landing');
      }
    } catch {
      setView('landing');
    }
  }, []);

  if (view === null) return <Splash text="" />;
  if (view === 'staff') return <StaffApp />;

  // Landing page — let user pick
  return (
    <LandingPage
      onPickStaff={() => {
        try { localStorage.setItem('tt_role_choice', 'staff'); } catch {}
        setView('staff');
      }}
      onPickPortal={() => {
        // We don't remember the portal choice (PMs use it rarely, often shared devices).
        // Just navigate to the portal route.
        window.location.hash = '#/portal';
      }}
    />
  );
}

function StaffApp() {
  const [session, setSession] = useState(null);
  const [loaded, setLoaded] = useState(false);
  const [configError, setConfigError] = useState(false);

  useEffect(() => {
    if (SUPABASE_URL.includes('PASTE_') || SUPABASE_ANON_KEY.includes('PASTE_')) {
      setConfigError(true); setLoaded(true); return;
    }
    (async () => {
      const s = await sessionStore.get();
      if (s?.employeeId) {
        const { data } = await supabase.from('employees').select('*').eq('id', s.employeeId).maybeSingle();
        if (data) setSession({ employee: data });
        else await sessionStore.clear();
      }
      setLoaded(true);
    })();
  }, []);

  if (!loaded) return <Splash text="Loading…" />;
  if (configError) return <ConfigError />;

  if (!session) {
    return <SignIn onSignIn={async (employee) => {
      // Remember they chose staff (in case localStorage was cleared)
      try { localStorage.setItem('tt_role_choice', 'staff'); } catch {}
      // Apply per-employee language pref before any UI mounts so the
      // cleaner sees the right locale immediately on this device.
      if (employee?.locale) {
        try { localStorage.setItem('tidytrack_locale', employee.locale); } catch {}
      }
      await sessionStore.set({ employeeId: employee.id });
      setSession({ employee });
    }} />;
  }
  const signOut = async () => { await sessionStore.clear(); setSession(null); };
  // Beta testers (is_beta_tester=true) get a sticky top toggle bar
  // letting them swap between BETA / EMPLOYEE / PM views. The flag is
  // set via SQL on a dedicated test-harness employee row — your real
  // owner account stays untouched.
  if (session.employee.is_beta_tester) {
    return <BetaShell employee={session.employee} onSignOut={signOut} />;
  }
  if (session.employee.role === 'manager' || session.employee.role === 'owner') {
    return <ManagerShell employee={session.employee} onSignOut={signOut} />;
  }
  return <EmployeeApp employee={session.employee} onSignOut={signOut} />;
}

// =================================================================
// BETA SHELL — wraps the appropriate inner shell (ManagerShell /
// EmployeeApp / PortalShell-stub) based on the current view. Only
// rendered for employees with is_beta_tester=true.
//
// View state is persisted to localStorage so a reload keeps you in
// whichever view you were last in. Window global is mirrored so any
// component anywhere in the tree can check the active view without
// needing context plumbing (matches the locale pattern).
// =================================================================
const BETA_VIEW_LS_KEY = 'tidytrack_beta_view';
function readBetaView() {
  try {
    const v = localStorage.getItem(BETA_VIEW_LS_KEY);
    if (v === 'beta' || v === 'employee' || v === 'pm') return v;
  } catch {}
  return 'beta';
}
function writeBetaView(v) {
  try { localStorage.setItem(BETA_VIEW_LS_KEY, v); } catch {}
  if (typeof window !== 'undefined') window.__tidytrack_beta_view = v;
}
// Gate helper used by features that want to render only inside the
// BETA view of a beta-tester account. Closed for everyone else even
// if they somehow set the window global manually.
function isBetaFeaturesEnabled(employee) {
  if (!employee?.is_beta_tester) return false;
  const v = (typeof window !== 'undefined' && window.__tidytrack_beta_view) || 'beta';
  return v === 'beta';
}

function BetaShell({ employee, onSignOut }) {
  const [view, setView] = useState(readBetaView());
  // Mirror to window global so deep components can read without prop drilling
  useEffect(() => { writeBetaView(view); }, [view]);
  // On mount, set the global once (in case something reads it before
  // the effect runs in StrictMode dev double-render).
  useEffect(() => {
    if (typeof window !== 'undefined') window.__tidytrack_beta_view = view;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  const VIEWS = [
    { id: 'beta',     label: 'BETA',     desc: 'Admin + new features' },
    { id: 'employee', label: 'EMPLOYEE', desc: 'What cleaners see' },
    { id: 'pm',       label: 'PM',       desc: 'What property managers see' },
  ];
  const banner = (
    <div className="fixed top-0 inset-x-0 z-50 bg-stone-900 text-stone-50 px-2 py-1.5 flex items-center gap-1 shadow-lg">
      <span className="text-[9px] uppercase tracking-widest font-mono text-amber-400 px-1.5 flex-shrink-0">
        Beta
      </span>
      <div className="flex-1 flex items-center gap-1 overflow-x-auto">
        {VIEWS.map(v => (
          <button key={v.id} onClick={() => setView(v.id)}
            className={`text-[10px] font-mono uppercase tracking-wider px-2.5 py-1 rounded-full whitespace-nowrap transition-colors ${
              view === v.id
                ? 'bg-amber-500 text-stone-900 font-bold'
                : 'bg-stone-800 text-stone-400 hover:text-stone-100'
            }`}>
            {v.label}
          </button>
        ))}
      </div>
      <button onClick={onSignOut}
        className="text-[10px] font-mono uppercase tracking-wider px-2 py-1 rounded-full text-stone-400 hover:text-stone-100 flex-shrink-0">
        Sign out
      </button>
    </div>
  );
  // Each branch keeps its own state (mount/unmount on switch).
  // That's intentional — a fresh EMPLOYEE view from BETA shows a clean
  // cleaner experience, not a half-finished one.
  let inner;
  if (view === 'beta') {
    inner = <ManagerShell employee={employee} onSignOut={onSignOut} />;
  } else if (view === 'employee') {
    inner = <EmployeeApp employee={employee} onSignOut={onSignOut} />;
  } else {
    // PM view — implemented in the next turn. Synthetic portalUser
    // injection requires PortalShell refactor we haven't done yet.
    inner = (
      <div className="min-h-screen bg-stone-50 pt-12 flex items-center justify-center">
        <div className="max-w-md mx-auto p-8 text-center">
          <div className="text-xs uppercase tracking-widest text-stone-500 font-mono mb-3">Coming soon</div>
          <div className="font-serif text-2xl text-stone-900 mb-2">PM view</div>
          <div className="text-sm text-stone-600">
            PM impersonation needs PortalShell adapter work. Shipping in a follow-up turn.
            For now, use BETA or EMPLOYEE.
          </div>
        </div>
      </div>
    );
  }
  return (
    <div>
      {banner}
      {/* Push the inner shell down so the banner doesn't overlap.
         The banner is ~32px tall; pt-9 (36px) gives a tiny buffer. */}
      <div className="pt-9">{inner}</div>
    </div>
  );
}

function Splash({ text }) {
  return <div className="min-h-screen bg-stone-50 flex items-center justify-center text-stone-400 text-sm">{text}</div>;
}

// =================================================================
// PROGRESS BAR — reusable step indicator. Used by both the upload
// wizard and the cleaner workflow so people see where they are.
//
// - `steps` is an array of labels in order, e.g. ['Property', 'Bedrooms', 'Sheet', 'Configure']
// - `currentStep` is the 0-based index of the step they're ON now
//   (segments to the left of this are filled, this one is in-progress)
// - `complete` (boolean) flips the whole bar to emerald green to signal
//   the workflow finished
//
// Visual model:
//   complete=false → segments [0..currentStep-1] are tan-filled,
//                    segment currentStep is half-filled with stripe,
//                    later segments are gray
//   complete=true  → all segments emerald
// =================================================================
// ProgressBar with optional click-to-navigate. When `onStepClick` is
// provided, past steps (i < currentStep) become tappable so the user
// can jump back. Future steps are NEVER clickable (can't skip ahead).
function ProgressBar({ steps, currentStep, complete = false, onStepClick }) {
  if (!steps || steps.length === 0) return null;
  return (
    <div className="w-full">
      <div className="flex gap-1">
        {steps.map((label, i) => {
          const isPast = i < currentStep;
          const isCurrent = i === currentStep;
          const fillClass = complete
            ? 'bg-emerald-500'
            : isPast
              ? 'bg-amber-500'
              : isCurrent
                ? 'bg-amber-300'
                : 'bg-stone-200';
          const canClick = onStepClick && isPast;
          const Wrapper = canClick ? 'button' : 'div';
          const wrapperProps = canClick
            ? { onClick: () => onStepClick(i), className: 'flex-1 group cursor-pointer', title: `Back to ${label}` }
            : { className: 'flex-1' };
          return (
            <Wrapper key={i} {...wrapperProps}>
              <div className={`h-1.5 rounded-full transition-colors ${fillClass} ${canClick ? 'group-hover:opacity-80' : ''}`} />
            </Wrapper>
          );
        })}
      </div>
      <div className="flex gap-1 mt-1">
        {steps.map((label, i) => {
          const isPast = i < currentStep;
          const isCurrent = i === currentStep;
          const textClass = complete
            ? 'text-emerald-700 font-bold'
            : isPast
              ? 'text-stone-700 font-medium'
              : isCurrent
                ? 'text-stone-900 font-bold'
                : 'text-stone-400';
          const canClick = onStepClick && isPast;
          const Wrapper = canClick ? 'button' : 'div';
          const wrapperProps = canClick
            ? { onClick: () => onStepClick(i), className: 'flex-1 text-center cursor-pointer' }
            : { className: 'flex-1 text-center' };
          return (
            <Wrapper key={i} {...wrapperProps}>
              <span className={`text-[9px] uppercase tracking-wider font-mono ${textClass}`}>
                {label}
              </span>
            </Wrapper>
          );
        })}
      </div>
    </div>
  );
}

// =================================================================
// CLEANER PROGRESS BAR — always-visible bar that lives below the
// Header during a cleaner's session. Shows where they are in their
// workflow at a glance and lets them jump backward by tapping a
// segment.
//
// 5 segments (left to right):
//   1. Property   — filled once shift.customer exists
//   2. Assignment — filled once they've opened a specific bedroom
//   3. Items      — filled once they've claimed (in_progress) items
//   4. Working    — filled once there's an active work block
//   5. Complete   — filled once the active assignment is fully done
//
// `segments` is computed by the parent screen and passed in. Each
// segment is `{ label, filled, onClick, isCurrent }`.
//
// When the cleaner is inside an active work block (`inActiveWork`
// is true) and they tap a segment that would leave the work block,
// we open `LeaveWorkblockModal` first to ask: Mark done, Stay here,
// or Pause. The cleaner's choice dictates the next action.
// =================================================================
function CleanerProgressBar({ segments, inActiveWork = false, onLeaveDecision }) {
  const [pendingNavigation, setPendingNavigation] = useState(null);

  if (!segments || segments.length === 0) return null;

  const handleClick = (segment) => {
    if (!segment.onClick) return;
    // If they're inside an active work block AND the segment they
    // tapped isn't the "working" segment they're currently on,
    // intercept with the warning modal first.
    if (inActiveWork && !segment.isCurrent) {
      setPendingNavigation(() => segment.onClick);
      return;
    }
    segment.onClick();
  };

  return (
    <>
      <div className="bg-stone-50 border-b border-stone-200 px-3 py-2.5" data-no-translate-children="false">
        <div className="flex items-center gap-1">
          {segments.map((segment, i) => {
            const isLast = i === segments.length - 1;
            const isComplete = !!segments[i + 1]?.filled || segment.complete;
            // Color logic:
            // - complete (later segment filled too) → emerald
            // - filled current → amber
            // - filled but not current → tan
            // - empty → gray
            let fillClass;
            if (segment.complete) fillClass = 'bg-emerald-500';
            else if (segment.isCurrent && segment.filled) fillClass = 'bg-amber-500';
            else if (segment.filled) fillClass = 'bg-amber-400';
            else fillClass = 'bg-stone-200';

            return (
              <button key={i}
                onClick={() => handleClick(segment)}
                disabled={!segment.onClick}
                className={`flex-1 group ${segment.onClick ? 'cursor-pointer' : 'cursor-default'}`}>
                <div className={`h-1.5 rounded-full transition-colors ${fillClass} ${segment.onClick ? 'group-hover:opacity-80' : ''}`} />
                <div className={`text-[8px] sm:text-[9px] uppercase tracking-wider font-mono mt-1 text-center truncate ${
                  segment.complete ? 'text-emerald-700 font-bold'
                  : segment.isCurrent ? 'text-stone-900 font-bold'
                  : segment.filled ? 'text-stone-700 font-medium'
                  : 'text-stone-400'
                }`}>
                  {segment.label}
                </div>
              </button>
            );
          })}
        </div>
      </div>
      {pendingNavigation && (
        <LeaveWorkblockModal
          onChoose={(decision) => {
            const nav = pendingNavigation;
            setPendingNavigation(null);
            if (decision === 'stay') return;
            // 'done' or 'pause' — bubble up the decision so the parent
            // can finish/pause the work block, THEN run the navigation.
            if (onLeaveDecision) {
              Promise.resolve(onLeaveDecision(decision)).then(() => nav());
            } else {
              nav();
            }
          }}
          onClose={() => setPendingNavigation(null)} />
      )}
    </>
  );
}

