// =================================================================
// PIN Sign In
// =================================================================
function SignIn({ onSignIn }) {
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [busy, setBusy] = useState(false);
  const press = (n) => { setError(''); if (pin.length < 4) setPin(pin + n); };
  const back = () => { setError(''); setPin(pin.slice(0, -1)); };
  useEffect(() => { if (pin.length === 4) tryLogin();
    // eslint-disable-next-line
  }, [pin]);
  const tryLogin = async () => {
    setBusy(true);
    const { data } = await supabase.from('employees').select('*').eq('pin', pin).eq('active', true).maybeSingle();
    setBusy(false);
    if (!data) {
      setError('Invalid PIN');
      setTimeout(() => { setPin(''); setError(''); }, 1200);
      return;
    }
    onSignIn(data);
  };

  // Summit Clean palette — applied inline here for the sample.
  // Gold: #C99B5C  ·  Black: #0A0A0A  ·  Cream: #FAF8F4  ·  Warm grey: #6B6258  ·  Border: #E8E3DA
  const GOLD = '#C99B5C';
  const BLACK = '#0A0A0A';
  const CREAM = '#FAF8F4';
  const BORDER = '#E8E3DA';
  const MUTED = '#6B6258';

  return (
    <div className="min-h-screen flex flex-col" style={{ backgroundColor: CREAM }}>
      {/* Dark brand header band — tightened so the keypad fits on small phones */}
      <div className="flex flex-col items-center py-5 sm:py-8" style={{ backgroundColor: BLACK }}>
        <img
          src="https://bbaynvqnbkjyqhzhhypr.supabase.co/storage/v1/object/public/brand/unnamed%20(2).png"
          alt="Summit Clean"
          className="w-28 sm:w-40 h-auto mx-auto"
        />
      </div>

      {/* PIN entry section */}
      <div className="flex-1 flex flex-col justify-center items-center px-6 max-w-sm mx-auto w-full py-4 sm:py-8">
        <div className="text-center mb-4 sm:mb-6">
          <p className="text-xs uppercase tracking-[0.25em] font-mono" style={{ color: MUTED, letterSpacing: '0.25em' }}>
            Welcome back
          </p>
          <h2 className="font-serif text-xl sm:text-2xl mt-2" style={{ color: BLACK }}>
            Enter your 4-digit PIN
          </h2>
        </div>

        {/* PIN dots */}
        <div className="flex gap-3 mb-2">
          {[0,1,2,3].map(i => (
            <div key={i}
              className="w-4 h-4 rounded-full border-2 transition-all"
              style={{
                backgroundColor: pin.length > i ? (error ? '#B23A3A' : GOLD) : 'transparent',
                borderColor: pin.length > i ? (error ? '#B23A3A' : GOLD) : BORDER
              }} />
          ))}
        </div>
        <div className="h-5 mb-3 sm:mb-5 text-xs font-mono" style={{ color: '#B23A3A' }}>{error}</div>

        {/* Numpad */}
        <div className="grid grid-cols-3 gap-2 sm:gap-3 w-full max-w-xs">
          {[1,2,3,4,5,6,7,8,9].map(n => (
            <button key={n} onClick={() => press(n)} disabled={busy}
              style={{
                backgroundColor: '#FFFFFF',
                borderColor: BORDER,
                color: BLACK,
                touchAction: 'manipulation'
              }}
              className="aspect-square rounded-2xl border text-2xl font-light active:scale-95 transition-all">
              {n}
            </button>
          ))}
          <div />
          <button onClick={() => press(0)} disabled={busy}
            style={{
              backgroundColor: '#FFFFFF',
              borderColor: BORDER,
              color: BLACK,
              touchAction: 'manipulation'
            }}
            className="aspect-square rounded-2xl border text-2xl font-light active:scale-95 transition-all">0</button>
          <button onClick={back} disabled={busy}
            style={{ color: MUTED, touchAction: 'manipulation' }}
            className="aspect-square rounded-2xl flex items-center justify-center active:scale-95 transition-all">
            <Delete size={20} />
          </button>
        </div>
      </div>

      {/* Footer */}
      <div className="text-center pb-3 sm:pb-6 space-y-1 sm:space-y-2">
        <button onClick={() => {
            try { localStorage.removeItem('tt_role_choice'); } catch {}
            window.location.hash = '';
            window.location.reload();
          }}
          className="text-xs font-mono hover:underline" style={{ color: MUTED }}>
          Not staff? Sign in as a property manager →
        </button>
        <div className="text-xs font-mono" style={{ color: MUTED }}>
          Summit Clean · Cleaning operations
        </div>
      </div>
    </div>
  );
}

// Role helpers — keep this central so we never drift
const isOwner   = (e) => e?.role === 'owner';
const isManager = (e) => e?.role === 'manager' || e?.role === 'owner';
const canSeeMoney = (e) => isOwner(e) || can(e, 'view_pay_info'); // managers see $ if toggled on; owners always

// =================================================================
// CAPABILITIES — per-employee feature toggles.
// Owners always have every capability. For others, the value comes
// from employees.responsibilities jsonb. See v19 migration.
// =================================================================
const CAPABILITIES = [
  { key: 'upload_assignments',       label: 'Upload assignments',         hint: 'Create assignments and upload PDFs or photos for cleaners.' },
  { key: 'approve_pm_assignments',   label: 'Approve PM assignments',     hint: 'Accept or reject assignments submitted by property managers.' },
  { key: 'mark_assignments_done',    label: 'Mark any assignment done',   hint: 'Mark assignments complete even when they did not personally work on them. Without this, an employee can only mark Done on assignments they started.' },
  { key: 'edit_shift_times',         label: 'Edit shift times',           hint: 'Manually adjust clock-in/out and work block times.' },
  { key: 'view_pay_info',            label: 'View pay info',              hint: 'See bill rates, money amounts, and invoices.' },
  { key: 'manage_units',             label: 'Manage units & properties',  hint: 'Add or edit units, parties, properties, and bulk imports.' },
  { key: 'manage_assignments_admin', label: 'Reassign & delete assignments', hint: 'Move assignments between bedrooms or delete them entirely.' },
  { key: 'edit_due_dates',           label: 'Change due dates',           hint: 'Tap an assignment\u2019s date to reschedule when it\u2019s due.' },
];

// Returns true if the employee has the given capability key.
// Owners always return true. Manager defaults are set at create time
// in the EmployeeForm. Missing keys default to false.
const can = (employee, capabilityKey) => {
  if (!employee) return false;
  if (employee.role === 'owner') return true;
  const r = employee.responsibilities;
  if (r && typeof r === 'object' && r[capabilityKey] === true) return true;
  return false;
};

// The beta apartment complex (any property with "beta" in its name) is
// only visible to owners and granted beta testers — everyone else has
// it filtered out of property lists, like the other beta-gated things.
const visibleProps = (list, employee) => {
  if (!Array.isArray(list)) return list || [];
  if (employee?.is_beta_tester || employee?.role === 'owner') return list;
  return list.filter(c => !/\bbeta\b/i.test(c?.name || ''));
};

// =================================================================
// TASK CATEGORIES — structured picker for cleaners. Coexists with
// freeform task names. Each task has both a category (e.g. "general")
// and an optional subcategory (e.g. "kitchen_area"). Order here is
// preserved in the picker UI.
//
// PM portal groups "By section" on category for clean breakdown.
// =================================================================
const TASK_CATEGORIES = [
  { id: 'bedroom',  label: 'Bedroom',  subcategories: null },
  { id: 'bathroom', label: 'Bathroom', subcategories: null },
  { id: 'vanity',   label: 'Vanity',   subcategories: null },
  // General is split into the 4 inspection-sheet groups (A/B/C/D)
  // that exist on the paper Carriage Cove White-Glove form — each
  // bedroom's sheet has its OWN General section, so a 4-bedroom unit
  // covers all 4 variants between roommates. Items inside a group
  // can be multi-selected and will collapse into a single combined
  // task at submit (see startTasksFromPicker).
  //
  //   A — Bedroom 1 sheet: Living Room, Patio, Water Heater Closet
  //   B — Bedroom 2 sheet: Refrigerator, Freezer, Microwave, Breezeway
  //   C — Bedroom 3 sheet: Hallway Vents, Stove, Oven, Dishwasher
  //   D — Bedroom 4 sheet: Kitchen Area
  { id: 'general',  label: 'General',  subcategories: [
    // Group A — Living Room / Patio / Water Heater
    { id: 'living_room',  label: 'Living room',  group: 'a', groupLabel: 'LR / Patio / Water Heater' },
    { id: 'patio',        label: 'Patio',        group: 'a', groupLabel: 'LR / Patio / Water Heater' },
    { id: 'water_heater', label: 'Water heater', group: 'a', groupLabel: 'LR / Patio / Water Heater' },
    { id: 'hallways',     label: 'Hallway',      group: 'a', groupLabel: 'LR / Patio / Water Heater' },
    // Group B — Refrigerator / Freezer / Microwave / Breezeway
    { id: 'refrigerator', label: 'Refrigerator', group: 'b', groupLabel: 'Fridge / Microwave / Breezeway' },
    { id: 'freezer',      label: 'Freezer',      group: 'b', groupLabel: 'Fridge / Microwave / Breezeway' },
    { id: 'microwave',    label: 'Microwave',    group: 'b', groupLabel: 'Fridge / Microwave / Breezeway' },
    { id: 'breezeway',    label: 'Breezeway',    group: 'b', groupLabel: 'Fridge / Microwave / Breezeway' },
    // Group C — Hallway Vents / Stove / Oven / Dishwasher
    { id: 'vents',        label: 'Hallway vents', group: 'c', groupLabel: 'Vents / Stove / Oven / Dishwasher' },
    { id: 'stove',        label: 'Stove',         group: 'c', groupLabel: 'Vents / Stove / Oven / Dishwasher' },
    { id: 'oven',         label: 'Oven',          group: 'c', groupLabel: 'Vents / Stove / Oven / Dishwasher' },
    { id: 'dishwasher',   label: 'Dishwasher',    group: 'c', groupLabel: 'Vents / Stove / Oven / Dishwasher' },
    // Group D — Kitchen
    { id: 'kitchen',      label: 'Kitchen',       group: 'd', groupLabel: 'Kitchen' },
  ]},
];

// Ordered list of General group keys, used so the UI renders them
// consistently (A → D) regardless of insertion order above.
const GENERAL_GROUP_ORDER = ['a', 'b', 'c', 'd'];

// Look up a friendly label for category/subcategory ids
const taskCategoryLabel = (category, subcategory) => {
  if (!category) return null;
  const cat = TASK_CATEGORIES.find(c => c.id === category);
  if (!cat) return category;
  if (!subcategory) return cat.label;
  const sub = cat.subcategories?.find(s => s.id === subcategory);
  return sub ? `${cat.label} — ${sub.label}` : cat.label;
};

// Short label for compact display (PM "By section" chips)
const taskCategoryShortLabel = (category, subcategory) => {
  if (!category) return null;
  const cat = TASK_CATEGORIES.find(c => c.id === category);
  if (!cat) return category;
  if (category === 'general' && subcategory) {
    const sub = cat.subcategories?.find(s => s.id === subcategory);
    return sub ? `General — ${sub.label}` : 'General';
  }
  return cat.label;
};

// Split a task name into individual items when it was built from a
// multi-item pick (cleaner ticked several subsections + Start). The
// picker joins picks with " + " so we use that as the splitter.
// Returns an array — single-item tasks return [name].
const splitTaskName = (name) => {
  if (!name) return [];
  // The picker uses " + " as the join string. Also handle " · " which
  // some older paths used as a separator.
  if (name.includes(' + ')) {
    return name.split(' + ').map(s => s.trim()).filter(Boolean);
  }
  return [name];
};

// =================================================================
// ADDRESS LINK — tappable address chip. Opens the address in the
// user's default maps app (native on phones, Google Maps in browser
// on desktop). Always rendered as a <span> with stopPropagation so
// it's safe to drop inside a parent <button> without nesting issues.
// Props:
//   address: the raw address string
//   icon: 'pin' (default) | 'none'
//   className: extra classes to apply
// =================================================================
function AddressLink({ address, icon = 'pin', className = '' }) {
  if (!address) return null;
  const mapsUrl = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}`;
  const openMaps = (e) => {
    e.stopPropagation();
    e.preventDefault();
    window.open(mapsUrl, '_blank', 'noopener,noreferrer');
  };
  return (
    <span onClick={openMaps} role="link" tabIndex={0}
      onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') openMaps(e); }}
      className={`inline-flex items-center gap-1 cursor-pointer hover:underline active:opacity-60 ${className}`}
      title="Open in maps">
      {icon === 'pin' && <MapPin size={11} className="flex-shrink-0" />}
      <span className="truncate">{address}</span>
    </span>
  );
}

// =================================================================
// TRANSLATABLE TEXT — wraps a text snippet (work notes, task name,
// etc) with a small inline translate toggle. Defaults to showing
// original; user taps "Translate" to fetch translation via Google
// Cloud Translate. Caches result in component state so toggling
// back is free. Gracefully hides the button if translation isn't
// configured.
// Props:
//   text: the original string
//   targetLang: 'en' | 'es' (the language to translate INTO when tapped)
//   className: classes for the wrapping text span
// =================================================================
function TranslatableText({ text, targetLang = 'en', className = '' }) {
  const [translated, setTranslated] = useState(null); // { text, sourceLang } | null
  const [showTranslation, setShowTranslation] = useState(false);
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState(null);

  if (!text || !text.trim()) return null;
  const canTranslate = isTextTranslateConfigured();

  const onToggle = async () => {
    setError(null);
    if (translated) {
      // Already fetched — just flip the view
      setShowTranslation(s => !s);
      return;
    }
    setBusy(true);
    try {
      const results = await translateText([text], targetLang);
      const first = results[0];
      if (!first) throw new Error('No translation returned.');
      // If detected source matches target, the translation is the same as original.
      // Inform the user rather than showing identical text.
      if (first.detectedSourceLanguage === targetLang) {
        setError(`This text is already in ${targetLang === 'en' ? 'English' : 'Spanish'}.`);
        setBusy(false);
        return;
      }
      setTranslated({ text: first.translatedText, sourceLang: first.detectedSourceLanguage });
      setShowTranslation(true);
    } catch (e) {
      setError(e.message || 'Translation failed.');
    } finally {
      setBusy(false);
    }
  };

  const visibleText = showTranslation && translated ? translated.text : text;
  const sourceLangLabel = translated?.sourceLang === 'es' ? 'Spanish' :
                          translated?.sourceLang === 'en' ? 'English' :
                          translated?.sourceLang || 'original';

  return (
    <span className={className}>
      <span>{visibleText}</span>
      {canTranslate && (
        <button onClick={onToggle} disabled={busy} type="button"
          className="ml-1.5 inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-600 text-[9px] font-mono uppercase tracking-wider align-middle disabled:opacity-50">
          <Languages size={9} />
          {busy ? '…' :
            showTranslation
              ? `Show ${sourceLangLabel}`
              : translated
                ? `Show ${targetLang === 'en' ? 'English' : 'Spanish'}`
                : `Translate`}
        </button>
      )}
      {error && (
        <span className="ml-1.5 text-[9px] font-mono text-amber-700 italic">({error})</span>
      )}
    </span>
  );
}

// =================================================================
// BED/BATH PICKER — bedrooms (1-8) + bathrooms (1, 1.5, ... 5) for
// simple properties and townhome units. Pass nullable to allow
// "not specified" state.
// =================================================================
function BedBathPicker({ bedrooms, bathrooms, onChange }) {
  const BEDROOM_OPTS = [1, 2, 3, 4, 5, 6, 7, 8];
  const BATHROOM_OPTS = [1, 1.5, 2, 2.5, 3, 3.5, 4, 4.5, 5];
  const formatBath = (n) => Number.isInteger(n) ? `${n}` : `${n}`;
  return (
    <div className="space-y-4">
      <div>
        <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Bedrooms</label>
        <div className="grid grid-cols-8 gap-1.5">
          {BEDROOM_OPTS.map(n => (
            <button key={n} type="button" onClick={() => onChange({ bedrooms: n, bathrooms })}
              className={`py-2.5 rounded-lg border-2 font-mono text-sm transition-all ${bedrooms === n ? 'border-stone-900 bg-stone-900 text-stone-50' : 'border-stone-200 bg-white text-stone-700 hover:border-stone-400'}`}>
              {n}
            </button>
          ))}
        </div>
        {bedrooms && (
          <button type="button" onClick={() => onChange({ bedrooms: null, bathrooms })}
            className="text-[11px] text-stone-500 hover:text-stone-700 mt-1.5 font-mono">
            Clear
          </button>
        )}
      </div>
      <div>
        <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Bathrooms <span className="normal-case text-stone-400 text-[10px]">(.5 = half bath)</span></label>
        <div className="grid grid-cols-9 gap-1.5">
          {BATHROOM_OPTS.map(n => (
            <button key={n} type="button" onClick={() => onChange({ bedrooms, bathrooms: n })}
              className={`py-2.5 rounded-lg border-2 font-mono text-xs transition-all ${bathrooms === n ? 'border-stone-900 bg-stone-900 text-stone-50' : 'border-stone-200 bg-white text-stone-700 hover:border-stone-400'}`}>
              {formatBath(n)}
            </button>
          ))}
        </div>
        {bathrooms && (
          <button type="button" onClick={() => onChange({ bedrooms, bathrooms: null })}
            className="text-[11px] text-stone-500 hover:text-stone-700 mt-1.5 font-mono">
            Clear
          </button>
        )}
      </div>
    </div>
  );
}

// =================================================================
// TASK CATEGORY PICKER — structured task starter for cleaners.
// Cleaner picks one of: Bedroom / Bathroom / Vanity / General.
// If General, a row of sub-category chips appears (kitchen, living
// room, hallways, fridge). Sub-categories support multi-select.
//
// Cleaner can also type a custom name to override the auto-filled
// name OR specify (freeform coexists with the structured picker).
//
// On submit:
//   - For single-select categories (bedroom/bathroom/vanity, or
//     general+0-or-1 subcategory): calls onStartOne(name, cat, sub).
//   - For multi-select general: calls onStartMany([{name,cat,sub}, ...])
//     which creates multiple tasks at once (first becomes active,
//     rest are queued for resume).
//
// Props:
//   busy: disabled state from parent
//   onStartOne(name, category, subcategory)
//   onStartMany(taskInputs)  // optional; falls back to onStartOne if not provided
//   defaultName, setDefaultName: shared freeform name state (for the
//                                 existing "type your own name" flow)
// =================================================================
// =================================================================
// PICKER TRANSLATIONS (Spanish)
//
// Static dictionary mapping template_item_key → ES label. Used by
// labelForTarget when the cleaner's locale is 'es'. Keys mirror the
