// =================================================================
// CHANGE PIN MODAL — cleaner changes their own 4-digit PIN
// Three steps: current PIN → new PIN → confirm new PIN.
// Blocks obvious PINs, requires new ≠ current, checks uniqueness.
// =================================================================
const OBVIOUS_PINS = new Set([
  '0000','1111','2222','3333','4444','5555','6666','7777','8888','9999',
  '1234','4321','0123','3210','1212','2121','1010','0101','2580','6969',
  '1004','2000','1313',
]);

function ChangePinModal({ employee, onClose, onSaved }) {
  const [step, setStep] = useState('current'); // current | new | confirm
  const [currentPin, setCurrentPin] = useState('');
  const [newPin, setNewPin] = useState('');
  const [confirmPin, setConfirmPin] = useState('');
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  const activePin =
    step === 'current' ? currentPin :
    step === 'new'     ? newPin :
    confirmPin;

  const setActivePin = (val) => {
    setError('');
    if (step === 'current') setCurrentPin(val);
    else if (step === 'new') setNewPin(val);
    else setConfirmPin(val);
  };

  const press = (n) => {
    if (busy) return;
    if (activePin.length >= 4) return;
    setActivePin(activePin + String(n));
  };
  const backspace = () => {
    if (busy) return;
    setActivePin(activePin.slice(0, -1));
  };

  // Auto-advance when 4 digits entered
  useEffect(() => {
    if (activePin.length !== 4 || busy) return;
    (async () => {
      if (step === 'current') {
        // Validate current PIN
        if (activePin !== employee.pin) {
          setError('That\'s not your current PIN.');
          setCurrentPin('');
          return;
        }
        setStep('new');
      } else if (step === 'new') {
        // Validate the new PIN
        if (OBVIOUS_PINS.has(activePin)) {
          setError('That PIN is too easy to guess. Try a less obvious one.');
          setNewPin('');
          return;
        }
        if (activePin === employee.pin) {
          setError('Your new PIN must be different from your current PIN.');
          setNewPin('');
          return;
        }
        setStep('confirm');
      } else {
        // Confirm matches new
        if (activePin !== newPin) {
          setError('PINs don\'t match. Try again.');
          setConfirmPin('');
          return;
        }
        // Final save: check uniqueness then update
        setBusy(true);
        const { data: dup } = await supabase.from('employees')
          .select('id').eq('pin', newPin).neq('id', employee.id).maybeSingle();
        if (dup) {
          setBusy(false);
          setError('That PIN is already in use by another employee. Try a different one.');
          setConfirmPin('');
          setNewPin('');
          setStep('new');
          return;
        }
        const { error: upErr } = await supabase.from('employees')
          .update({ pin: newPin }).eq('id', employee.id);
        setBusy(false);
        if (upErr) {
          setError('Could not save: ' + upErr.message);
          setConfirmPin('');
          return;
        }
        alert('PIN updated! Use your new PIN next time you sign in.');
        onSaved(newPin);
      }
    })();
    // eslint-disable-next-line
  }, [activePin, step]);

  const titles = {
    current: 'Enter your current PIN',
    new: 'Choose a new 4-digit PIN',
    confirm: 'Confirm your new PIN',
  };
  const subtitles = {
    current: 'We need to verify it\'s really you.',
    new: 'Pick something memorable but not obvious.',
    confirm: 'Type it once more to make sure.',
  };

  return (
    <div className="fixed inset-0 bg-stone-900/90 z-50 flex flex-col">
      <div className="flex items-center justify-between p-4 text-stone-50">
        <button onClick={onClose} className="text-stone-300 text-sm font-mono hover:text-stone-50 disabled:opacity-50" disabled={busy}>
          Cancel
        </button>
        <div className="text-xs font-mono text-stone-400 uppercase tracking-wider">
          Step {step === 'current' ? '1' : step === 'new' ? '2' : '3'} of 3
        </div>
        <div className="w-12" />
      </div>
      <div className="flex-1 flex flex-col items-center justify-center px-6 max-w-sm mx-auto w-full">
        <div className="text-center mb-6">
          <div className="font-serif text-2xl text-stone-50 mb-1">{titles[step]}</div>
          <div className="text-sm text-stone-400">{subtitles[step]}</div>
        </div>
        <div className="flex gap-3 mb-2">
          {[0,1,2,3].map(i => (
            <div key={i}
              className={`w-4 h-4 rounded-full border-2 transition-all ${
                activePin.length > i
                  ? (error ? 'bg-red-500 border-red-500' : 'bg-amber-500 border-amber-500')
                  : 'bg-transparent border-stone-600'
              }`} />
          ))}
        </div>
        <div className="h-6 mb-6 text-xs font-mono text-red-400 text-center">{error}</div>
        <div className="grid grid-cols-3 gap-3 w-full max-w-xs">
          {[1,2,3,4,5,6,7,8,9].map(n => (
            <button key={n} onClick={() => press(n)} disabled={busy}
              className="aspect-square rounded-2xl bg-stone-800 hover:bg-stone-700 text-stone-50 text-2xl font-mono active:scale-95 transition-transform disabled:opacity-50">
              {n}
            </button>
          ))}
          <div />
          <button onClick={() => press(0)} disabled={busy}
            className="aspect-square rounded-2xl bg-stone-800 hover:bg-stone-700 text-stone-50 text-2xl font-mono active:scale-95 transition-transform disabled:opacity-50">
            0
          </button>
          <button onClick={backspace} disabled={busy || activePin.length === 0}
            className="aspect-square rounded-2xl bg-stone-800 hover:bg-stone-700 text-stone-50 flex items-center justify-center active:scale-95 transition-transform disabled:opacity-30">
            <Delete size={22} />
          </button>
        </div>
      </div>
    </div>
  );
}

// =================================================================
// PORTAL MENU SHEET — slide-up panel from the hamburger button.
// Holds the secondary actions (switch property, settings, sign out, help).
// =================================================================
function PortalMenuSheet({ portalUser, property, hasMultipleProperties, portalKind, isPmStaff,
  onClose, onSwitchProperty, onShowWelcome, onChangeCode, onShowTeam, onSignOut }) {
  const kindLabel = portalKind === 'property_owner' ? 'Property Owner'
    : portalKind === 'pm_staff' ? 'PM Staff'
    : 'Property Manager';

  const Item = ({ icon: Icon, label, hint, onClick, danger }) => (
    <button onClick={onClick}
      className={`w-full px-4 py-4 flex items-center gap-3 active:bg-stone-100 text-left border-b border-stone-100 last:border-b-0 ${danger ? 'text-red-700' : 'text-stone-900'}`}>
      <Icon size={18} className={danger ? 'text-red-600' : 'text-stone-500'} />
      <div className="flex-1 min-w-0">
        <div className="font-medium text-sm">{label}</div>
        {hint && <div className="text-xs text-stone-500 truncate">{hint}</div>}
      </div>
      <ChevronRight size={16} className="text-stone-400" />
    </button>
  );

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-stone-900/60" onClick={onClose} />
      {/* Sheet */}
      <div className="relative bg-stone-50 w-full sm:max-w-md rounded-t-3xl sm:rounded-3xl overflow-hidden shadow-2xl">
        {/* Header — identifies who's signed in */}
        <div className="px-5 py-4 border-b border-stone-200 bg-white">
          <div className="text-[10px] uppercase tracking-wider font-mono text-amber-700">
            Signed in as
          </div>
          <div className="font-serif text-lg text-stone-900 truncate">{portalUser?.name || 'Portal user'}</div>
          <div className="text-xs text-stone-500 font-mono">{kindLabel}</div>
          {property && (
            <div className="mt-2 pt-2 border-t border-stone-100 text-xs text-stone-600 flex items-center gap-1.5">
              <Building2 size={12} className="text-amber-700" />
              Viewing: <span className="font-medium">{property.name}</span>
            </div>
          )}
        </div>

        {/* Menu items */}
        <div className="bg-white">
          {hasMultipleProperties && (
            <Item icon={Layers} label="Switch property" hint="Pick a different property in your portfolio"
              onClick={onSwitchProperty} />
          )}
          {portalKind === 'property_owner' && (
            <Item icon={Users} label="Property team" hint="See & manage PMs on this property"
              onClick={onShowTeam} />
          )}
          <Item icon={HelpCircle} label="How this works" hint="Quick overview of the portal"
            onClick={onShowWelcome} />
          {!isPmStaff && portalUser && !portalUser._legacy && (
            <Item icon={Settings} label="Change my code" hint="Update your portfolio access code"
              onClick={onChangeCode} />
          )}
          <Item icon={LogOut} label="Sign out" danger onClick={onSignOut} />
        </div>

        {/* Footer cancel */}
        <button onClick={onClose}
          className="w-full py-3 text-sm font-mono text-stone-500 hover:bg-stone-100 border-t border-stone-200">
          Close
        </button>
      </div>
    </div>
  );
}

// =================================================================
// PORTAL TEAM MODAL — Property owner sees other portal users on this
// property and can detach PMs/staff (not other owners) from it.
// =================================================================
function PortalTeamModal({ property, portalUser, onClose }) {
  const [users, setUsers] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [detaching, setDetaching] = useState(null);

  const load = async () => {
    setLoaded(false);
    const { data: links } = await supabase.from('portal_user_properties')
      .select('portal_user:portal_users(*)')
      .eq('property_id', property.id);
    const all = (links || [])
      .map(l => l.portal_user)
      .filter(Boolean);
    setUsers(all);
    setLoaded(true);
  };
  useEffect(() => { load(); /* eslint-disable-next-line */ }, [property.id]);

  const detach = async (user) => {
    if (!confirm(`Remove ${user.name} from ${property.name}? They'll lose access to this property but keep access to any others.`)) return;
    setDetaching(user.id);
    const { error } = await supabase.from('portal_user_properties')
      .delete()
      .eq('portal_user_id', user.id)
      .eq('property_id', property.id);
    setDetaching(null);
    if (error) {
      alert('Could not remove: ' + error.message);
      return;
    }
    load();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center">
      <div className="absolute inset-0 bg-stone-900/60" onClick={onClose} />
      <div className="relative bg-stone-50 w-full sm:max-w-md rounded-t-3xl sm:rounded-3xl overflow-hidden shadow-2xl max-h-[85vh] flex flex-col">
        <div className="px-5 py-4 border-b border-stone-200 bg-white flex items-center justify-between">
          <div className="min-w-0">
            <div className="text-[10px] uppercase tracking-wider font-mono text-amber-700">Property team</div>
            <div className="font-serif text-lg text-stone-900 truncate">{property.name}</div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100 flex-shrink-0">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-5">
          {!loaded ? (
            <div className="text-center text-sm text-stone-400 py-8">Loading…</div>
          ) : users.length === 0 ? (
            <div className="text-center text-sm text-stone-400 py-8">No one else has access to this property.</div>
          ) : (
            <div className="space-y-2">
              {users.map(u => {
                const isYou = u.id === portalUser?.id;
                const isOtherOwner = u.kind === 'property_owner' && !isYou;
                const canDetach = !isYou && !isOtherOwner;
                return (
                  <div key={u.id} className="p-3 rounded-2xl bg-white border border-stone-200">
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1">
                          <span className="font-medium text-stone-900 truncate">{u.name}</span>
                          <span className={`text-[9px] uppercase tracking-wider px-1.5 py-0.5 rounded-full font-mono ${
                            u.kind === 'property_owner' ? 'bg-amber-100 text-amber-900' :
                            u.kind === 'pm_staff' ? 'bg-stone-200 text-stone-700' :
                            'bg-stone-900 text-stone-50'
                          }`}>
                            {u.kind === 'property_owner' ? 'OWNER' : u.kind === 'pm_staff' ? 'STAFF' : 'PM'}
                          </span>
                          {isYou && <span className="text-[10px] font-mono text-stone-400">(you)</span>}
                        </div>
                        {u.phone && <div className="text-xs text-stone-500">{u.phone}</div>}
                      </div>
                      {canDetach && (
                        <button onClick={() => detach(u)} disabled={detaching === u.id}
                          className="px-3 py-1.5 rounded-full bg-red-50 hover:bg-red-100 text-red-700 text-xs font-mono flex-shrink-0 active:scale-95 disabled:opacity-50">
                          {detaching === u.id ? '…' : 'Remove'}
                        </button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
          <div className="mt-4 p-3 rounded-xl bg-stone-100 text-xs text-stone-600">
            To add a new PM, contact Summit Clean. You can only remove non-owner team members from this property.
          </div>
        </div>
      </div>
    </div>
  );
}

function ChangePortalCodeModal({ portalUser, onClose, onSaved }) {
  const [oldCode, setOldCode] = useState('');
  const [newCode, setNewCode] = useState('');
  const [confirmCode, setConfirmCode] = useState('');
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  const validateCode = (c) => {
    if (c.length < 6) return 'Code must be at least 6 characters.';
    if (!/[a-z]/i.test(c)) return 'Code must contain at least one letter.';
    if (!/\d/.test(c)) return 'Code must contain at least one number.';
    return null;
  };

  const save = async () => {
    setError('');
    if (portalUser._legacy) {
      setError('Code changes require a small data migration. Contact Summit Clean to enable this feature for your account.');
      return;
    }
    if (oldCode.trim().toLowerCase() !== (portalUser.code || '').toLowerCase()) {
      setError('Old code is incorrect.');
      return;
    }
    const cleanNew = newCode.trim().toLowerCase();
    const v = validateCode(cleanNew);
    if (v) { setError(v); return; }
    if (cleanNew !== confirmCode.trim().toLowerCase()) {
      setError('New codes don\'t match.');
      return;
    }
    if (cleanNew === oldCode.trim().toLowerCase()) {
      setError('New code must be different from the old code.');
      return;
    }
    setBusy(true);
    // Check it's not already in use by another portal user
    const { data: dupe } = await supabase.from('portal_users')
      .select('id').eq('code', cleanNew).neq('id', portalUser.id).maybeSingle();
    // Also check legacy customer codes for safety
    const { data: dupePortal } = await supabase.from('customers')
      .select('id').eq('portal_code', cleanNew).maybeSingle();
    const { data: dupeStaff } = await supabase.from('customers')
      .select('id').eq('staff_portal_code', cleanNew).maybeSingle();
    if (dupe || dupePortal || dupeStaff) {
      setBusy(false);
      setError('That code is already in use. Try a different one.');
      return;
    }
    // Update the code on the portal_users row
    const { error: upErr } = await supabase.from('portal_users')
      .update({ code: cleanNew }).eq('id', portalUser.id);
    if (upErr) {
      setBusy(false);
      setError('Could not save: ' + upErr.message);
      return;
    }
    // Update local portal session so the new code is remembered
    try {
      const stored = localStorage.getItem('tidytrack_portal');
      if (stored) {
        const parsed = JSON.parse(stored);
        parsed.code = cleanNew;
        localStorage.setItem('tidytrack_portal', JSON.stringify(parsed));
      }
    } catch {}
    setBusy(false);
    alert('Code updated. Use your new code next time you sign in.');
    onSaved();
  };

  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl max-h-[90vh] flex flex-col">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div>
            <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">Account</div>
            <div className="font-serif text-xl text-stone-900">Change my access code</div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          <p className="text-sm text-stone-600">
            Pick a new code that's at least 6 characters long with both letters and numbers.
            You'll use this code the next time you sign in.
          </p>
          <div>
            <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-1 block">Current code</label>
            <input type="text" value={oldCode} onChange={(e) => setOldCode(e.target.value)} autoComplete="off"
              className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white font-mono" />
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-1 block">New code</label>
            <input type="text" value={newCode} onChange={(e) => setNewCode(e.target.value)} autoComplete="off"
              placeholder="At least 6 chars, with letters + numbers"
              className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white font-mono" />
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-1 block">Confirm new code</label>
            <input type="text" value={confirmCode} onChange={(e) => setConfirmCode(e.target.value)} autoComplete="off"
              className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white font-mono" />
          </div>
          {error && (
            <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
              <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
            </div>
          )}
        </div>
        <div className="p-5 border-t border-stone-200 space-y-2">
          <button onClick={save} disabled={busy}
            className="w-full py-3 rounded-2xl bg-stone-900 text-stone-50 font-medium disabled:opacity-50">
            {busy ? 'Saving…' : 'Save new code'}
          </button>
          <button onClick={onClose} disabled={busy}
            className="w-full py-2 rounded-2xl text-stone-600 text-sm font-medium">
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
}

// =================================================================
// PORTAL APP — separate flow for property managers and property owners.
// Sign in with a portfolio code → if they have multiple properties,
// pick one. They see only that property's photos, dates, and units.
// No cleaner names, no $ amounts (unless their kind allows it later).
// =================================================================
function PortalApp({ previewMode = false, previewEmployee = null, onExitPreview = null }) {
  const [portalUser, setPortalUser] = useState(null); // the portal_users row
  const [properties, setProperties] = useState([]);   // all props this user can access
  const [selectedProperty, setSelectedProperty] = useState(null);
  const [loaded, setLoaded] = useState(false);

  // Load properties for a given portal user
  const loadProperties = async (userId) => {
    const { data } = await supabase.from('portal_user_properties')
      .select('property:customers(*)')
      .eq('portal_user_id', userId);
    const props = (data || [])
      .map(r => r.property)
      .filter(p => p && p.active)
      .sort((a, b) => (a.name || '').localeCompare(b.name || ''));
    return props;
  };

  useEffect(() => {
    // Owner "Preview as PM": synthetic PM user + all multi-unit properties.
    if (previewMode) {
      (async () => {
        const synth = { id: null, name: previewEmployee?.name || 'Owner', kind: 'property_manager', __preview: true };
        const { data } = await supabase.from('customers').select('*')
          .eq('active', true).eq('property_type', 'multi_unit').order('name');
        const props = data || [];
        setPortalUser(synth);
        setProperties(props);
        if (props.length === 1) setSelectedProperty(props[0]);
        setLoaded(true);
      })();
      return;
    }
    // Auto-restore previous portal session
    (async () => {
      try {
        const stored = localStorage.getItem('tidytrack_portal');
        if (stored) {
          const parsed = JSON.parse(stored);
          // New format: { userId, propertyId, code }
          if (parsed.userId) {
            const { data: pu } = await supabase.from('portal_users')
              .select('*').eq('id', parsed.userId).eq('active', true).maybeSingle();
            if (pu) {
              const props = await loadProperties(pu.id);
              setPortalUser(pu);
              setProperties(props);
              // Re-select previously-viewed property if it's still in their list
              const stillThere = props.find(p => p.id === parsed.propertyId);
              if (stillThere) setSelectedProperty(stillThere);
              else if (props.length === 1) setSelectedProperty(props[0]);
            } else {
              localStorage.removeItem('tidytrack_portal');
            }
          } else if (parsed.code) {
            // Old format — try to migrate using the saved code
            const { data: pu } = await supabase.from('portal_users')
              .select('*').eq('code', parsed.code.toLowerCase()).eq('active', true).maybeSingle();
            if (pu) {
              const props = await loadProperties(pu.id);
              setPortalUser(pu);
              setProperties(props);
              const stillThere = props.find(p => p.id === parsed.propertyId);
              if (stillThere) setSelectedProperty(stillThere);
              else if (props.length === 1) setSelectedProperty(props[0]);
              // Upgrade localStorage to the new format
              localStorage.setItem('tidytrack_portal', JSON.stringify({
                userId: pu.id,
                propertyId: stillThere?.id || (props.length === 1 ? props[0].id : null),
                code: pu.code,
              }));
            } else {
              localStorage.removeItem('tidytrack_portal');
            }
          }
        }
      } catch (e) {
        console.warn('[portal] auto-restore failed', e);
      }
      setLoaded(true);
    })();
  }, [previewMode]);

  const onSignIn = async (user, props) => {
    setPortalUser(user);
    setProperties(props);
    // If only 1 property, auto-select it
    const auto = props.length === 1 ? props[0] : null;
    setSelectedProperty(auto);
    localStorage.setItem('tidytrack_portal', JSON.stringify({
      userId: user.id,
      propertyId: auto?.id || null,
      code: user.code,
    }));
  };

  const onPickProperty = (prop) => {
    setSelectedProperty(prop);
    if (previewMode) return;
    localStorage.setItem('tidytrack_portal', JSON.stringify({
      userId: portalUser.id,
      propertyId: prop.id,
      code: portalUser.code,
    }));
  };

  const onBackToPicker = () => {
    setSelectedProperty(null);
    if (previewMode) return;
    localStorage.setItem('tidytrack_portal', JSON.stringify({
      userId: portalUser.id,
      propertyId: null,
      code: portalUser.code,
    }));
  };

  const onSignOut = () => {
    if (previewMode) { onExitPreview && onExitPreview(); return; }
    localStorage.removeItem('tidytrack_portal');
    setPortalUser(null);
    setProperties([]);
    setSelectedProperty(null);
  };

  // Refresh the selected property record + reload properties list
  const refreshProperty = async () => {
    if (previewMode || !portalUser || !portalUser.id) return;
    const props = await loadProperties(portalUser.id);
    setProperties(props);
    if (selectedProperty) {
      const fresh = props.find(p => p.id === selectedProperty.id);
      if (fresh) setSelectedProperty(fresh);
      else setSelectedProperty(null); // they were detached from this property
    }
  };

  const withPreviewBanner = (node) => previewMode ? (
    <div className="min-h-screen bg-stone-50">
      <div className="bg-indigo-600 text-white px-4 py-2 text-xs font-mono flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2"><Eye size={12} /> Preview as PM — this is what your property managers see</div>
        <button onClick={() => onExitPreview && onExitPreview()} className="px-2 py-0.5 rounded bg-white/20 hover:bg-white/30">Exit preview</button>
      </div>
      {node}
    </div>
  ) : node;

  if (!loaded) return withPreviewBanner(<Splash text="Loading…" />);
  if (!portalUser) return <PortalSignIn onSignIn={onSignIn} />;
  if (!selectedProperty) {
    return withPreviewBanner(<PortalPropertyPicker portalUser={portalUser} properties={properties}
      onPick={onPickProperty} onSignOut={onSignOut} />);
  }
  return withPreviewBanner(<PortalDashboard
    property={selectedProperty}
    portalKind={portalUser.kind}
    portalUser={portalUser}
    properties={properties}
    onSwitchProperty={onPickProperty}
    hasMultipleProperties={properties.length > 1}
    onBackToPicker={onBackToPicker}
    onSignOut={onSignOut}
    onRefreshProperty={refreshProperty} />);
}

function PortalSignIn({ onSignIn }) {
  const [code, setCode] = useState('');
  const [error, setError] = useState('');
  const [busy, setBusy] = useState(false);

  const tryLogin = async () => {
    if (!code.trim()) return;
    setError(''); setBusy(true);
    const trimmed = code.trim().toLowerCase();

    // Look up the portal user by code
    const { data: user } = await supabase.from('portal_users')
      .select('*').eq('code', trimmed).eq('active', true).maybeSingle();

    if (user) {
      // Load their properties
      const { data: links } = await supabase.from('portal_user_properties')
        .select('property:customers(*)')
        .eq('portal_user_id', user.id);
      const props = (links || [])
        .map(r => r.property)
        .filter(p => p && p.active)
        .sort((a, b) => (a.name || '').localeCompare(b.name || ''));
      setBusy(false);
      if (props.length === 0) {
        setError('Your code is valid but no properties are assigned to you yet. Contact Summit Clean.');
        return;
      }
      onSignIn(user, props);
      return;
    }

    // Backward-compat fallback: try the old per-property codes
    // (in case the v18 migration hasn't been run yet, or wasn't able to migrate this code)
    let { data } = await supabase.from('customers')
      .select('*').eq('portal_code', trimmed).eq('active', true).maybeSingle();
    let kind = 'pm';
    if (!data) {
      ({ data } = await supabase.from('customers')
        .select('*').eq('staff_portal_code', trimmed).eq('active', true).maybeSingle());
      kind = 'pm_staff';
    }
    setBusy(false);
    if (!data) {
      setError("That code didn't match. Check with your cleaning company.");
      return;
    }
    // Synthesize a "fake" portal user so the rest of the flow works
    const synthUser = {
      id: 'legacy-' + data.id,
      code: trimmed,
      name: kind === 'pm_staff' ? `PM staff of ${data.name}` : `PM of ${data.name}`,
      kind: kind,
      active: true,
      _legacy: true, // marker so we don't try to update portal_users table for these
    };
    onSignIn(synthUser, [data]);
  };

  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      {/* Dark brand header band — tightened so content fits on small phones */}
      <div className="flex flex-col items-center py-5 sm:py-8 bg-stone-900">
        <img
          src="https://bbaynvqnbkjyqhzhhypr.supabase.co/storage/v1/object/public/brand/unnamed%20(2).png"
          alt="Summit Clean"
          className="w-28 sm:w-40 h-auto mx-auto"
        />
      </div>

      <div className="flex-1 flex flex-col justify-center items-center px-6 max-w-sm mx-auto w-full py-4 sm:py-8">
        <div className="mb-4 sm:mb-6 text-center">
          <p className="text-xs uppercase tracking-[0.25em] font-mono text-stone-500">
            Welcome
          </p>
          <h2 className="font-serif text-xl sm:text-2xl mt-2 text-stone-900">
            Property manager portal
          </h2>
        </div>

        <div className="w-full">
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Access code</label>
          <input type="text" value={code} onChange={(e) => setCode(e.target.value.toLowerCase().replace(/[^a-z0-9]/g, ''))}
            placeholder="e.g. sunset2024"
            onKeyDown={(e) => e.key === 'Enter' && tryLogin()}
            className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white focus:outline-none focus:border-stone-900 text-stone-900 font-mono text-lg tracking-wide" />

          {error && (
            <div className="mt-3 p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
              <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
            </div>
          )}

          <button onClick={tryLogin} disabled={busy || !code.trim()}
            className="w-full mt-4 py-4 rounded-2xl bg-stone-900 text-stone-50 font-medium active:scale-98 disabled:opacity-50">
            {busy ? 'Signing in…' : 'Sign in'}
          </button>

          <p className="text-xs text-stone-500 mt-6 text-center">
            Don't have a code? Ask Summit Clean for access.
          </p>
        </div>
      </div>
      <div className="text-center pb-6 text-xs text-stone-400 font-mono">
        <button onClick={() => {
            // Clear any remembered choice so they get to the landing page
            try { localStorage.removeItem('tt_role_choice'); } catch {}
            window.location.hash = '';
          }}
          className="hover:text-stone-600">
          ← Back
        </button>
      </div>
    </div>
  );
}

// =================================================================
// PORTAL PROPERTY PICKER — shown after sign-in when the user has 2+
// properties in their portfolio. Lets them pick which to view.
// =================================================================
function PortalPropertyPicker({ portalUser, properties, onPick, onSignOut }) {
  const kindLabel = portalUser.kind === 'property_owner' ? 'Property Owner'
    : portalUser.kind === 'pm_staff' ? 'PM Staff'
    : 'Property Manager';
  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      <div className="bg-stone-900 text-stone-50 px-5 py-5 flex items-center justify-between">
        <div className="flex items-center gap-3 min-w-0">
          <img
            src="https://bbaynvqnbkjyqhzhhypr.supabase.co/storage/v1/object/public/brand/unnamed%20(2).png"
            alt="Summit Clean"
            className="h-10 w-auto object-contain flex-shrink-0"
          />
          <div className="min-w-0">
            <div className="text-[10px] uppercase tracking-wider font-mono text-amber-400">
              {kindLabel}
            </div>
            <div className="font-serif text-lg truncate">{portalUser.name}</div>
          </div>
        </div>
        <button onClick={onSignOut} className="text-xs text-stone-300 font-mono hover:text-stone-50 flex-shrink-0 ml-2">
          Sign out
        </button>
      </div>
      <div className="flex-1 px-5 py-8 max-w-md mx-auto w-full">
        <div className="text-center mb-6">
          <h2 className="font-serif text-2xl text-stone-900 mb-1">
            {greetingForTime()}, <span className="italic text-amber-700">{portalUser.name?.split(' ')[0] || portalUser.name}</span>
          </h2>
          <p className="text-sm text-stone-500">
            You {properties.length === 1 ? 'have access to 1 property' : `have access to ${properties.length} properties`}. Pick one to get started.
          </p>
        </div>
        <div className="space-y-2">
          {properties.map(p => (
            <button key={p.id} onClick={() => onPick(p)}
              className="w-full p-4 rounded-2xl bg-white border border-stone-200 hover:border-amber-500 active:scale-[0.99] transition-all text-left flex items-center gap-3">
              <Building2 size={20} className="text-amber-700 flex-shrink-0" />
              <div className="flex-1 min-w-0">
                <div className="font-serif text-lg text-stone-900 truncate">{p.name}</div>
                {p.address && (
                  <div className="text-xs text-stone-500">
                    <AddressLink address={p.address} />
                  </div>
                )}
              </div>
              <ChevronRight size={18} className="text-stone-400 flex-shrink-0" />
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

function PortalDashboard({ property, portalKind, portalUser, properties, onSwitchProperty, hasMultipleProperties, onBackToPicker, onSignOut, onRefreshProperty }) {
  const [view, setView] = useState({ kind: 'home' });
  // 'home' (recent activity), 'unit-day' (drill into one unit's day), 'all-photos' (gallery)

  if (view.kind === 'unit-day') {
    return <PortalUnitDay property={property} unitId={view.unitId} date={view.date}
      portalUser={portalUser}
      onBack={() => setView({ kind: 'home' })} />;
  }

  return <PortalHome property={property} portalKind={portalKind} portalUser={portalUser}
    properties={properties} onSwitchProperty={onSwitchProperty}
    hasMultipleProperties={hasMultipleProperties} onBackToPicker={onBackToPicker}
    onSignOut={onSignOut}
    onRefreshProperty={onRefreshProperty}
    onOpenUnitDay={(unitId, date) => setView({ kind: 'unit-day', unitId, date })} />;
}

function PortalHome({ property, portalKind, portalUser, properties, onSwitchProperty, hasMultipleProperties, onBackToPicker, onSignOut, onRefreshProperty, onOpenUnitDay }) {
  const [tab, setTab] = useState('history'); // 'history' | 'assignments'
  const [asgSub, setAsgSub] = useState('requests'); // 'requests' | 'concerns'
  const [groups, setGroups] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [filter, setFilter] = useState('7d');
  const [showWelcome, setShowWelcome] = useState(false);
  const [showChangeCode, setShowChangeCode] = useState(false);
  const [showMessages, setShowMessages] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showTeam, setShowTeam] = useState(false);
  const pmUnread = useUnreadCount({ customer: property });
  const isPmStaff = portalKind === 'pm_staff';

  // Show welcome modal on first sign-in for this property.
  // We track per-property since one PM might manage multiple properties.
  useEffect(() => {
    try {
      const key = `tt_pm_welcomed_${property.id}`;
      if (!localStorage.getItem(key)) setShowWelcome(true);
    } catch {}
  }, [property.id]);

  const dismissWelcome = () => {
    try { localStorage.setItem(`tt_pm_welcomed_${property.id}`, '1'); } catch {}
    setShowWelcome(false);
  };

  useEffect(() => { (async () => {
    if (tab !== 'history') return;
    setLoaded(false);
    const days = filter === '7d' ? 7 : filter === '30d' ? 30 : 365;
    let since = new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString();
    if (property.portal_start_date) {
      const portalStart = `${property.portal_start_date}T00:00:00Z`;
      if (portalStart > since) since = portalStart;
    }
    console.log('[Portal] filtering from:', since, '| portal_start_date:', property.portal_start_date);

    if (property.property_type === 'multi_unit') {
      // Pull both: work_blocks in window, AND the current status of every
      // assignment_target for this property. PMs should only see units
      // where (a) real work happened (at least one task or photo) AND
      // (b) the assignment for that unit/bedroom is currently in 'done'
      // status. Reset back to pending → instantly removed from PM view.
      // Scope the done-targets query to THIS property's units and paginate
      // it — otherwise PostgREST's 1000-row cap on a global done-targets
      // query drops this property's cleans (they fall past the cap when a
      // busy property has thousands of done checklist items).
      const { data: propUnits } = await supabase.from('units').select('id').eq('customer_id', property.id);
      const propUnitIds = (propUnits || []).map(u => u.id);
      const fetchDoneTargets = async () => {
        let rows = [];
        if (propUnitIds.length) {
          const PAGE = 1000;
          for (let from = 0; ; from += PAGE) {
            const { data, error } = await supabase.from('assignment_targets')
              .select('unit_id, party_id, completed_at, unit:units(id, label), assignment:assignments!inner(customer_id, active, deleted_at)')
              .eq('status', 'done').in('unit_id', propUnitIds)
              .range(from, from + PAGE - 1);
            if (error || !data) break;
            rows = rows.concat(data);
            if (data.length < PAGE) break;
            if (from > 100000) break;
          }
        }
        // Whole-property (null-unit) done assignments — few, unscoped is fine.
        const { data: plData } = await supabase.from('assignment_targets')
          .select('unit_id, party_id, completed_at, unit:units(id, label), assignment:assignments!inner(customer_id, active, deleted_at)')
          .eq('status', 'done').is('unit_id', null);
        return rows.concat(plData || []);
      };
      const [{ data: blocks }, doneTargets] = await Promise.all([
        supabase.from('work_blocks')
          .select('id, start_time, end_time, unit_id, party_id, unit:units(id, label), shift:shifts!inner(customer_id), tasks(id, photos(kind, resolved_at))')
          .gte('start_time', since)
          .order('start_time', { ascending: false }),
        fetchDoneTargets(),
      ]);

      // Build a Set of "unit_id:party_id" keys that are currently Done.
      // Property-level Done assignments (no unit/party) cover everything
      // under that property, so we track those separately. This is only a
      // gate — history entries themselves come from real work blocks below,
      // so a unit appears on a date only if it was actually cleaned then
      // (not merely marked "done" without anyone clocking in).
      const doneUnitParty = new Set();
      let propertyLevelDone = false;
      (doneTargets || []).forEach(t => {
        if (t.assignment?.customer_id !== property.id) return;
        if (t.assignment?.active === false || t.assignment?.deleted_at) return;
        if (!t.unit_id && !t.party_id) {
          propertyLevelDone = true;
          return;
        }
        doneUnitParty.add(`${t.unit_id || ''}:${t.party_id || ''}`);
        if (t.unit_id && t.party_id) doneUnitParty.add(`${t.unit_id}:`); // also unit-level match
      });

      const byDate = {};

      // Enrich with photos/damage from work blocks for units that are Done.
      const filtered = (blocks || []).filter(b => {
        if (b.shift?.customer_id !== property.id || !b.unit) return false;
        if (propertyLevelDone) return true;
        const key1 = `${b.unit_id || ''}:${b.party_id || ''}`;
        const key2 = `${b.unit_id || ''}:`;
        return doneUnitParty.has(key1) || doneUnitParty.has(key2);
      });
      filtered.forEach(b => {
        const date = new Date(b.start_time).toISOString().split('T')[0];
        if (!byDate[date]) byDate[date] = {};
        const u = b.unit;
        if (!byDate[date][u.id]) byDate[date][u.id] = { unitId: u.id, label: u.label, photoCount: 0, hasDamage: false, hasResolvedDamage: false };
        (b.tasks || []).forEach(t => (t.photos || []).forEach(p => {
          // Track active and resolved damage separately. Active damage drives
          // the red badge; resolved damage powers the "past damage" sub-view.
          if (p.kind === 'damage') {
            if (p.resolved_at) byDate[date][u.id].hasResolvedDamage = true;
            else byDate[date][u.id].hasDamage = true;
          }
          byDate[date][u.id].photoCount++;
        }));
      });
      const out = Object.entries(byDate)
        .map(([date, byUnit]) => ({
          date,
          units: Object.values(byUnit).sort((a, b) => naturalCompare(a.label, b.label))
        }))
        .sort((a, b) => b.date.localeCompare(a.date));
      setGroups(out);
    } else {
      // Simple property — same dual filter (real work + Done assignment),
      // but there's no unit/party granularity so any Done assignment for
      // this property qualifies.
      const [{ data: shifts }, { data: doneTargets }] = await Promise.all([
        supabase.from('shifts')
          .select('id, start_time, end_time, tasks(id, photos(kind, resolved_at))')
          .eq('customer_id', property.id)
          .eq('is_preview', false)
          .gte('start_time', since)
          .order('start_time', { ascending: false }),
        supabase.from('assignment_targets')
          .select('id, assignment:assignments!inner(customer_id, active)')
          .eq('status', 'done'),
      ]);
      const hasDoneAssignment = (doneTargets || []).some(t =>
        t.assignment?.customer_id === property.id && t.assignment?.active !== false
      );
      const out = (shifts || [])
        .filter(s => {
          const hasWork = (s.tasks || []).some(t => (t.photos || []).length > 0) || (s.tasks || []).length > 0;
          return hasWork && hasDoneAssignment;
        })
        .map(s => {
          let photoCount = 0, hasDamage = false, hasResolvedDamage = false;
          (s.tasks || []).forEach(t => (t.photos || []).forEach(p => {
            photoCount++;
            if (p.kind === 'damage') {
              if (p.resolved_at) hasResolvedDamage = true;
              else hasDamage = true;
            }
          }));
          return {
            date: new Date(s.start_time).toISOString().split('T')[0],
            units: [{ unitId: null, label: 'Cleaning visit', photoCount, hasDamage, hasResolvedDamage }]
          };
        });
      setGroups(out);
    }
    setLoaded(true);
  })(); }, [property.id, filter, tab]);

  // Messages overlay — takes over the whole screen when active
  if (showMessages) {
    return <PortalMessagesTab property={property} portalKind={portalKind}
      onClose={() => setShowMessages(false)} />;
  }

  return (
    <div className="min-h-screen bg-stone-50 pb-12">
      <div className="bg-stone-900 text-stone-50 px-5 pt-5 pb-6">
        <div className="flex items-center justify-between mb-4 gap-2">
          <button onClick={() => setTab('history')} className="flex items-center gap-3 active:scale-95 transition-transform min-w-0" title="Home">
            <img
              src="https://bbaynvqnbkjyqhzhhypr.supabase.co/storage/v1/object/public/brand/unnamed%20(2).png"
              alt="Summit Clean"
              className="h-10 w-auto object-contain flex-shrink-0"
            />
            <div className="min-w-0">
              <div className="text-xs text-stone-400 font-mono uppercase tracking-wider flex items-center gap-1.5">
                {portalKind === 'property_owner' ? 'Property Owner'
                  : portalKind === 'pm_staff' ? 'PM Staff'
                  : 'Property Manager'}
              </div>
              <div className="text-sm font-serif truncate">{property.name}</div>
            </div>
          </button>
          <div className="flex items-center gap-2 flex-shrink-0">
            <button onClick={() => setShowMessages(true)}
              className="relative p-2 rounded-full bg-stone-800 hover:bg-stone-700 text-stone-50"
              title="Messages">
              <MessageCircle size={16} />
              {pmUnread > 0 && (
                <span className="absolute -top-1 -right-1 min-w-[18px] h-[18px] px-1 rounded-full bg-amber-600 text-white text-[10px] font-mono font-bold flex items-center justify-center border-2 border-stone-900">
                  {pmUnread > 99 ? '99+' : pmUnread}
                </span>
              )}
            </button>
            <button onClick={() => setShowMenu(true)}
              className="p-2 rounded-full bg-stone-800 hover:bg-stone-700 text-stone-50"
              title="Menu">
              <Menu size={16} />
            </button>
          </div>
        </div>
        {portalUser?.name && (
          <div className="text-xs text-stone-300 mt-2 font-mono">
            {greetingForTime()}, <span className="text-amber-400">{portalUser.name.split(' ')[0]}</span>
          </div>
        )}
        <h1 className="text-3xl font-light tracking-tight mt-1">{property.name}</h1>
        {hasMultipleProperties && Array.isArray(properties) && properties.length > 1 && onSwitchProperty && (
          <div className="mt-2 relative inline-flex items-center">
            <select
              value={property.id}
              onChange={(e) => { const p = properties.find(x => x.id === e.target.value); if (p && p.id !== property.id) onSwitchProperty(p); }}
              className="appearance-none pl-3 pr-8 py-1.5 rounded-lg bg-stone-100 border border-stone-300 text-stone-900 text-xs font-mono cursor-pointer">
              {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
            <span className="absolute right-2.5 text-stone-500 pointer-events-none text-[10px]">▾</span>
          </div>
        )}
        {property.address && (
          <div className="text-sm text-stone-300 mt-1">
            <AddressLink address={property.address} className="text-amber-400" />
          </div>
        )}
        {property.portal_start_date && (
          <div className="text-xs text-amber-400 font-mono mt-2">
            Showing cleanings from {new Date(property.portal_start_date + 'T12:00:00').toLocaleDateString('en-US', { month:'long', day:'numeric', year:'numeric' })} forward
          </div>
        )}
      </div>

      {/* Tab switcher */}
      <div className="px-5 pt-4">
        <div className="flex gap-1 bg-stone-100 p-1 rounded-xl">
          <button onClick={() => setTab('history')}
            className={`flex-1 py-2 px-2 rounded-lg text-xs font-medium ${tab === 'history' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
            History
          </button>
          <button onClick={() => setTab('assignments')}
            className={`flex-1 py-2 px-2 rounded-lg text-xs font-medium ${tab === 'assignments' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
            Assignments
          </button>
        </div>
      </div>

      {tab === 'history' && (
        <PortalHistoryTab property={property} groups={groups} loaded={loaded}
          filter={filter} setFilter={setFilter} onOpenUnitDay={onOpenUnitDay} />
      )}
      {tab === 'assignments' && (
        <div>
          <div className="px-5 pt-3">
            <div className="flex gap-1 bg-stone-100 p-1 rounded-xl">
              <button onClick={() => setAsgSub('requests')}
                className={`flex-1 py-2 px-2 rounded-lg text-xs font-medium ${asgSub === 'requests' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
                Assignments
              </button>
              <button onClick={() => setAsgSub('concerns')}
                className={`flex-1 py-2 px-2 rounded-lg text-xs font-medium ${asgSub === 'concerns' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
                Concerns
              </button>
            </div>
            <p className="text-[11px] text-stone-400 font-mono mt-2 px-1">
              {asgSub === 'requests'
                ? 'Request a cleaning for the team.'
                : 'Send us photos or a message — e.g. a resident complaint or something that needs attention.'}
            </p>
          </div>
          {asgSub === 'requests'
            ? <PortalAssignmentsTab property={property} portalKind={portalKind} portalUser={portalUser} />
            : <PortalPhotoUploadTab property={property} portalKind={portalKind} />}
        </div>
      )}

      {showWelcome && (
        <WelcomeModal propertyName={property.name} onClose={dismissWelcome} />
      )}
      {showMenu && (
        <PortalMenuSheet
          portalUser={portalUser}
          property={property}
          hasMultipleProperties={hasMultipleProperties}
          portalKind={portalKind}
          isPmStaff={isPmStaff}
          onClose={() => setShowMenu(false)}
          onSwitchProperty={() => { setShowMenu(false); onBackToPicker && onBackToPicker(); }}
          onShowWelcome={() => { setShowMenu(false); setShowWelcome(true); }}
          onChangeCode={() => { setShowMenu(false); setShowChangeCode(true); }}
          onShowTeam={() => { setShowMenu(false); setShowTeam(true); }}
          onSignOut={() => { setShowMenu(false); onSignOut && onSignOut(); }}
        />
      )}
      {showTeam && (
        <PortalTeamModal property={property} portalUser={portalUser}
          onClose={() => setShowTeam(false)} />
      )}
      {showChangeCode && portalUser && (
        <ChangePortalCodeModal portalUser={portalUser}
          onClose={() => setShowChangeCode(false)}
          onSaved={() => { setShowChangeCode(false); onRefreshProperty && onRefreshProperty(); }} />
      )}
    </div>
  );
}

// History tab — the original PortalHome content extracted
function PortalHistoryTab({ property, groups, loaded, filter, setFilter, onOpenUnitDay }) {
  // Filters — PM-appropriate. Date, building, and apartment. We
  // intentionally don't expose category/cleaner filters here because PMs
  // shouldn't be slicing by who did the work or by task type.
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [filterDate, setFilterDate] = useState('');        // YYYY-MM-DD or '' for all
  const [filterBuildings, setFilterBuildings] = useState(new Set()); // multi-select of building keys
  const [apartmentSearch, setApartmentSearch] = useState('');

  // Build the set of available buildings and dates from the loaded
  // groups so the filter UI only offers options that actually have
  // cleanings. Empty Set = show all.
  const availableBuildings = (() => {
    const set = new Set();
    groups.forEach(g => g.units.forEach(u => {
      const b = buildingFromLabel(u.label);
      if (b) set.add(b);
    }));
    return [...set].sort(naturalCompare);
  })();
  const availableDates = (() => {
    const set = new Set();
    groups.forEach(g => set.add(g.date));
    return [...set].sort().reverse(); // newest first
  })();

  // Apply filters to the displayed groups. Order: date → building →
  // apartment. We filter inside each group rather than dropping whole
  // dates so the user can see exactly which units match across a date.
  const aq = apartmentSearch.trim().toLowerCase();
  const filteredGroups = groups
    .filter(g => !filterDate || g.date === filterDate)
    .map(g => ({
      ...g,
      units: g.units.filter(u => {
        if (filterBuildings.size > 0) {
          const b = buildingFromLabel(u.label);
          if (!b || !filterBuildings.has(b)) return false;
        }
        if (aq) {
          if (!(u.label || '').toLowerCase().includes(aq)) return false;
        }
        return true;
      })
    }))
    .filter(g => g.units.length > 0);

  const activeFilterCount = (filterDate ? 1 : 0) + filterBuildings.size + (aq ? 1 : 0);
  const toggleBuilding = (b) => setFilterBuildings(prev => {
    const next = new Set(prev);
    if (next.has(b)) next.delete(b); else next.add(b);
    return next;
  });
  const clearFilters = () => {
    setFilterDate(''); setFilterBuildings(new Set()); setApartmentSearch('');
  };

  // Stats use filtered groups so the numbers reflect what's actually
  // on screen — otherwise the PM sees "12 cleanings" while only 3 rows
  // are visible after filtering.
  const totalPhotos = filteredGroups.reduce((sum, g) => sum + g.units.reduce((s, u) => s + u.photoCount, 0), 0);
  const damageCount = filteredGroups.reduce((sum, g) => sum + g.units.filter(u => u.hasDamage).length, 0);
  const resolvedDamageCount = filteredGroups.reduce((sum, g) => sum + g.units.filter(u => u.hasResolvedDamage).length, 0);
  const totalCleanings = filteredGroups.reduce((sum, g) => sum + g.units.length, 0);
  // Build the list of damage entries (date + unit) for the expandable view
  const damageEntries = [];
  const resolvedDamageEntries = [];
  filteredGroups.forEach(g => g.units.forEach(u => {
    if (u.hasDamage) damageEntries.push({ date: g.date, unitId: u.unitId, label: u.label });
    if (u.hasResolvedDamage) resolvedDamageEntries.push({ date: g.date, unitId: u.unitId, label: u.label });
  }));
  const [damageExpanded, setDamageExpanded] = useState(false);
  const [damageSubTab, setDamageSubTab] = useState('active'); // 'active' | 'resolved'

  return (
    <div className="px-5 pt-6">
      {/* Sticky damage indicator — pins to the top of the viewport when the
         PM scrolls past the stats row, so they never lose sight of active
         damage while reviewing the cleaning history below. Hidden when no
         active damage. Clicking it expands the same drill-down list. */}
      {damageCount > 0 && (
        <button
          onClick={() => setDamageExpanded(e => !e)}
          className="sticky top-0 z-30 -mx-5 mb-3 px-5 py-2.5 bg-red-600 hover:bg-red-700 text-white flex items-center justify-between gap-3 shadow-md active:scale-[0.99] transition-all">
          <div className="flex items-center gap-2 min-w-0">
            <AlertCircle size={16} className="flex-shrink-0" />
            <span className="text-sm font-medium truncate">
              {damageCount} {damageCount === 1 ? 'unit has' : 'units have'} active damage
            </span>
          </div>
          <span className="text-[10px] uppercase tracking-wider font-mono opacity-90 flex-shrink-0 flex items-center gap-0.5">
            {damageExpanded ? 'Hide' : 'View'}
            <ChevronRight size={12} className={`transition-transform ${damageExpanded ? 'rotate-90' : ''}`} />
          </span>
        </button>
      )}

      <div className="grid grid-cols-3 gap-3 mb-3">
        <div className="p-4 rounded-2xl bg-white border border-stone-200">
          <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-1">Cleanings</div>
          <div className="text-2xl font-serif">{totalCleanings}</div>
        </div>
        <div className="p-4 rounded-2xl bg-white border border-stone-200">
          <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-1">Photos</div>
          <div className="text-2xl font-serif">{totalPhotos}</div>
        </div>
        <button
          onClick={() => {
            if (damageCount === 0 && resolvedDamageCount === 0) return;
            // If there's no active damage but there IS past damage, default sub-tab to resolved
            if (damageCount === 0 && resolvedDamageCount > 0) setDamageSubTab('resolved');
            else setDamageSubTab('active');
            setDamageExpanded(e => !e);
          }}
          disabled={damageCount === 0 && resolvedDamageCount === 0}
          className={`p-4 rounded-2xl border text-left transition-all ${damageCount > 0 ? 'bg-red-50 border-red-200 hover:border-red-400 cursor-pointer active:scale-[0.98]' : resolvedDamageCount > 0 ? 'bg-white border-stone-200 hover:border-stone-400 cursor-pointer active:scale-[0.98]' : 'bg-white border-stone-200 cursor-default'}`}>
          <div className={`flex items-center justify-between mb-1`}>
            <div className={`text-xs uppercase tracking-wider font-mono ${damageCount > 0 ? 'text-red-700' : 'text-stone-500'}`}>
              Damage{resolvedDamageCount > 0 && damageCount === 0 ? ' (past)' : ''}
            </div>
            {(damageCount > 0 || resolvedDamageCount > 0) && (
              <ChevronRight size={12} className={`${damageCount > 0 ? 'text-red-700' : 'text-stone-500'} transition-transform ${damageExpanded ? 'rotate-90' : ''}`} />
            )}
          </div>
          <div className={`text-2xl font-serif ${damageCount > 0 ? 'text-red-800' : ''}`}>{damageCount}</div>
          {resolvedDamageCount > 0 && damageCount > 0 && (
            <div className="text-[10px] font-mono text-stone-500 mt-0.5">+ {resolvedDamageCount} resolved</div>
          )}
        </button>
      </div>

      {/* Damage drill-down: Active and Resolved sub-tabs let PMs scan
         current issues OR browse past resolved damage without diving
         into each unit-day. Open when expanded AND there's something
         to show in either bucket. */}
      {damageExpanded && (damageCount > 0 || resolvedDamageCount > 0) && (
        <div className="mb-4 p-4 rounded-2xl bg-red-50/50 border-2 border-red-200">
          <div className="flex items-center justify-between mb-3">
            <div className="text-xs uppercase tracking-wider font-mono text-red-700 flex items-center gap-1.5">
              <AlertCircle size={12} /> Damage report
            </div>
            <button onClick={() => setDamageExpanded(false)}
              className="text-[10px] text-red-700 hover:text-red-900 font-mono uppercase tracking-wider">
              Hide
            </button>
          </div>

          {/* Sub-tab toggle: Active vs Resolved */}
          <div className="flex items-center gap-1 p-1 bg-white/70 rounded-xl mb-3">
            <button onClick={() => setDamageSubTab('active')}
              className={`flex-1 py-1.5 px-2 rounded-lg text-[11px] font-medium transition-colors flex items-center justify-center gap-1.5 ${damageSubTab === 'active' ? 'bg-red-600 text-white shadow-sm' : 'text-red-700 hover:bg-red-100'}`}>
              Active
              <span className={`text-[9px] px-1.5 py-0.5 rounded-full font-mono ${damageSubTab === 'active' ? 'bg-white/20 text-white' : 'bg-red-100 text-red-800'}`}>
                {damageCount}
              </span>
            </button>
            <button onClick={() => setDamageSubTab('resolved')}
              className={`flex-1 py-1.5 px-2 rounded-lg text-[11px] font-medium transition-colors flex items-center justify-center gap-1.5 ${damageSubTab === 'resolved' ? 'bg-stone-600 text-white shadow-sm' : 'text-stone-700 hover:bg-stone-100'}`}>
              Past (resolved)
              <span className={`text-[9px] px-1.5 py-0.5 rounded-full font-mono ${damageSubTab === 'resolved' ? 'bg-white/20 text-white' : 'bg-stone-100 text-stone-800'}`}>
                {resolvedDamageCount}
              </span>
            </button>
          </div>

          {damageSubTab === 'active' ? (
            damageEntries.length === 0 ? (
              <div className="text-center py-4 text-[11px] text-stone-500 italic">
                No active damage in this period. 🎉
              </div>
            ) : (
              <div className="space-y-1.5">
                {damageEntries.map((e, i) => (
                  <button key={`active-${e.date}-${e.unitId || i}`}
                    onClick={() => onOpenUnitDay(e.unitId, e.date)}
                    className="w-full p-3 rounded-xl bg-white border border-red-200 hover:border-red-400 active:scale-[0.99] transition-all flex items-center justify-between gap-3 text-left">
                    <div className="flex-1 min-w-0">
                      <div className="font-medium text-stone-900 text-sm truncate">{e.label}</div>
                      <div className="text-[11px] text-stone-500 font-mono">
                        {new Date(e.date + 'T12:00:00').toLocaleDateString('en-US', { weekday:'short', month:'short', day:'numeric' })}
                      </div>
                    </div>
                    <span className="text-[10px] uppercase tracking-wider font-mono text-red-700 flex-shrink-0">Resolve →</span>
                  </button>
                ))}
              </div>
            )
          ) : (
            resolvedDamageEntries.length === 0 ? (
              <div className="text-center py-4 text-[11px] text-stone-500 italic">
                No resolved damage in this period.
              </div>
            ) : (
              <div className="space-y-1.5">
                {resolvedDamageEntries.map((e, i) => (
                  <button key={`resolved-${e.date}-${e.unitId || i}`}
                    onClick={() => onOpenUnitDay(e.unitId, e.date)}
                    className="w-full p-3 rounded-xl bg-white border border-stone-200 hover:border-stone-400 active:scale-[0.99] transition-all flex items-center justify-between gap-3 text-left">
                    <div className="flex-1 min-w-0">
                      <div className="font-medium text-stone-900 text-sm truncate flex items-center gap-1.5">
                        <Check size={12} className="text-emerald-600 flex-shrink-0" />
                        {e.label}
                      </div>
                      <div className="text-[11px] text-stone-500 font-mono">
                        {new Date(e.date + 'T12:00:00').toLocaleDateString('en-US', { weekday:'short', month:'short', day:'numeric' })}
                      </div>
                    </div>
                    <span className="text-[10px] uppercase tracking-wider font-mono text-stone-600 flex-shrink-0">View →</span>
                  </button>
                ))}
              </div>
            )
          )}
        </div>
      )}

      <div className="mb-3 flex gap-2 mt-3 flex-wrap">
        {[{ id: '7d', label: '7 days' }, { id: '30d', label: '30 days' }, { id: '1y', label: '1 year' }].map(f => (
          <button key={f.id} onClick={() => setFilter(f.id)}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
              filter === f.id ? 'bg-stone-900 text-stone-50' : 'bg-stone-100 text-stone-600'
            }`}>
            {f.label}
          </button>
        ))}
      </div>

      {/* Filters panel — PM-appropriate: date / building / apartment.
         The date list only shows dates where cleanings were actually
         done (the "signify which dates have work" affordance), with
         counts so the PM knows how many units to expect. Building and
         apartment filters narrow the list further. */}
      {groups.length > 0 && (
        <div className="mb-4">
          <button onClick={() => setFiltersOpen(o => !o)}
            className={`w-full flex items-center justify-between px-3 py-2 rounded-xl border transition-colors ${activeFilterCount > 0 ? 'bg-amber-50 border-amber-300 text-amber-900' : 'bg-white border-stone-200 text-stone-600 hover:border-stone-400'}`}>
            <div className="flex items-center gap-2">
              <Settings size={14} />
              <span className="text-xs uppercase tracking-wider font-mono">
                Filters{activeFilterCount > 0 ? ` (${activeFilterCount})` : ''}
              </span>
              <span className="text-[10px] font-mono text-stone-500">
                Showing {filteredGroups.reduce((s, g) => s + g.units.length, 0)} of {groups.reduce((s, g) => s + g.units.length, 0)}
              </span>
            </div>
            <ChevronRight size={14} className={`transition-transform ${filtersOpen ? 'rotate-90' : ''}`} />
          </button>
          {filtersOpen && (
            <div className="p-3 rounded-xl bg-stone-50 border border-stone-200 mt-1 space-y-3">
              {/* Date filter — list of dates with cleanings, count each.
                 Single-select: tap a date to drill down, tap again to clear. */}
              {availableDates.length > 0 && (
                <div>
                  <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1.5">
                    Dates with cleanings ({availableDates.length})
                  </div>
                  <div className="grid grid-cols-2 gap-1.5">
                    {availableDates.map(date => {
                      const dateGroup = groups.find(g => g.date === date);
                      const count = dateGroup?.units.length || 0;
                      const isActive = filterDate === date;
                      return (
                        <button key={date}
                          onClick={() => setFilterDate(isActive ? '' : date)}
                          className={`px-2.5 py-2 rounded-lg text-left text-xs transition-colors ${isActive ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-200 text-stone-700 hover:border-stone-400'}`}>
                          <div className="flex items-center justify-between gap-1">
                            <span className="font-mono truncate">
                              {new Date(date + 'T12:00:00').toLocaleDateString('en-US', { month:'short', day:'numeric', weekday:'short' })}
                            </span>
                            <span className={`text-[10px] font-mono px-1.5 py-0.5 rounded-full flex-shrink-0 ${isActive ? 'bg-stone-700 text-stone-100' : 'bg-emerald-100 text-emerald-800'}`}>
                              {count}
                            </span>
                          </div>
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}

              {/* Building filter — chips, multi-select. Only shown when
                 there's more than one building in the data. */}
              {availableBuildings.length > 1 && (
                <div>
                  <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1.5">Building</div>
                  <div className="flex gap-1.5 flex-wrap">
                    {availableBuildings.map(b => {
                      const active = filterBuildings.has(b);
                      return (
                        <button key={b} onClick={() => toggleBuilding(b)}
                          className={`px-2.5 py-1 rounded-full text-xs font-mono flex items-center gap-1 transition-colors ${active ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-300 text-stone-600 hover:border-stone-500'}`}>
                          {active && <Check size={10} />}
                          {b}
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}

              {/* Apartment search — fast text filter on unit label. */}
              <div>
                <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1.5">Apartment</div>
                <input type="text" value={apartmentSearch}
                  onChange={(e) => setApartmentSearch(e.target.value)}
                  placeholder="e.g. 305"
                  className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm focus:outline-none focus:border-stone-900" />
              </div>

              {activeFilterCount > 0 && (
                <button onClick={clearFilters}
                  className="text-xs text-stone-600 hover:text-stone-900 font-mono underline">
                  Clear all filters
                </button>
              )}
            </div>
          )}
        </div>
      )}

      {!loaded ? <Splash text="Loading…" /> : groups.length === 0 ? (
        <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
          No cleanings in this period.
        </div>
      ) : filteredGroups.length === 0 ? (
        <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
          No cleanings match the current filters.
          {activeFilterCount > 0 && (
            <button onClick={clearFilters}
              className="block mx-auto mt-2 text-xs text-stone-700 hover:text-stone-900 font-mono underline">
              Clear all filters
            </button>
          )}
        </div>
      ) : (
        <div className="space-y-6">
          {filteredGroups.map(g => (
            <div key={g.date}>
              <div className="text-sm font-mono text-stone-500 mb-2 uppercase tracking-wider">
                {new Date(g.date + 'T12:00:00').toLocaleDateString('en-US', { weekday:'long', month:'long', day:'numeric', year:'numeric' })}
              </div>
              <div className="space-y-2">
                {g.units.map(u => (
                  <button key={`${g.date}-${u.unitId || 'simple'}`}
                    onClick={() => onOpenUnitDay(u.unitId, g.date)}
                    className={`w-full text-left p-4 rounded-2xl border transition-colors relative overflow-hidden ${
                      u.hasDamage
                        ? 'bg-red-50 border-red-300 hover:border-red-500 border-l-4 border-l-red-600'
                        : u.hasResolvedDamage
                          ? 'bg-white border-stone-200 hover:border-stone-400 border-l-4 border-l-emerald-500'
                          : 'bg-white border-stone-200 hover:border-stone-400'
                    }`}>
                    <div className="flex items-center justify-between gap-3">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          {u.hasDamage && <AlertCircle size={16} className="text-red-600 flex-shrink-0" />}
                          {!u.hasDamage && u.hasResolvedDamage && <Check size={16} className="text-emerald-600 flex-shrink-0" />}
                          <span className={`font-serif text-lg ${u.hasDamage ? 'text-red-900' : 'text-stone-900'}`}>{u.label}</span>
                          {u.hasDamage && (
                            <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-red-600 text-white font-bold">
                              ⚠ Damage
                            </span>
                          )}
                          {!u.hasDamage && u.hasResolvedDamage && (
                            <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-emerald-100 text-emerald-800 border border-emerald-300">
                              Damage resolved
                            </span>
                          )}
                          {u.hasDamage && u.hasResolvedDamage && (
                            <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 text-stone-600 border border-stone-200"
                              title="This cleaning also had past damage that was resolved">
                              + past
                            </span>
                          )}
                        </div>
                        <div className={`text-xs font-mono mt-1 ${u.hasDamage ? 'text-red-700' : 'text-stone-500'}`}>
                          {u.photoCount} {u.photoCount === 1 ? 'photo' : 'photos'}{u.hasDamage ? ' · tap to resolve' : ''}
                        </div>
                      </div>
                      <ChevronRight size={16} className={`flex-shrink-0 ${u.hasDamage ? 'text-red-600' : 'text-stone-400'}`} />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}


// Detail screen: one unit, one day. Shows all parties cleaned with photos.
function PortalUnitDay({ property, unitId, date, portalUser, onBack }) {
  const [unit, setUnit] = useState(null);
  const [blocks, setBlocks] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [viewMode, setViewMode] = useState('all'); // 'all' | 'by-section'
  // Selection mode lets the PM check photos and bulk-download or share
  const [selectMode, setSelectMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState(new Set());
  const [bulkBusy, setBulkBusy] = useState(false);
  // Bedroom tab — when a unit has multiple bedrooms cleaned on the same
  // day, the PM needs to see photos isolated by bedroom. Without this,
  // pictures from 3 different bedrooms all merge into one stream which
  // makes it impossible to tell which photo belongs to which bedroom.
  // Default '' = "All bedrooms" (merged view, kept as an option but
  // not the default once we know there are multiple bedrooms).
  const [bedroomTab, setBedroomTab] = useState('');

  const toggleSelectOne = (photoId) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(photoId)) next.delete(photoId);
      else next.add(photoId);
      return next;
    });
  };
  const clearSelection = () => setSelectedIds(new Set());
  const exitSelectMode = () => { setSelectMode(false); setSelectedIds(new Set()); };

  useEffect(() => { (async () => {
    setLoaded(false);

    // Enforce portal start date — refuse to load anything before it
    if (property.portal_start_date && date < property.portal_start_date) {
      setBlocks([]); setLoaded(true);
      return;
    }

    const dayStart = `${date}T00:00:00`;
    const dayEnd = `${date}T23:59:59`;

    if (unitId) {
      const { data: u } = await supabase.from('units').select('*').eq('id', unitId).maybeSingle();
      setUnit(u);
      const { data: bs } = await supabase
        .from('work_blocks')
        .select('*, party:parties(label,full_name), shift:shifts!inner(customer_id), tasks(*, photos(*, taken_by_employee:employees!taken_by(name)))')
        .eq('unit_id', unitId)
        .eq('is_preview', false)
        .gte('start_time', dayStart).lte('start_time', dayEnd)
        .order('start_time');
      const filtered = (bs || []).filter(b => b.shift?.customer_id === property.id);
      setBlocks(filtered);
    } else {
      // Simple property: pull tasks for shifts on this date
      const { data: shifts } = await supabase
        .from('shifts')
        .select('*, tasks(*, photos(*, taken_by_employee:employees!taken_by(name)))')
        .eq('customer_id', property.id)
        .eq('is_preview', false)
        .gte('start_time', dayStart).lte('start_time', dayEnd)
        .order('start_time');
      // Wrap each shift as a "block" for uniform display
      const fakeBlocks = (shifts || []).map(s => ({
        id: s.id,
        start_time: s.start_time, end_time: s.end_time,
        party: null,
        tasks: s.tasks || []
      }));
      setBlocks(fakeBlocks);
    }
    setLoaded(true);
  })(); }, [unitId, date, property.id]);

  // Compute the list of bedrooms (parties) that were cleaned on this
  // day. When there's more than one, we default the tab to the first
  // bedroom alphabetically so photos appear isolated by default. The
  // PM can switch to "All bedrooms" if they want the merged view.
  const partyLabels = (() => {
    const labels = [...new Set(blocks.map(b => b.party?.label).filter(Boolean))];
    return labels.sort(naturalCompare);
  })();
  // Auto-pick the first bedroom on initial load if there are multiple.
  // Doesn't override a user's choice — only sets when bedroomTab is empty.
  useEffect(() => {
    if (partyLabels.length > 1 && !bedroomTab) {
      setBedroomTab(partyLabels[0]);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [blocks]);

  if (!loaded) return <Splash text="Loading…" />;

  // Aggregate all photos for this unit/day, separated by kind.
  // We also tag each photo with the task's category/subcategory so
  // the "By section" view can group on them.
  // Bedroom-tab filter: when the PM picks a specific bedroom, only
  // include blocks for that party. '' means All bedrooms (no filter).
  const visibleBlocks = bedroomTab
    ? blocks.filter(b => b.party?.label === bedroomTab)
    : blocks;
  const allBefore = [];
  const allAfter = [];
  const allDamageActive = []; // unresolved damage — shows in red banner
  const allDamageResolved = []; // resolved damage — collapsed history below
  visibleBlocks.forEach(b => (b.tasks || []).forEach(t => (t.photos || []).forEach(p => {
    const enriched = {
      ...p,
      taskName: t.name,
      taskCategory: t.category,
      taskSubcategory: t.subcategory,
      partyLabel: b.party?.label,
    };
    if (p.kind === 'before') allBefore.push(enriched);
    else if (p.kind === 'after') allAfter.push(enriched);
    else if (p.kind === 'damage') {
      if (p.resolved_at) allDamageResolved.push(enriched);
      else allDamageActive.push(enriched);
    }
  })));

  // Build a flat lookup so the toolbar can find selected photos and
  // their context for download/share filename tagging.
  const allPhotos = [...allBefore, ...allAfter, ...allDamageActive, ...allDamageResolved];
  const photoContext = (p) => ({
    propertyName: property.name,
    unitLabel: unit?.label || null,
    partyLabel: p.partyLabel,
    taskName: p.taskName,
    date,
  });
  const getSelectedPhotos = () => allPhotos.filter(p => selectedIds.has(p.id));

  const handleBulkDownload = async () => {
    const sel = getSelectedPhotos();
    if (sel.length === 0) return;
    setBulkBusy(true);
    await downloadPhotos(sel, (p) => photoContext(p));
    setBulkBusy(false);
  };

  const handleBulkShare = async () => {
    const sel = getSelectedPhotos();
    if (sel.length === 0) return;
    setBulkBusy(true);
    const ok = await sharePhotos(sel, (p) => photoContext(p));
    setBulkBusy(false);
    if (!ok && canShareFiles()) {
      alert('Share didn\'t complete. You can try Download instead.');
    } else if (!ok && !canShareFiles()) {
      alert('Share isn\'t available on this device — please use Download.');
    }
  };

  // Local mutation helper — flip a photo's resolved state and re-fetch
  // (cheap reload to keep state in sync).
  const setPhotoResolution = async (photo, resolve) => {
    const payload = resolve
      ? { resolved_at: new Date().toISOString(), resolved_by: portalUser?.id || null, resolved_by_kind: 'portal_user' }
      : { resolved_at: null, resolved_by: null, resolved_by_kind: null };
    const { error } = await supabase.from('photos').update(payload).eq('id', photo.id);
    if (error) {
      alert('Could not update damage status: ' + error.message);
      return;
    }
    // Update in place via block mutation
    setBlocks(prev => prev.map(b => ({
      ...b,
      tasks: (b.tasks || []).map(t => ({
        ...t,
        photos: (t.photos || []).map(p =>
          p.id === photo.id ? { ...p, ...payload } : p
        ),
      })),
    })));
  };

  return (
    <div className="min-h-screen bg-stone-50 pb-12">
      <style>{`
        @media print {
          body { background: white !important; }
          .no-print { display: none !important; }
        }
      `}</style>
      <div className="no-print bg-stone-900 text-stone-50 px-5 py-4 flex items-center justify-between">
        <button onClick={onBack} className="flex items-center gap-2 text-stone-400 text-sm hover:text-stone-50">
          <ArrowLeft size={16} /> Back
        </button>
        <button onClick={() => window.print()}
          className="px-4 py-2 rounded-full bg-stone-50 text-stone-900 text-sm font-medium flex items-center gap-2">
          <Printer size={14} /> Print
        </button>
      </div>

      <div className="px-5 pt-6">
        <div className="text-xs uppercase tracking-widest text-stone-400 font-mono mb-2">
          {new Date(date + 'T12:00:00').toLocaleDateString('en-US', { weekday:'long', month:'long', day:'numeric', year:'numeric' })}
        </div>
        <h1 className="font-serif text-3xl text-stone-900 mb-1">{unit?.label || property.name}</h1>
        <div className="text-sm text-stone-600 mb-2">{property.name}</div>
        {/* Bedroom selector — always a clickable strip (never a static
           "Cleaned: chips" line). When there's only one bedroom, the
           strip shows just that one button (selected by default).
           When there are multiple, each bedroom is a tab that filters
           the photo grid below. The "All bedrooms" tab preserves the
           merged view as an option. */}
        {partyLabels.length > 0 && (
          <div className="mt-4 p-3 rounded-2xl bg-amber-50 border-2 border-amber-300">
            <div className="text-[10px] uppercase tracking-wider font-mono text-amber-800 mb-2 font-bold">
              {partyLabels.length === 1 ? 'Bedroom cleaned' : `Tap a bedroom (${partyLabels.length} cleaned this day)`}
            </div>
            <div className="flex gap-1.5 overflow-x-auto pb-1 -mx-3 px-3">
              {partyLabels.map(label => {
                const active = bedroomTab === label || (partyLabels.length === 1 && !bedroomTab);
                return (
                  <button key={label} onClick={() => setBedroomTab(label)}
                    className={`px-4 py-2.5 rounded-xl text-sm font-medium whitespace-nowrap flex-shrink-0 transition-colors ${active ? 'bg-stone-900 text-stone-50 border-2 border-stone-900 shadow-sm' : 'bg-white text-stone-700 border-2 border-stone-200 hover:border-stone-400'}`}>
                    {label}
                  </button>
                );
              })}
              {partyLabels.length > 1 && (
                <button onClick={() => setBedroomTab('')}
                  className={`px-4 py-2.5 rounded-xl text-sm font-medium whitespace-nowrap flex-shrink-0 transition-colors ${bedroomTab === '' ? 'bg-stone-900 text-stone-50 border-2 border-stone-900 shadow-sm' : 'bg-white text-stone-600 border-2 border-stone-200 hover:border-stone-400'}`}>
                  All bedrooms
                </button>
              )}
            </div>
            {/* Always show "Viewing: X" so user knows which bedroom is active */}
            <div className="mt-2.5 text-xs text-amber-900">
              <span className="uppercase tracking-wider font-mono text-amber-700 mr-1.5">Viewing:</span>
              <span className="font-medium">
                {bedroomTab || (partyLabels.length === 1 ? partyLabels[0] : 'All bedrooms (merged)')}
              </span>
            </div>
          </div>
        )}
      </div>

      <div className="px-5 pt-6 space-y-6">
        {/* View mode toggle + Select button on the same row */}
        <div className="flex items-center gap-2">
          <div className="flex-1 flex items-center gap-1 p-1 bg-stone-100 rounded-xl">
            <button onClick={() => setViewMode('all')}
              className={`flex-1 py-2 px-3 rounded-lg text-xs font-medium transition-colors ${viewMode === 'all' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
              All photos
            </button>
            <button onClick={() => setViewMode('by-section')}
              className={`flex-1 py-2 px-3 rounded-lg text-xs font-medium transition-colors ${viewMode === 'by-section' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
              By section
            </button>
          </div>
          <button onClick={() => { setSelectMode(s => !s); setSelectedIds(new Set()); }}
            className={`px-3 py-2 rounded-xl text-xs font-medium flex items-center gap-1.5 flex-shrink-0 transition-colors ${selectMode ? 'bg-stone-900 text-stone-50' : 'bg-stone-100 text-stone-700 hover:bg-stone-200'}`}>
            {selectMode ? <Check size={14} /> : <Square size={14} />}
            {selectMode ? 'Done' : 'Select'}
          </button>
        </div>

        {viewMode === 'all' ? (
          <>
            {allDamageActive.length > 0 && (
              <PortalPhotoSection
                label="Active damage"
                photos={allDamageActive}
                highlight="red"
                description="Issues identified during cleaning. Tap a photo to resolve."
                onResolve={(p) => setPhotoResolution(p, true)}
                selectMode={selectMode} selectedIds={selectedIds} onToggleSelect={toggleSelectOne}
              />
            )}
            {allDamageResolved.length > 0 && (
              <ResolvedDamageHistory
                photos={allDamageResolved}
                onReopen={(p) => setPhotoResolution(p, false)}
              />
            )}
            <PortalPhotoSection label="Before cleaning" photos={allBefore}
              selectMode={selectMode} selectedIds={selectedIds} onToggleSelect={toggleSelectOne} />
            <PortalPhotoSection label="After cleaning"  photos={allAfter}
              selectMode={selectMode} selectedIds={selectedIds} onToggleSelect={toggleSelectOne} />
          </>
        ) : (
          // BY-SECTION MODE — bucket photos by the most specific identifier
          // available. The cleaner could organize their work in 3 ways:
          //   1. Structured: Quick picker → category + subcategory set
          //      → group by the structured label (e.g. "Bedroom", "General — Kitchen")
          //   2. Freeform per party: cleaning Bedroom 2 with tasks
          //      "habitación" + "baño" → group by task name within party
          //      (e.g. "Bedroom 2 — habitación", "Bedroom 2 — baño")
          //   3. Freeform without parties: simple property with tasks named
          //      "kitchen", "bathroom" → group by task name alone
          // Task name is more SPECIFIC than party label, so it takes
          // precedence — that was the bug that lumped all photos under
          // "Bedroom 2" when the cleaner clearly split work into habitación
          // and baño tasks.
          (() => {
            const sectionMap = new Map();
            const sectionAll = [...allBefore, ...allAfter, ...allDamageActive, ...allDamageResolved];

            // Figure out if task names are useful for grouping — i.e. are
            // there multiple distinct task names? If there's only one task
            // name, falling back to party label gives more useful labels.
            const distinctTaskNames = new Set(sectionAll.map(p => p.taskName).filter(Boolean));
            const useTaskNameAsKey = distinctTaskNames.size > 1;

            const buildKey = (p) => {
              // Structured category trumps everything
              const catLabel = taskCategoryShortLabel(p.taskCategory, p.taskSubcategory);
              if (catLabel) return catLabel;
              // If task names vary, use them (optionally prefixed with party)
              if (useTaskNameAsKey && p.taskName) {
                return p.partyLabel ? `${p.partyLabel} — ${p.taskName}` : p.taskName;
              }
              // Otherwise group by party
              return p.partyLabel || p.taskName || 'Other';
            };

            sectionAll.forEach(p => {
              const key = buildKey(p);
              if (!sectionMap.has(key)) sectionMap.set(key, { before: [], after: [], damage: [], damageResolved: [] });
              const bucket = sectionMap.get(key);
              if (p.kind === 'before') bucket.before.push(p);
              else if (p.kind === 'after') bucket.after.push(p);
              else if (p.kind === 'damage') {
                if (p.resolved_at) bucket.damageResolved.push(p);
                else bucket.damage.push(p);
              }
            });
            // Order: bedroom > bathroom > vanity > general > others alphabetical, "Other" last
            const orderHint = (label) => {
              const l = (label || '').toLowerCase();
              if (l.startsWith('bedroom')) return 0;
              if (l.startsWith('bathroom')) return 1;
              if (l.startsWith('vanity')) return 2;
              if (l.startsWith('general')) return 3;
              if (label === 'Other') return 99;
              return 50;
            };
            const sorted = Array.from(sectionMap.entries()).sort(([a], [b]) => {
              const oA = orderHint(a), oB = orderHint(b);
              if (oA !== oB) return oA - oB;
              return a.localeCompare(b);
            });
            return sorted.map(([sectionLabel, buckets]) => (
              <div key={sectionLabel} className="p-4 rounded-2xl bg-white border border-stone-200 space-y-4">
                <div className="flex items-baseline justify-between pb-2 border-b border-stone-200">
                  <h2 className="font-serif text-2xl text-stone-900">{sectionLabel}</h2>
                  <span className="text-[11px] font-mono text-stone-500">
                    {buckets.before.length + buckets.after.length + buckets.damage.length + buckets.damageResolved.length} photos
                  </span>
                </div>
                {buckets.damageResolved.length > 0 && (
                  <ResolvedDamageHistory
                    photos={buckets.damageResolved}
                    onReopen={(p) => setPhotoResolution(p, false)}
                  />
                )}
                {/* 3-column side-by-side layout on desktop, stacked on
                   mobile. Each child uses `compact` so its inner thumbnail
                   grid adapts to the available width. */}
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                  <PortalPhotoSection label="Before" photos={buckets.before} compact
                    selectMode={selectMode} selectedIds={selectedIds} onToggleSelect={toggleSelectOne} />
                  <PortalPhotoSection label="After" photos={buckets.after} compact
                    selectMode={selectMode} selectedIds={selectedIds} onToggleSelect={toggleSelectOne} />
                  {buckets.damage.length > 0 ? (
                    <PortalPhotoSection
                      label="Active damage" photos={buckets.damage} highlight="red" compact
                      description="Tap to resolve."
                      onResolve={(p) => setPhotoResolution(p, true)}
                      selectMode={selectMode} selectedIds={selectedIds} onToggleSelect={toggleSelectOne}
                    />
                  ) : (
                    <PortalPhotoSection label="Damage" photos={[]} highlight="red" compact />
                  )}
                </div>
              </div>
            ));
          })()
        )}

        {/* Per-party breakdown (no cleaner names — only labels and notes) */}
        {blocks.length > 0 && blocks.some(b => b.party || b.tasks?.length) && (
          <div className="mt-6">
            <div className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-3">Cleaning breakdown</div>
            <div className="space-y-3">
              {blocks.map(b => (
                <div key={b.id} className="p-4 rounded-2xl bg-white border border-stone-200">
                  {b.party && (
                    <div className="font-serif text-base text-stone-900 mb-1">
                      {b.party.label}{b.party.full_name && ` · ${b.party.full_name}`}
                    </div>
                  )}
                  {b.work_notes && (
                    <div className="text-sm text-stone-600 italic mb-2">
                      "<TranslatableText text={b.work_notes} targetLang="en" />"
                    </div>
                  )}
                  {b.tasks?.length > 0 && (
                    <ul className="text-sm text-stone-700 space-y-0.5">
                      {b.tasks.map(t => <li key={t.id} className="flex items-center gap-2">
                        <Check size={12} className="text-emerald-600 flex-shrink-0" />
                        <TranslatableText text={t.name} targetLang="en" />
                      </li>)}
                    </ul>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {allBefore.length === 0 && allAfter.length === 0 && allDamageActive.length === 0 && allDamageResolved.length === 0 && (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            No photos recorded for this date.
          </div>
        )}

        {/* Bottom spacer when select mode is active so the toolbar doesn't
           cover content */}
        {selectMode && <div className="h-20" />}
      </div>

      {/* Selection toolbar pinned to the bottom while select mode is on */}
      {selectMode && (
        <div className="fixed bottom-0 left-0 right-0 z-40 bg-stone-900 text-stone-50 shadow-2xl"
          style={{ paddingBottom: 'max(0.75rem, env(safe-area-inset-bottom))' }}>
          <div className="px-4 py-3 max-w-2xl mx-auto flex items-center gap-2">
            <div className="flex-1 min-w-0">
              <div className="text-xs font-mono uppercase tracking-wider text-stone-400">Selected</div>
              <div className="text-base font-medium">{selectedIds.size} {selectedIds.size === 1 ? 'photo' : 'photos'}</div>
            </div>
            <button onClick={clearSelection} disabled={selectedIds.size === 0 || bulkBusy}
              className="px-3 py-2 rounded-full bg-stone-800 hover:bg-stone-700 text-stone-50 text-xs font-mono disabled:opacity-40">
              Clear
            </button>
            <button onClick={handleBulkDownload} disabled={selectedIds.size === 0 || bulkBusy}
              className="px-3 py-2 rounded-full bg-amber-600 hover:bg-amber-700 text-white text-xs font-medium flex items-center gap-1.5 disabled:opacity-40">
              {bulkBusy ? <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin" /> : <Download size={14} />}
              Download
            </button>
            {canShareFiles() && (
              <button onClick={handleBulkShare} disabled={selectedIds.size === 0 || bulkBusy}
                className="px-3 py-2 rounded-full bg-blue-600 hover:bg-blue-700 text-white text-xs font-medium flex items-center gap-1.5 disabled:opacity-40">
                <Share2 size={14} />
                Share
              </button>
            )}
            <button onClick={exitSelectMode} disabled={bulkBusy}
              className="p-2 rounded-full hover:bg-stone-800 disabled:opacity-40">
              <X size={16} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// =================================================================
// RESOLVED DAMAGE HISTORY — collapsed, neutral panel showing damage
// =================================================================
// RESOLVED DAMAGE — sits right under Active damage. Shows photos
// the PM has marked resolved with "Re-open" buttons in case they
// were marked by mistake. Always inline (not collapsed) so the
// history stays in context.
// =================================================================
function ResolvedDamageHistory({ photos, onReopen }) {
  const [zoom, setZoom] = useState(null);
  if (!photos.length) return null;
  return (
    <div className="rounded-2xl bg-stone-50 border border-stone-200 p-4">
      <div className="flex items-baseline justify-between mb-3 pb-2 border-b border-stone-200">
        <h3 className="font-serif text-xl flex items-center gap-2 text-stone-700">
          <Check size={16} className="text-emerald-600" />
          Resolved damage
        </h3>
        <span className="text-xs font-mono text-stone-500">{photos.length}</span>
      </div>
      <p className="text-[11px] text-stone-500 italic mb-3">
        Previously flagged damage that's been marked resolved. Tap "Re-open" if it should still be active.
      </p>
      <div className="grid grid-cols-3 sm:grid-cols-4 gap-2">
        {photos.map(p => (
          <div key={p.id} className="relative">
            <button onClick={() => setZoom(p)}
              className="block aspect-square w-full rounded-lg overflow-hidden bg-stone-200 opacity-80 hover:opacity-100 transition-opacity relative">
              <img loading="lazy" src={p.public_url} alt="" className="w-full h-full object-cover" />
              <span className="absolute top-1 left-1 px-1.5 py-0.5 rounded bg-emerald-700/90 text-white text-[9px] font-mono uppercase tracking-wider">
                Resolved
              </span>
              {p.partyLabel && (
                <span className="absolute bottom-1 left-1 right-1 px-1.5 py-0.5 rounded bg-black/70 text-white text-[9px] font-mono truncate">
                  {p.partyLabel}
                </span>
              )}
            </button>
            <button onClick={() => onReopen(p)}
              className="mt-1 w-full px-2 py-1 rounded bg-white border border-stone-300 hover:bg-stone-50 text-stone-700 text-[10px] font-mono">
              Re-open
            </button>
          </div>
        ))}
      </div>
      {zoom && (
        <PhotoZoomViewer photos={photos} initialUrl={zoom.public_url} onClose={() => setZoom(null)} />
      )}
    </div>
  );
}

function PortalPhotoSection({ label, photos, highlight, description, onResolve, selectMode, selectedIds, onToggleSelect, compact }) {
  const [zoom, setZoom] = useState(null);
  const isDamage = highlight === 'red';
  // `compact` is set when this section sits inside a 3-column side-by-side
  // wrapper (by-section view: Before | After | Damage). The inner grid
  // adapts to whatever width the parent gives us:
  //   - compact + phone (outer collapses to 1 col, full width): 4 cols inside
  //   - compact + desktop (outer is 3 cols, ~200px each): 2 cols inside
  //   - non-compact (standalone full-width "All photos" mode): 3/4 cols
  const innerGridClass = compact
    ? 'grid grid-cols-4 sm:grid-cols-2 gap-1.5'
    : 'grid grid-cols-3 sm:grid-cols-4 gap-2';
  if (photos.length === 0) {
    return (
      <div>
        <div className={`flex items-baseline justify-between mb-2 ${isDamage ? 'pb-1.5 border-b-2 border-red-200' : ''}`}>
          <h3 className={`font-serif text-base flex items-center gap-1.5 ${isDamage ? 'text-red-800' : 'text-stone-900'}`}>
            {isDamage && '⚠'} {label}
          </h3>
          <span className="text-[10px] font-mono text-stone-400">0</span>
        </div>
        <div className={`aspect-square rounded-lg border-2 border-dashed flex items-center justify-center ${isDamage ? 'border-red-100 text-red-200' : 'border-stone-200 text-stone-300'}`}>
          <Camera size={18} />
        </div>
      </div>
    );
  }
  // Determine the badge to put on each thumbnail based on the photo's kind.
  const kindBadge = (p) => {
    const k = p.kind || (label.toLowerCase().includes('before') ? 'before' :
                        label.toLowerCase().includes('after') ? 'after' :
                        label.toLowerCase().includes('damage') ? 'damage' : null);
    if (!k) return null;
    const bg = k === 'damage' ? 'bg-red-600' : k === 'before' ? 'bg-blue-600' : k === 'after' ? 'bg-emerald-600' : 'bg-stone-700';
    return (
      <span className={`absolute top-0.5 left-0.5 px-1 py-0.5 rounded text-white text-[8px] font-mono uppercase tracking-wider ${bg}/90`}>
        {k}
      </span>
    );
  };
  return (
    <div>
      <div className={`flex items-baseline justify-between mb-2 ${isDamage ? 'pb-1.5 border-b-2 border-red-200' : ''}`}>
        <h3 className={`font-serif text-base flex items-center gap-1.5 ${isDamage ? 'text-red-800' : 'text-stone-900'}`}>
          {isDamage && '⚠'} {label}
        </h3>
        <span className="text-[10px] font-mono text-stone-500">{photos.length}</span>
      </div>
      {description && <p className="text-xs text-stone-600 mb-2">{description}</p>}
      <div className={innerGridClass}>
        {photos.map(p => {
          const isSelected = selectMode && selectedIds && selectedIds.has(p.id);
          return (
            <div key={p.id} className="relative">
              <button
                onClick={() => selectMode ? onToggleSelect(p.id) : setZoom(p)}
                className={`relative aspect-square w-full rounded-lg overflow-hidden ${isDamage ? 'ring-2 ring-red-400' : ''} ${isSelected ? 'ring-4 ring-stone-900' : ''}`}>
                <img loading="lazy" src={p.public_url} alt="" className="w-full h-full object-cover" />
                {kindBadge(p)}
                {p.took_extra && (
                  <span className="absolute top-0.5 right-0.5 px-1 py-0.5 rounded bg-amber-500 text-white text-[8px] font-mono uppercase tracking-wider flex items-center gap-0.5">
                    <Clock size={7} /> Extra
                  </span>
                )}
                {p.partyLabel && (
                  <span className="absolute bottom-0.5 left-0.5 right-0.5 px-1 py-0.5 rounded bg-black/70 text-white text-[8px] font-mono truncate">
                    {p.partyLabel}
                  </span>
                )}
                {selectMode && (
                  <span className={`absolute top-0.5 right-0.5 w-5 h-5 rounded-full border-2 flex items-center justify-center ${isSelected ? 'bg-stone-900 border-stone-900' : 'bg-white/80 border-white'}`}>
                    {isSelected && <Check size={12} className="text-white" />}
                  </span>
                )}
              </button>
              {onResolve && isDamage && !selectMode && (
                <button onClick={() => onResolve(p)}
                  className="mt-1 w-full px-1 py-0.5 rounded bg-emerald-700 hover:bg-emerald-800 text-white text-[9px] font-mono active:scale-95">
                  Resolve
                </button>
              )}
            </div>
          );
        })}
      </div>
      {zoom && (
        <PhotoZoomViewer photos={photos} initialUrl={zoom.public_url}
          onClose={() => setZoom(null)}
          onResolveCurrent={onResolve && isDamage ? (p) => { onResolve(p); setZoom(null); } : null} />
      )}
    </div>
  );
}

// =================================================================
// DAILY VIEW — calendar-first drill-down
// Calendar month → pick a date → see units cleaned that day → pick a unit → full detail
// =================================================================
function DailyView({ employee, onSignOut, onOpenMessages, onLogoClick }) {
  const [view, setView] = useState({ kind: 'calendar' });
  const showMoney = canSeeMoney(employee);
  // Persistent state for the Assigned vs Cleaned audit so its filters
  // / property / date range survive a side trip into BedroomHistoryView.
  // Lifted from AssignedVsCleanedView itself because that component
  // unmounts when the user navigates to a bedroom's history and back —
  // local useState would reset every time. Held at this level (the
  // common parent of both views) so neither leg of the journey loses it.
  const todayISO = new Date().toISOString().split('T')[0];
  const [auditState, setAuditState] = useState({
    selectedPropertyId: '',
    start: todayISO,
    end: todayISO,
    filterBuildings: [],
    filterStatuses: [],
    collapsedBuildings: [],
    scrollY: 0,
  });

  const openBedroomHistory = (params) => setView({ kind: 'bedroom-history', ...params, from: view });

  if (view.kind === 'day') {
    return <DailyDayDetail date={view.date} employee={employee} showMoney={showMoney}
      onBack={() => setView({ kind: 'calendar' })}
      onOpenUnit={(propertyId, unitId, unitLabel, propertyName) =>
        setView({ kind: 'unit-day', date: view.date, propertyId, unitId, unitLabel, propertyName })} />;
  }
  if (view.kind === 'unit-day') {
    return <DailyUnitDayDetail date={view.date} propertyId={view.propertyId} unitId={view.unitId}
      unitLabel={view.unitLabel} propertyName={view.propertyName}
      employee={employee} showMoney={showMoney}
      onBack={() => setView({ kind: 'day', date: view.date })}
      onOpenBedroomHistory={openBedroomHistory} />;
  }
  if (view.kind === 'bedroom-history') {
    return <BedroomHistoryView
      propertyId={view.propertyId} propertyName={view.propertyName}
      unitId={view.unitId} unitLabel={view.unitLabel}
      partyId={view.partyId} partyLabel={view.partyLabel}
      employee={employee}
      onBack={() => setView(view.from || { kind: 'calendar' })} />;
  }
  if (view.kind === 'inbox') {
    return <InboxView employee={employee}
      onBack={() => setView({ kind: 'calendar' })} />;
  }
  if (view.kind === 'assigned-vs-cleaned') {
    return <AssignedVsCleanedView employee={employee}
      onBack={() => setView({ kind: 'calendar' })}
      onOpenBedroomHistory={openBedroomHistory}
      persistedState={auditState}
      onStateChange={setAuditState} />;
  }

  return <DailyCalendar employee={employee} onSignOut={onSignOut}
    onPickDay={(date) => setView({ kind: 'day', date })}
    onOpenInbox={() => setView({ kind: 'inbox' })}
    onOpenAssignedVsCleaned={() => setView({ kind: 'assigned-vs-cleaned' })}
    onOpenMessages={onOpenMessages}
    onLogoClick={onLogoClick} />;
}

// Helpers — local-time YYYY-MM-DD (avoids UTC midnight bugs)
const toDateKey = (d) => {
  const yr = d.getFullYear();
  const mo = String(d.getMonth() + 1).padStart(2, '0');
  const dy = String(d.getDate()).padStart(2, '0');
  return `${yr}-${mo}-${dy}`;
};

// WhosWherePanel — owner-facing "who's working right now" widget shown
// on the owner home (DailyCalendar). Lists every active work block
// across all properties with cleaner name + property + bedroom +
// elapsed time. Auto-refreshes so it stays current without page
// reloads. Empty state when no one's on the clock.
//
// On each load it also runs cleanup on stale sessions:
//   - SOFT (90min inactive): set shift end_time = last_activity_at so
//     the cleaner only gets credit for time they were actively in the
//     app. The idle detector would have done this if the app was open
//     — this catches cases where the cleaner closed the app entirely.
//   - HARD (2h since start): force-close anything still open with
//     end_time = NOW. Safety net for sessions that somehow slipped
//     past the soft pass (no last_activity_at recorded, etc).
const STALE_IDLE_MIN = 90;   // soft auto-clockout threshold (minutes)
const STALE_FORCE_MIN = 120; // hard force-close threshold (minutes)
function WhosWherePanel({ employee }) {
  const [rows, setRows] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [collapsed, setCollapsed] = useState(false);
  // useTick so the elapsed timer updates live.
  useTick(true);

  // Two-tier auto-close:
  //   1) SOFT — shifts with last_activity_at older than 90 min get
  //      end_time = last_activity_at. Cleaner gets credit only for
  //      time they were actually active in the app.
  //   2) HARD — anything still open with start_time older than 120 min
  //      gets end_time = NOW. Catches sessions where last_activity_at
  //      is null or somehow missed the soft pass.
  // Work blocks: no last_activity_at column on that table, so we
  // hard-close them at 120 min from start. A workblock open longer
  // than 2 hours is almost certainly stale (a real bedroom clean
  // rarely exceeds that).
  const cleanupStale = async () => {
    const now = Date.now();
    const idleCutoffISO = new Date(now - STALE_IDLE_MIN * 60 * 1000).toISOString();
    const forceCutoffISO = new Date(now - STALE_FORCE_MIN * 60 * 1000).toISOString();
    try {
      // 1) Soft auto-clockout — pull shifts past the idle cutoff and
      //    set end_time per-row to their last_activity_at. We can't
      //    do this in a single UPDATE (Supabase JS doesn't support
      //    column-to-column updates) so we fetch then patch.
      const { data: idleShifts } = await supabase.from('shifts')
        .select('id, last_activity_at, start_time')
        .is('end_time', null)
        .not('last_activity_at', 'is', null)
        .lt('last_activity_at', idleCutoffISO);
      for (const s of (idleShifts || [])) {
        const endTime = s.last_activity_at || s.start_time;
        await supabase.from('shifts').update({ end_time: endTime }).eq('id', s.id);
        // Also close any open work_block belonging to this shift, with
        // the same end_time so timing stays consistent.
        await supabase.from('work_blocks')
          .update({ end_time: endTime })
          .eq('shift_id', s.id)
          .is('end_time', null);
      }
      // 2) Hard force close — catch-all for anything still open beyond
      //    the 2-hour cutoff (e.g. shift with no last_activity_at, or
      //    a work_block whose parent shift is somehow already closed).
      await supabase.from('shifts')
        .update({ end_time: new Date().toISOString() })
        .is('end_time', null)
        .lt('start_time', forceCutoffISO);
      await supabase.from('work_blocks')
        .update({ end_time: new Date().toISOString() })
        .is('end_time', null)
        .lt('start_time', forceCutoffISO);
    } catch (e) {
      console.warn('[whos-where] stale cleanup failed:', e);
    }
  };

  const load = async () => {
    // Run cleanup first so the next two queries only return live rows.
    await cleanupStale();
    // Defensive client-side cutoff using the hard threshold — even if
    // cleanup failed, we never show a session "active" beyond
    // STALE_FORCE_MIN.
    const cutoffMs = Date.now() - STALE_FORCE_MIN * 60 * 1000;
    // Open work_blocks property-wide. Pull cleaner + property +
    // unit/party labels in one shot via embeds so we don't fan out
    // queries per block.
    const { data: blocks } = await supabase.from('work_blocks')
      .select('id, start_time, unit_id, party_id, unit:units(label), party:parties(label), shift:shifts!inner(id, customer_id, employee:employees(id, name), customer:customers(id, name))')
      .is('end_time', null)
      .order('start_time', { ascending: true });
    // Also pull cleaners who are clocked in but not yet at a bedroom
    // (active shift, no open work_block). Helpful for the owner to
    // see "Maria is at the property but hasn't started a bedroom yet."
    const { data: shifts } = await supabase.from('shifts')
      .select('id, start_time, customer_id, employee:employees(id, name), customer:customers(id, name)')
      .is('end_time', null);
    const blockedShiftIds = new Set((blocks || []).map(b => b.shift?.id).filter(Boolean));
    const standby = (shifts || []).filter(s => !blockedShiftIds.has(s.id));
    setRows([
      ...(blocks || [])
        .filter(b => new Date(b.start_time).getTime() > cutoffMs)
        .map(b => ({
          kind: 'block',
          id: b.id,
          cleanerName: b.shift?.employee?.name || '?',
          propertyName: b.shift?.customer?.name || '',
          unitLabel: b.unit?.label,
          partyLabel: b.party?.label,
          startTime: b.start_time,
        })),
      ...standby
        .filter(s => new Date(s.start_time).getTime() > cutoffMs)
        .map(s => ({
          kind: 'standby',
          id: s.id,
          cleanerName: s.employee?.name || '?',
          propertyName: s.customer?.name || '',
          startTime: s.start_time,
        })),
    ]);
    setLoaded(true);
  };
  useEffect(() => {
    load();
    const iv = setInterval(load, 30000); // refresh every 30s
    return () => clearInterval(iv);
  }, []);

  if (!loaded) return null;
  const activeCount = rows.filter(r => r.kind === 'block').length;
  const standbyCount = rows.filter(r => r.kind === 'standby').length;
  return (
    <div className="mb-5 rounded-2xl bg-white border border-stone-200 overflow-hidden">
      <button onClick={() => setCollapsed(c => !c)}
        className="w-full px-4 py-3 flex items-center gap-3 hover:bg-stone-50 transition-colors">
        <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse flex-shrink-0" />
        <div className="text-left flex-1 min-w-0">
          <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500">
            Who's working right now
          </div>
          <div className="text-sm text-stone-900 font-medium">
            {activeCount > 0 ? (
              <>{activeCount} {activeCount === 1 ? 'cleaner' : 'cleaners'} in bedrooms</>
            ) : (
              <span className="text-stone-500">No one on the clock</span>
            )}
            {standbyCount > 0 && (
              <span className="text-stone-500"> · {standbyCount} on standby</span>
            )}
          </div>
        </div>
        <ChevronRight size={16} className={`text-stone-400 flex-shrink-0 transition-transform ${collapsed ? '' : 'rotate-90'}`} />
      </button>
      {!collapsed && rows.length > 0 && (
        <div className="border-t border-stone-100 divide-y divide-stone-100">
          {rows.map(r => {
            const elapsed = Date.now() - new Date(r.startTime).getTime();
            return (
              <div key={`${r.kind}:${r.id}`} className="px-4 py-2.5 flex items-center gap-3">
                <div className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${r.kind === 'block' ? 'bg-emerald-500' : 'bg-stone-400'}`} />
                <div className="flex-1 min-w-0">
                  <div className="text-sm text-stone-900">
                    <span className="font-bold">{r.cleanerName}</span>
                    {r.kind === 'block' ? (
                      <>
                        <span className="text-stone-400"> · </span>
                        <span className="text-stone-700">{r.propertyName}</span>
                        {r.unitLabel && (
                          <>
                            <span className="text-stone-400"> · </span>
                            <span className="font-mono text-xs text-stone-700">{r.unitLabel}</span>
                          </>
                        )}
                        {r.partyLabel && (
                          <>
                            <span className="text-stone-400"> · </span>
                            <span className="italic text-amber-700">{r.partyLabel}</span>
                          </>
                        )}
                      </>
                    ) : (
                      <>
                        <span className="text-stone-400"> · </span>
                        <span className="text-stone-700">{r.propertyName}</span>
                        <span className="text-stone-400"> · </span>
                        <span className="text-stone-500 text-xs">on standby</span>
                      </>
                    )}
                  </div>
                </div>
                <div className="text-[11px] font-mono text-stone-500 flex-shrink-0">
                  {fmtTimeShort(elapsed)}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// AssignedVsCleanedView — side-by-side audit view for owners. Picks
// a date range + a property, shows one row per bedroom with what was
// assigned vs what got done. Status icons make it easy to scan:
//   ✓ green  — all assigned items are done
//   ◐ amber  — partial (some done, some still pending)
//   ✗ red    — nothing started yet
// Tapping a row opens the existing Quick glance (AssignmentViewer) so
// the owner can drill into specific items. The History button on each
// row goes to the bedroom history overlay.
function AssignedVsCleanedView({ employee, onBack, onOpenBedroomHistory, persistedState, onStateChange }) {
  const today = new Date(); today.setHours(0, 0, 0, 0);
  const isoDate = (d) => d.toISOString().split('T')[0];
  // Initialize state from the parent-held persistedState. This is what
  // lets the audit's filters / property / dates survive a round trip to
  // BedroomHistoryView and back. Falls back to today / empty on first
  // mount when persistedState defaults are still in place.
  const [start, setStart] = useState(persistedState?.start || isoDate(today));
  const [end, setEnd] = useState(persistedState?.end || isoDate(today));
  const [properties, setProperties] = useState([]);
  const [selectedPropertyId, setSelectedPropertyId] = useState(persistedState?.selectedPropertyId || '');
  const [rows, setRows] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [busy, setBusy] = useState(false);
  const [opened, setOpened] = useState(null); // assignment_target for Quick glance
  // Sub-filters — chips that appear AFTER the initial date+property
  // filters have populated rows. Multi-select; empty = "all".
  //   filterBuildings — which building prefixes (B1, B7…) to show
  //   filterStatuses  — 'done' | 'partial' | 'not_started'
  // Collapsed buildings are tracked separately so the user can hide
  // ones they don't care about.
  const [filterBuildings, setFilterBuildings] = useState(new Set(persistedState?.filterBuildings || []));
  const [filterStatuses, setFilterStatuses] = useState(new Set(persistedState?.filterStatuses || []));
  const [collapsedBuildings, setCollapsedBuildings] = useState(new Set(persistedState?.collapsedBuildings || []));
  // Reset all sub-state when the data set changes so the chips don't
  // reference values that no longer exist. Skip the first mount so we
  // don't immediately wipe whatever persistedState we just restored —
  // useEffect always fires once with the initial values, which would
  // otherwise blank the filters as the component remounts after a
  // BedroomHistoryView round trip.
  const isInitialResetMountRef = useRef(true);
  useEffect(() => {
    if (isInitialResetMountRef.current) {
      isInitialResetMountRef.current = false;
      return;
    }
    setFilterBuildings(new Set());
    setFilterStatuses(new Set());
    setCollapsedBuildings(new Set());
  }, [selectedPropertyId, start, end]);

  // Push every state change up to the parent so it persists across
  // unmount/remount cycles. Sets are serialized to plain arrays so
  // React state comparisons stay shallow + cheap.
  useEffect(() => {
    if (typeof onStateChange === 'function') {
      onStateChange(prev => ({
        ...(prev || {}),
        start, end, selectedPropertyId,
        filterBuildings: [...filterBuildings],
        filterStatuses: [...filterStatuses],
        collapsedBuildings: [...collapsedBuildings],
      }));
    }
  }, [start, end, selectedPropertyId, filterBuildings, filterStatuses, collapsedBuildings]);

  // Restore scroll position from the persisted state on first mount,
  // then save current scrollY back to it on unmount so a return trip
  // from BedroomHistoryView lands in the same place.
  useEffect(() => {
    if (persistedState?.scrollY) {
      // Defer to next tick so the rows have rendered before scrolling.
      setTimeout(() => window.scrollTo(0, persistedState.scrollY), 0);
    }
    return () => {
      if (typeof onStateChange === 'function') {
        onStateChange(prev => ({ ...(prev || {}), scrollY: window.scrollY }));
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Building prefix extracted from a unit label. "B1-101" → "B1",
  // "B7-326" → "B7". If there's no dash we fall back to the whole
  // label (which is rare).
  const buildingFromLabel = (unitLabel) => {
    if (!unitLabel) return '—';
    const idx = unitLabel.indexOf('-');
    return idx > 0 ? unitLabel.slice(0, idx) : unitLabel;
  };
  // Status bucket for a row (matches the top summary chips).
  const statusOfRow = (r) => {
    if (r.total === 0) return null;
    if (r.doneAnyTime === 0) return 'not_started';
    if (r.doneAnyTime >= r.total) return 'done';
    return 'partial';
  };

  useEffect(() => { (async () => {
    const { data } = await supabase.from('customers').select('id, name')
      .eq('active', true).order('name');
    setProperties(data || []);
  })(); }, []);

  // Build the per-bedroom comparison:
  //   - For each (unit, party) at the chosen property with any active
  //     assignment in the range, count total items and items that
  //     completed within the range.
  //   - Status icon derived from done/total counts.
  const load = async () => {
    if (!selectedPropertyId) { setRows([]); setLoaded(true); return; }
    setBusy(true);
    try {
      const startISO = new Date(start + 'T00:00:00').toISOString();
      const endISO = new Date(end + 'T23:59:59.999').toISOString();
      // Pull every active assignment target at this property along
      // with completion data. We filter visibility in-memory so the
      // range filter only applies to the COMPLETED side.
      const { data } = await supabase.from('assignment_targets')
        .select(`
          id, status, completed_at, recheck_passed_at, template_section, template_item_key, status_notes,
          unit:units(id, label),
          party:parties(id, label),
          assignment:assignments!inner(id, title, assignment_type, customer_id, active, source, pm_status, deleted_at, file_url, file_kind)
        `)
        .eq('assignment.customer_id', selectedPropertyId);
      const targets = (data || []).filter(t =>
        t.assignment?.customer_id === selectedPropertyId &&
        t.assignment?.active &&
      !t.assignment?.deleted_at &&
        (t.assignment?.source !== 'pm' || t.assignment?.pm_status === 'approved')
      );
      const startMs = new Date(startISO).getTime();
      const endMs = new Date(endISO).getTime();
      // Group by (unit, party). For each: total, doneInRange, doneAnyTime, sampleTarget for quick glance.
      const groups = new Map();
      for (const t of targets) {
        // Date-range filter: items completed BEFORE the start of the
        // chosen range aren't relevant to "what was left to clean as
        // of this range". Skip them so a "today" view doesn't show
        // items completed yesterday as already-done — they were
        // already accounted for in a previous report. Items still
        // pending / paused / in_progress always count (regardless of
        // when they were created) since they're still outstanding.
        if (t.status === 'done' && t.completed_at) {
          const completedMs = new Date(t.completed_at).getTime();
          if (completedMs < startMs) continue;
        }
        const uId = t.unit?.id || '_no_unit';
        const pId = t.party?.id || '_no_party';
        const key = `${uId}::${pId}`;
        if (!groups.has(key)) groups.set(key, {
          key, unitId: t.unit?.id, unitLabel: t.unit?.label || 'Unit',
          partyId: t.party?.id, partyLabel: t.party?.label || 'Bedroom',
          total: 0, doneInRange: 0, doneAnyTime: 0, blockedCount: 0,
          sampleTarget: t,
          assignmentType: t.assignment?.assignment_type,
          hasFile: !!t.assignment?.file_url,
        });
        const g = groups.get(key);
        g.total += 1;
        if (t.status === 'done') {
          g.doneAnyTime += 1;
          if (t.completed_at) {
            const ts = new Date(t.completed_at).getTime();
            if (ts >= startMs && ts <= endMs) g.doneInRange += 1;
          }
        }
        // Blocked items count toward "done" for the audit — the cleaner
        // is finished dealing with them (just waiting on owner review),
        // not still pending. We also track blockedCount separately so
        // the row can surface a visible Blocked badge instead of just
        // a green check pretending nothing's wrong.
        if (t.status === 'blocked') {
          g.doneAnyTime += 1;
          g.doneInRange += 1; // blocked is always "in-range" — it's still active
          g.blockedCount += 1;
        }
      }
      // Sort naturally by unit label then bedroom label
      const sorted = Array.from(groups.values()).sort((a, b) =>
        naturalCompare(a.unitLabel, b.unitLabel) ||
        naturalCompare(a.partyLabel, b.partyLabel)
      );
      setRows(sorted);
    } catch (e) {
      console.warn('[AssignedVsCleaned] load failed', e);
      setRows([]);
    }
    setLoaded(true);
    setBusy(false);
  };
  useEffect(() => { load(); }, [selectedPropertyId, start, end]);

  // Permission flags + bedroom-level bulk actions for blocked items.
  // Audit is owner-side, but we still gate Mark done by permission
  // (owner / manager always; cleaners need explicit can() permission).
  // Reopen is more permissive — anyone with an employee identity.
  const isStaff = employee?.role === 'owner' || employee?.role === 'manager';
  const canMarkDone = isStaff || can(employee, 'mark_assignments_done');
  const canReopen = !!employee?.id;

  // Bulk update every relevant item at this bedroom. Used by the
  // inline Reopen / Mark done buttons on each audit row so the owner
  // can resolve a whole bedroom in one tap.
  //
  // For "done": targets any item NOT already done (pending, paused,
  // in_progress, blocked) and flips it to done.
  // For "pending": targets any item NOT already pending (in_progress,
  // paused, blocked, done) and resets it.
  const bulkUpdateAllAtBedroom = async (g, newStatus) => {
    if (!g.unitId || !g.partyId) return;
    // Pre-check what we'd actually change so the confirm prompt and
    // skip-on-empty path are accurate.
    const { data: existing } = await supabase.from('assignment_targets')
      .select('id, status, assignment:assignments!inner(customer_id, active, source, pm_status, deleted_at)')
      .eq('unit_id', g.unitId)
      .eq('party_id', g.partyId);
    const scoped = (existing || []).filter(t =>
      t.assignment?.customer_id === selectedPropertyId &&
      t.assignment?.active &&
      !t.assignment?.deleted_at &&
      (t.assignment?.source !== 'pm' || t.assignment?.pm_status === 'approved')
    );
    const targets = scoped.filter(t => t.status !== newStatus);
    if (targets.length === 0) {
      alert(`Nothing to change — every item at ${g.unitLabel} · ${g.partyLabel} is already ${newStatus === 'done' ? 'done' : 'pending'}.`);
      return;
    }
    if (!confirm(
      newStatus === 'done'
        ? `Mark all ${targets.length} item${targets.length === 1 ? '' : 's'} at ${g.unitLabel} · ${g.partyLabel} as done?`
        : `Send all ${targets.length} item${targets.length === 1 ? '' : 's'} at ${g.unitLabel} · ${g.partyLabel} back to pending?`
    )) return;
    setBusy(true);
    try {
      const ids = targets.map(t => t.id);
      const patch = { status: newStatus };
      if (newStatus === 'done') {
        patch.completed_at = new Date().toISOString();
        patch.completed_by = employee?.id || null;
      } else if (newStatus === 'pending') {
        // Clear blocker reason + start stamps so reopened items start
        // truly fresh. Audit trail (photos, history) is preserved
        // elsewhere — we're not destroying anything.
        patch.status_notes = null;
        patch.started_at = null;
        patch.started_by = null;
        patch.completed_at = null;
        patch.completed_by = null;
      }
      await supabase.from('assignment_targets').update(patch).in('id', ids);
    } catch (e) {
      alert('Could not update: ' + (e.message || e));
    }
    setBusy(false);
    load();
  };

  // Status helper — returns { icon, color, label }. Blocked items
  // count toward "done" so a bedroom is never marked as red X just
  // because the cleaner had to flag something — they're done dealing
  // with it. A separate amber "Blocked" state surfaces when one or
  // more items at the bedroom are blocked so the owner knows review
  // is needed without losing the "completed" signal.
  const statusFor = (g) => {
    if (g.total === 0) return { Icon: Square, color: 'text-stone-300', bg: 'bg-stone-50', label: 'No items' };
    if (g.doneAnyTime === 0) return { Icon: X, color: 'text-red-600', bg: 'bg-red-50', label: 'Nothing started' };
    if (g.doneAnyTime >= g.total) {
      if (g.blockedCount > 0) {
        return { Icon: AlertCircle, color: 'text-amber-700', bg: 'bg-amber-50', label: 'Done with blockers' };
      }
      return { Icon: Check, color: 'text-emerald-600', bg: 'bg-emerald-50', label: 'All done' };
    }
    return { Icon: Circle, color: 'text-amber-600', bg: 'bg-amber-50', label: 'Partial' };
  };

  return (
    <div className="min-h-screen bg-stone-50 pb-12">
      <div className="px-5 py-4 border-b border-stone-200 bg-white sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
            <ArrowLeft size={20} className="text-stone-700" />
          </button>
          <div className="min-w-0 flex-1">
            <div className="text-[10px] uppercase tracking-wider text-stone-500 font-mono">Audit</div>
            <div className="font-serif text-lg text-stone-900">Assigned vs cleaned</div>
          </div>
        </div>
      </div>

      <div className="px-5 pt-4 max-w-3xl mx-auto">
        {/* Date range — single day allowed (start = end). Quick
           presets help skip to common windows. */}
        <div className="rounded-2xl bg-white border border-stone-200 p-4 mb-3">
          <div className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-2">Date range</div>
          <div className="flex flex-wrap gap-2 mb-3">
            {[{ d: 1, label: 'Today' }, { d: 7, label: 'Last 7d' }, { d: 14, label: 'Last 14d' }, { d: 30, label: 'Last 30d' }].map(p => (
              <button key={p.d} onClick={() => {
                const e = new Date(); e.setHours(0, 0, 0, 0);
                const s = new Date(e); s.setDate(s.getDate() - (p.d - 1));
                setStart(isoDate(s)); setEnd(isoDate(e));
              }}
                className="px-3 py-1.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 text-xs font-medium">
                {p.label}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-3">
            <input type="date" value={start} onChange={(e) => setStart(e.target.value)}
              className="flex-1 px-3 py-2 rounded-lg border border-stone-300 text-sm" />
            <span className="text-stone-400 text-xs">to</span>
            <input type="date" value={end} onChange={(e) => setEnd(e.target.value)}
              className="flex-1 px-3 py-2 rounded-lg border border-stone-300 text-sm" />
          </div>
        </div>

        {/* Property selector — required. Without it we'd be summing
           thousands of bedrooms which isn't useful. */}
        <div className="rounded-2xl bg-white border border-stone-200 p-4 mb-3">
          <div className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-2">Property</div>
          <select value={selectedPropertyId} onChange={(e) => setSelectedPropertyId(e.target.value)}
            className="w-full px-3 py-2 rounded-lg border border-stone-300 text-sm">
            <option value="">— Pick a property —</option>
            {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
          </select>
        </div>

        {/* Results list */}
        {!selectedPropertyId ? (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            Pick a property to see the audit.
          </div>
        ) : busy && !loaded ? (
          <div className="text-center py-12 text-stone-400 text-sm">Loading…</div>
        ) : rows.length === 0 ? (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            No active assignments at this property.
          </div>
        ) : (
          (() => {
            // Compute available chips + filtered rows + grouped data here
            // so we can use the results downstream without re-deriving.
            const availableBuildings = (() => {
              const set = new Set();
              rows.forEach(r => set.add(buildingFromLabel(r.unitLabel)));
              return Array.from(set).sort(naturalCompare);
            })();
            const presentStatuses = (() => {
              const set = new Set();
              rows.forEach(r => { const s = statusOfRow(r); if (s) set.add(s); });
              return ['done', 'partial', 'not_started'].filter(s => set.has(s));
            })();
            const filteredRows = rows.filter(r => {
              if (filterBuildings.size > 0 && !filterBuildings.has(buildingFromLabel(r.unitLabel))) return false;
              if (filterStatuses.size > 0) {
                const s = statusOfRow(r);
                if (!s || !filterStatuses.has(s)) return false;
              }
              return true;
            });
            const grouped = (() => {
              const m = new Map();
              filteredRows.forEach(r => {
                const b = buildingFromLabel(r.unitLabel);
                if (!m.has(b)) m.set(b, []);
                m.get(b).push(r);
              });
              return Array.from(m.entries()).sort((a, b) => naturalCompare(a[0], b[0]));
            })();
            const toggleSetVal = (setter) => (val) => setter(prev => {
              const next = new Set(prev);
              if (next.has(val)) next.delete(val); else next.add(val);
              return next;
            });
            const toggleBuilding = toggleSetVal(setFilterBuildings);
            const toggleStatus   = toggleSetVal(setFilterStatuses);
            const toggleCollapsed = toggleSetVal(setCollapsedBuildings);
            const statusLabels = { done: 'Fully done', partial: 'Partial', not_started: 'Not started' };
            const statusColors = {
              done: 'bg-emerald-100 text-emerald-800 border-emerald-300',
              partial: 'bg-amber-100 text-amber-800 border-amber-300',
              not_started: 'bg-red-100 text-red-800 border-red-300',
            };
            return (
          <>
            {/* Sub-filters — appear only after the initial query has
               populated rows. Buildings + statuses derived from the
               actual data so chips never reference values that don't
               exist. Multi-select; empty = "show all". */}
            {(availableBuildings.length > 1 || presentStatuses.length > 1) && (
              <div className="rounded-2xl bg-white border border-stone-200 p-4 mb-3">
                {availableBuildings.length > 1 && (
                  <div className="mb-2">
                    <div className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1.5">
                      Buildings {filterBuildings.size === 0 && <span className="text-stone-400">(showing all)</span>}
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                      {availableBuildings.map(b => {
                        const active = filterBuildings.has(b);
                        return (
                          <button key={b} onClick={() => toggleBuilding(b)}
                            className={`px-2.5 py-1 rounded-full text-xs font-medium border-2 transition-colors ${active ? 'bg-stone-900 border-stone-900 text-stone-50' : 'bg-white border-stone-200 text-stone-700 hover:border-stone-400'}`}>
                            {b}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
                {presentStatuses.length > 1 && (
                  <div>
                    <div className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1.5">
                      Status {filterStatuses.size === 0 && <span className="text-stone-400">(showing all)</span>}
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                      {presentStatuses.map(s => {
                        const active = filterStatuses.has(s);
                        return (
                          <button key={s} onClick={() => toggleStatus(s)}
                            className={`px-2.5 py-1 rounded-full text-xs font-medium border-2 transition-colors ${active ? statusColors[s] : 'bg-white border-stone-200 text-stone-600 hover:border-stone-400'}`}>
                            {statusLabels[s]}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Top-level summary — reflects FILTERED rows so the
               numbers match what's actually visible below. */}
            <div className="rounded-2xl bg-white border border-stone-200 p-4 mb-3">
              <div className="grid grid-cols-3 gap-2 text-center">
                <div>
                  <div className="text-2xl font-mono font-light text-emerald-700">
                    {filteredRows.filter(r => r.doneAnyTime >= r.total && r.total > 0).length}
                  </div>
                  <div className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mt-0.5">Fully done</div>
                </div>
                <div>
                  <div className="text-2xl font-mono font-light text-amber-700">
                    {filteredRows.filter(r => r.doneAnyTime > 0 && r.doneAnyTime < r.total).length}
                  </div>
                  <div className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mt-0.5">Partial</div>
                </div>
                <div>
                  <div className="text-2xl font-mono font-light text-red-700">
                    {filteredRows.filter(r => r.doneAnyTime === 0 && r.total > 0).length}
                  </div>
                  <div className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mt-0.5">Not started</div>
                </div>
              </div>
            </div>

            {filteredRows.length === 0 ? (
              <div className="text-center py-10 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
                Nothing matches those filters.
              </div>
            ) : (
              <div className="space-y-3">
                {grouped.map(([buildingName, buildingRows]) => {
                  const isCollapsed = collapsedBuildings.has(buildingName);
                  // Per-building totals so the header doubles as a summary
                  const bDone = buildingRows.filter(r => r.doneAnyTime >= r.total && r.total > 0).length;
                  const bPartial = buildingRows.filter(r => r.doneAnyTime > 0 && r.doneAnyTime < r.total).length;
                  const bNotStarted = buildingRows.filter(r => r.doneAnyTime === 0 && r.total > 0).length;
                  return (
                    <div key={buildingName} className="rounded-2xl bg-white border border-stone-200 overflow-hidden">
                      <button onClick={() => toggleCollapsed(buildingName)}
                        className="w-full px-4 py-3 flex items-center gap-3 hover:bg-stone-50 transition-colors">
                        <div className="text-left flex-1 min-w-0">
                          <div className="font-serif text-base text-stone-900">{buildingName}</div>
                          <div className="text-[10px] font-mono text-stone-500 mt-0.5">
                            {buildingRows.length} bedroom{buildingRows.length === 1 ? '' : 's'}
                            {bDone > 0 && <span className="text-emerald-700"> · {bDone} done</span>}
                            {bPartial > 0 && <span className="text-amber-700"> · {bPartial} partial</span>}
                            {bNotStarted > 0 && <span className="text-red-700"> · {bNotStarted} not started</span>}
                          </div>
                        </div>
                        <ChevronRight size={16}
                          className={`text-stone-400 flex-shrink-0 transition-transform ${isCollapsed ? '' : 'rotate-90'}`} />
                      </button>
                      {!isCollapsed && (
                        <div className="border-t border-stone-100 p-3 space-y-2 bg-stone-50">
                          {buildingRows.map(g => {
                            const s = statusFor(g);
                            const StatusIcon = s.Icon;
                            const pct = g.total > 0 ? Math.round((g.doneAnyTime / g.total) * 100) : 0;
                            return (
                              <div key={g.key} className="rounded-xl bg-white border border-stone-200 px-3 py-2.5">
                                <div className="flex items-center gap-3">
                                  <div className={`w-8 h-8 rounded-full ${s.bg} ${s.color} flex items-center justify-center flex-shrink-0`}>
                                    <StatusIcon size={15} strokeWidth={2.5} />
                                  </div>
                                  <div className="flex-1 min-w-0">
                                    <div className="text-sm text-stone-900 truncate flex items-center gap-1.5">
                                      <span className="font-medium">{g.unitLabel}</span>
                                      <span className="text-stone-400">·</span>
                                      <span className="italic text-amber-700">{g.partyLabel}</span>
                                      {g.assignmentType && (
                                        <AssignmentTypeChip type={g.assignmentType} />
                                      )}
                                      {/* Blocked badge — clear visible signal that
                                         items at this bedroom need owner review even
                                         though the bedroom counts as "complete". */}
                                      {g.blockedCount > 0 && (
                                        <span className="text-[9px] uppercase tracking-widest font-mono px-1.5 py-0.5 rounded-full bg-amber-100 text-amber-800 border border-amber-300 inline-flex items-center gap-0.5">
                                          <AlertCircle size={9} />
                                          Blocked {g.blockedCount > 1 ? `· ${g.blockedCount}` : ''}
                                        </span>
                                      )}
                                    </div>
                                    <div className="flex items-center gap-2 mt-1">
                                      <div className="text-[11px] text-stone-600 font-mono whitespace-nowrap">
                                        <span className="text-stone-900 font-bold">{g.doneAnyTime}</span>
                                        <span className="text-stone-400"> / </span>
                                        <span>{g.total}</span>
                                      </div>
                                      <div className="flex-1 h-1 bg-stone-200 rounded-full overflow-hidden">
                                        <div className={`h-full transition-all ${pct >= 100 ? (g.blockedCount > 0 ? 'bg-amber-500' : 'bg-emerald-500') : pct > 0 ? 'bg-amber-500' : 'bg-red-400'}`}
                                          style={{ width: `${pct}%` }} />
                                      </div>
                                      <div className="text-[10px] font-mono text-stone-500 whitespace-nowrap">{pct}%</div>
                                    </div>
                                  </div>
                                  {/* Inline action buttons. Quick glance + History
                                     are always present. Reopen + Mark done only
                                     appear when this bedroom has blocked items,
                                     so the owner can resolve them in one tap
                                     without opening Quick glance. */}
                                  <div className="flex items-center gap-0.5 flex-shrink-0">
                                    <button onClick={() => setOpened(g.sampleTarget)}
                                      className="p-1.5 rounded-full hover:bg-stone-100 text-stone-500 hover:text-stone-900"
                                      title="Quick glance">
                                      <Eye size={14} />
                                    </button>
                                    {onOpenBedroomHistory && g.unitId && g.partyId && (
                                      <button onClick={() => onOpenBedroomHistory({
                                        propertyId: selectedPropertyId,
                                        unitId: g.unitId, unitLabel: g.unitLabel,
                                        partyId: g.partyId, partyLabel: g.partyLabel,
                                      })}
                                        className="p-1.5 rounded-full hover:bg-stone-100 text-stone-500 hover:text-stone-900"
                                        title="History">
                                        <Clock size={14} />
                                      </button>
                                    )}
                                    {canReopen && (
                                      <button onClick={() => bulkUpdateAllAtBedroom(g, 'pending')}
                                        disabled={busy}
                                        className="p-1.5 rounded-full hover:bg-stone-100 text-stone-500 hover:text-stone-900 disabled:opacity-50"
                                        title="Reopen everything at this bedroom">
                                        <Play size={14} />
                                      </button>
                                    )}
                                    {canMarkDone && (
                                      <button onClick={() => bulkUpdateAllAtBedroom(g, 'done')}
                                        disabled={busy}
                                        className="p-1.5 rounded-full hover:bg-emerald-50 text-emerald-700 disabled:opacity-50"
                                        title="Mark everything at this bedroom done">
                                        <Check size={14} />
                                      </button>
                                    )}
                                  </div>
                                </div>
                                {g.doneInRange > 0 && g.doneInRange !== g.doneAnyTime && (
                                  <div className="text-[10px] font-mono text-stone-500 mt-1 pl-11">
                                    {g.doneInRange} done within range · {g.doneAnyTime - g.doneInRange} outside
                                  </div>
                                )}
                              </div>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </>
            );
          })()
        )}
      </div>

      {opened && (
        opened.assignment?.template_set_id || opened.template_section
          ? <ChecklistAssignmentView assignment={opened.assignment}
              employee={employee}
              quickGlance={true}
              onClose={() => setOpened(null)}
              onOpenSheet={opened.assignment?.file_url
                ? () => window.open(opened.assignment.file_url, '_blank', 'noopener')
                : null} />
          : <AssignmentViewer target={opened} employee={employee} onClose={() => setOpened(null)} />
      )}
    </div>
  );
}

// =================================================================
// BETA: ActivityTimelineView — full-screen view that pulls today's
// events from multiple tables and renders them in reverse-chrono
// order. Gated behind isBetaFeaturesEnabled; the entry button on
// DailyCalendar is conditionally rendered.
//
// Event sources:
//   - shifts.start_time / end_time  → clock in / out
//   - work_blocks.start_time / end_time → block started / finished
//   - photos.created_at (kind=damage) → damage flagged
//   - recheck_requests.created_at → PM requested recheck
//
// Day boundary defaults to TODAY in the viewer's local timezone.
// Could expand to a date picker later, but the point of the timeline
// is "what happened today" so we keep it simple for v1.
// =================================================================
function ActivityTimelineView({ employee, onClose }) {
  const [events, setEvents] = useState([]);
  const [loaded, setLoaded] = useState(false);
  // Use today's local start/end as ISO strings for the queries.
  const dayBounds = (() => {
    const start = new Date(); start.setHours(0, 0, 0, 0);
    const end = new Date(); end.setHours(23, 59, 59, 999);
    return { startISO: start.toISOString(), endISO: end.toISOString() };
  })();

  useEffect(() => {
    let cancelled = false;
    (async () => {
      const { startISO, endISO } = dayBounds;
      // Pull everything in parallel. Each event source maps to a
      // normalized { ts, kind, title, body, actor } shape for rendering.
      const [shiftsR, blocksR, photosR, rechecksR] = await Promise.all([
        supabase.from('shifts')
          .select('id, start_time, end_time, employee:employees(id, name), customer:customers(id, name)')
          .gte('start_time', startISO).lte('start_time', endISO)
          .eq('is_preview', false),
        supabase.from('work_blocks')
          .select('id, start_time, end_time, unit:units(label), party:parties(label), shift:shifts(employee:employees(id, name), customer:customers(id, name))')
          .gte('start_time', startISO).lte('start_time', endISO),
        supabase.from('photos')
          .select('id, created_at, kind, taken_by_employee:employees!taken_by(id, name), task:tasks(work_block:work_blocks(unit:units(label), party:parties(label), shift:shifts(customer:customers(name))))')
          .eq('kind', 'damage')
          .gte('created_at', startISO).lte('created_at', endISO)
          .is('deleted_at', null),
        supabase.from('recheck_requests')
          .select('id, created_at, status, target:assignment_targets(unit:units(label), party:parties(label), assignment:assignments(property:customers(name)))')
          .gte('created_at', startISO).lte('created_at', endISO),
      ]);
      if (cancelled) return;
      const all = [];
      // Shifts: clock in + clock out
      (shiftsR.data || []).forEach(s => {
        all.push({
          ts: s.start_time, kind: 'shift_start',
          actor: s.employee?.name || '?',
          title: `${s.employee?.name || 'A cleaner'} clocked in`,
          body: s.customer?.name || '',
        });
        if (s.end_time) {
          all.push({
            ts: s.end_time, kind: 'shift_end',
            actor: s.employee?.name || '?',
            title: `${s.employee?.name || 'A cleaner'} clocked out`,
            body: s.customer?.name || '',
          });
        }
      });
      // Work blocks: started + finished
      (blocksR.data || []).forEach(b => {
        const cleaner = b.shift?.employee?.name || '?';
        const where = `${b.unit?.label || ''} · ${b.party?.label || ''}`;
        all.push({
          ts: b.start_time, kind: 'block_start',
          actor: cleaner,
          title: `${cleaner} started cleaning ${where}`,
          body: b.shift?.customer?.name || '',
        });
        if (b.end_time) {
          all.push({
            ts: b.end_time, kind: 'block_end',
            actor: cleaner,
            title: `${cleaner} finished ${where}`,
            body: b.shift?.customer?.name || '',
          });
        }
      });
      // Damage photos
      (photosR.data || []).forEach(p => {
        const cleaner = p.taken_by_employee?.name || 'A cleaner';
        const where = `${p.task?.work_block?.unit?.label || ''} · ${p.task?.work_block?.party?.label || ''}`;
        all.push({
          ts: p.created_at, kind: 'damage',
          actor: cleaner,
          title: `⚠ ${cleaner} flagged damage at ${where}`,
          body: p.task?.work_block?.shift?.customer?.name || '',
        });
      });
      // Recheck requests
      (rechecksR.data || []).forEach(r => {
        const where = `${r.target?.unit?.label || ''} · ${r.target?.party?.label || ''}`;
        all.push({
          ts: r.created_at, kind: 'recheck',
          actor: 'PM',
          title: `PM requested recheck at ${where}`,
          body: r.target?.assignment?.property?.name || '',
        });
      });
      // Sort reverse-chronological so most recent is on top
      all.sort((a, b) => new Date(b.ts) - new Date(a.ts));
      setEvents(all);
      setLoaded(true);
    })();
    return () => { cancelled = true; };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const iconFor = (kind) => {
    switch (kind) {
      case 'shift_start':  return { Icon: Play,   color: 'bg-emerald-100 text-emerald-700' };
      case 'shift_end':    return { Icon: Pause,  color: 'bg-stone-100 text-stone-600' };
      case 'block_start':  return { Icon: Camera, color: 'bg-blue-100 text-blue-700' };
      case 'block_end':    return { Icon: Check,  color: 'bg-emerald-100 text-emerald-700' };
      case 'damage':       return { Icon: ImageIcon, color: 'bg-red-100 text-red-700' };
      case 'recheck':      return { Icon: Eye,    color: 'bg-amber-100 text-amber-700' };
      default:             return { Icon: Clock,  color: 'bg-stone-100 text-stone-500' };
    }
  };

  return (
    <div className="fixed inset-0 z-40 bg-stone-50 overflow-y-auto">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200 bg-white sticky top-0 z-10">
        <button onClick={onClose} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div className="flex-1 min-w-0">
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono flex items-center gap-2">
            Beta · Today
            <span className="text-[8px] uppercase tracking-widest font-mono px-1.5 py-0.5 rounded-full bg-amber-200 text-amber-800">Beta</span>
          </div>
          <h1 className="font-serif text-2xl text-stone-900">Activity timeline</h1>
        </div>
      </div>
      <div className="max-w-2xl mx-auto px-5 py-6">
        {!loaded ? (
          <div className="text-center py-12 text-stone-400 text-sm">Loading…</div>
        ) : events.length === 0 ? (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            No activity yet today.
          </div>
        ) : (
          <div className="relative">
            {/* Vertical timeline rule */}
            <div className="absolute left-4 top-2 bottom-2 w-px bg-stone-200" />
            <div className="space-y-2">
              {events.map((e, i) => {
                const { Icon, color } = iconFor(e.kind);
                return (
                  <div key={i} className="relative flex items-start gap-3 pl-1">
                    <div className={`relative z-10 w-8 h-8 rounded-full ${color} flex items-center justify-center flex-shrink-0 ring-4 ring-stone-50`}>
                      <Icon size={14} />
                    </div>
                    <div className="flex-1 min-w-0 pt-1 pb-3">
                      <div className="text-sm text-stone-900">{e.title}</div>
                      {e.body && (
                        <div className="text-[11px] text-stone-500 font-mono mt-0.5 truncate">{e.body}</div>
                      )}
                      <div className="text-[10px] font-mono text-stone-400 mt-0.5">
                        {fmtClock(e.ts)}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// TranslationOverridesModal — owner-facing admin view for managing
// Spanish label overrides cleaners have saved per property. Groups
// overrides by property; each row shows English fallback → override
// label + a Revert button. Owner can clean up bad edits centrally
// instead of asking each cleaner to undo their own.
function TranslationOverridesModal({ employee, onClose }) {
  const [rows, setRows] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [busy, setBusy] = useState(false);
  const [filter, setFilter] = useState('');

  const load = async () => {
    setLoaded(false);
    // Pull every override + the property name + who edited it. We
    // don't restrict by property here — owner sees all their data.
    const { data } = await supabase.from('item_label_overrides')
      .select(`
        id, property_id, template_item_key, locale, label, edited_at,
        property:customers(id, name),
        editor:employees!edited_by(id, name)
      `)
      .order('edited_at', { ascending: false });
    setRows(data || []);
    setLoaded(true);
  };
  useEffect(() => { load(); }, []);

  const revert = async (row) => {
    if (!confirm(`Revert "${row.label}" back to the default Spanish label?`)) return;
    setBusy(true);
    const { error } = await supabase.from('item_label_overrides').delete().eq('id', row.id);
    setBusy(false);
    if (error) { alert('Could not revert: ' + error.message); return; }
    setRows(prev => prev.filter(r => r.id !== row.id));
  };

  // Derive default Spanish label (from the static dictionary) so the
  // owner can see what we'd fall back to after a revert.
  const dictionaryLabelFor = (key) => PICKER_ES?.[key] || null;
  // Friendly English fallback for context
  const englishFor = (key) => {
    if (!key) return '';
    return key.replace(/^[a-z_]+:/, '').replace(/_/g, ' ').replace(/^./, c => c.toUpperCase());
  };

  // Group rows by property for tidier display
  const grouped = (() => {
    const m = new Map();
    const q = filter.trim().toLowerCase();
    rows.filter(r => {
      if (!q) return true;
      return (
        r.label?.toLowerCase().includes(q) ||
        r.template_item_key?.toLowerCase().includes(q) ||
        r.property?.name?.toLowerCase().includes(q) ||
        r.editor?.name?.toLowerCase().includes(q)
      );
    }).forEach(r => {
      const key = r.property?.id || '_none';
      if (!m.has(key)) m.set(key, { name: r.property?.name || 'Unknown property', rows: [] });
      m.get(key).rows.push(r);
    });
    return Array.from(m.values()).sort((a, b) => a.name.localeCompare(b.name));
  })();

  return (
    <div onClick={onClose}
      className="fixed inset-0 bg-stone-900/70 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div onClick={(e) => e.stopPropagation()}
        className="bg-stone-50 w-full sm:max-w-2xl sm:rounded-3xl rounded-t-3xl flex flex-col max-h-[90vh]">
        <div className="p-5 border-b border-stone-200 flex items-start justify-between gap-2">
          <div className="flex-1 min-w-0">
            <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">Admin</div>
            <div className="font-serif text-xl text-stone-900">Spanish label overrides</div>
            <div className="text-xs text-stone-500 mt-0.5">
              Per-property item labels cleaners have edited from the default Spanish translation.
            </div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100 flex-shrink-0">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="px-5 pt-3">
          <input type="text" value={filter} onChange={(e) => setFilter(e.target.value)}
            placeholder="Filter by property, item, or editor…"
            className="w-full px-3 py-2 rounded-lg border border-stone-300 text-sm" />
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {!loaded ? (
            <div className="text-center py-12 text-stone-400 text-sm">Loading…</div>
          ) : grouped.length === 0 ? (
            <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
              {rows.length === 0 ? 'No label overrides yet.' : 'Nothing matches that filter.'}
            </div>
          ) : (
            grouped.map((g, gi) => (
              <div key={gi} className="rounded-2xl bg-white border border-stone-200 overflow-hidden">
                <div className="px-4 py-2.5 bg-stone-50 border-b border-stone-200 flex items-center gap-2">
                  <Building2 size={14} className="text-stone-500" />
                  <span className="font-serif text-base text-stone-900">{g.name}</span>
                  <span className="text-[10px] font-mono text-stone-500">({g.rows.length})</span>
                </div>
                <div className="divide-y divide-stone-100">
                  {g.rows.map(r => {
                    const defLabel = dictionaryLabelFor(r.template_item_key);
                    const enLabel = englishFor(r.template_item_key);
                    return (
                      <div key={r.id} className="px-4 py-3 flex items-start gap-3">
                        <div className="flex-1 min-w-0">
                          <div className="text-[10px] font-mono text-stone-500 mb-0.5 truncate">{r.template_item_key}</div>
                          <div className="text-sm text-stone-900 truncate">
                            <span className="text-stone-500">{enLabel}</span>
                            <span className="text-stone-300 mx-1.5">→</span>
                            <span className="font-medium">{r.label}</span>
                          </div>
                          <div className="text-[10px] font-mono text-stone-400 mt-0.5 truncate">
                            {r.editor?.name || 'someone'} · {fmtDate(r.edited_at)}
                            {defLabel && defLabel !== r.label && (
                              <span> · Default: <span className="text-stone-600">{defLabel}</span></span>
                            )}
                          </div>
                        </div>
                        <button onClick={() => revert(r)} disabled={busy}
                          className="text-[10px] uppercase tracking-wider font-mono px-2 py-1 rounded-full bg-stone-100 hover:bg-red-100 hover:text-red-800 text-stone-700 flex items-center gap-1 disabled:opacity-50 flex-shrink-0">
                          <Delete size={11} /> Revert
                        </button>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

function DailyCalendar({ employee, onSignOut, onPickDay, onOpenInbox, onOpenAssignedVsCleaned, onOpenMessages, onLogoClick }) {
  const today = new Date();
  const [viewMonth, setViewMonth] = useState(new Date(today.getFullYear(), today.getMonth(), 1));
  const [activity, setActivity] = useState({});
  const [loaded, setLoaded] = useState(false);
  const [inboxCounts, setInboxCounts] = useState({ pendingAssignments: 0, pendingRechecks: 0, newPhotos: 0 });
  // Owner-only modal for managing Spanish label overrides across properties.
  const [showOverrides, setShowOverrides] = useState(false);
  // Beta-gated demo view. Only mounts when isBetaFeaturesEnabled
  // returns true (beta tester logged in + currently in BETA view).
  const [showActivityTimeline, setShowActivityTimeline] = useState(false);
  const betaEnabled = isBetaFeaturesEnabled(employee);
  // Who's-where modal — opened from the person icon in the header,
  // replacing the always-visible panel on the home screen.
  const [whosWhereOpen, setWhosWhereOpen] = useState(false);

  // Load inbox counts
  useEffect(() => {
    (async () => {
      const { count: pAssign } = await supabase.from('assignments')
        .select('id', { count: 'exact', head: true })
        .eq('source', 'pm').eq('pm_status', 'pending');
      const { count: pRechecks } = await supabase.from('recheck_requests')
        .select('id', { count: 'exact', head: true })
        .eq('pm_status', 'pending');
      const { count: pPhotos } = await supabase.from('pm_photos')
        .select('id', { count: 'exact', head: true })
        .eq('status', 'new');
      setInboxCounts({
        pendingAssignments: pAssign || 0,
        pendingRechecks: pRechecks || 0,
        newPhotos: pPhotos || 0,
      });
    })();
  }, []);
  const inboxTotal = inboxCounts.pendingAssignments + inboxCounts.pendingRechecks + inboxCounts.newPhotos;

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setLoaded(false);
      // Pull just shift summary for this month (3-month buffer)
      const start = new Date(viewMonth.getFullYear(), viewMonth.getMonth() - 1, 1).toISOString();
      const end   = new Date(viewMonth.getFullYear(), viewMonth.getMonth() + 2, 1).toISOString();

      // Lightweight: just shift IDs, start, property — no nested rows
      const { data: shifts, error: sErr } = await supabase
        .from('shifts')
        .select('id, start_time, customer_id')
        .gte('start_time', start)
        .lt('start_time', end)
        .eq('is_preview', false);  // Don't mark calendar days for preview-only activity
      if (sErr) { console.error('[DailyCalendar] shifts error:', sErr); }
      if (cancelled) return;

      // Separately: which days in this window have damage photos? One query, ID-only.
      // We get all UNRESOLVED damage photos created in the window, then
      // map their task → shift → date. Resolved damage doesn't contribute
      // to the red dot on the calendar.
      const { data: damagePhotos } = await supabase
        .from('photos')
        .select('task_id, resolved_at, tasks!inner(shift_id, work_block_id, shifts(start_time), work_blocks(shift_id, shifts(start_time)))')
        .eq('kind', 'damage')
        .is('resolved_at', null);
      if (cancelled) return;

      // Build a set of date keys that have at least one damage photo
      const damageDays = new Set();
      (damagePhotos || []).forEach(p => {
        const startTime = p.tasks?.shifts?.start_time
          || p.tasks?.work_blocks?.shifts?.start_time;
        if (startTime) damageDays.add(toDateKey(new Date(startTime)));
      });

      // Build per-day counts from shifts alone
      const map = {};
      (shifts || []).forEach(s => {
        const key = toDateKey(new Date(s.start_time));
        if (!map[key]) map[key] = { shiftCount: 0, properties: new Set() };
        map[key].shiftCount++;
        if (s.customer_id) map[key].properties.add(s.customer_id);
      });

      const final = {};
      Object.entries(map).forEach(([k, v]) => {
        final[k] = {
          shiftCount: v.shiftCount,
          propertyCount: v.properties.size,
          hasDamage: damageDays.has(k)
        };
      });
      if (cancelled) return;
      setActivity(final);
      setLoaded(true);
    })();
    return () => { cancelled = true; };
  }, [viewMonth]);

  // Build the calendar grid
  const year = viewMonth.getFullYear();
  const month = viewMonth.getMonth();
  const firstDay = new Date(year, month, 1);
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const startWeekday = firstDay.getDay(); // 0 = Sunday

  const cells = [];
  // Leading blanks
  for (let i = 0; i < startWeekday; i++) cells.push(null);
  // Days of the month
  for (let d = 1; d <= daysInMonth; d++) {
    const date = new Date(year, month, d);
    cells.push({ day: d, key: toDateKey(date), date });
  }
  // Trailing blanks to fill last row
  while (cells.length % 7 !== 0) cells.push(null);

  const monthName = viewMonth.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
  const todayKey = toDateKey(today);

  const goPrev = () => setViewMonth(new Date(year, month - 1, 1));
  const goNext = () => setViewMonth(new Date(year, month + 1, 1));
  const goToday = () => setViewMonth(new Date(today.getFullYear(), today.getMonth(), 1));

  return (
    <div className="pb-24">
      <Header name={employee.name} onSignOut={onSignOut} role={employee.role} employee={employee} onOpenMessages={onOpenMessages} onLogoClick={onLogoClick}
        onOpenWhosHere={() => setWhosWhereOpen(true)}
        menuItems={[
          ...(onOpenAssignedVsCleaned ? [{ icon: <Eye size={18} />, label: 'Assigned vs cleaned', onClick: onOpenAssignedVsCleaned }] : []),
          ...(betaEnabled ? [{ icon: <Clock size={18} />, label: 'Activity timeline', onClick: () => setShowActivityTimeline(true) }] : []),
          { icon: <Languages size={18} />, label: 'Label overrides', onClick: () => setShowOverrides(true) },
        ]} />
      <div className="px-5 pt-6">
        {inboxTotal > 0 && (
          <button onClick={onOpenInbox}
            className="w-full mb-5 p-4 rounded-2xl bg-amber-50 border-2 border-amber-300 hover:border-amber-500 active:scale-98 transition-all flex items-center justify-between gap-3">
            <div className="flex items-center gap-3">
              <div className="w-9 h-9 rounded-full bg-amber-600 text-white flex items-center justify-center font-mono text-sm font-bold">
                {inboxTotal}
              </div>
              <div className="text-left">
                <div className="font-serif text-base text-stone-900">
                  Inbox — needs review
                </div>
                <div className="text-xs text-stone-600 font-mono">
                  {[
                    inboxCounts.pendingAssignments > 0 && `${inboxCounts.pendingAssignments} ${inboxCounts.pendingAssignments === 1 ? 'assignment' : 'assignments'}`,
                    inboxCounts.pendingRechecks > 0 && `${inboxCounts.pendingRechecks} ${inboxCounts.pendingRechecks === 1 ? 'recheck' : 'rechecks'}`,
                    inboxCounts.newPhotos > 0 && `${inboxCounts.newPhotos} ${inboxCounts.newPhotos === 1 ? 'photo' : 'photos'}`,
                  ].filter(Boolean).join(' · ')}
                  {' from property managers'}
                </div>
              </div>
            </div>
            <ChevronRight size={18} className="text-stone-400 flex-shrink-0" />
          </button>
        )}
        {/* "Who's working now" moved to the person icon in the header.
           The three occasional tools (Assigned vs cleaned, Activity
           timeline, Label overrides) moved into the header ⋯ menu — see
           the menuItems passed to <Header> above. This keeps the home
           focused on the inbox + the calendar. */}
        <div className="flex items-center justify-between mb-3 mt-1">
          <div className="text-xs uppercase tracking-widest text-stone-400 font-mono">
            Daily browser
          </div>
        </div>

        {/* Month navigator */}
        <div className="flex items-center justify-between mb-4">
          <button onClick={goPrev}
            className="p-2 rounded-full bg-stone-100 hover:bg-stone-200 active:scale-95 transition-all">
            <ChevronLeft size={18} className="text-stone-700" />
          </button>
          <div className="text-center">
            <div className="font-serif text-xl text-stone-900">{monthName}</div>
            <button onClick={goToday} className="text-xs font-mono text-amber-700 hover:text-amber-800 mt-0.5">
              Jump to today
            </button>
          </div>
          <button onClick={goNext}
            className="p-2 rounded-full bg-stone-100 hover:bg-stone-200 active:scale-95 transition-all">
            <ChevronRight size={18} className="text-stone-700" />
          </button>
        </div>

        {/* Weekday headers */}
        <div className="grid grid-cols-7 gap-1 mb-1">
          {['S','M','T','W','T','F','S'].map((d, i) => (
            <div key={i} className="text-center text-[10px] font-mono uppercase tracking-wider text-stone-400 py-1">
              {d}
            </div>
          ))}
        </div>

        {/* Calendar grid */}
        <div className="grid grid-cols-7 gap-1">
          {cells.map((cell, i) => {
            if (!cell) return <div key={i} />;
            const a = activity[cell.key];
            const isToday = cell.key === todayKey;
            const isFuture = cell.date > today;
            return (
              <button key={i}
                disabled={!a}
                onClick={() => a && onPickDay(cell.key)}
                className={`aspect-square rounded-xl flex flex-col items-center justify-center text-sm relative transition-all ${
                  !a ? (isFuture ? 'text-stone-300' : 'text-stone-400 hover:bg-stone-50') :
                  a.hasDamage ? 'bg-red-50 border-2 border-red-300 text-red-900 hover:border-red-500 active:scale-95' :
                  'bg-amber-50 border-2 border-amber-300 text-amber-900 hover:border-amber-500 active:scale-95'
                } ${isToday ? 'ring-2 ring-stone-900 ring-offset-1' : ''}`}>
                <div className={`font-mono ${a ? 'font-bold' : ''}`}>{cell.day}</div>
                {a && (
                  <div className="text-[9px] font-mono mt-0.5 leading-none">
                    {a.shiftCount} {a.shiftCount === 1 ? 'shift' : 'shifts'}
                  </div>
                )}
                {a?.hasDamage && (
                  <div className="absolute top-0.5 right-0.5 w-1.5 h-1.5 rounded-full bg-red-500" />
                )}
              </button>
            );
          })}
        </div>

        {/* Legend */}
        <div className="mt-4 flex items-center justify-center gap-4 text-xs text-stone-500 font-mono">
          <div className="flex items-center gap-1.5">
            <div className="w-3 h-3 rounded bg-amber-50 border-2 border-amber-300" />
            Cleaned
          </div>
          <div className="flex items-center gap-1.5">
            <div className="w-3 h-3 rounded bg-red-50 border-2 border-red-300" />
            Damage
          </div>
          <div className="flex items-center gap-1.5">
            <div className="w-3 h-3 rounded ring-2 ring-stone-900" />
            Today
          </div>
        </div>

        {!loaded && <div className="text-center mt-6 text-xs text-stone-400 font-mono">Loading…</div>}
        {loaded && Object.keys(activity).length === 0 && (
          <div className="mt-6 text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            No cleanings recorded this month.
          </div>
        )}
      </div>
      {showOverrides && (
        <TranslationOverridesModal
          employee={employee}
          onClose={() => setShowOverrides(false)} />
      )}
      {showActivityTimeline && (
        <ActivityTimelineView
          employee={employee}
          onClose={() => setShowActivityTimeline(false)} />
      )}
      {/* Who's-where modal — opened from the header person icon. Reuses
         the all-properties live panel that used to sit on the home. */}
      {whosWhereOpen && (
        <div className="fixed inset-0 z-50 bg-black/40 flex items-end sm:items-center justify-center sm:p-4"
          onClick={() => setWhosWhereOpen(false)}>
          <div className="bg-stone-50 w-full sm:max-w-md rounded-t-3xl sm:rounded-3xl max-h-[85vh] overflow-y-auto"
            onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between px-5 py-4 border-b border-stone-200 sticky top-0 bg-stone-50 z-10">
              <div className="font-serif text-lg text-stone-900">Who's where right now</div>
              <button onClick={() => setWhosWhereOpen(false)}
                className="p-2 rounded-full hover:bg-stone-200 active:scale-95 transition-transform">
                <X size={18} className="text-stone-600" />
              </button>
            </div>
            <div className="p-4">
              <WhosWherePanel employee={employee} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Day detail: shows all properties + units cleaned on this date
function DailyDayDetail({ date, employee, showMoney, onBack, onOpenUnit }) {
  const [data, setData] = useState(null);
  // Filters — multi-select for cleaners + properties so the owner can
  // zoom into a specific person or building's day. Empty Set = "no filter".
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [filterCleaners, setFilterCleaners] = useState(new Set());
  const [filterProperties, setFilterProperties] = useState(new Set());
  const [filterCategories, setFilterCategories] = useState(new Set());

  useEffect(() => { (async () => {
    const dayStart = `${date}T00:00:00`;
    const dayEnd   = `${date}T23:59:59`;

    // Get all shifts that started this day. Include idle_seconds so the
    // per-cleaner breakdown can show clocked-in time + idle adjustments.
    // Exclude preview-mode shifts (owner using "Preview as cleaner").
    const { data: shifts } = await supabase
      .from('shifts')
      .select('id, start_time, end_time, customer_id, idle_seconds, employee:employees(id,name), customer:customers(id,name,property_type,bill_rate_hourly), work_blocks(id, start_time, end_time, bill_rate_at_work, unit:units(id, label), party:parties(id, label, full_name), tasks(*, photos(*, taken_by_employee:employees!taken_by(name))))')
      .gte('start_time', dayStart)
      .lte('start_time', dayEnd)
      .eq('is_preview', false)
      .order('start_time');

    // Group by property → unit
    // For multi_unit shifts we use work_blocks. For simple shifts, group by property only.
    const groups = {};  // { propertyId: { property, units: { unitId: { unitLabel, employees: Set, totalMs, hasDamage, photoCount } } } }

    // Per-cleaner aggregate: { employeeId: { name, totalActiveMs, totalShiftMs, idleSeconds, hasOpenShift, units: Set, categories: Set } }
    // - totalActiveMs = sum of work_block durations (the time they were billing for)
    // - totalShiftMs = sum of shift durations (total clocked-in time)
    // - idleSeconds = sum of idle_seconds across shifts (DB-detected inactivity)
    // - hasOpenShift = at least one shift still active (no end_time)
    const byCleaner = {};

    (shifts || []).forEach(s => {
      if (!s.customer_id) return;
      const propId = s.customer_id;
      if (!groups[propId]) {
        groups[propId] = { property: s.customer, units: {}, simpleShifts: [] };
      }
      const propGroup = groups[propId];

      // Per-cleaner aggregation
      const eId = s.employee?.id || 'unknown';
      if (!byCleaner[eId]) {
        byCleaner[eId] = {
          employeeId: eId, name: s.employee?.name || '—',
          totalActiveMs: 0, totalShiftMs: 0, idleSeconds: 0,
          hasOpenShift: false, units: new Set(), categories: new Set(),
          properties: new Set(),
        };
      }
      const c = byCleaner[eId];
      const shiftMs = (s.end_time ? new Date(s.end_time) : new Date()) - new Date(s.start_time);
      c.totalShiftMs += shiftMs;
      c.idleSeconds += (s.idle_seconds || 0);
      if (!s.end_time) c.hasOpenShift = true;
      c.properties.add(s.customer?.name || '—');

      if (s.customer.property_type === 'multi_unit') {
        (s.work_blocks || []).forEach(b => {
          if (!b.unit) return;
          const uId = b.unit.id;
          if (!propGroup.units[uId]) {
            propGroup.units[uId] = {
              unitId: uId, unitLabel: b.unit.label,
              employees: new Set(), totalMs: 0, hasDamage: false, photoCount: 0, blocks: []
            };
          }
          const ug = propGroup.units[uId];
          ug.employees.add(s.employee?.name || '?');
          ug.blocks.push({ block: b, employee: s.employee, rate: s.customer.bill_rate_hourly });
          const blockMs = b.end_time
            ? new Date(b.end_time) - new Date(b.start_time)
            : new Date() - new Date(b.start_time);
          ug.totalMs += blockMs;
          c.totalActiveMs += blockMs;
          c.units.add(b.unit.label);
          (b.tasks || []).forEach(t => {
            if (t.category) c.categories.add(t.category);
            (t.photos || []).forEach(p => {
              ug.photoCount++;
              if (p.kind === 'damage') ug.hasDamage = true;
            });
          });
        });
      } else {
        propGroup.simpleShifts.push(s);
        // For simple-property shifts there's no work_block breakdown,
        // so active time equals shift time
        c.totalActiveMs += shiftMs;
      }
    });

    setData({ groups, shifts: shifts || [], byCleaner });
  })(); }, [date]);

  if (!data) return <Splash text="Loading…" />;

  const dateObj = new Date(date + 'T12:00:00');
  const propIds = Object.keys(data.groups);
  const totalShifts = data.shifts.length;
  const totalProperties = propIds.length;

  return (
    <div className="pb-24">
      <div className="bg-stone-900 text-stone-50 px-5 pt-5 pb-6">
        <button onClick={onBack} className="flex items-center gap-2 text-stone-400 text-sm mb-4 hover:text-stone-50">
          <ArrowLeft size={16} /> Back to calendar
        </button>
        <div className="text-xs uppercase tracking-widest text-stone-400 font-mono mb-2">
          {dateObj.toLocaleDateString('en-US', { weekday:'long' })}
        </div>
        <h1 className="font-serif text-3xl mb-1">
          {dateObj.toLocaleDateString('en-US', { month:'long', day:'numeric', year:'numeric' })}
        </h1>
        <div className="text-sm text-stone-300 mt-2">
          {totalShifts} {totalShifts === 1 ? 'shift' : 'shifts'} across {totalProperties} {totalProperties === 1 ? 'property' : 'properties'}
        </div>
      </div>

      <div className="px-5 pt-6">
        {/* Filters + per-cleaner breakdown live above the property
           grouping so the owner can quickly see "who worked how long"
           before drilling into specific properties/units. */}
        {data.shifts.length > 0 && (() => {
          // Compute filter options from the unfiltered data
          const allCleaners = Object.values(data.byCleaner).map(c => ({ id: c.employeeId, name: c.name }))
            .sort((a, b) => a.name.localeCompare(b.name));
          const allProperties = Object.values(data.groups).map(g => g.property?.name).filter(Boolean);
          const uniqueProps = [...new Set(allProperties)].sort();
          const allCategories = new Set();
          Object.values(data.byCleaner).forEach(c => c.categories.forEach(cat => allCategories.add(cat)));
          const availableCategories = TASK_CATEGORIES.filter(c => allCategories.has(c.id));

          // Apply filters to per-cleaner list
          const cleanersFiltered = Object.values(data.byCleaner).filter(c => {
            if (filterCleaners.size > 0 && !filterCleaners.has(c.employeeId)) return false;
            if (filterProperties.size > 0) {
              const hit = [...c.properties].some(p => filterProperties.has(p));
              if (!hit) return false;
            }
            if (filterCategories.size > 0) {
              const hit = [...c.categories].some(cat => filterCategories.has(cat));
              if (!hit) return false;
            }
            return true;
          }).sort((a, b) => b.totalActiveMs - a.totalActiveMs);

          const activeFilterCount = filterCleaners.size + filterProperties.size + filterCategories.size;
          const toggleSet = (setter) => (value) => setter(prev => {
            const next = new Set(prev);
            if (next.has(value)) next.delete(value);
            else next.add(value);
            return next;
          });
          return (
            <>
              {(allCleaners.length > 0 || uniqueProps.length > 1 || availableCategories.length > 0) && (
                <div className="mb-4">
                  <button onClick={() => setFiltersOpen(o => !o)}
                    className={`w-full flex items-center justify-between px-3 py-2 rounded-xl border ${activeFilterCount > 0 ? 'bg-amber-50 border-amber-300 text-amber-900' : 'bg-white border-stone-200 text-stone-600'}`}>
                    <div className="flex items-center gap-2">
                      <Settings size={14} />
                      <span className="text-xs uppercase tracking-wider font-mono">
                        Filters{activeFilterCount > 0 ? ` (${activeFilterCount})` : ''}
                      </span>
                    </div>
                    <ChevronRight size={14} className={`transition-transform ${filtersOpen ? 'rotate-90' : ''}`} />
                  </button>
                  {filtersOpen && (
                    <div className="p-3 rounded-xl bg-stone-50 border border-stone-200 mt-1 space-y-3">
                      {allCleaners.length > 0 && (
                        <div>
                          <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1">Cleaner</div>
                          <div className="flex gap-1.5 flex-wrap">
                            {allCleaners.map(c => {
                              const active = filterCleaners.has(c.id);
                              return (
                                <button key={c.id} onClick={() => toggleSet(setFilterCleaners)(c.id)}
                                  className={`px-2.5 py-1 rounded-full text-xs font-mono flex items-center gap-1 ${active ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-300 text-stone-600'}`}>
                                  {active && <Check size={10} />} {c.name}
                                </button>
                              );
                            })}
                          </div>
                        </div>
                      )}
                      {uniqueProps.length > 1 && (
                        <div>
                          <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1">Property</div>
                          <div className="flex gap-1.5 flex-wrap">
                            {uniqueProps.map(name => {
                              const active = filterProperties.has(name);
                              return (
                                <button key={name} onClick={() => toggleSet(setFilterProperties)(name)}
                                  className={`px-2.5 py-1 rounded-full text-xs font-mono flex items-center gap-1 ${active ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-300 text-stone-600'}`}>
                                  {active && <Check size={10} />} {name}
                                </button>
                              );
                            })}
                          </div>
                        </div>
                      )}
                      {availableCategories.length > 0 && (
                        <div>
                          <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1">Task category</div>
                          <div className="flex gap-1.5 flex-wrap">
                            {availableCategories.map(c => {
                              const active = filterCategories.has(c.id);
                              return (
                                <button key={c.id} onClick={() => toggleSet(setFilterCategories)(c.id)}
                                  className={`px-2.5 py-1 rounded-full text-xs font-mono flex items-center gap-1 ${active ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-300 text-stone-600'}`}>
                                  {active && <Check size={10} />} {c.label}
                                </button>
                              );
                            })}
                          </div>
                        </div>
                      )}
                      {activeFilterCount > 0 && (
                        <button onClick={() => { setFilterCleaners(new Set()); setFilterProperties(new Set()); setFilterCategories(new Set()); }}
                          className="text-[10px] uppercase tracking-wider font-mono text-amber-700 hover:text-amber-900">
                          Clear all filters
                        </button>
                      )}
                    </div>
                  )}
                </div>
              )}

              {/* Per-cleaner breakdown card */}
              {cleanersFiltered.length > 0 && (
                <div className="mb-6 p-4 rounded-2xl bg-stone-900 text-stone-50">
                  <div className="text-xs uppercase tracking-wider text-stone-400 font-mono mb-3 flex items-center gap-2">
                    <Users size={12} /> By cleaner
                  </div>
                  <div className="space-y-2">
                    {cleanersFiltered.map(c => {
                      // Idle handling: subtract idle from clocked-in to get an
                      // "adjusted" billable estimate. Flag excessive idle (over
                      // 15% of shift time, or more than 30 min) so the owner
                      // can review.
                      const idleMs = (c.idleSeconds || 0) * 1000;
                      const adjustedMs = Math.max(0, c.totalShiftMs - idleMs);
                      const idlePct = c.totalShiftMs > 0 ? (idleMs / c.totalShiftMs) : 0;
                      const idleHighlight = idleMs > 30 * 60 * 1000 || idlePct > 0.15;
                      return (
                        <div key={c.employeeId} className="flex items-start justify-between gap-3 py-1.5 border-b border-stone-800 last:border-0">
                          <div className="flex-1 min-w-0">
                            <div className="font-serif text-base truncate flex items-center gap-2">
                              {c.name}
                              {c.hasOpenShift && <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />}
                            </div>
                            <div className="text-[11px] font-mono text-stone-400 mt-0.5">
                              {[...c.units].slice(0, 4).join(', ')}{c.units.size > 4 && ` +${c.units.size - 4} more`}
                            </div>
                          </div>
                          <div className="text-right flex-shrink-0">
                            {/* Active work time first, then total clocked-in in parens. */}
                            <div className="font-mono text-sm">
                              {fmtTimeShort(c.totalActiveMs)}
                              <span className="text-stone-400 ml-1">({fmtTimeShort(c.totalShiftMs)})</span>
                            </div>
                            {idleHighlight && (
                              <div className="text-[10px] font-mono text-amber-300 mt-0.5 flex items-center justify-end gap-1">
                                <AlertCircle size={10} />
                                {fmtTimeShort(idleMs)} idle · adj {fmtTimeShort(adjustedMs)}
                              </div>
                            )}
                            {!idleHighlight && idleMs > 0 && (
                              <div className="text-[10px] font-mono text-stone-500 mt-0.5">
                                {fmtTimeShort(idleMs)} idle
                              </div>
                            )}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                  <div className="mt-2 pt-2 text-[10px] text-stone-500 font-mono">
                    Active = sum of work blocks. (Clocked-in) = total shift time. Adj = adjusted for idle.
                  </div>
                </div>
              )}
            </>
          );
        })()}

        {propIds.length === 0 ? (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            No cleanings on this date.
          </div>
        ) : (
          <div className="space-y-6">
            {propIds.map(propId => {
              const pg = data.groups[propId];
              const unitIds = Object.keys(pg.units);
              const sortedUnits = unitIds.map(id => pg.units[id])
                .sort((a, b) => naturalCompare(a.unitLabel, b.unitLabel));

              return (
                <div key={propId}>
                  <div className="flex items-baseline justify-between mb-3 pb-2 border-b border-stone-200">
                    <h3 className="font-serif text-xl text-stone-900 flex items-center gap-2">
                      <Building2 size={16} /> {pg.property.name}
                    </h3>
                    <span className="text-xs font-mono text-stone-500">
                      {sortedUnits.length || pg.simpleShifts.length} {(sortedUnits.length || pg.simpleShifts.length) === 1 ? 'cleaning' : 'cleanings'}
                    </span>
                  </div>

                  {/* Multi-unit: list of units */}
                  {sortedUnits.length > 0 && (
                    <div className="space-y-2">
                      {sortedUnits.map(u => (
                        <button key={u.unitId}
                          onClick={() => onOpenUnit(propId, u.unitId, u.unitLabel, pg.property.name)}
                          className={`w-full text-left p-4 rounded-2xl border transition-colors ${
                            u.hasDamage ? 'bg-red-50/50 border-red-200 hover:border-red-400' : 'bg-white border-stone-200 hover:border-stone-400'
                          }`}>
                          <div className="flex items-center justify-between">
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-2 flex-wrap mb-1">
                                <span className="font-serif text-lg text-stone-900">{u.unitLabel}</span>
                                {u.hasDamage && (
                                  <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-red-100 text-red-700">
                                    ⚠ Damage
                                  </span>
                                )}
                              </div>
                              <div className="text-xs text-stone-500 font-mono">
                                {fmtTimeShort(u.totalMs)} total · {u.employees.size} {u.employees.size === 1 ? 'cleaner' : 'cleaners'} · {u.photoCount} {u.photoCount === 1 ? 'photo' : 'photos'}
                              </div>
                              <div className="text-xs text-stone-600 mt-1">
                                {[...u.employees].join(', ')}
                              </div>
                            </div>
                            <ChevronRight size={16} className="text-stone-400 flex-shrink-0 ml-2" />
                          </div>
                        </button>
                      ))}
                    </div>
                  )}

                  {/* Simple-property shifts: just list them as-is */}
                  {pg.simpleShifts.length > 0 && (
                    <div className="space-y-2">
                      {pg.simpleShifts.map(s => {
                        const dur = (s.end_time ? new Date(s.end_time) : new Date()) - new Date(s.start_time);
                        return (
                          <div key={s.id} className="p-4 rounded-2xl bg-white border border-stone-200">
                            <div className="font-serif text-base text-stone-900">{s.employee?.name}</div>
                            <div className="text-xs text-stone-500 font-mono mt-1">
                              {fmtClock(s.start_time)}{s.end_time && ` — ${fmtClock(s.end_time)}`} · {fmtTimeShort(dur)}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );

  // Helper hoisted so we can call it inside the JSX above
  // (onOpenUnit comes in as a prop from the parent — see DailyView)
}

// Unit + day detail — full breakdown of who cleaned what at that unit on that date, with photos
// =================================================================
// BEDROOM HISTORY VIEW — Full timeline of activity at a single bedroom.
// Shows past assignments, work blocks, photos, notes grouped by date.
//
// Access scoping:
//   - Cleaners: limited to last 6 months (180 days)
//   - Owners/managers: full lifetime
//
// Reached from "View bedroom history" buttons on DailyUnitDayDetail,
// PartyList admin, and other bedroom-anchored views.
// =================================================================
// =================================================================
// DAY PHOTO TABS — Tabbed photo grid for a single day in
// BedroomHistoryView. Tabs: All / Before / After / Damage.
// "All" shows photos grouped (before → after → damage → other);
// each kind tab shows only that kind in time order.
// =================================================================
function DayPhotoTabs({ photos, isStaff }) {
  const [activeTab, setActiveTab] = useState('all');

  // Bucket photos by kind
  const byKind = { before: [], after: [], damage: [], other: [] };
  photos.forEach(p => {
    const k = p.kind === 'before' || p.kind === 'after' || p.kind === 'damage' ? p.kind : 'other';
    byKind[k].push(p);
  });
  // Sort each bucket oldest-first
  Object.keys(byKind).forEach(k => byKind[k].sort((a, b) =>
    new Date(a.created_at || 0) - new Date(b.created_at || 0)
  ));

  const TABS = [
    { id: 'all',    label: 'All',    count: photos.length },
    { id: 'before', label: 'Before', count: byKind.before.length },
    { id: 'after',  label: 'After',  count: byKind.after.length },
    { id: 'damage', label: 'Damage', count: byKind.damage.length },
  ].filter(t => t.id === 'all' || t.count > 0); // hide kinds with no photos

  // Build the visible list based on active tab
  let visible;
  if (activeTab === 'all') {
    visible = [
      ...byKind.before.map(p => ({ ...p, _kindLabel: 'Before' })),
      ...byKind.after.map(p => ({ ...p, _kindLabel: 'After' })),
      ...byKind.damage.map(p => ({ ...p, _kindLabel: 'Damage' })),
      ...byKind.other.map(p => ({ ...p, _kindLabel: p.kind || 'Other' })),
    ];
  } else {
    visible = byKind[activeTab] || [];
  }

  return (
    <div className="mb-3">
      <div className="flex items-center gap-1.5 mb-2 overflow-x-auto pb-1">
        {TABS.map(tab => {
          const isActive = activeTab === tab.id;
          const colorClass = tab.id === 'damage'
            ? (isActive ? 'bg-red-100 text-red-900 ring-1 ring-red-300' : 'text-red-700 hover:bg-red-50')
            : tab.id === 'before'
            ? (isActive ? 'bg-blue-100 text-blue-900 ring-1 ring-blue-300' : 'text-blue-700 hover:bg-blue-50')
            : tab.id === 'after'
            ? (isActive ? 'bg-emerald-100 text-emerald-900 ring-1 ring-emerald-300' : 'text-emerald-700 hover:bg-emerald-50')
            : (isActive ? 'bg-stone-900 text-stone-50' : 'text-stone-600 hover:bg-stone-100');
          return (
            <button key={tab.id} onClick={() => setActiveTab(tab.id)}
              className={`px-3 py-1.5 rounded-full text-[11px] font-mono whitespace-nowrap transition-colors ${colorClass}`}>
              {tab.label} <span className="opacity-70">({tab.count})</span>
            </button>
          );
        })}
      </div>
      <div className="grid grid-cols-4 gap-1.5">
        {visible.map((p, i) => {
          // Section header within "All": insert a kind separator before the first photo of each group
          const prev = i > 0 ? visible[i - 1] : null;
          const showSeparator = activeTab === 'all' && (!prev || prev._kindLabel !== p._kindLabel);
          return (
            <React.Fragment key={p.id}>
              {showSeparator && (
                <div className="col-span-4 text-[9px] uppercase tracking-wider font-mono text-stone-500 mt-1 pt-1 border-t border-stone-100 first:border-t-0 first:mt-0 first:pt-0">
                  {p._kindLabel}
                </div>
              )}
              <a href={p.public_url} target="_blank" rel="noreferrer"
                className="relative aspect-square rounded-lg overflow-hidden bg-stone-200 active:opacity-80">
                <img src={p.public_url} alt="" loading="lazy" className="w-full h-full object-cover" />
                {p.kind && activeTab === 'all' && (
                  <div className={`absolute top-1 left-1 px-1 py-0.5 rounded text-white text-[8px] uppercase tracking-wider ${
                    p.kind === 'damage' ? 'bg-red-700/85' :
                    p.kind === 'before' ? 'bg-blue-700/85' :
                    p.kind === 'after' ? 'bg-emerald-700/85' :
                    'bg-black/70'
                  }`}>
                    {p.kind}
                  </div>
                )}
                {isStaff && p.cleanerName && (
                  <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-black/80 to-transparent p-1">
                    <div className="text-[8px] text-white font-mono leading-tight truncate">{p.cleanerName}</div>
                  </div>
                )}
              </a>
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
}

function BedroomHistoryView({ propertyId, propertyName, unitId, unitLabel, partyId, partyLabel, employee, onBack }) {
  const isStaff = employee?.role === 'owner' || employee?.role === 'manager';
  const [data, setData] = useState({ days: [], loading: true });
  const [openedAssignment, setOpenedAssignment] = useState(null);
  // Pull a wide window in one query so the date pills can show
  // which days have work. The user picks ONE day to focus on
  // (default: today). Cleaners are capped at 180 days.
  const WINDOW_DAYS = isStaff ? 365 : 180;
  // selectedDay = null → "all days in window"
  //            = 'today' → today only
  //            = 'YYYY-MM-DD' → that specific date
  const todayKey = (() => {
    const d = new Date(); d.setHours(0, 0, 0, 0);
    return d.toISOString().slice(0, 10);
  })();
  const [selectedDay, setSelectedDay] = useState('today');

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setData(d => ({ ...d, loading: true }));
      // Load the full window in one go. The "selected day" is a
      // display filter only; we want the pill row to show every day
      // that has activity so the cleaner can browse between them.
      const since = new Date();
      since.setDate(since.getDate() - WINDOW_DAYS);
      since.setHours(0, 0, 0, 0);
      const sinceISO = since.toISOString();

      // Fetch work blocks at this bedroom in the window. We pull the
      // shift owner (the cleaner who started the block) PLUS the
      // multi-cleaner participants table so a shared block lists every
      // helper, not just whoever opened it first.
      //
      // Photos include both active AND soft-deleted ones so the
      // history can surface deletion audit. We resolve names for both
      // the taker AND deleter via two FK aliases.
      let blocksQ = supabase.from('work_blocks')
        .select(`
          *, shift:shifts!inner(id, customer_id, employee:employees(id, name)),
          tasks(*, photos(*, taken_by_employee:employees!taken_by(name), deleted_by_employee:employees!deleted_by(name))),
          participants:work_block_participants(id, joined_at, left_at, employee:employees(id, name))
        `)
        .eq('unit_id', unitId)
        .eq('party_id', partyId)
        .order('start_time', { ascending: false });
      if (sinceISO) blocksQ = blocksQ.gte('start_time', sinceISO);
      const { data: blocksRaw } = await blocksQ;
      const blocks = (blocksRaw || []).filter(b => b.shift?.customer_id === propertyId);

      // Fetch assignment_targets at this bedroom (and property-wide) in the window
      let targetsQ = supabase.from('assignment_targets')
        .select('*, assignment:assignments!inner(id, title, notes, file_url, file_kind, customer_id, active, source, pm_status, deleted_at, assignment_type, scheduled_date, created_at)')
        .or(`and(unit_id.eq.${unitId},party_id.eq.${partyId}),and(unit_id.is.null,party_id.is.null)`)
        .order('created_at', { ascending: false });
      const { data: targetsRaw } = await targetsQ;
      const targets = (targetsRaw || []).filter(t =>
        t.assignment?.customer_id === propertyId &&
        t.assignment?.active &&
      !t.assignment?.deleted_at &&
        (t.assignment?.source !== 'pm' || t.assignment?.pm_status === 'approved')
      ).filter(t => {
        if (!sinceISO) return true;
        const dateStr = t.assignment?.scheduled_date || t.assignment?.created_at;
        return !dateStr || dateStr >= sinceISO.slice(0, 10);
      });

      if (cancelled) return;

      // Group by local date key (YYYY-MM-DD)
      const dayMap = new Map();
      const ensureDay = (key) => {
        if (!dayMap.has(key)) {
          dayMap.set(key, { key, blocks: [], targets: [], photos: [], totalMs: 0 });
        }
        return dayMap.get(key);
      };

      blocks.forEach(b => {
        const d = new Date(b.start_time);
        const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
        const day = ensureDay(key);
        day.blocks.push(b);
        const dur = (b.end_time ? new Date(b.end_time) : new Date()) - new Date(b.start_time);
        day.totalMs += dur;
        // Flatten photos — split active vs deleted. Active photos go
        // into the visible strip; deleted ones go into a separate
        // audit list rendered for owners/managers only. Photo taker
        // preferred from join, falls back to shift owner for legacy.
        (b.tasks || []).forEach(t => {
          (t.photos || []).forEach(p => {
            const takerName = p.taken_by_employee?.name || b.shift?.employee?.name || 'Cleaner';
            if (p.deleted_at) {
              day.deletedPhotos = day.deletedPhotos || [];
              day.deletedPhotos.push({
                ...p,
                taskName: t.name,
                cleanerName: takerName,
                deletedByName: p.deleted_by_employee?.name || 'someone',
              });
            } else {
              day.photos.push({ ...p, taskName: t.name, cleanerName: takerName });
            }
          });
        });
      });

      targets.forEach(t => {
        const dateStr = t.assignment?.scheduled_date || t.assignment?.created_at?.slice(0, 10);
        if (!dateStr) return;
        const day = ensureDay(dateStr);
        day.targets.push(t);
      });

      const days = Array.from(dayMap.values()).sort((a, b) => b.key.localeCompare(a.key));
      setData({ days, loading: false });
    })();
    return () => { cancelled = true; };
  }, [propertyId, unitId, partyId, WINDOW_DAYS, isStaff]);

  return (
    <div className="fixed inset-0 z-40 bg-stone-50 overflow-y-auto">
      <div className="pb-24 min-h-screen">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200 bg-white sticky top-0 z-10">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div className="flex-1 min-w-0">
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono truncate">{propertyName}</div>
          <h1 className="font-serif text-2xl text-stone-900 truncate">
            {unitLabel}{partyLabel && <span className="italic text-amber-700"> · {partyLabel}</span>}
          </h1>
          <div className="text-xs text-stone-500 mt-0.5">Bedroom history</div>
        </div>
      </div>

      <div className="px-5 pt-4">
        {(() => {
          // Build a pill set: Today + every day that has activity
          // (work blocks OR targets) within the window. Days are
          // sorted newest-first. The first pill is always "Today"
          // (highlighted as default). If today itself has activity
          // it's not duplicated.
          const dayKeys = data.days.map(d => d.key);
          const set = new Set(dayKeys);
          set.add(todayKey);
          const allKeys = Array.from(set).sort((a, b) => b.localeCompare(a));
          // Render
          return (
            <div className="flex gap-1.5 mb-4 overflow-x-auto pb-1">
              <button onClick={() => setSelectedDay(null)}
                className={`px-3 py-1.5 rounded-full text-xs font-mono whitespace-nowrap ${
                  selectedDay === null
                    ? 'bg-stone-900 text-stone-50'
                    : 'bg-white border border-stone-200 text-stone-600 hover:border-stone-400'
                }`}>
                All ({data.days.length})
              </button>
              {allKeys.map(dk => {
                const isToday = dk === todayKey;
                const hasActivity = dayKeys.includes(dk);
                const dayData = data.days.find(d => d.key === dk);
                const count = dayData ? (dayData.blocks.length + dayData.targets.length) : 0;
                const active = (selectedDay === 'today' && isToday) || selectedDay === dk;
                const label = isToday ? 'Today' : (() => {
                  const d = new Date(dk + 'T12:00:00');
                  const yesterday = new Date(); yesterday.setDate(yesterday.getDate() - 1); yesterday.setHours(0, 0, 0, 0);
                  const yKey = yesterday.toISOString().slice(0, 10);
                  if (dk === yKey) return 'Yesterday';
                  return d.toLocaleDateString([], { month: 'short', day: 'numeric' });
                })();
                return (
                  <button key={dk} onClick={() => setSelectedDay(isToday ? 'today' : dk)}
                    className={`px-3 py-1.5 rounded-full text-xs font-mono whitespace-nowrap flex items-center gap-1 ${
                      active ? 'bg-stone-900 text-stone-50'
                        : hasActivity ? 'bg-white border border-stone-200 text-stone-700 hover:border-stone-400'
                        : 'bg-stone-50 border border-stone-200 text-stone-400'
                    }`}>
                    <span>{label}</span>
                    {count > 0 && (
                      <span className={`text-[9px] px-1.5 py-0.5 rounded-full ${active ? 'bg-stone-700 text-stone-50' : 'bg-stone-200 text-stone-600'}`}>
                        {count}
                      </span>
                    )}
                  </button>
                );
              })}
              {/* Pick a specific date — opens native picker. */}
              <label className="px-3 py-1.5 rounded-full text-xs font-mono whitespace-nowrap bg-white border border-stone-200 text-stone-600 flex items-center gap-1 cursor-pointer hover:bg-stone-50">
                <Calendar size={11} />
                <span>Pick date</span>
                <input type="date"
                  max={todayKey}
                  onChange={(e) => { if (e.target.value) setSelectedDay(e.target.value); e.target.value = ''; }}
                  className="sr-only" />
              </label>
            </div>
          );
        })()}
        {!isStaff && (
          <div className="text-[11px] text-stone-500 italic mb-3">
            Cleaners can view up to 6 months of history.
          </div>
        )}

        {data.loading ? (
          <div className="text-center py-12 text-stone-400 text-sm">Loading history…</div>
        ) : (() => {
          // Filter days to the picked one (or show all)
          const days = selectedDay === null ? data.days
            : selectedDay === 'today'
              ? data.days.filter(d => d.key === todayKey)
              : data.days.filter(d => d.key === selectedDay);
          if (days.length === 0) {
            const dayLabel = selectedDay === 'today' ? 'today' :
              selectedDay ? new Date(selectedDay + 'T12:00:00').toLocaleDateString([], { month: 'long', day: 'numeric' }) :
              'this window';
            return (
              <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
                No activity for this bedroom on {dayLabel}.
              </div>
            );
          }
          return (
            <div className="space-y-6">
              {days.map(day => (
              <div key={day.key}>
                <div className="sticky top-0 bg-stone-50 py-2 z-10 border-b border-stone-200 mb-3">
                  <div className="font-serif text-lg text-stone-900">
                    {fmtDateWithDay(day.key + 'T12:00:00')}
                  </div>
                  <div className="text-[11px] text-stone-500 font-mono">
                    {day.blocks.length > 0 && `${day.blocks.length} work block${day.blocks.length === 1 ? '' : 's'}`}
                    {day.targets.length > 0 && ` · ${day.targets.length} assignment${day.targets.length === 1 ? '' : 's'}`}
                    {day.totalMs > 0 && ` · ${fmtTimeShort(day.totalMs)} total`}
                  </div>
                </div>

                {day.targets.length > 0 && (
                  <div className="mb-3 space-y-2">
                    {day.targets.map(t => {
                      const a = t.assignment;
                      return (
                        <div key={t.id} className="p-3 rounded-xl bg-amber-50 border border-amber-200">
                          <div className="flex items-start justify-between gap-2">
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-1.5 mb-1 flex-wrap">
                                <span className="text-[10px] uppercase tracking-wider font-mono text-amber-900">Assignment</span>
                                {a.assignment_type && (
                                  <span className="text-[10px] font-mono px-1.5 py-0.5 rounded-full bg-amber-200 text-amber-900">
                                    {assignmentTypeLabel(a.assignment_type)}
                                  </span>
                                )}
                                <span className="text-[10px] font-mono text-stone-500">{t.status}</span>
                              </div>
                              <div className="text-sm font-medium text-stone-900 truncate">{a.title}</div>
                              {a.notes && <div className="text-xs text-stone-600 mt-1 line-clamp-2">{a.notes}</div>}
                            </div>
                            {a.file_url && (
                              <button onClick={() => setOpenedAssignment(t)}
                                className="px-3 py-1.5 rounded-full bg-stone-900 hover:bg-stone-700 text-stone-50 text-xs font-mono flex items-center gap-1 flex-shrink-0 active:scale-95">
                                {a.file_kind === 'pdf' ? <FileText size={11} /> : <ImageIcon size={11} />}
                                View
                              </button>
                            )}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}

                {day.blocks.length > 0 && (
                  <div className="space-y-3 mb-3">
                    {day.blocks.map(b => {
                      const dur = (b.end_time ? new Date(b.end_time) : new Date()) - new Date(b.start_time);
                      // Build the list of cleaners on this block:
                      // start with the shift owner, then merge in
                      // every participant (deduped by id). Single-
                      // cleaner blocks render as before.
                      const cleanerSet = new Map();
                      if (b.shift?.employee?.id) cleanerSet.set(b.shift.employee.id, b.shift.employee.name || 'Cleaner');
                      (b.participants || []).forEach(p => {
                        if (p.employee?.id && !cleanerSet.has(p.employee.id)) {
                          cleanerSet.set(p.employee.id, p.employee.name || 'Cleaner');
                        }
                      });
                      const cleaners = Array.from(cleanerSet.values());
                      const cleaner = cleaners.length === 0 ? 'Cleaner'
                        : cleaners.length === 1 ? cleaners[0]
                        : cleaners.join(' + ');
                      const isMultiCleaner = cleaners.length > 1;
                      return (
                        <div key={b.id} className="p-3 rounded-xl bg-white border border-stone-200">
                          <div className="flex items-start justify-between gap-2 mb-2 flex-wrap">
                            <div className="flex items-center gap-2 min-w-0">
                              {isMultiCleaner
                                ? <Users size={13} className="text-amber-600 flex-shrink-0" />
                                : <User size={13} className="text-stone-400 flex-shrink-0" />}
                              <span className={`font-medium text-sm truncate ${isMultiCleaner ? 'text-amber-900' : 'text-stone-900'}`}>{cleaner}</span>
                              {isMultiCleaner && (
                                <span className="text-[9px] uppercase tracking-wider font-mono px-1.5 py-0.5 rounded-full bg-amber-100 text-amber-800 border border-amber-300 font-bold">
                                  Team
                                </span>
                              )}
                            </div>
                            <div className="text-xs font-mono text-stone-500">
                              {fmtClock(b.start_time)}{b.end_time && ` — ${fmtClock(b.end_time)}`} · {fmtTimeShort(dur)}
                            </div>
                          </div>
                          {b.work_notes && (
                            <div className="text-xs text-stone-600 italic pl-5 mb-2">
                              "<TranslatableText text={b.work_notes} targetLang="en" />"
                            </div>
                          )}
                          {b.tasks?.length > 0 && (
                            <div className="pl-5 space-y-1.5">
                              {b.tasks.map(t => (
                                <div key={t.id} className="text-xs text-stone-700 flex items-start gap-1.5">
                                  {t.end_time ? <Check size={11} className="text-emerald-600 mt-0.5 flex-shrink-0" /> : <span className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse mt-1 flex-shrink-0" />}
                                  <span className="flex-1"><TranslatableText text={t.name} targetLang="en" /></span>
                                  {t.photos?.length > 0 && (
                                    <span className="text-[10px] font-mono text-stone-400">{t.photos.length} 📷</span>
                                  )}
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}

                {day.photos.length > 0 && (
                  <DayPhotoTabs photos={day.photos} isStaff={isStaff} />
                )}
                {/* Deleted photos audit — visible to owner/manager only.
                   Shows who deleted what and when so accountability is
                   preserved even after the photo is hidden from view. */}
                {isStaff && day.deletedPhotos && day.deletedPhotos.length > 0 && (
                  <div className="mt-3 p-3 rounded-xl bg-stone-100 border border-stone-200">
                    <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-2 flex items-center gap-1.5">
                      <Trash2 size={10} /> Deleted photos ({day.deletedPhotos.length})
                    </div>
                    <div className="space-y-1">
                      {day.deletedPhotos.map(p => (
                        <div key={p.id} className="text-[11px] font-mono text-stone-600 flex items-baseline gap-2">
                          <span className="text-stone-400">·</span>
                          <span>
                            <span className="text-stone-900">{p.deletedByName}</span>
                            <span className="text-stone-500"> deleted </span>
                            <span className="text-stone-700">{p.kind || 'a photo'}</span>
                            <span className="text-stone-500"> by </span>
                            <span className="text-stone-900">{p.cleanerName}</span>
                          </span>
                          <span className="text-stone-400 flex-shrink-0">
                            {p.deleted_at && fmtClock(p.deleted_at)}
                          </span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
          );
        })()}
      </div>

      {openedAssignment && (
        <AssignmentViewer target={openedAssignment} employee={employee} onClose={() => setOpenedAssignment(null)} />
      )}
      </div>
    </div>
  );
}

function DailyUnitDayDetail({ date, propertyId, unitId, unitLabel, propertyName, employee, showMoney, onBack, onOpenBedroomHistory }) {
  const canEdit = employee?.role === 'owner' || employee?.role === 'manager';
  const [blocks, setBlocks] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [editingBlock, setEditingBlock] = useState(null);
  const [deletingBlock, setDeletingBlock] = useState(null);
  const [deletingShift, setDeletingShift] = useState(null); // shift obj
  const [busy, setBusy] = useState(false);

  const reload = async () => {
    setLoaded(false);
    const dayStart = `${date}T00:00:00`;
    const dayEnd   = `${date}T23:59:59`;
    const { data } = await supabase
      .from('work_blocks')
      .select('*, party:parties(label, full_name), shift:shifts!inner(id, customer_id, start_time, end_time, employee:employees(id,name), bill_rate_at_work, customer:customers(bill_rate_hourly, name)), tasks(*, photos(*, taken_by_employee:employees!taken_by(name)))')
      .eq('unit_id', unitId)
      .gte('start_time', dayStart)
      .lte('start_time', dayEnd)
      .order('start_time');
    const filtered = (data || []).filter(b => b.shift?.customer_id === propertyId);
    setBlocks(filtered);
    setLoaded(true);
  };

  useEffect(() => { reload(); /* eslint-disable-next-line */ }, [date, unitId, propertyId]);

  const saveBlockTimes = async (block, startISO, endISO) => {
    setBusy(true);
    const { error } = await supabase.from('work_blocks')
      .update({ start_time: startISO, end_time: endISO || null })
      .eq('id', block.id);
    setBusy(false);
    if (error) { alert('Could not save: ' + error.message); return; }
    setEditingBlock(null);
    reload();
  };

  const deleteBlock = async (block) => {
    setBusy(true);
    const { error } = await supabase.from('work_blocks').delete().eq('id', block.id);
    setBusy(false);
    if (error) { alert('Could not delete: ' + error.message); return; }
    setDeletingBlock(null);
    reload();
  };

  const deleteShift = async (shift) => {
    setBusy(true);
    const { error } = await supabase.from('shifts').delete().eq('id', shift.id);
    setBusy(false);
    if (error) { alert('Could not delete: ' + error.message); return; }
    setDeletingShift(null);
    reload();
  };

  if (!loaded) return <Splash text="Loading…" />;

  // Aggregate stats
  const employeeTimes = {}; // name -> totalMs
  let totalMs = 0;
  let totalBillable = 0;
  const allTasks = [];
  blocks.forEach(b => {
    const dur = (b.end_time ? new Date(b.end_time) : new Date()) - new Date(b.start_time);
    totalMs += dur;
    const empName = b.shift?.employee?.name || '?';
    employeeTimes[empName] = (employeeTimes[empName] || 0) + dur;
    if (showMoney && b.end_time) {
      const rate = b.bill_rate_at_work || b.shift?.customer?.bill_rate_hourly || 0;
      totalBillable += (dur / 1000 / 3600) * rate;
    }
    (b.tasks || []).forEach(t => allTasks.push({ ...t, employee: empName, party: b.party }));
  });

  // Group tasks by party for display
  const partyGroups = {};
  blocks.forEach(b => {
    const partyKey = b.party?.id || 'no-party';
    if (!partyGroups[partyKey]) {
      partyGroups[partyKey] = { party: b.party, blocks: [] };
    }
    partyGroups[partyKey].blocks.push(b);
  });

  const dateObj = new Date(date + 'T12:00:00');

  return (
    <div className="pb-24">
      <style>{`
        @media print {
          body { background: white !important; }
          .no-print { display: none !important; }
        }
      `}</style>

      <div className="no-print bg-stone-900 text-stone-50 px-5 py-4 flex items-center justify-between">
        <button onClick={onBack} className="flex items-center gap-2 text-stone-400 text-sm hover:text-stone-50">
          <ArrowLeft size={16} /> Back
        </button>
        <button onClick={() => window.print()}
          className="px-4 py-2 rounded-full bg-stone-50 text-stone-900 text-sm font-medium flex items-center gap-2">
          <Printer size={14} /> Print
        </button>
      </div>

      <div className="px-5 pt-6">
        <div className="text-xs uppercase tracking-widest text-stone-400 font-mono mb-2">
          {dateObj.toLocaleDateString('en-US', { weekday:'long', month:'long', day:'numeric', year:'numeric' })}
        </div>
        <h1 className="font-serif text-3xl text-stone-900 mb-1">{unitLabel}</h1>
        <div className="text-sm text-stone-600 flex items-center gap-1.5">
          <Building2 size={13} /> {propertyName}
        </div>

        {/* Stats summary */}
        <div className={`grid ${showMoney ? 'grid-cols-3' : 'grid-cols-2'} gap-3 mt-6 mb-6`}>
          <div className="p-4 rounded-2xl bg-white border border-stone-200">
            <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-1">Total time</div>
            <div className="text-2xl font-serif">{fmtTimeShort(totalMs)}</div>
          </div>
          <div className="p-4 rounded-2xl bg-white border border-stone-200">
            <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-1">Cleaners</div>
            <div className="text-2xl font-serif">{Object.keys(employeeTimes).length}</div>
          </div>
          {showMoney && (
            <div className="p-4 rounded-2xl bg-amber-50 border border-amber-200">
              <div className="text-xs uppercase tracking-wider font-mono text-amber-700 mb-1">Billable</div>
              <div className="text-2xl font-serif text-amber-900">{fmtMoney(totalBillable)}</div>
            </div>
          )}
        </div>

        {/* Per-employee summary */}
        <div className="mb-6">
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-3">Time by cleaner</div>
          <div className="space-y-2">
            {Object.entries(employeeTimes)
              .sort((a, b) => b[1] - a[1])
              .map(([name, ms]) => (
                <div key={name} className="flex items-center justify-between p-3 bg-white border border-stone-200 rounded-xl">
                  <div className="flex items-center gap-2">
                    <User size={14} className="text-stone-400" />
                    <span className="text-stone-900">{name}</span>
                  </div>
                  <span className="font-mono text-sm text-stone-700">{fmtTimeShort(ms)}</span>
                </div>
              ))}
          </div>
        </div>

        {/* Per-party detail */}
        <div className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-3">Cleaning details</div>
        {blocks.length === 0 ? (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            No work blocks recorded.
          </div>
        ) : (
          <div className="space-y-4">
            {Object.values(partyGroups).map((pg, i) => {
              // Use the first block in this party group to anchor the date-aware assignment query
              const sampleBlock = pg.blocks[0];
              return (
              <div key={i} className="p-4 rounded-2xl bg-white border border-stone-200">
                {pg.party && (
                  <div className="mb-3">
                    <div className="font-serif text-lg text-stone-900 flex items-center gap-2 flex-wrap">
                      {pg.party.label}
                      {pg.party.full_name && <span className="text-sm text-stone-500">{pg.party.full_name}</span>}
                    </div>
                    <div className="mt-2 flex items-center gap-2 flex-wrap">
                      <WorkBlockAssignmentLink block={sampleBlock} propertyId={propertyId} employee={employee} compact />
                      <button onClick={() => onOpenBedroomHistory && onOpenBedroomHistory({
                          propertyId, propertyName, unitId, unitLabel,
                          partyId: pg.party.id, partyLabel: pg.party.label
                        })}
                        className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 text-[11px] font-mono active:scale-95">
                        <Clock size={10} /> View bedroom history
                      </button>
                    </div>
                  </div>
                )}
                <div className="space-y-3">
                  {pg.blocks.map(b => {
                    const dur = (b.end_time ? new Date(b.end_time) : new Date()) - new Date(b.start_time);
                    const billable = showMoney && b.end_time
                      ? (dur / 1000 / 3600) * (b.bill_rate_at_work || b.shift?.customer?.bill_rate_hourly || 0)
                      : 0;
                    return (
                      <div key={b.id} className="pb-3 border-b border-stone-100 last:border-b-0 last:pb-0">
                        <div className="flex items-start justify-between mb-2 flex-wrap gap-2">
                          <div className="flex items-center gap-2">
                            <User size={13} className="text-stone-400" />
                            <span className="font-medium text-stone-900 text-sm">{b.shift?.employee?.name}</span>
                          </div>
                          <div className="text-xs font-mono text-stone-500">
                            {fmtClock(b.start_time)}{b.end_time && ` — ${fmtClock(b.end_time)}`} · {fmtTimeShort(dur)}
                            {showMoney && billable > 0 && <span className="text-emerald-700 ml-2">{fmtMoney(billable)}</span>}
                          </div>
                        </div>
                        {b.work_notes && (
                          <div className="text-xs text-stone-600 italic mb-2 pl-5">
                            "<TranslatableText text={b.work_notes} targetLang="en" />"
                          </div>
                        )}
                        {b.tasks?.length > 0 && (
                          <div className="pl-5 space-y-2">
                            {b.tasks.map(t => <TaskDetail key={t.id} task={t} compact employee={employee} />)}
                          </div>
                        )}
                        {/* Per-block edit/delete actions */}
                        {canEdit && (
                          <div className="mt-3 pl-5 flex gap-2 no-print">
                            <button onClick={() => setEditingBlock(b)}
                              className="px-3 py-1.5 rounded-lg bg-stone-50 hover:bg-stone-100 text-stone-700 text-xs font-medium flex items-center gap-1.5">
                              <Edit2 size={11} /> Edit times
                            </button>
                            <button onClick={() => setDeletingBlock(b)}
                              className="px-3 py-1.5 rounded-lg border border-red-200 text-red-700 text-xs font-medium flex items-center gap-1.5 hover:bg-red-50">
                              <Trash2 size={11} /> Delete block
                            </button>
                            <button onClick={() => setDeletingShift(b.shift)}
                              className="px-3 py-1.5 rounded-lg border border-red-200 text-red-700 text-xs font-medium flex items-center gap-1.5 hover:bg-red-50 ml-auto">
                              <Trash2 size={11} /> Delete this shift
                            </button>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Modals (reused from ShiftDetail) */}
      {editingBlock && (
        <TimeEditModal
          title="Edit work block times"
          subtitle={`${unitLabel} · ${editingBlock.party?.label || ''}`}
          startTime={editingBlock.start_time}
          endTime={editingBlock.end_time}
          busy={busy}
          onSave={(s, e) => saveBlockTimes(editingBlock, s, e)}
          onClose={() => setEditingBlock(null)} />
      )}
      {deletingBlock && (
        <DeleteConfirmModal
          title="Delete this work block?"
          description="This removes the work block and all its tasks and photos, but keeps the rest of the shift intact."
          itemSummary={`${unitLabel} · ${deletingBlock.party?.label || ''} · ${deletingBlock.shift?.employee?.name || ''}`}
          busy={busy}
          onConfirm={() => deleteBlock(deletingBlock)}
          onClose={() => setDeletingBlock(null)} />
      )}
      {deletingShift && (
        <DeleteConfirmModal
          title="Delete this entire shift?"
          description="This permanently deletes the whole shift for this cleaner, including ALL work blocks (other apartments too, not just this one), tasks, and photos. This cannot be undone."
          itemSummary={`${deletingShift.employee?.name} · ${fmtDate(deletingShift.start_time)} · ${deletingShift.customer?.name || ''}`}
          busy={busy}
          onConfirm={() => deleteShift(deletingShift)}
          onClose={() => setDeletingShift(null)} />
      )}
    </div>
  );
}

// =================================================================
// ASSIGNMENT LIST — owner/manager view of all assignments for a property
// =================================================================
function AssignmentList({ property, employee, onBack, onNew, onNewChecklist, onNewQuick, onOpen }) {
  const [assignments, setAssignments] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [filter, setFilter] = useState('open'); // open | all
  const [search, setSearch] = useState('');
  // Which building groups are collapsed (default expanded)
  const [collapsedBuildings, setCollapsedBuildings] = useState({});
  // Which floor groups inside a building are collapsed (default expanded).
  // Keyed by `${buildingKey}::${floorKey}` so two buildings can both
  // have a Floor 1 without colliding.
  const [collapsedFloors, setCollapsedFloors] = useState({});
  // Bulk-delete selection set — only available to users with the
  // archive_assignments permission. Tracks assignment IDs the user
  // has ticked for deletion. The mode flag turns the checkboxes
  // on/off so the layout doesn't grow checkboxes for everyone.
  const [bulkMode, setBulkMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState(new Set());
  // Which apartment dropdowns are open inside a building
  const [openApartments, setOpenApartments] = useState({}); // { 'B1-101': true }
  // Filters — priority and cleaning type. Expandable panel keeps the
  // controls compact when not in use.
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [priorityOnly, setPriorityOnly] = useState(false);
  const [filterTypes, setFilterTypes] = useState(new Set()); // assignment_type values
  // Track which row is currently saving a priority toggle so we can
  // disable the button + show a busy state.
  const [togglingId, setTogglingId] = useState(null);
  // Inline due-date editing (owners / granted users).
  const [editDateId, setEditDateId] = useState(null);
  const canEditDates = can(employee, 'edit_due_dates');
  const saveDue = async (id, date) => {
    setEditDateId(null);
    await supabase.from('assignments').update({ scheduled_date: date || null }).eq('id', id);
    load();
  };

  const load = async () => {
    // Pull targets so we can group by unit and surface priority/type
    const { data } = await supabase
      .from('assignments')
      .select('*, targets:assignment_targets(id, status, priority, unit_id, party_id, unit:units(label), party:parties(label))')
      .eq('customer_id', property.id)
      .is('deleted_at', null)
      .order('created_at', { ascending: false });
    setAssignments(data || []); setLoaded(true);
  };
  useEffect(() => { load(); }, [property.id]);
  useAssignmentSync(load, 'asgn-list');

  // Flip priority on the WHOLE assignment (all its targets). If any
  // target is currently priority, sweep them all off; otherwise sweep
  // them all on. Saves a click compared to opening the detail page.
  const togglePriority = async (assignment) => {
    if (togglingId) return; // already busy with another
    const targetIds = (assignment.targets || []).map(t => t.id);
    if (targetIds.length === 0) return;
    const newPriority = !assignment.hasPriority;
    setTogglingId(assignment.id);
    // Optimistic update so the chip flips instantly
    setAssignments(prev => prev.map(a => a.id === assignment.id ? {
      ...a,
      targets: (a.targets || []).map(t => ({ ...t, priority: newPriority }))
    } : a));
    const { error } = await supabase.from('assignment_targets')
      .update({ priority: newPriority }).in('id', targetIds);
    setTogglingId(null);
    if (error) {
      alert('Could not update priority: ' + error.message);
      load(); // re-fetch authoritative state
    }
  };

  // Aggregate status + flags per assignment
  const decorated = (assignments || []).map(a => {
    const targets = a.targets || [];
    const total = targets.length;
    // Blocked counts toward "done" for the X/N done display — the
    // cleaner can't do those items, so from a workload standpoint
    // they're closed. The Blocked pill still appears below so the
    // owner sees at a glance which need follow-up.
    const done = targets.filter(t => t.status === 'done' || t.status === 'blocked').length;
    const trulyDone = targets.filter(t => t.status === 'done').length;
    const inProgress = targets.filter(t => t.status === 'in_progress').length;
    const blocked = targets.filter(t => t.status === 'blocked').length;
    const allDone = total > 0 && done === total;
    const hasPriority = targets.some(t => t.priority);
    // Primary unit label: most targets share one unit, take the first non-null
    const firstUnitLabel = targets.find(t => t.unit?.label)?.unit?.label || '';
    return {
      ...a, total, done, trulyDone, inProgress, blocked, allDone,
      hasPriority,
      firstUnitLabel,
    };
  });

  // Search across title, notes, unit label, bedroom label
  const q = search.trim().toLowerCase();
  const matchesSearch = (a) => {
    if (!q) return true;
    if ((a.title || '').toLowerCase().includes(q)) return true;
    if ((a.notes || '').toLowerCase().includes(q)) return true;
    if ((a.firstUnitLabel || '').toLowerCase().includes(q)) return true;
    const bedroom = (a.targets || []).some(t => (t.party?.label || '').toLowerCase().includes(q));
    if (bedroom) return true;
    return false;
  };

  // Buckets distinguishing what cleaners can see vs what's still
  // waiting on the owner. The "Open" filter mirrors the cleaner-side
  // visibility filter so the counts match (no more "owner sees 100
  // open but cleaner only sees 52"). PM-pending stays surfaced via
  // the awaitingApproval counter so the user knows what's stuck.
  const isCleanerVisible = (a) =>
    !a.allDone && a.active && (a.source !== 'pm' || a.pm_status === 'approved');
  const isAwaitingApproval = (a) =>
    a.active && a.source === 'pm' && a.pm_status === 'pending';
  const awaitingApproval = decorated.filter(isAwaitingApproval);

  const visible = decorated
    .filter(a => filter === 'open' ? isCleanerVisible(a) : true)
    .filter(a => !priorityOnly || (a.hasPriority && !a.allDone))
    .filter(a => filterTypes.size === 0 || filterTypes.has(a.assignment_type))
    .filter(matchesSearch);

  // Available cleaning types for the type filter chips — derived from
  // the current assignments so we don't offer types that don't exist.
  const availableTypes = (() => {
    const set = new Set();
    decorated.forEach(a => { if (a.assignment_type) set.add(a.assignment_type); });
    return [...set];
  })();

  const activeFilterCount = (priorityOnly ? 1 : 0) + filterTypes.size;
  const toggleType = (typ) => setFilterTypes(prev => {
    const next = new Set(prev);
    if (next.has(typ)) next.delete(typ); else next.add(typ);
    return next;
  });
  const clearFilters = () => { setPriorityOnly(false); setFilterTypes(new Set()); };

  // Group by building. Property-level (no unit) goes into "Whole property".
  // Within each building, sub-group by unit label so when one unit has
  // multiple assignments we can show a collapsible dropdown.
  const buildings = {}; // { buildingKey: { units: { unitLabel: [assignments] } } }
  visible.forEach(a => {
    const buildingKey = a.firstUnitLabel
      ? (buildingFromLabel(a.firstUnitLabel) || a.firstUnitLabel)
      : 'Whole property';
    const unitKey = a.firstUnitLabel || 'Whole property';
    if (!buildings[buildingKey]) buildings[buildingKey] = {};
    if (!buildings[buildingKey][unitKey]) buildings[buildingKey][unitKey] = [];
    buildings[buildingKey][unitKey].push(a);
  });
  const buildingKeys = Object.keys(buildings).sort((a, b) => {
    if (a === 'Whole property') return -1;
    if (b === 'Whole property') return 1;
    return naturalCompare(a, b);
  });

  const toggleBuilding = (b) => setCollapsedBuildings(prev => ({ ...prev, [b]: !prev[b] }));
  const toggleApartment = (key) => setOpenApartments(prev => ({ ...prev, [key]: !prev[key] }));

  // Render a single assignment row (used inside apartment groups). Pulled
  // into a helper so the apartment-dropdown and single-card paths share
  // identical visual treatment.
  // NOTE: we use a div+onClick (not <button>) so the priority toggle
  // can be a nested <button> without HTML-invalid nested-interactive
  // elements. Keyboard a11y maintained via tabIndex + onKeyDown.
  const renderAssignmentRow = (a) => {
    const isToggling = togglingId === a.id;
    const isSelected = selectedIds.has(a.id);
    const handleRowClick = () => {
      // In bulk mode the row tap toggles selection; otherwise it
      // opens the detail view as it did before.
      if (bulkMode) {
        setSelectedIds(prev => {
          const next = new Set(prev);
          if (next.has(a.id)) next.delete(a.id);
          else next.add(a.id);
          return next;
        });
      } else {
        onOpen(a);
      }
    };
    return (
      <div key={a.id} onClick={handleRowClick}
        tabIndex={0}
        onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); handleRowClick(); } }}
        role="button"
        className={`w-full text-left p-3 rounded-xl border cursor-pointer ${
          bulkMode && isSelected ? 'bg-amber-50 border-amber-400 ring-2 ring-amber-300' :
          a.allDone ? 'bg-stone-100 border-stone-200 opacity-70' :
          a.blocked > 0 ? 'bg-red-50/50 border-red-200' :
          'bg-white border-stone-200'} hover:border-stone-400 transition-colors`}>
        <div className="flex items-start justify-between gap-2">
          {/* Checkbox cell (bulk mode only) */}
          {bulkMode && (
            <div className={`mt-0.5 w-5 h-5 rounded border-2 flex-shrink-0 flex items-center justify-center ${isSelected ? 'border-amber-600 bg-amber-600' : 'border-stone-300 bg-white'}`}>
              {isSelected && <Check size={12} className="text-white" />}
            </div>
          )}
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-1 flex-wrap">
              {a.file_kind === 'pdf'
                ? <FileText size={14} className="text-stone-500 flex-shrink-0" />
                : <ImageIcon size={14} className="text-stone-500 flex-shrink-0" />}
              <span className="font-serif text-base text-stone-900 truncate">{a.title}</span>
            </div>
            <div className="flex items-center gap-1.5 flex-wrap mt-1">
              {/* Priority TOGGLE — click flips ALL targets of this
                 assignment between priority on/off. stopPropagation
                 so the row click (open detail) doesn't also fire. */}
              {!a.allDone && !bulkMode && (
                <button
                  onClick={(e) => { e.stopPropagation(); togglePriority(a); }}
                  disabled={isToggling}
                  className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 transition-colors disabled:opacity-50 ${a.hasPriority
                      ? 'bg-red-100 text-red-800 border-red-300 font-bold hover:bg-red-200'
                      : 'bg-stone-100 text-stone-500 border-stone-200 hover:bg-stone-200'}`}>
                  <AlertCircle size={10} /> {a.hasPriority ? 'Priority' : 'Mark priority'}
                </button>
              )}
              <AssignmentTypeChip type={a.assignment_type} />
              {a.allDone && <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-emerald-100 text-emerald-800 border border-emerald-300">Done</span>}
              {a.blocked > 0 && <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-red-100 text-red-700 border border-red-300">⚠ Blocked</span>}
              {a.source === 'pm' && a.pm_status === 'pending' && (
                <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-amber-100 text-amber-800 border border-amber-300 font-bold">
                  ⚠ Awaiting approval
                </span>
              )}
              {a.source === 'pm' && a.pm_status === 'rejected' && (
                <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-red-100 text-red-700 border border-red-300">
                  Rejected
                </span>
              )}
            </div>
            <div className="text-xs text-stone-500 font-mono mt-1 flex items-center gap-2 flex-wrap">
              {editDateId === a.id ? (
                <input type="date" autoFocus value={a.scheduled_date || ''}
                  onChange={(e) => saveDue(a.id, e.target.value)}
                  onBlur={() => setEditDateId(null)}
                  onClick={(e) => e.stopPropagation()}
                  className="text-[11px] font-mono px-1.5 py-0.5 rounded border border-stone-400 bg-white" />
              ) : canEditDates ? (
                <button onClick={(e) => { e.stopPropagation(); setEditDateId(a.id); }}
                  className={`px-2 py-0.5 rounded-full border flex items-center gap-1 ${a.scheduled_date
                    ? (assignmentDueKind(a.scheduled_date) === 'overdue' ? 'bg-red-100 text-red-700 border-red-200'
                       : assignmentDueKind(a.scheduled_date) === 'today' ? 'bg-emerald-100 text-emerald-800 border-emerald-200'
                       : 'bg-stone-100 text-stone-600 border-stone-200')
                    : 'bg-white text-stone-500 border-dashed border-stone-300'}`}>
                  <Calendar size={9} /> {a.scheduled_date
                    ? (assignmentDueKind(a.scheduled_date) === 'today' ? 'Due today'
                       : assignmentDueKind(a.scheduled_date) === 'overdue' ? `Overdue · ${fmtDueDate(a.scheduled_date)}`
                       : `Due ${fmtDueDate(a.scheduled_date)}`)
                    : 'Set due date'}
                </button>
              ) : (
                a.scheduled_date ? <span className="flex items-center gap-1"><Calendar size={9} /> Due {fmtDueDate(a.scheduled_date)}</span> : <span>{fmtDate(a.created_at)}</span>
              )}
              <span>{a.done}/{a.total} done{a.inProgress > 0 && `, ${a.inProgress} in progress`}</span>
            </div>
            {a.notes && <div className="text-xs text-stone-600 mt-1 line-clamp-1">{a.notes}</div>}
          </div>
          {!bulkMode && <ChevronRight size={14} className="text-stone-400 flex-shrink-0 mt-1" />}
        </div>
      </div>
    );
  };

  return (
    <div className="pb-24">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div className="flex-1 min-w-0">
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono truncate">{property.name}</div>
          <div className="font-serif text-xl text-stone-900">Assignments</div>
        </div>
        {/* Select-mode toggle — only owners / uploaders see this since
           it gates bulk deletion. Toggling exits and clears selection. */}
        {can(employee, 'upload_assignments') && assignments.length > 0 && (
          <button onClick={() => { setBulkMode(m => !m); setSelectedIds(new Set()); }}
            className={`px-3 py-1.5 rounded-full text-xs font-medium ${bulkMode ? 'bg-stone-900 text-stone-50' : 'bg-stone-100 text-stone-700 hover:bg-stone-200'}`}>
            {bulkMode ? 'Cancel' : 'Select'}
          </button>
        )}
      </div>

      {/* Bulk-action toolbar — sticky-ish row that appears just under
         the header whenever the owner has tapped Select. Shows the
         selected count + Select all + Delete in one row. */}
      {bulkMode && (() => {
        // Show counts based on what's actually visible after search/filter
        // so "select all" feels like it acts on what the user sees.
        const visibleIds = []; // populated below from decorated/filtered list
        try {
          const ids = (typeof decorated !== 'undefined' ? decorated : []).map(d => d.assignment.id);
          visibleIds.push(...ids);
        } catch (e) { /* decorated not in scope yet during render — fine */ }
        const allSelected = visibleIds.length > 0 && visibleIds.every(id => selectedIds.has(id));
        const handleDelete = async () => {
          if (selectedIds.size === 0) return;
          if (!confirm(`Delete ${selectedIds.size} assignment${selectedIds.size === 1 ? '' : 's'}? They'll be archived (recoverable from the DB if needed).`)) return;
          const { error } = await supabase.from('assignments')
            .update({ active: false })
            .in('id', Array.from(selectedIds));
          if (error) { alert('Could not delete: ' + error.message); return; }
          setSelectedIds(new Set());
          setBulkMode(false);
          await load();
        };
        return (
          <div className="sticky top-0 z-20 bg-amber-50 border-b border-amber-200 px-5 py-2.5 flex items-center gap-2 flex-wrap">
            <span className="text-xs font-mono text-amber-900 font-bold">
              {selectedIds.size} selected
            </span>
            <button onClick={() => {
              if (allSelected) setSelectedIds(new Set());
              else setSelectedIds(new Set(visibleIds));
            }} className="text-[11px] font-mono px-2 py-1 rounded-full bg-white border border-amber-300 text-amber-900 hover:bg-amber-100">
              {allSelected ? 'Clear all' : `Select all visible (${visibleIds.length})`}
            </button>
            <div className="flex-1" />
            <button onClick={handleDelete} disabled={selectedIds.size === 0}
              className="text-xs font-medium px-3 py-1.5 rounded-full bg-red-600 text-white hover:bg-red-700 disabled:opacity-40 disabled:cursor-not-allowed flex items-center gap-1">
              <X size={12} /> Delete selected
            </button>
          </div>
        );
      })()}

      <div className="px-5 pt-6">
        {can(employee, 'upload_assignments') && (
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mb-4">
            {onNewQuick && (
              <button onClick={onNewQuick}
                className="p-4 rounded-2xl bg-stone-900 text-stone-50 font-medium flex items-center justify-center gap-2 active:scale-98">
                <Building2 size={18} /> Quick assignment
              </button>
            )}
            {onNewChecklist && (
              <button onClick={onNewChecklist}
                className="p-4 rounded-2xl border-2 border-stone-300 bg-white text-stone-700 font-medium flex items-center justify-center gap-2 active:scale-98">
                <FileText size={18} /> New checklist assignment
              </button>
            )}
            <button onClick={onNew}
              className="p-4 rounded-2xl border-2 border-stone-300 bg-white text-stone-700 font-medium flex items-center justify-center gap-2 active:scale-98">
              <Plus size={18} /> Upload sheet (legacy)
            </button>
          </div>
        )}

        {/* Search bar — always on for assignments. Filters across
           title, notes, unit, and bedroom in one box. */}
        {assignments.length > 0 && (
          <div className="mb-3">
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder={`Search ${assignments.length} assignment${assignments.length === 1 ? '' : 's'} (apartment, bedroom, title, notes)…`}
              className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white focus:outline-none focus:border-stone-900 text-stone-900 text-sm" />
          </div>
        )}

        {/* Filter panel — collapsible. Lets the owner narrow the list
           to priority-only or specific cleaning types. Counts active
           filters on the button so it's clear something's narrowing. */}
        {assignments.length > 0 && (
          <div className="mb-3">
            <button onClick={() => setFiltersOpen(o => !o)}
              className={`w-full flex items-center justify-between px-3 py-2 rounded-xl border transition-colors ${activeFilterCount > 0 ? 'bg-amber-50 border-amber-300 text-amber-900' : 'bg-white border-stone-200 text-stone-600 hover:border-stone-400'}`}>
              <div className="flex items-center gap-2">
                <Settings size={14} />
                <span className="text-xs uppercase tracking-wider font-mono">
                  Filters{activeFilterCount > 0 ? ` (${activeFilterCount})` : ''}
                </span>
                <span className="text-[10px] font-mono text-stone-500">
                  Showing {visible.length} of {decorated.length}
                </span>
              </div>
              <ChevronRight size={14} className={`transition-transform ${filtersOpen ? 'rotate-90' : ''}`} />
            </button>
            {filtersOpen && (
              <div className="p-3 rounded-xl bg-stone-50 border border-stone-200 mt-1 space-y-3">
                <div>
                  <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1.5">Priority</div>
                  <button onClick={() => setPriorityOnly(p => !p)}
                    className={`px-3 py-1.5 rounded-full text-xs font-mono inline-flex items-center gap-1.5 transition-colors ${priorityOnly ? 'bg-red-100 text-red-800 border border-red-300 font-bold' : 'bg-white border border-stone-300 text-stone-600 hover:border-stone-500'}`}>
                    {priorityOnly && <Check size={11} />}
                    <AlertCircle size={11} /> Priority only
                  </button>
                </div>
                {availableTypes.length > 1 && (
                  <div>
                    <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1.5">Cleaning type</div>
                    <div className="flex gap-1.5 flex-wrap">
                      {availableTypes.map(typ => {
                        const active = filterTypes.has(typ);
                        return (
                          <button key={typ} onClick={() => toggleType(typ)}
                            className={`px-2.5 py-1 rounded-full text-xs font-mono flex items-center gap-1 transition-colors ${active ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-300 text-stone-600 hover:border-stone-500'}`}>
                            {active && <Check size={10} />}
                            {assignmentTypeLabel(typ)}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
                {activeFilterCount > 0 && (
                  <button onClick={clearFilters}
                    className="text-xs text-stone-600 hover:text-stone-900 font-mono underline">
                    Clear all filters
                  </button>
                )}
              </div>
            )}
          </div>
        )}

        <div className="flex gap-2 mb-4">
          <button onClick={() => setFilter('open')}
            className={`px-4 py-2 rounded-full text-sm font-medium ${filter === 'open' ? 'bg-stone-900 text-stone-50' : 'bg-stone-100 text-stone-600'}`}>
            Open ({decorated.filter(isCleanerVisible).length})
          </button>
          <button onClick={() => setFilter('all')}
            className={`px-4 py-2 rounded-full text-sm font-medium ${filter === 'all' ? 'bg-stone-900 text-stone-50' : 'bg-stone-100 text-stone-600'}`}>
            All ({decorated.length})
          </button>
        </div>

        {/* Awaiting approval callout — PM-portal uploads still in
           pm_status='pending' aren't visible to cleaners. Without this
           the owner saw inflated Open counts and wondered why cleaners
           weren't seeing the work. The Approve all button bulk-updates
           every awaiting assignment in one query — sidesteps the
           one-at-a-time queue entirely. */}
        {awaitingApproval.length > 0 && (
          <div className="mb-4 p-3 rounded-xl bg-amber-50 border-2 border-amber-300 flex items-start justify-between gap-3">
            <div className="flex-1 min-w-0">
              <div className="text-xs uppercase tracking-wider font-mono font-bold text-amber-900 mb-0.5">
                ⚠ {awaitingApproval.length} awaiting your approval
              </div>
              <div className="text-xs text-stone-700">
                These were uploaded by a property manager and need your approval before cleaners can see them.
              </div>
            </div>
            <div className="flex flex-col gap-1.5 flex-shrink-0">
              <button onClick={async () => {
                if (!confirm(`Approve all ${awaitingApproval.length} pending assignments at this property in one go?`)) return;
                const ids = awaitingApproval.map(a => a.id);
                const { error: ae } = await supabase.from('assignments').update({
                  pm_status: 'approved',
                  approved_by: employee?.id,
                  approved_at: new Date().toISOString(),
                  pm_rejection_reason: null,
                }).in('id', ids);
                if (ae) { alert('Bulk approve failed: ' + ae.message); return; }
                await load();
                alert(`Approved ${ids.length} assignments. They're now visible to cleaners.`);
              }}
                className="px-3 py-1.5 rounded-lg bg-emerald-700 hover:bg-emerald-800 text-white text-xs font-medium">
                Approve all ({awaitingApproval.length})
              </button>
              <button onClick={() => setFilter('all')}
                className="px-3 py-1.5 rounded-lg bg-amber-700 hover:bg-amber-800 text-white text-xs font-medium">
                View all
              </button>
            </div>
          </div>
        )}

        {!loaded ? <Splash text="Loading…" /> : visible.length === 0 ? (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            {q
              ? `No assignments match "${search}".`
              : (priorityOnly || filterTypes.size > 0)
                ? <>No assignments match the current filters.
                    <button onClick={clearFilters}
                      className="block mx-auto mt-2 text-xs text-stone-700 hover:text-stone-900 font-mono underline">
                      Clear all filters
                    </button>
                  </>
                : filter === 'open' ? 'No open assignments. Tap "Upload new assignment" to add one.' : 'No assignments yet.'}
          </div>
        ) : (
          <div className="space-y-4">
            {buildingKeys.map(buildingKey => {
              const unitsInBuilding = buildings[buildingKey];
              const unitKeys = Object.keys(unitsInBuilding).sort(naturalCompare);
              const isCollapsed = !!collapsedBuildings[buildingKey];
              const buildingTotal = unitKeys.reduce((sum, uk) => sum + unitsInBuilding[uk].length, 0);
              const buildingHasPriority = unitKeys.some(uk =>
                unitsInBuilding[uk].some(a => a.hasPriority && !a.allDone)
              );
              return (
                <div key={buildingKey} className="rounded-2xl border border-stone-200 bg-white overflow-hidden">
                  <button onClick={() => toggleBuilding(buildingKey)}
                    className="w-full px-4 py-3 flex items-center justify-between bg-stone-50 hover:bg-stone-100 transition-colors">
                    <div className="flex items-center gap-2 min-w-0">
                      <Building2 size={16} className="text-stone-700 flex-shrink-0" />
                      <span className="font-serif text-base text-stone-900 truncate">{buildingKey}</span>
                      <span className="text-xs font-mono px-2 py-0.5 rounded-full bg-stone-200 text-stone-700 flex-shrink-0">
                        {buildingTotal}
                      </span>
                      <PriorityChip on={buildingHasPriority} size="xs" />
                    </div>
                    <ChevronRight size={14} className={`text-stone-500 flex-shrink-0 transition-transform ${isCollapsed ? '' : 'rotate-90'}`} />
                  </button>
                  {!isCollapsed && (
                    <div className="p-3 space-y-3">
                      {(() => {
                        // Sub-group by floor (first digit of apt number)
                        // so the owner sees Floor 1 → Floor 2 → Floor 3
                        // sections within each building.
                        const byFloor = {};
                        unitKeys.forEach(uk => {
                          const f = floorFromLabel(uk);
                          const fk = f != null ? String(f) : '—';
                          if (!byFloor[fk]) byFloor[fk] = [];
                          byFloor[fk].push(uk);
                        });
                        const floorKeys = Object.keys(byFloor).sort((a, b) => {
                          if (a === '—') return 1;
                          if (b === '—') return -1;
                          return parseInt(a, 10) - parseInt(b, 10);
                        });
                        const showFloorHeaders = floorKeys.length > 1;
                        const renderUnitKey = (unitKey) => {
                          const assignmentsInUnit = unitsInBuilding[unitKey];
                          // Single assignment in this unit — render plain.
                          if (assignmentsInUnit.length === 1) {
                            return renderAssignmentRow(assignmentsInUnit[0]);
                          }
                          // Multiple — render as a dropdown labeled with apt + count.
                          const apartmentKey = `${buildingKey}::${unitKey}`;
                          const isOpen = !!openApartments[apartmentKey];
                          const unitHasPriority = assignmentsInUnit.some(a => a.hasPriority && !a.allDone);
                          return (
                            <div key={unitKey} className="rounded-xl border border-amber-200 bg-amber-50/30 overflow-hidden">
                              <button onClick={() => toggleApartment(apartmentKey)}
                                className="w-full px-3 py-2 flex items-center justify-between hover:bg-amber-50">
                                <div className="flex items-center gap-2 min-w-0">
                                  <span className="font-mono text-sm text-stone-800 truncate">{unitKey}</span>
                                  <span className="text-xs font-mono px-2 py-0.5 rounded-full bg-amber-600 text-white font-bold flex-shrink-0">
                                    {assignmentsInUnit.length}
                                  </span>
                                  <PriorityChip on={unitHasPriority} size="xs" />
                                </div>
                                <ChevronRight size={14} className={`text-amber-700 flex-shrink-0 transition-transform ${isOpen ? 'rotate-90' : ''}`} />
                              </button>
                              {isOpen && (
                                <div className="px-2 pb-2 pt-1 space-y-2 border-t border-amber-100">
                                  {assignmentsInUnit.map(a => renderAssignmentRow(a))}
                                </div>
                              )}
                            </div>
                          );
                        };
                        if (!showFloorHeaders) {
                          // Single-floor building — no floor headers, just the apartments
                          return unitKeys.map(renderUnitKey);
                        }
                        return floorKeys.map(fk => {
                          const floorKey = `${buildingKey}::${fk}`;
                          const floorOpen = !collapsedFloors[floorKey];
                          return (
                            <div key={fk}>
                              <button
                                onClick={() => setCollapsedFloors(prev => ({ ...prev, [floorKey]: !prev[floorKey] }))}
                                className="w-full flex items-center gap-2 mb-1.5 px-1 hover:bg-stone-50 rounded transition-colors text-left">
                                <ChevronRight size={12} className={`text-stone-500 flex-shrink-0 transition-transform ${floorOpen ? 'rotate-90' : ''}`} />
                                <span className="text-sm font-bold text-stone-800 tracking-wide">
                                  {fk === '—' ? 'Other' : `Floor ${fk}`}
                                </span>
                                <span className="text-xs font-mono text-stone-500">({byFloor[fk].length})</span>
                                <div className="flex-1 h-px bg-stone-300" />
                              </button>
                              {floorOpen && (
                                <div className="space-y-2">
                                  {byFloor[fk].map(renderUnitKey)}
                                </div>
                              )}
                            </div>
                          );
                        });
                      })()}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

// =================================================================
// ASSIGNMENT FORM — bulk multi-file uploader
//
// Lets the owner/manager pick multiple files at once and configure
// each one individually (title, notes, property/unit/party target)
// before saving them all in one batch.
//
// `property` is the *default* property (where they came from). Each
// file can be retargeted to a different property if needed.
// =================================================================
// =================================================================
// QUICK ASSIGNMENT — for properties without the full bedroom/template
// setup (e.g. Bridges, Citifront). Just: apartment number, how many
// bed/bath, and the clean type. Creates the apartment (unit) on the
// fly if it doesn't exist, so a cleaner can pick it up right away.
// =================================================================
const QUICK_TYPES = [
  { key: 'standard',        label: 'Standard' },
  { key: 'deep',            label: 'Deep clean' },
  { key: 'move_out_check',  label: 'Move-out' },
  { key: 'cleaning_check',  label: 'Cleaning check' },
  { key: 'reclean',         label: 'Re-clean' },
];
function QuickAssignmentForm({ property, employee, onCancel, onSaved }) {
  const [apt, setApt] = useState('');
  const [bedrooms, setBedrooms] = useState(2);
  const [bathrooms, setBathrooms] = useState(2);
  const [cleanType, setCleanType] = useState('');
  const [scheduledDate, setScheduledDate] = useState('');
  const [priority, setPriority] = useState(false);
  const [notes, setNotes] = useState('');
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  const step = (setter, val, delta, min = 0, max = 12) =>
    setter(Math.max(min, Math.min(max, (parseInt(val, 10) || 0) + delta)));

  const submit = async () => {
    const label = apt.trim();
    if (!label) { setError('Enter an apartment number.'); return; }
    if (!cleanType) { setError('Pick a clean type.'); return; }
    if (busy) return;
    setBusy(true); setError('');
    try {
      const br = parseInt(bedrooms, 10) || 0;
      const ba = parseInt(bathrooms, 10) || 0;
      // Find the apartment (unit), else create it.
      const { data: existing } = await supabase.from('units').select('*')
        .eq('customer_id', property.id).ilike('label', label).limit(1);
      let unit = (existing && existing[0]) || null;
      if (!unit) {
        const { data: created, error: ue } = await supabase.from('units').insert({
          customer_id: property.id, label, kind: 'townhome',
          bedrooms: br, bathrooms: ba, active: true, sort_order: 0,
        }).select().single();
        if (ue) throw ue;
        unit = created;
      } else {
        await supabase.from('units').update({ bedrooms: br, bathrooms: ba }).eq('id', unit.id);
      }
      // Ensure a party to attach the job to (whole-apartment "Main").
      const { data: parties } = await supabase.from('parties').select('*')
        .eq('unit_id', unit.id).eq('active', true).order('sort_order');
      let party = (parties || []).find(p => (p.label || '').toLowerCase() === 'main') || (parties || [])[0] || null;
      if (!party) {
        const { data: cp, error: pe } = await supabase.from('parties').insert({
          unit_id: unit.id, label: 'Main', sort_order: 1, active: true,
        }).select().single();
        if (pe) throw pe;
        party = cp;
      }
      // Create the assignment + one target.
      const typeLabel = (QUICK_TYPES.find(t => t.key === cleanType) || {}).label || cleanType;
      const title = `Apt ${label} · ${br}BR/${ba}BA · ${typeLabel}`;
      // Route this property through the multi-unit cleaner flow (property →
      // pick apartment → clean), like Carriage — otherwise a cleaner
      // clocking in jumps straight into one clean with no apartment shown.
      if (property.property_type !== 'multi_unit') {
        await supabase.from('customers').update({ property_type: 'multi_unit' }).eq('id', property.id);
      }
      const { data: asg, error: ae } = await supabase.from('assignments').insert({
        customer_id: property.id, title, notes: notes.trim() || null,
        uploaded_by: employee.id, active: true, assignment_type: cleanType,
        scheduled_date: scheduledDate || null,
      }).select().single();
      if (ae) throw ae;
      const { error: te } = await supabase.from('assignment_targets').insert({
        assignment_id: asg.id, unit_id: unit.id, party_id: party.id,
        status: 'pending', priority: !!priority,
      });
      if (te) throw te;
      setBusy(false);
      onSaved();
    } catch (e) {
      setBusy(false);
      setError(e.message || String(e));
    }
  };

  const Stepper = ({ label, value, setter }) => (
    <div className="flex-1">
      <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">{label}</label>
      <div className="flex items-center gap-2">
        <button onClick={() => step(setter, value, -1)} className="w-10 h-10 rounded-xl border border-stone-300 bg-white text-stone-700 text-lg font-medium active:scale-95">–</button>
        <div className="flex-1 text-center text-lg font-mono text-stone-900 py-2 rounded-xl bg-stone-100">{value}</div>
        <button onClick={() => step(setter, value, 1)} className="w-10 h-10 rounded-xl border border-stone-300 bg-white text-stone-700 text-lg font-medium active:scale-95">+</button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-stone-50 pb-28">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200 sticky top-0 bg-stone-50 z-10">
        <button onClick={onCancel} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div>
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">{property.name}</div>
          <div className="font-serif text-xl text-stone-900">Quick assignment</div>
        </div>
      </div>

      <div className="px-5 pt-6 space-y-5 max-w-md mx-auto">
        <p className="text-sm text-stone-600">Just clean an apartment — no checklist needed. We'll create the apartment if it's not in the system yet.</p>

        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Apartment number</label>
          <input value={apt} onChange={e => setApt(e.target.value)} placeholder="e.g. 302"
            className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white text-stone-900" />
        </div>

        <div className="flex gap-3">
          <Stepper label="Bedrooms" value={bedrooms} setter={setBedrooms} />
          <Stepper label="Bathrooms" value={bathrooms} setter={setBathrooms} />
        </div>

        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Clean type</label>
          <div className="grid grid-cols-2 gap-2">
            {QUICK_TYPES.map(t => (
              <button key={t.key} onClick={() => setCleanType(t.key)}
                className={`px-3 py-2.5 rounded-xl border-2 text-sm font-medium transition-colors ${cleanType === t.key ? 'bg-amber-50 border-amber-500 text-amber-900' : 'bg-white border-stone-200 text-stone-700 hover:border-stone-400'}`}>
                {t.label}
              </button>
            ))}
          </div>
        </div>

        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Target date (optional)</label>
          <input type="date" value={scheduledDate} onChange={e => setScheduledDate(e.target.value)}
            className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white text-stone-900" />
        </div>

        <button onClick={() => setPriority(p => !p)}
          className={`w-full px-4 py-3 rounded-xl border-2 text-sm font-medium flex items-center justify-between transition-colors ${priority ? 'bg-red-50 border-red-400 text-red-800' : 'bg-white border-stone-200 text-stone-600'}`}>
          <span>Mark urgent (sorts to top for cleaners)</span>
          <span className={`w-5 h-5 rounded-md flex items-center justify-center ${priority ? 'bg-red-600 text-white' : 'border-2 border-stone-300'}`}>{priority && <Check size={12} />}</span>
        </button>

        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Notes (optional)</label>
          <textarea value={notes} onChange={e => setNotes(e.target.value)} rows={2} placeholder="Anything the cleaner should know…"
            className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white text-stone-900 text-sm" />
        </div>

        {error && <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-sm text-red-700">{error}</div>}

        <button onClick={submit} disabled={busy || !apt.trim() || !cleanType}
          className="w-full py-4 rounded-2xl bg-stone-900 text-stone-50 font-medium active:scale-98 disabled:opacity-50 flex items-center justify-center gap-2">
          <Plus size={18} /> {busy ? 'Creating…' : 'Create assignment'}
        </button>
      </div>
    </div>
  );
}

function AssignmentForm({ property, employee, onCancel, onSaved }) {
  // Each row: { id, file, title, notes, propertyId, scope, unitId, partyId, multipleTargets }
  const [rows, setRows] = useState([]);
  const [allProperties, setAllProperties] = useState([]);
  // Active employees for the "Assign to" dropdown — managers and
  // owners shouldn't get assigned cleaning work, so we limit to role=employee.
  const [employees, setEmployees] = useState([]);
  // Cache of units per property: { [propertyId]: [{id, label, parties:[...]}] }
  const [unitsByProperty, setUnitsByProperty] = useState({});
  const [busy, setBusy] = useState(false);
  const [progress, setProgress] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    (async () => {
      const { data } = await supabase.from('customers').select('*')
        .eq('active', true).order('name');
      setAllProperties(visibleProps(data, employee));
      const { data: emps } = await supabase.from('employees')
        .select('id, name, role').eq('active', true)
        .in('role', ['employee', 'manager']).order('name');
      setEmployees(emps || []);
    })();
  }, []);

  // Load units for a property on demand (and cache)
  const ensureUnitsLoaded = async (propertyId) => {
    if (unitsByProperty[propertyId]) return unitsByProperty[propertyId];
    const { data } = await supabase.from('units')
      .select('*, parties(id, label, full_name, active, sort_order)')
      .eq('customer_id', propertyId).eq('active', true)
      .order('sort_order').order('label');
    // Sort: common areas (clubhouse, gym, etc) first, then everything else alphabetical.
    // Common areas are typically the kind of thing assignments get uploaded for
    // (clubhouse cleanings) so surfacing them at the top saves scrolling.
    const sorted = (data || []).slice().sort((a, b) => {
      const aCommon = a.kind === 'common_area';
      const bCommon = b.kind === 'common_area';
      if (aCommon && !bCommon) return -1;
      if (!aCommon && bCommon) return 1;
      return naturalCompare(a.label, b.label);
    });
    setUnitsByProperty(prev => ({ ...prev, [propertyId]: sorted }));
    return sorted;
  };

  // When a property is set/changed on a row, prefetch its units
  useEffect(() => {
    const ids = [...new Set(rows.map(r => r.propertyId).filter(Boolean))];
    ids.forEach(id => { if (!unitsByProperty[id]) ensureUnitsLoaded(id); });
    // eslint-disable-next-line
  }, [rows]);

  const addFiles = (files) => {
    const newRows = Array.from(files).map(f => {
      const defaultProperty = property?.id || (allProperties[0]?.id || '');
      return {
        id: `${Date.now()}_${Math.random().toString(36).slice(2,8)}`,
        file: f,
        // Start empty so picking a unit + bedroom auto-fills the title.
        // (Previously we pre-filled from the filename; that meant the
        // title was never "empty" and the auto-fill wouldn't replace it,
        // breaking the auto-population behavior the user expects.)
        title: '',
        notes: '',
        propertyId: defaultProperty,
        scope: 'single',
        unitId: '',
        partyId: '',
        multipleTargets: [], // [{ unitId, partyId }]
        // Cleaning type (Standard / Deep / Move-out check / etc) — empty
        // default so the owner has to actively pick. Validation enforces.
        assignmentType: '',
        // Optional target date for when this assignment should be done
        scheduledDate: '',
        // Priority flag — flagged assignments sort to the top of the
        // cleaner's list and show with a red urgent badge.
        priority: false,
        // Optional employee ID — when set, this assignment shows as
        // assigned to a specific cleaner. Others can still see it but
        // it surfaces with their name attached as a recommendation.
        assignedTo: '',
      };
    });
    setRows(prev => [...prev, ...newRows]);
  };

  const handleFileInput = (e) => {
    if (e.target.files && e.target.files.length > 0) {
      addFiles(e.target.files);
      e.target.value = ''; // reset so picking the same file again re-fires
    }
  };

  const updateRow = (id, patch) => {
    setRows(prev => prev.map(r => r.id === id ? { ...r, ...patch } : r));
  };

  const removeRow = (id) => {
    setRows(prev => prev.filter(r => r.id !== id));
  };

  // Auto-build a title prefix from the target selection, e.g. "B3-205 · Bedroom 2 — "
  // Called when unit/party changes on a row. Replaces any existing auto-prefix but
  // keeps anything the user manually typed after it.
  // When the user picks a unit/party in single mode, set the title to
  // a compact identifier like "B1-103-1". If they've manually edited
  // the title to something custom that doesn't match the auto-format,
  // we don't clobber it — only update when the title is empty or
  // matches the previous auto-built pattern.
  const autoPrefixFor = (rowId, unitIdNew, partyIdNew) => {
    setRows(prev => prev.map(r => {
      if (r.id !== rowId) return r;
      const units = unitsByProperty[r.propertyId] || [];
      const unit = units.find(u => u.id === unitIdNew);
      const party = (unit?.parties || []).find(p => p.id === partyIdNew);
      const newAutoTitle = buildTargetTitle(unit?.label, party?.label);
      // Compute what the OLD auto title would have been, so we can detect
      // whether the current title is still the auto value (safe to replace)
      // vs custom (preserve).
      const oldUnit = units.find(u => u.id === r.unitId);
      const oldParty = (oldUnit?.parties || []).find(p => p.id === r.partyId);
      const oldAutoTitle = buildTargetTitle(oldUnit?.label, oldParty?.label);
      // Also strip legacy " — " prefixed manual edits so they get refreshed
      const legacyPrefixMatch = r.title.match(/^[^—]+ — (.*)$/);
      const titleIsAuto =
        r.title === oldAutoTitle ||
        r.title === '' ||
        (legacyPrefixMatch && legacyPrefixMatch[1] === '');
      const nextTitle = titleIsAuto ? newAutoTitle : r.title;
      return { ...r, unitId: unitIdNew, partyId: partyIdNew, title: nextTitle };
    }));
  };

  // When the property on a row changes, reset its scope/targets
  const changeRowProperty = (id, newPropId) => {
    updateRow(id, {
      propertyId: newPropId,
      scope: 'single',
      unitId: '', partyId: '', multipleTargets: []
    });
  };

  const toggleTarget = (rowId, uId, pId) => {
    setRows(prev => prev.map(r => {
      if (r.id !== rowId) return r;
      const exists = r.multipleTargets.some(t => t.unitId === uId && (t.partyId || null) === (pId || null));
      const next = exists
        ? r.multipleTargets.filter(t => !(t.unitId === uId && (t.partyId || null) === (pId || null)))
        : [...r.multipleTargets, { unitId: uId, partyId: pId || null }];
      return { ...r, multipleTargets: next };
    }));
  };

  // Select / deselect every active party inside a unit, for one row
  const toggleAllInUnit = (rowId, unit) => {
    setRows(prev => prev.map(r => {
      if (r.id !== rowId) return r;
      const activeParties = (unit.parties || []).filter(p => p.active);
      const allSelected = activeParties.every(p =>
        r.multipleTargets.some(t => t.unitId === unit.id && (t.partyId || null) === p.id));
      const next = allSelected
        ? r.multipleTargets.filter(t => t.unitId !== unit.id)
        : [
            ...r.multipleTargets.filter(t => t.unitId !== unit.id),
            ...activeParties.map(p => ({ unitId: unit.id, partyId: p.id }))
          ];
      return { ...r, multipleTargets: next };
    }));
  };

  // Per-row search text for the multi-select
  const [unitSearches, setUnitSearches] = useState({}); // { [rowId]: 'searchString' }
  const setUnitSearch = (rowId, q) => setUnitSearches(prev => ({ ...prev, [rowId]: q }));

  const validateRows = () => {
    if (rows.length === 0) return 'Add at least one file.';
    for (const r of rows) {
      if (!r.propertyId) return `One of the files has no property set.`;
      const prop = allProperties.find(p => p.id === r.propertyId);
      const isMulti = prop?.property_type === 'multi_unit';
      // Title check: required only in single mode (multi auto-generates per target)
      if (!(isMulti && r.scope === 'multiple') && !r.title.trim()) {
        return `One of the files is missing a title. Pick the unit + bedroom to auto-fill, or type one.`;
      }
      if (!r.assignmentType) return `"${r.title || r.file.name}" needs a cleaning type picked.`;
      if (isMulti) {
        if (r.scope === 'multiple') {
          if (!r.multipleTargets || r.multipleTargets.length === 0) {
            return `"${r.title || r.file.name}" needs at least one bedroom selected.`;
          }
        } else {
          if (!r.unitId || !r.partyId) {
            return `"${r.title || r.file.name}" needs a unit and bedroom.`;
          }
        }
      }
    }
    return null;
  };

  const saveAll = async () => {
    setError('');
    const v = validateRows();
    if (v) { setError(v); return; }
    setBusy(true);
    try {
      let totalCreated = 0;
      for (let i = 0; i < rows.length; i++) {
        const r = rows[i];
        setProgress(`Uploading file ${i + 1} of ${rows.length}…`);
        const { path, publicUrl, kind } = await uploadAssignmentFile(r.file, r.propertyId);

        const prop = allProperties.find(p => p.id === r.propertyId);
        const isMulti = prop?.property_type === 'multi_unit';
        const units = unitsByProperty[r.propertyId] || [];

        // Build the list of (target, generated title) pairs we'll create
        // assignments for. In multi mode each target becomes its own
        // assignments row with a per-bedroom title like "B1-101-1", so
        // each cleaner sees their own clean identifier. The file URL is
        // shared across all of them since they reference the same PDF.
        const targets = (() => {
          if (!isMulti) {
            return [{ unit_id: null, party_id: null, title: r.title.trim() }];
          }
          if (r.scope === 'multiple') {
            return r.multipleTargets.map(t => {
              const u = units.find(uu => uu.id === t.unitId);
              const p = (u?.parties || []).find(pp => pp.id === t.partyId);
              return {
                unit_id: t.unitId,
                party_id: t.partyId,
                title: buildTargetTitle(u?.label, p?.label) || r.title.trim(),
              };
            });
          }
          return [{ unit_id: r.unitId, party_id: r.partyId, title: r.title.trim() }];
        })();

        for (let t = 0; t < targets.length; t++) {
          const target = targets[t];
          if (targets.length > 1) {
            setProgress(`Creating assignment ${t + 1} of ${targets.length} for file ${i + 1}…`);
          }
          const { data: created, error: e } = await supabase.from('assignments')
            .insert({
              customer_id: r.propertyId,
              title: target.title,
              notes: r.notes.trim() || null,
              file_path: path,
              file_url: publicUrl,
              file_kind: kind,
              uploaded_by: employee.id,
              active: true,
              assignment_type: r.assignmentType,
              scheduled_date: r.scheduledDate || null,
            }).select().single();
          if (e) throw e;

          // Fire-and-forget auto-translation for the first one only; siblings
          // sharing the same file will read the translation from any sibling
          // since file_url is identical. (Keeps API costs down for big batches.)
          if (t === 0) {
            autoTranslateAssignment(created.id, publicUrl, kind);
          }

          const { error: te } = await supabase.from('assignment_targets').insert({
            assignment_id: created.id,
            unit_id: target.unit_id,
            party_id: target.party_id,
            status: 'pending',
            priority: !!r.priority,
            assigned_to: r.assignedTo || null,
          });
          if (te) throw te;
          totalCreated++;
        }
      }
      setProgress(`Done — ${totalCreated} assignment${totalCreated === 1 ? '' : 's'} created.`);
      setTimeout(() => onSaved(), 400);
    } catch (err) {
      setError(err.message || String(err));
      setBusy(false);
    }
  };

  return (
    <div className="min-h-screen bg-stone-50 pb-24">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200 sticky top-0 bg-stone-50 z-10">
        <button onClick={onCancel} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div>
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">New assignments</div>
          <div className="font-serif text-xl text-stone-900">Upload &amp; assign</div>
        </div>
      </div>

      <div className="px-5 pt-6">
        {/* File picker — always available, can add more */}
        <label className="block w-full p-6 border-2 border-dashed border-stone-300 rounded-2xl text-center cursor-pointer hover:border-stone-900 transition-colors mb-4">
          <Plus size={28} className="mx-auto mb-2 text-stone-500" />
          <div className="text-stone-700 font-medium text-sm">
            {rows.length === 0 ? 'Pick one or more PDFs / images' : 'Add more files'}
          </div>
          <div className="text-xs text-stone-500 mt-0.5">You can configure each one below before saving</div>
          <input type="file" accept="application/pdf,image/*" multiple onChange={handleFileInput} className="hidden" />
        </label>

        {rows.length === 0 && (
          <div className="text-center py-8 text-stone-400 text-sm">
            No files yet. Pick some files to get started.
          </div>
        )}

        {/* Per-file configuration rows */}
        <div className="space-y-3">
          {rows.map((row, idx) => {
            const prop = allProperties.find(p => p.id === row.propertyId);
            const isMulti = prop?.property_type === 'multi_unit';
            const units = unitsByProperty[row.propertyId] || [];
            const rowParties = (units.find(u => u.id === row.unitId)?.parties || [])
              .filter(p => p.active).sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));
            const isPdf = row.file.type === 'application/pdf' || /\.pdf$/i.test(row.file.name);

            return (
              <div key={row.id} className="p-4 rounded-2xl bg-white border border-stone-200">
                <div className="flex items-start gap-3 mb-3">
                  <div className="flex-shrink-0 w-10 h-10 rounded-xl bg-stone-100 flex items-center justify-center">
                    {isPdf ? <FileText size={18} className="text-stone-600" /> : <ImageIcon size={18} className="text-stone-600" />}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="text-xs font-mono text-stone-500 truncate">{row.file.name}</div>
                    <div className="text-[10px] font-mono text-stone-400">
                      {(row.file.size / 1024).toFixed(0)} KB · #{idx + 1}
                    </div>
                  </div>
                  <button onClick={() => removeRow(row.id)} disabled={busy}
                    className="p-2 rounded-full hover:bg-stone-100 text-stone-500">
                    <X size={16} />
                  </button>
                </div>

                <div className="space-y-3">
                  {/* Cleaning type — empty default forces an active pick.
                     Sits at the top of the config since user wants this
                     decision early in the flow. */}
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">
                        Cleaning type <span className="text-red-600">*</span>
                      </label>
                      <select value={row.assignmentType}
                        onChange={(e) => updateRow(row.id, { assignmentType: e.target.value })}
                        className={`w-full px-3 py-2 rounded-lg border bg-white text-sm ${row.assignmentType ? 'border-stone-300' : 'border-amber-400'}`}>
                        <option value="">Pick a type…</option>
                        {ASSIGNMENT_TYPES.map(t => (
                          <option key={t.value} value={t.value}>{t.label}</option>
                        ))}
                      </select>
                    </div>
                    <div>
                      <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">
                        Due date <span className="text-stone-400 normal-case">(optional)</span>
                      </label>
                      <input type="date" value={row.scheduledDate}
                        onChange={(e) => updateRow(row.id, { scheduledDate: e.target.value })}
                        className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm" />
                    </div>
                  </div>

                  {/* Priority + Assignee — both optional. Priority sorts to
                     top of cleaner lists and shows urgent badge. Assignee
                     pins to a specific cleaner (others can still see it). */}
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">
                        Priority
                      </label>
                      <button type="button"
                        onClick={() => updateRow(row.id, { priority: !row.priority })}
                        className={`w-full px-3 py-2 rounded-lg border text-sm flex items-center justify-center gap-1.5 transition-colors ${row.priority ? 'border-red-400 bg-red-50 text-red-800' : 'border-stone-300 bg-white text-stone-500'}`}>
                        {row.priority ? <AlertCircle size={14} /> : null}
                        {row.priority ? 'Priority — do first' : 'Mark as priority'}
                      </button>
                    </div>
                    <div>
                      <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">
                        Assign to <span className="text-stone-400 normal-case">(optional)</span>
                      </label>
                      <select value={row.assignedTo}
                        onChange={(e) => updateRow(row.id, { assignedTo: e.target.value })}
                        className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm">
                        <option value="">Anyone</option>
                        {employees.map(e => (
                          <option key={e.id} value={e.id}>{e.name}{e.role === 'manager' ? ' (manager)' : ''}</option>
                        ))}
                      </select>
                    </div>
                  </div>

                  <div>
                    <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">Title</label>
                    <input type="text" value={row.title} onChange={(e) => updateRow(row.id, { title: e.target.value })}
                      placeholder={row.scope === 'multiple' ? 'Auto-filled per bedroom on save' : 'Pick a unit + bedroom to auto-fill'}
                      disabled={row.scope === 'multiple'}
                      className={`w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm ${row.scope === 'multiple' ? 'opacity-60 bg-stone-50' : ''}`} />
                    {row.assignmentType && (
                      <div className="mt-1 text-[10px] font-mono text-stone-500">
                        Cleaning type: <span className="text-amber-700 font-medium">{assignmentTypeLabel(row.assignmentType)}</span>
                      </div>
                    )}
                  </div>

                  <div>
                    <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">Notes (optional)</label>
                    <textarea value={row.notes} onChange={(e) => updateRow(row.id, { notes: e.target.value })}
                      rows={2} placeholder="Standing instructions or context…"
                      className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm resize-none" />
                  </div>

                  <div>
                    <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">Property</label>
                    <select value={row.propertyId} onChange={(e) => changeRowProperty(row.id, e.target.value)}
                      className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm">
                      {allProperties.map(p => <option key={p.id} value={p.id}>{p.name}{p.property_type === 'multi_unit' ? ' (multi-unit)' : ''}</option>)}
                    </select>
                  </div>

                  {isMulti && (
                    <div>
                      <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">Send to</label>
                      {/* Scope toggle: single bedroom vs multiple. Switching
                         resets the OTHER side's state to avoid confusion
                         when saving. */}
                      <div className="flex items-center gap-1 p-1 bg-stone-100 rounded-xl mb-2">
                        <button type="button"
                          onClick={() => updateRow(row.id, { scope: 'single', multipleTargets: [] })}
                          className={`flex-1 py-1.5 px-2 rounded-lg text-[11px] font-medium transition-colors ${(row.scope || 'single') === 'single' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
                          Single bedroom
                        </button>
                        <button type="button"
                          onClick={() => updateRow(row.id, { scope: 'multiple', unitId: '', partyId: '' })}
                          className={`flex-1 py-1.5 px-2 rounded-lg text-[11px] font-medium transition-colors ${row.scope === 'multiple' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
                          Multiple bedrooms
                        </button>
                      </div>

                      {(row.scope || 'single') === 'single' ? (
                        <div className="grid grid-cols-2 gap-2">
                          <SearchableUnitPicker
                            units={units}
                            value={row.unitId}
                            placeholder="Pick a unit…"
                            onChange={(newUnitId) => autoPrefixFor(row.id, newUnitId, '')} />
                          <select value={row.partyId} onChange={(e) => autoPrefixFor(row.id, row.unitId, e.target.value)}
                            disabled={!row.unitId}
                            className="px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm disabled:opacity-50">
                            <option value="">Bedroom…</option>
                            {rowParties.map(p => <option key={p.id} value={p.id}>{p.label}</option>)}
                          </select>
                        </div>
                      ) : (
                        // Multi mode: tree of units → bedrooms with
                        // checkboxes. "Select all" per unit makes it
                        // easy to assign one PDF to every bedroom in a
                        // building.
                        <div className="space-y-1.5 max-h-72 overflow-y-auto border border-stone-200 rounded-xl p-2 bg-stone-50">
                          {/* Search box to filter units */}
                          <input
                            type="text"
                            value={unitSearches[row.id] || ''}
                            onChange={(e) => setUnitSearch(row.id, e.target.value)}
                            placeholder="Filter units…"
                            className="w-full px-2 py-1.5 rounded-lg border border-stone-300 bg-white text-xs mb-1" />
                          {(() => {
                            const q = (unitSearches[row.id] || '').trim().toLowerCase();
                            const filteredUnits = q
                              ? units.filter(u => (u.label || '').toLowerCase().includes(q))
                              : units;
                            if (filteredUnits.length === 0) {
                              return <div className="text-center py-3 text-stone-400 text-xs italic">
                                {units.length === 0 ? 'No units in this property.' : 'No units match your search.'}
                              </div>;
                            }
                            return filteredUnits.map(u => {
                              const activeParties = (u.parties || []).filter(p => p.active).sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));
                              const allSelected = activeParties.length > 0 && activeParties.every(p =>
                                row.multipleTargets.some(t => t.unitId === u.id && (t.partyId || null) === p.id));
                              const someSelected = activeParties.some(p =>
                                row.multipleTargets.some(t => t.unitId === u.id && (t.partyId || null) === p.id));
                              return (
                                <div key={u.id} className="bg-white rounded-lg border border-stone-200 p-2">
                                  <button type="button"
                                    onClick={() => toggleAllInUnit(row.id, u)}
                                    className="w-full flex items-center gap-2 mb-1 text-left">
                                    <div className={`w-4 h-4 rounded border-2 flex-shrink-0 flex items-center justify-center ${allSelected ? 'border-amber-600 bg-amber-600' : someSelected ? 'border-amber-600 bg-amber-100' : 'border-stone-300'}`}>
                                      {allSelected && <Check size={11} className="text-white" />}
                                      {!allSelected && someSelected && <div className="w-2 h-2 bg-amber-600 rounded-sm" />}
                                    </div>
                                    <span className="text-xs font-medium text-stone-900">{u.label}</span>
                                    <span className="text-[10px] font-mono text-stone-400 ml-auto">
                                      {activeParties.length} bedroom{activeParties.length === 1 ? '' : 's'}
                                    </span>
                                  </button>
                                  {activeParties.length > 0 && (
                                    <div className="ml-6 grid grid-cols-2 gap-1">
                                      {activeParties.map(p => {
                                        const checked = row.multipleTargets.some(t => t.unitId === u.id && (t.partyId || null) === p.id);
                                        return (
                                          <button key={p.id} type="button"
                                            onClick={() => toggleTarget(row.id, u.id, p.id)}
                                            className={`flex items-center gap-1.5 px-2 py-1 rounded-lg text-left border ${checked ? 'border-amber-600 bg-amber-50' : 'border-stone-200 bg-white hover:border-stone-400'}`}>
                                            <div className={`w-3.5 h-3.5 rounded border-2 flex-shrink-0 flex items-center justify-center ${checked ? 'border-amber-600 bg-amber-600' : 'border-stone-300'}`}>
                                              {checked && <Check size={9} className="text-white" />}
                                            </div>
                                            <span className="text-[11px] text-stone-900 truncate">{p.label}</span>
                                          </button>
                                        );
                                      })}
                                    </div>
                                  )}
                                </div>
                              );
                            });
                          })()}
                          {row.multipleTargets.length > 0 && (() => {
                            // Compute the generated titles so the user sees
                            // exactly what each assignment will be named.
                            const generated = row.multipleTargets.map(t => {
                              const u = units.find(uu => uu.id === t.unitId);
                              const p = (u?.parties || []).find(pp => pp.id === t.partyId);
                              return buildTargetTitle(u?.label, p?.label);
                            });
                            const preview = generated.slice(0, 4).join(', ');
                            const more = generated.length > 4 ? `, +${generated.length - 4} more` : '';
                            return (
                              <div className="text-[10px] font-mono text-amber-700 px-1 pt-1 border-t border-stone-200">
                                <div>
                                  Creating {row.multipleTargets.length} assignment{row.multipleTargets.length === 1 ? '' : 's'}:
                                </div>
                                <div className="text-amber-900 mt-0.5">{preview}{more}</div>
                                {row.assignmentType && (
                                  <div className="text-stone-500 mt-0.5">
                                    Type: <span className="text-amber-700">{assignmentTypeLabel(row.assignmentType)}</span>
                                  </div>
                                )}
                              </div>
                            );
                          })()}
                        </div>
                      )}
                    </div>
                  )}

                </div>
              </div>
            );
          })}
        </div>

        {/* Inline submit area at bottom of the page (NOT fixed — avoids overlap with the manager nav bar) */}
        {rows.length > 0 && (
          <div className="mt-6 space-y-3">
            {error && (
              <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
                <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
              </div>
            )}
            {busy && progress && (
              <div className="p-3 rounded-xl bg-stone-100 text-stone-700 text-sm font-mono flex items-center gap-3">
                <div className="w-4 h-4 border-2 border-stone-700 border-t-transparent rounded-full animate-spin flex-shrink-0" />
                {progress}
              </div>
            )}
            <button onClick={saveAll} disabled={busy}
              className="w-full py-4 rounded-2xl bg-stone-900 text-stone-50 font-medium disabled:opacity-50">
              {busy ? 'Uploading…' : `Save ${rows.length} assignment${rows.length === 1 ? '' : 's'}`}
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

// =================================================================
// CHECKLIST ASSIGNMENT WIZARD — the new template-driven upload flow.
//
// Drives an apartment from "I need work done here" to a set of
// per-bedroom assignments, each holding the specific failed items.
// Five steps:
//   0. Pick the apartment (unit)
//   1. Pick which bedrooms need work (1-4 multi-select)
//   2. Pick sheet type (cleaning_check or move_out_clean) — label only
//   3. Configure each bedroom: bathroom variant, general variant,
//      checkmark items per section, with Pass / Fail Entire shortcuts
//   4. Review + submit → creates one assignment per non-passed bedroom,
//      each with assignment_targets per checked item.
//
// Shared bathroom autofill: bedrooms 1 & 2 share bathroom 1 (tub);
// bedrooms 3 & 4 share bathroom 2 (toilet). When the uploader picks
// a bathroom variant for one bedroom, the partner bedroom auto-suggests
// the opposite variant.
//
// Optional sheet image upload (single file) gets attached to ALL
// assignments created so cleaners can still view the original paper
// sheet if they want.
// =================================================================
// Lightweight overlay that pops a single sheet attachment so the
// uploader can confirm which file is which without leaving the wizard.
// Clicking anywhere outside the image (the dark backdrop) closes it.
// Images render full-fit; PDFs render in an embedded iframe.
function SheetQuickViewModal({ file, url, onClose }) {
  if (!file || !url) return null;
  const isImage = file.type && file.type.startsWith('image/');
  return (
    <div
      onClick={onClose}
      className="fixed inset-0 bg-stone-900/90 z-[60] flex items-center justify-center p-4">
      <div className="absolute top-4 right-4 flex items-center gap-2">
        <div className="text-xs text-stone-300 font-mono bg-stone-800 px-3 py-1.5 rounded-full">
          {file.name}
        </div>
        <button onClick={onClose}
          className="p-2 rounded-full bg-stone-800 hover:bg-stone-700 text-stone-50"
          title="Close">
          <X size={20} />
        </button>
      </div>
      {/* Stop propagation on the content so tapping the image itself
         doesn't close the modal — only the backdrop should. */}
      <div onClick={e => e.stopPropagation()} className="max-w-5xl max-h-[85vh] w-full flex items-center justify-center">
        {isImage ? (
          <img src={url} alt={file.name} className="max-w-full max-h-[85vh] rounded-lg object-contain" />
        ) : (
          <iframe src={url} title={file.name} className="w-full h-[85vh] rounded-lg bg-white" />
        )}
      </div>
    </div>
  );
}

function ChecklistAssignmentWizard({ property, employee, actorKind = null, portalUser = null, onCancel, onSaved }) {
  // 6 steps total. The wizard is short enough that an accidental
  // refresh just starts over — no state persistence here.
  const [step, setStep] = useState(0);
  // When invoked from the PM portal, every created assignment is
  // marked source='pm' + pm_status='pending' so it flows through the
  // owner-approval queue. When invoked from staff (no actorKind),
  // assignments take effect immediately.
  const isPmActor = actorKind === 'pm' || actorKind === 'pm_staff';

  // === Step 1: pick the apartment(s) + upload mode ===
  // We no longer keep a single "selectedUnit" — the new tree shows
  // all apartments at once and the uploader can pick bedrooms across
  // multiple apartments. The apartment for any given assignment is
  // looked up via party.unit_id at submit time.
  const [units, setUnits] = useState([]);
  const [unitSearch, setUnitSearch] = useState('');
  // 'single' = one bedroom only · 'multi' = up to 4 bedrooms at once
  const [uploadMode, setUploadMode] = useState(null);

  // === Step 3: pick the bedrooms (parties) ===
  const [parties, setParties] = useState([]);
  // Map of partyId → true if selected for this upload
  const [selectedParties, setSelectedParties] = useState({});

  // === Step 2: sheet type ===
  const [sheetType, setSheetType] = useState(null); // 'cleaning_check' | 'move_out_clean'

  // === Step 4: per-bedroom configuration ===
  // { [partyId]: { mode: 'configure' | 'pass' | 'fail_entire',
  //                bathroomVariant: 'a' | 'b',
  //                generalVariant: 'a' | 'b' | 'c' | 'd',
  //                checked: { '<section>:<itemKey>': true } } }
  const [config, setConfig] = useState({});
  // Which party we're currently editing inside step 4
  const [activePartyId, setActivePartyId] = useState(null);

  // === Step 0: sheet image attachments (optional, multiple allowed) ===
  // Uploaders often have ONE sheet per bedroom and want to attach them
  // all so cleaners can pick the right one. We accept any number of
  // image/PDF files and upload each one on submit.
  const [sheetFiles, setSheetFiles] = useState([]);
  // Map of fileName → object URL for image previews. Built lazily as
  // files are added so we don't leak object URLs.
  const [sheetPreviews, setSheetPreviews] = useState({});

  // Template data
  const [templateSet, setTemplateSet] = useState(null);
  const [variants, setVariants] = useState([]); // all variants under the set
  const [items, setItems] = useState([]);       // all items under those variants
  const [templateLoading, setTemplateLoading] = useState(true);
  const [templateError, setTemplateError] = useState(null);
  // Draft text for the "add a custom item" inputs, keyed by partyId:section
  const [customText, setCustomText] = useState({});

  // Submission
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');
  const [submitted, setSubmitted] = useState(false);
  // Synchronous lock against double-submit. setBusy is async (React
  // batches state) so two rapid taps can both pass the `if (busy)`
  // check before busy=true takes effect. A ref flips synchronously
  // and is the reliable guard. The old setBusy-based check stays as
  // the visual disabled state for the button.
  const submittingRef = useRef(false);
  // True once the uploader has tapped "Next" on the configure step
  // with an incomplete bedroom — used to gate the red error dots so
  // we don't show them before they've even tried.
  const [nextAttempted, setNextAttempted] = useState(false);
  // Sheet preview overlay — set to { file, url } when the user taps
  // the eye/quick-view button on a sheet card. Tapping the backdrop
  // clears this and closes the overlay.
  const [quickView, setQuickView] = useState(null);

  // -----------------------------------------------------------------
  // Load units (apartments) for this property
  // -----------------------------------------------------------------
  useEffect(() => {
    (async () => {
      const { data } = await supabase.from('units')
        .select('*')
        .eq('customer_id', property.id)
        .eq('active', true)
        .order('sort_order').order('label');
      setUnits(data || []);
    })();
  }, [property.id]);

  // -----------------------------------------------------------------
  // Load template set. Move-out cleans use their own granular set
  // (sheet_type='move_out_clean'); cleaning checks use the property's
  // set or the global default. Re-runs when the sheet type changes.
  // -----------------------------------------------------------------
  useEffect(() => {
    let cancelled = false;
    (async () => {
      setTemplateLoading(true); setTemplateError(null);
      try {
        let chosen = null;
        if (sheetType === 'move_out_clean') {
          // Property-specific move-out set, else the global move-out set.
          const { data: ownMO } = await supabase.from('section_template_sets')
            .select('*').eq('customer_id', property.id).eq('sheet_type', 'move_out_clean').limit(1);
          chosen = (ownMO && ownMO[0]) || null;
          if (!chosen) {
            const { data: globalMO } = await supabase.from('section_template_sets')
              .select('*').eq('sheet_type', 'move_out_clean').is('customer_id', null).limit(1);
            chosen = (globalMO && globalMO[0]) || null;
          }
        }
        if (!chosen) {
          // Cleaning checks (and fallback if the move-out set isn't there yet):
          // property-specific, then global default.
          const { data: ownSet } = await supabase.from('section_template_sets')
            .select('*').eq('customer_id', property.id).limit(1);
          chosen = (ownSet && ownSet[0]) || null;
          if (!chosen) {
            const { data: defaultSet } = await supabase.from('section_template_sets')
              .select('*').eq('is_default', true).is('customer_id', null).limit(1);
            chosen = (defaultSet && defaultSet[0]) || null;
          }
        }
        if (cancelled) return;
        if (!chosen) {
          setTemplateError('No checklist template found for this property. Run the v27 migration first.');
          setTemplateLoading(false);
          return;
        }
        setTemplateSet(chosen);
        // Load variants + items in one go
        const { data: vData } = await supabase.from('section_template_variants')
          .select('*').eq('set_id', chosen.id).order('sort_order');
        if (cancelled) return;
        setVariants(vData || []);
        const variantIds = (vData || []).map(v => v.id);
        if (variantIds.length > 0) {
          const { data: iData } = await supabase.from('section_template_items')
            .select('*').in('variant_id', variantIds).order('sort_order');
          if (cancelled) return;
          setItems(iData || []);
        } else {
          setItems([]);
        }
      } catch (e) {
        if (!cancelled) setTemplateError(e.message || 'Could not load checklist templates.');
      }
      if (!cancelled) setTemplateLoading(false);
    })();
    return () => { cancelled = true; };
  }, [property.id, sheetType]);

  // -----------------------------------------------------------------
  // Load ALL parties for ALL units of this property up-front. The
  // legacy-style tree shows every apartment with its bedrooms inline
  // so the uploader can check any combination, even across apartments.
  // -----------------------------------------------------------------
  useEffect(() => {
    if (units.length === 0) { setParties([]); return; }
    (async () => {
      const unitIds = units.map(u => u.id);
      const { data } = await supabase.from('parties').select('*')
        .in('unit_id', unitIds).eq('active', true)
        .order('sort_order').order('label');
      setParties(data || []);
    })();
  }, [units]);

  // -----------------------------------------------------------------
  // Sheet image previews — build object URLs for any image files in
  // sheetFiles, revoke them on cleanup so the browser doesn't leak.
  // -----------------------------------------------------------------
  useEffect(() => {
    const urls = {};
    sheetFiles.forEach(f => {
      if (f.type && f.type.startsWith('image/')) {
        urls[f.name] = URL.createObjectURL(f);
      }
    });
    setSheetPreviews(urls);
    return () => {
      Object.values(urls).forEach(u => URL.revokeObjectURL(u));
    };
  }, [sheetFiles]);

  // Append new sheet files to the list. Filters out files already
  // present by name+size so re-picking the input doesn't duplicate.
  // Accepts a plain array — callers must snapshot the FileList from
  // the input element BEFORE this runs because clearing input.value
  // (which we do to allow re-picking the same file) also wipes
  // input.files, and React state updates are async so the FileList
  // would be empty by the time the setter reads from it.
  const addSheetFiles = (files) => {
    if (!files || files.length === 0) return;
    setSheetFiles(prev => {
      const existing = new Set(prev.map(f => `${f.name}-${f.size}`));
      const additions = files.filter(f => !existing.has(`${f.name}-${f.size}`));
      return [...prev, ...additions];
    });
  };

  const removeSheetFile = (idx) => {
    setSheetFiles(prev => prev.filter((_, i) => i !== idx));
  };

  // Renames a sheet file at the given index. We can't mutate the File
  // object's name directly (it's read-only) so we wrap the file with a
  // new File that has the new name but the same content and type. We
  // also need to update any per-bedroom sheetFileName references that
  // pointed at the old name so the assignment still works at submit.
  const renameSheetFile = (idx, newName) => {
    setSheetFiles(prev => {
      if (idx < 0 || idx >= prev.length) return prev;
      const orig = prev[idx];
      // Preserve the original extension if user dropped it
      const origExt = (orig.name.match(/\.[^.]+$/) || [''])[0];
      const cleaned = newName.trim() || orig.name;
      const finalName = /\.[^.]+$/.test(cleaned) ? cleaned : `${cleaned}${origExt}`;
      if (finalName === orig.name) return prev;
      const wrapped = new File([orig], finalName, { type: orig.type, lastModified: orig.lastModified });
      const next = [...prev];
      next[idx] = wrapped;
      // Update any per-bedroom assignment that pointed at the old name
      setConfig(cfg => {
        const out = { ...cfg };
        Object.keys(out).forEach(pid => {
          if (out[pid]?.sheetFileName === orig.name) {
            out[pid] = { ...out[pid], sheetFileName: finalName };
          }
        });
        return out;
      });
      return next;
    });
  };

  // Build a sensible suggested filename from the currently selected
  // bedrooms. Examples:
  //   1 bedroom, 1 apartment:   "B1-101 Bedroom 1"
  //   2 bedrooms, 1 apartment:  "B1-101 Bedrooms 1 + 2"
  //   bedrooms across apts:     "Multi-apartment"
  // Falls back to "" when nothing's picked yet — that disables the
  // suggestion button on the sheet card.
  const suggestedSheetName = () => {
    const ids = Object.keys(selectedParties).filter(k => selectedParties[k]);
    if (ids.length === 0) return '';
    const grouped = {};
    ids.forEach(id => {
      const p = parties.find(x => x.id === id);
      if (!p) return;
      if (!grouped[p.unit_id]) grouped[p.unit_id] = [];
      grouped[p.unit_id].push(p);
    });
    const unitIds = Object.keys(grouped);
    if (unitIds.length > 1) return 'Multi-apartment';
    const uid = unitIds[0];
    const u = units.find(uu => uu.id === uid);
    const aptLabel = u?.label || '';
    const ps = grouped[uid].sort((a, b) => {
      const an = parseInt((a.label || '').match(/(\d+)/)?.[1] || '0', 10);
      const bn = parseInt((b.label || '').match(/(\d+)/)?.[1] || '0', 10);
      return an - bn;
    });
    if (ps.length === 1) return `${aptLabel} ${ps[0].label}`;
    const nums = ps.map(p => (p.label || '').match(/(\d+)/)?.[1]).filter(Boolean);
    return `${aptLabel} Bedrooms ${nums.join(' + ')}`;
  };

  // Track which sheet card is currently being edited (idx) + its
  // in-progress new name. null when nothing's being edited.
  const [renamingIdx, setRenamingIdx] = useState(null);
  const [renamingValue, setRenamingValue] = useState('');

  // Helper lookups against template data
  const variantsBySection = (sectionKey) =>
    variants.filter(v => v.section_key === sectionKey);
  const variantById = (id) => variants.find(v => v.id === id);
  const itemsForVariant = (variantId) =>
    items.filter(i => i.variant_id === variantId);
  const variantBySectionKey = (sectionKey, variantKey) =>
    variants.find(v => v.section_key === sectionKey && v.variant_key === variantKey);

  // For configure step: pick the active party, default to first selected
  useEffect(() => {
    if (step !== 3) return;
    const ids = Object.keys(selectedParties).filter(k => selectedParties[k]);
    if (ids.length === 0) return;
    if (!activePartyId || !selectedParties[activePartyId]) {
      setActivePartyId(ids[0]);
    }
  }, [step, selectedParties, activePartyId]);

  // -----------------------------------------------------------------
  // Make sure a config shell exists for a bedroom. Called when the
  // bedroom is first selected (either via individual toggle or via
  // "Select all bedrooms in this apartment" in multi mode).
  // -----------------------------------------------------------------
  const ensureConfigShell = (partyId) => {
    setConfig(prev => {
      if (prev[partyId]) return prev;
      const party = parties.find(p => p.id === partyId);
      // Default bathroom variant uses bedroom-number PARITY so partners
      // start opposite by default:
      //   1, 3 (odd)  → 'a' (tub responsibility)
      //   2, 4 (even) → 'b' (toilet responsibility)
      // This matches the convention where the lower-numbered bedroom
      // owns the tub side and the higher one owns the toilet side.
      const num = parseInt((party?.label || '').match(/(\d+)/)?.[1] || '0', 10);
      const bathroomVariant = num > 0 ? (num % 2 === 1 ? 'a' : 'b') : null;
      return {
        ...prev,
        [partyId]: {
          mode: 'configure',
          bathroomVariant,
          generalVariant: null,
          checked: {},
          passedSections: {},
        },
      };
    });
  };

  // -----------------------------------------------------------------
  // Toggle a bedroom on/off. In single mode the uploader can only have
  // ONE bedroom selected at a time — picking a new bedroom replaces
  // the previous one (even if it's in a different apartment). Multi
  // mode allows free selection across apartments.
  // -----------------------------------------------------------------
  const togglePartySelection = (partyId) => {
    setSelectedParties(prev => {
      const next = uploadMode === 'single' ? {} : { ...prev };
      if (prev[partyId] && uploadMode !== 'single') { delete next[partyId]; }
      else { next[partyId] = true; }
      return next;
    });
    ensureConfigShell(partyId);
  };

  // -----------------------------------------------------------------
  // Shared-bathroom autofill: if uploader changes bathroom variant for
  // one bedroom, suggest the OPPOSITE for the other bedroom in the
  // same bathroom group. Only suggests — uploader can override.
  // -----------------------------------------------------------------
  const setBathroomVariantWithAutofill = (partyId, variant) => {
    setConfig(prev => {
      const next = { ...prev };
      const current = next[partyId] || { mode: 'configure', checked: {} };
      next[partyId] = { ...current, bathroomVariant: variant };
      // Find the partner bedroom (same bathroom group, different bedroom number)
      const party = parties.find(p => p.id === partyId);
      const myNum = parseInt((party?.label || '').match(/(\d+)/)?.[1] || '0', 10);
      const myBathroom = bathroomNumberForBedroom(party?.label);
      if (myBathroom) {
        const partnerNum = myBathroom === 1
          ? (myNum === 1 ? 2 : 1)
          : (myNum === 3 ? 4 : 3);
        // CRITICAL: scope partner search to the SAME apartment. Without
        // this guard, multi-apartment selections would match the first
        // bedroom with the right number anywhere — likely the wrong
        // apartment's partner.
        const partnerParty = parties.find(p => {
          const n = parseInt((p.label || '').match(/(\d+)/)?.[1] || '0', 10);
          return n === partnerNum && p.unit_id === party?.unit_id;
        });
        if (partnerParty && selectedParties[partnerParty.id]) {
          // Roommates SPLIT the bathroom — one has tub responsibility,
          // the other has toilet responsibility. So the partner's
          // variant is FORCED to the opposite of this one whenever this
          // bedroom's variant changes. The uploader can still go to the
          // partner's tab and override manually if they really need to.
          const opposite = variant === 'a' ? 'b' : 'a';
          const partnerCurrent = next[partnerParty.id] || { mode: 'configure', checked: {}, passedSections: {} };
          next[partnerParty.id] = { ...partnerCurrent, bathroomVariant: opposite };
        }
      }
      return next;
    });
  };

  const setGeneralVariant = (partyId, variant) => {
    setConfig(prev => {
      const current = prev[partyId] || { mode: 'configure', checked: {} };
      // If the bedroom is in Fail-Entire mode and didn't have a
      // variant before (or had a different one), we need to:
      //  1) Drop any general:* checks tied to the OLD variant
      //  2) Add general:* checks for every item in the NEW variant
      // This keeps Fail-Entire semantically honest: "fail everything
      // in the assigned General area" — once the variant is known.
      if (current.mode === 'fail_entire') {
        const newChecked = { ...(current.checked || {}) };
        // Strip every existing general:* check so the variant swap is clean.
        Object.keys(newChecked).forEach(k => {
          if (k.startsWith('general:')) delete newChecked[k];
        });
        const gv = variantBySectionKey('general', variant);
        if (gv) itemsForVariant(gv.id).forEach(i => { newChecked[`general:${i.item_key}`] = true; });
        return { ...prev, [partyId]: { ...current, generalVariant: variant, checked: newChecked } };
      }
      return { ...prev, [partyId]: { ...current, generalVariant: variant } };
    });
  };

  // Per-bedroom cleaning type. Lives on the assignment row as the
  // existing `assignment_type` column at submit time so downstream
  // filtering/coloring still works.
  const setCleaningType = (partyId, value) => {
    setConfig(prev => ({
      ...prev,
      [partyId]: { ...(prev[partyId] || { mode: 'configure', checked: {} }), cleaningType: value },
    }));
  };

  // Per-bedroom sheet file assignment. Stores the file NAME so we can
  // look up the actual File object at submit time. Null = no sheet
  // attached to this bedroom.
  const setSheetForBedroom = (partyId, fileName) => {
    setConfig(prev => ({
      ...prev,
      [partyId]: { ...(prev[partyId] || { mode: 'configure', checked: {} }), sheetFileName: fileName },
    }));
  };

  const toggleItem = (partyId, sectionKey, itemKey) => {
    const key = `${sectionKey}:${itemKey}`;
    setConfig(prev => {
      const current = prev[partyId] || { mode: 'configure', checked: {} };
      const checked = { ...current.checked };
      if (checked[key]) delete checked[key]; else checked[key] = true;
      return { ...prev, [partyId]: { ...current, checked, mode: 'configure' } };
    });
  };

  // Add a custom item to a section for THIS assignment only (not the
  // template). Stored with a "custom_" key + the label; on submit it
  // becomes a target with the label in status_notes (same idea as a
  // cleaner's requested item).
  const addCustomItem = (partyId, sectionKey, label) => {
    const trimmed = (label || '').trim();
    if (!trimmed) return;
    const itemKey = `custom_${Date.now()}${Math.floor(Math.random() * 1000)}`;
    const key = `${sectionKey}:${itemKey}`;
    setConfig(prev => {
      const current = prev[partyId] || { mode: 'configure', checked: {}, customLabels: {} };
      return { ...prev, [partyId]: {
        ...current, mode: 'configure',
        checked: { ...(current.checked || {}), [key]: true },
        customLabels: { ...(current.customLabels || {}), [key]: trimmed },
        // adding work means the section isn't "passed"
        passedSections: { ...(current.passedSections || {}), [sectionKey]: false },
      } };
    });
  };
  const removeCustomItem = (partyId, key) => {
    setConfig(prev => {
      const current = prev[partyId];
      if (!current) return prev;
      const checked = { ...(current.checked || {}) }; delete checked[key];
      const customLabels = { ...(current.customLabels || {}) }; delete customLabels[key];
      return { ...prev, [partyId]: { ...current, checked, customLabels } };
    });
  };

  // Pass/Fail Entire is now a toggle: clicking the same mode again
  // flips back to 'configure' (so neither button is active). Fail
  // Entire auto-fills missing variants with defaults ('a' for both)
  // so the cleaner has SOMETHING checked even if the uploader didn't
  // pick variants first — they can still fix variants on the next
  // pass.
  const setMode = (partyId, mode) => {
    setConfig(prev => {
      const current = prev[partyId] || { bathroomVariant: null, generalVariant: null, checked: {}, passedSections: {} };
      // Toggle off: clicking the same mode again clears it back to configure
      if (current.mode === mode) {
        return { ...prev, [partyId]: { ...current, mode: 'configure' } };
      }
      if (mode === 'fail_entire') {
        // Bathroom variant follows the bedroom-parity rule (odd→tub,
        // even→toilet) so we can auto-default safely — bedrooms in the
        // same apartment naturally get different bathroom variants
        // because of the parity split. General has NO such natural
        // mapping, so we leave it UNSET and force the uploader to
        // pick one per bedroom. This prevents the bug where two
        // bedrooms in the same apartment both end up with the same
        // General assignment (e.g. both getting "Living Room").
        const bathroomVariant = current.bathroomVariant || 'a';
        const checked = {};
        const bedroomV = variantBySectionKey('bedroom', 'default');
        if (bedroomV) itemsForVariant(bedroomV.id).forEach(i => { checked[`bedroom:${i.item_key}`] = true; });
        const vanityV = variantBySectionKey('vanity', 'default');
        if (vanityV) itemsForVariant(vanityV.id).forEach(i => { checked[`vanity:${i.item_key}`] = true; });
        const bv = variantBySectionKey('bathroom', bathroomVariant);
        if (bv) itemsForVariant(bv.id).forEach(i => { checked[`bathroom:${i.item_key}`] = true; });
        // Only check General items if a variant has actually been
        // picked. Otherwise leave General empty so the uploader sees
        // a clear "pick a variant" prompt before they can submit.
        if (current.generalVariant) {
          const gv = variantBySectionKey('general', current.generalVariant);
          if (gv) itemsForVariant(gv.id).forEach(i => { checked[`general:${i.item_key}`] = true; });
        }
        return { ...prev, [partyId]: {
          ...current, mode, bathroomVariant,
          // Explicitly preserve (or leave null) generalVariant — no auto-default.
          generalVariant: current.generalVariant || null,
          checked,
          passedSections: {}, // un-pass any sections that were marked
        } };
      }
      if (mode === 'pass') {
        return { ...prev, [partyId]: { ...current, mode, checked: {}, passedSections: {} } };
      }
      return { ...prev, [partyId]: { ...current, mode } };
    });
  };

  // Section-level pass toggle. When marked, the section's items are
  // visually grayed and won't be submitted. The cleaner can un-pass to
  // bring items back. Section pass is independent of whole-bedroom pass.
  const toggleSectionPass = (partyId, sectionKey) => {
    setConfig(prev => {
      const current = prev[partyId] || { mode: 'configure', checked: {}, passedSections: {}, failedSections: {} };
      const passedSections = { ...(current.passedSections || {}) };
      const failedSections = { ...(current.failedSections || {}) };
      const willPass = !passedSections[sectionKey];
      if (willPass) {
        passedSections[sectionKey] = true;
        delete failedSections[sectionKey]; // mutually exclusive with fail-all
        // Also un-check all items in that section so a passed section
        // never contributes targets at submit time.
        const cleared = { ...(current.checked || {}) };
        Object.keys(cleared).forEach(k => {
          if (k.startsWith(`${sectionKey}:`)) delete cleared[k];
        });
        return { ...prev, [partyId]: { ...current, passedSections, failedSections, checked: cleared } };
      } else {
        delete passedSections[sectionKey];
        return { ...prev, [partyId]: { ...current, passedSections } };
      }
    });
  };

  // Section-level FAIL ALL — the mirror of toggleSectionPass.
  // The cleaner failed every item in this section, so we auto-check
  // them all. Like Pass, this is mutually exclusive with Pass and
  // also with the whole-bedroom Pass mode (since fail-all sets up
  // work that contradicts "no work").
  const toggleSectionFail = (partyId, sectionKey) => {
    setConfig(prev => {
      const current = prev[partyId] || { mode: 'configure', checked: {}, passedSections: {}, failedSections: {} };
      const failedSections = { ...(current.failedSections || {}) };
      const passedSections = { ...(current.passedSections || {}) };
      const willFail = !failedSections[sectionKey];
      if (willFail) {
        failedSections[sectionKey] = true;
        delete passedSections[sectionKey]; // mutually exclusive with pass-all
        // Auto-check every item in this section for the currently
        // selected variant. If no variant is picked yet for the
        // section, no items get checked (the uploader needs to pick
        // a variant first — the section tab will continue to flag).
        const variantKey = sectionKey === 'bathroom' ? current.bathroomVariant
          : sectionKey === 'general' ? current.generalVariant
          : 'default';
        const variant = variantKey ? variantBySectionKey(sectionKey, variantKey) : null;
        const variantItems = variant ? itemsForVariant(variant.id) : [];
        const checked = { ...(current.checked || {}) };
        variantItems.forEach(it => {
          checked[`${sectionKey}:${it.item_key}`] = true;
        });
        return { ...prev, [partyId]: { ...current, passedSections, failedSections, checked } };
      } else {
        delete failedSections[sectionKey];
        // Un-check the items that fail-all auto-checked. We can't
        // distinguish auto-checked from manually-checked, so we clear
        // everything in this section — the uploader can re-check
        // anything they wanted manually.
        const checked = { ...(current.checked || {}) };
        Object.keys(checked).forEach(k => {
          if (k.startsWith(`${sectionKey}:`)) delete checked[k];
        });
        return { ...prev, [partyId]: { ...current, failedSections, checked } };
      }
    });
  };

  // -----------------------------------------------------------------
  // Validation per step
  //   0 = sheet upload (optional, always passes)
  //   1 = apartment + mode picked
  //   2 = sheet type picked
  //   3 = at least one bedroom selected
  //   4 = every selected bedroom configured (Pass OR variants+items)
  //   5 = review (no advance, only submit)
  // -----------------------------------------------------------------
  const canAdvanceFromStep = () => {
    if (step === 0) return true; // sheet upload is optional
    if (step === 1) {
      // Apartment + mode + bedrooms all on one step now. Need a mode
      // chosen and at least one bedroom checked. In single mode the
      // selection is capped at 1 (enforced by togglePartySelection).
      if (!uploadMode) return false;
      const ids = Object.keys(selectedParties).filter(k => selectedParties[k]);
      if (ids.length === 0) return false;
      if (uploadMode === 'single' && ids.length > 1) return false;
      return true;
    }
    if (step === 2) return !!sheetType;
    if (step === 3) {
      // Configure step. Every selected bedroom must have EVERY section
      // accounted for. A section is "done" when it's either passed
      // (passedSections[s] === true) or has at least one item checked.
      // Bathroom/General with items checked also need their variant
      // picked so we know which template to use.
      //
      // Whole-bedroom Pass (mode === 'pass') short-circuits all of this.
      const ids = Object.keys(selectedParties).filter(k => selectedParties[k]);
      return ids.every(id => sectionsForBedroomComplete(id).every(Boolean));
    }
    return true;
  };

  // Returns an array [bedroom, vanity, bathroom, general] of booleans
  // indicating whether each section is "done". Used by the validation
  // gate and by the section-tab error indicators so the uploader sees
  // exactly which sections still need attention.
  const sectionsForBedroomComplete = (partyId) => {
    const c = config[partyId];
    if (!c) return [false, false, false, false];
    if (c.mode === 'pass') return [true, true, true, true];
    const checked = c.checked || {};
    const passed = c.passedSections || {};
    const failed = c.failedSections || {};
    const sectionDone = (key, variantNeeded, variantValue) => {
      // Variant REQUIRED for bathroom and general even when passed
      // or failed — the cleaner's responsibility for which general
      // area (Kitchen, LR, Fridge, Vents) needs to be captured so
      // the cleaner can request items from that variant later.
      if (variantNeeded && !variantValue) return false;
      if (passed[key]) return true;
      if (failed[key]) return true;
      const hasItems = Object.keys(checked).some(k => k.startsWith(`${key}:`));
      if (!hasItems) return false;
      return true;
    };
    return [
      sectionDone('bedroom',  false, null),
      sectionDone('vanity',   false, null),
      sectionDone('bathroom', true,  c.bathroomVariant),
      sectionDone('general',  true,  c.generalVariant),
    ];
  };

  // -----------------------------------------------------------------
  // Submit: create one assignment per non-pass bedroom with its targets.
  // Multiple sheet uploads: all files are uploaded to storage. The
  // first becomes the assignment's primary `file_url`; the rest are
  // listed in the title/notes for now (a future migration can add a
  // proper `sheet_files JSONB` column).
  // -----------------------------------------------------------------
  const submit = async () => {
    // Ref-based lock: flips synchronously so a second rapid tap never
    // gets through. setBusy is async and can be raced.
    if (submittingRef.current || busy) return;
    // Pre-count what we're about to create so the user can sanity-
    // check before we hit the database. This guards against the
    // "I clicked once and now there are 57 cards" surprise that comes
    // from Fail-Entire mode quietly checking ~28 items per bedroom.
    const selectedPartyIds = Object.keys(selectedParties).filter(k => selectedParties[k]);
    const previewCounts = selectedPartyIds.reduce((acc, pid) => {
      const cc = config[pid];
      if (!cc || cc.mode === 'pass') return acc;
      acc.assignments += 1;
      acc.items += Object.keys(cc.checked || {}).length;
      return acc;
    }, { assignments: 0, items: 0 });
    if (previewCounts.assignments === 0) {
      setError('Nothing to create — every bedroom is set to Pass.');
      return;
    }
    // Unique-variant validation across an apartment. Each bedroom in
    // a 4-bedroom unit should get a DIFFERENT General variant — only
    // one bedroom is "the kitchen bedroom", only one is "the LR
    // bedroom", etc. If two bedrooms in the same unit ended up with
    // the same variant, that's a data-entry mistake we want to catch
    // before writing to the DB. Same rule applies whether the bedroom
    // is in configure or fail_entire mode (both produce General items).
    const variantConflicts = []; // [{ unitLabel, variant, bedroomLabels }]
    const missingVariants = []; // [{ bedroomLabel }]
    {
      const byUnit = {}; // unitId -> { variant -> [bedroomLabel] }
      selectedPartyIds.forEach(pid => {
        const cc = config[pid];
        if (!cc || cc.mode === 'pass') return;
        const party = parties.find(p => p.id === pid);
        if (!party) return;
        // ALWAYS require a generalVariant when the bedroom isn't being
        // skipped entirely. Even if no general items are checked, the
        // variant tells the cleaner which general area this bedroom is
        // responsible for — which matters for the Request flow later
        // (cleaner notices something not on the sheet, taps Request,
        // modal filters items by this variant). Without the variant,
        // the cleaner has no way to know what they could request.
        if (!cc.generalVariant) {
          missingVariants.push({ bedroomLabel: party.label || pid });
          return;
        }
        const uid = party.unit_id;
        if (!byUnit[uid]) byUnit[uid] = {};
        if (!byUnit[uid][cc.generalVariant]) byUnit[uid][cc.generalVariant] = [];
        byUnit[uid][cc.generalVariant].push(party.label || pid);
      });
      Object.entries(byUnit).forEach(([uid, variants]) => {
        const unit = units.find(u => u.id === uid);
        const unitLabel = unit?.label || uid;
        Object.entries(variants).forEach(([variant, labels]) => {
          if (labels.length > 1) {
            variantConflicts.push({ unitLabel, variant: variant.toUpperCase(), bedroomLabels: labels });
          }
        });
      });
    }
    if (missingVariants.length > 0) {
      setError(
        `Pick a General variant (LR / Fridge / Vents / Kitchen) for: ` +
        missingVariants.map(m => m.bedroomLabel).join(', ') +
        `. Each bedroom in an apartment gets its own General area.`
      );
      return;
    }
    if (variantConflicts.length > 0) {
      const msgs = variantConflicts.map(c =>
        `${c.unitLabel}: variant ${c.variant} is assigned to ${c.bedroomLabels.join(' AND ')}`
      );
      setError(
        `Each bedroom in the same apartment needs a UNIQUE General variant — ` +
        `there's a 1:1 mapping (LR=A, Fridge=B, Vents=C, Kitchen=D).\n\n` +
        msgs.join('\n')
      );
      return;
    }
    // Confirmation only fires above a reasonable threshold to avoid
    // nagging on small uploads. 25 items is enough to span 1 bedroom
    // in Fail-Entire mode; anything more and we ask.
    if (previewCounts.items >= 25) {
      const ok = confirm(
        `About to create ${previewCounts.assignments} assignment${previewCounts.assignments === 1 ? '' : 's'} ` +
        `with ${previewCounts.items} checklist item${previewCounts.items === 1 ? '' : 's'} total.\n\n` +
        `Continue?`
      );
      if (!ok) return;
    }
    submittingRef.current = true;
    setBusy(true); setError('');
    try {
      // Upload all sheet files first; collect URL + storage path by
      // file NAME so we can look up both for each bedroom's chosen
      // sheet. file_path is also stored on the assignment so the
      // delete-assignment flow can clean up the storage object.
      const uploadedByName = {};
      for (const sf of sheetFiles) {
        const safe = sf.name.replace(/[^a-zA-Z0-9._-]/g, '_');
        const path = `assignments/${property.id}/${Date.now()}-${safe}`;
        const { error: upErr } = await supabase.storage.from('assignments').upload(path, sf);
        if (upErr) throw new Error('Sheet upload failed: ' + upErr.message);
        const { data: urlData } = supabase.storage.from('assignments').getPublicUrl(path);
        uploadedByName[sf.name] = {
          url: urlData?.publicUrl || null,
          path,
          kind: sf.type === 'application/pdf' ? 'pdf' : 'image',
          name: sf.name,
        };
      }

      // Determine the friendly assignment title from sheet type
      const titleBase = sheetType === 'cleaning_check'
        ? 'Cleaning check'
        : 'Move-out clean';

      // selectedPartyIds is computed at the top of submit (used by
      // the pre-create confirm). Reuse it here.
      const created = [];
      for (const partyId of selectedPartyIds) {
        const c = config[partyId];
        if (!c || c.mode === 'pass') continue;
        const party = parties.find(p => p.id === partyId);
        // Each bedroom's assignment lives at its own apartment. The
        // wizard supports cross-apartment selections so we look the
        // unit up from the party itself, not from a single state var.
        const partyUnit = units.find(u => u.id === party?.unit_id);
        if (!partyUnit) {
          throw new Error(`Couldn't find the apartment for ${party?.label || partyId}.`);
        }
        // Sheet for this bedroom. If the uploader picked a specific
        // sheet via the dropdown use that. Otherwise default to the
        // single uploaded sheet (if any). With zero sheets, no file
        // is attached.
        let bedroomSheet = null;
        if (c.sheetFileName && uploadedByName[c.sheetFileName]) {
          bedroomSheet = uploadedByName[c.sheetFileName];
        } else if (Object.keys(uploadedByName).length === 1) {
          bedroomSheet = uploadedByName[Object.keys(uploadedByName)[0]];
        }
        // Per-bedroom cleaning type. Defaults from sheet type.
        const cleaningType = c.cleaningType
          || (sheetType === 'cleaning_check' ? 'cleaning_check' : 'move_out_check');
        // Build the insert payload as a FRESH object literal so there's
        // zero possibility of a stale field sneaking in. Only the
        // schema's actual assignments columns are listed here, so any
        // accidental reference to unit_id / party_id / source from a
        // future refactor would not survive this rebuild. We also use
        // an explicit .select() column list below — never .select()
        // unqualified — to keep PostgREST's column resolution from
        // touching anything outside this list.
        const SAFE_COLS = {
          customer_id: property.id,
          title: `${titleBase} · ${partyUnit?.label || ''}${party?.label ? ' · ' + party.label : ''}`.trim(),
          notes: null,
          file_url: bedroomSheet?.url || null,
          file_path: bedroomSheet?.path || null,
          file_kind: bedroomSheet?.kind || null,
          assignment_type: cleaningType,
          active: true,
          uploaded_by: employee?.id || null,
          sheet_type: sheetType,
          template_set_id: templateSet?.id || null,
          bathroom_variant: c.bathroomVariant || null,
          general_variant: c.generalVariant || null,
          // PM-sourced assignments need owner approval before they
          // become visible to cleaners. Staff-sourced (no actorKind)
          // skip this step and take effect immediately.
          ...(isPmActor ? {
            source: 'pm',
            pm_status: 'pending',
            actor_kind: actorKind,
          } : {}),
        };
        const assignmentInsert = JSON.parse(JSON.stringify(SAFE_COLS));
        if (typeof console !== 'undefined') {
          console.log('[wizard] assignments insert FULL payload:', assignmentInsert);
        }
        const { data: created_assignment, error: aErr } = await supabase.from('assignments')
          .insert(assignmentInsert)
          // Explicit column list — never bare .select() — so PostgREST
          // doesn't try to resolve columns that aren't in our payload.
          .select('id, customer_id, title, file_url, file_kind, file_path, assignment_type, active, sheet_type, template_set_id, bathroom_variant, general_variant, uploaded_by, source, pm_status, actor_kind, created_at')
          .single();
        if (aErr) {
          if (typeof console !== 'undefined') {
            console.error('[wizard] assignment insert error RAW:', aErr);
          }
          throw new Error('Assignment insert failed: ' + aErr.message);
        }

        // Build the target rows — one per checked item
        const targetRows = [];
        Object.keys(c.checked).forEach(k => {
          const [sectionKey, itemKey] = k.split(':', 2);
          const row = {
            assignment_id: created_assignment.id,
            unit_id: partyUnit?.id || null,
            party_id: partyId,
            status: 'pending',
            template_section: sectionKey,
            template_item_key: itemKey,
          };
          // Custom (uploader-added) items carry their label in status_notes.
          if (itemKey && itemKey.startsWith('custom_') && c.customLabels && c.customLabels[k]) {
            row.status_notes = c.customLabels[k];
          }
          targetRows.push(row);
        });
        if (targetRows.length > 0) {
          const { error: tErr } = await supabase.from('assignment_targets').insert(targetRows);
          if (tErr) throw new Error('Target insert failed: ' + tErr.message);
        }
        created.push(created_assignment);
      }

      setSubmitted(true);
      // Brief pause so the cleaner sees the green progress bar before redirect
      setTimeout(() => onSaved(created), 800);
    } catch (e) {
      setError(e.message || 'Something went wrong.');
    } finally {
      setBusy(false);
      submittingRef.current = false;
    }
  };

  // Steps for the progress bar. Apartment + bedrooms are now ONE
  // combined step — after the uploader picks an apartment, the
  // bedrooms appear inline below the apartment list.
  //   0. Sheet upload (optional)
  //   1. Apartment + mode + bedrooms (multi: pick many, single: pick one)
  //   2. Sheet type (cleaning check / move-out clean)
  //   3. Configure each bedroom (sections + items)
  //   4. Review + submit
  const stepLabels = ['Sheet', 'Apartment', 'Type', 'Configure', 'Done'];

  // === Render ======================================================
  if (templateLoading) return <Splash text="Loading templates…" />;
  if (templateError) {
    return (
      <div className="min-h-screen bg-stone-50 px-5 py-6">
        <button onClick={onCancel} className="text-sm text-stone-600 mb-3">← Back</button>
        <div className="p-4 rounded-2xl bg-red-50 border border-red-200 text-red-700 text-sm">
          <div className="flex items-start gap-2"><AlertCircle size={16} className="flex-shrink-0 mt-0.5" />
            <div><div className="font-medium">Couldn't load templates</div><div className="text-xs mt-1">{templateError}</div></div>
          </div>
        </div>
      </div>
    );
  }

  // -----------------------------------------------------------------
  // Step 0 — Sheet uploads (optional, multiple allowed). The uploader
  // can attach one sheet per bedroom — cleaners will see all attached
  // sheets inside their assignment.
  // -----------------------------------------------------------------
  const renderSheetUpload = () => {
    return (
      <div>
        <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-1">Step 1 · Attach paper sheets (optional)</div>
        <div className="text-sm text-stone-600 mb-4">
          Take photos or attach PDFs of the inspection sheets. You can attach more than one — for example, one sheet per bedroom. Cleaners will see all sheets inside the assignment. Skip if you don't have them.
        </div>

        {/* Already-attached files */}
        {sheetFiles.length > 0 && (
          <div className="space-y-2 mb-3">
            {sheetFiles.map((f, idx) => {
              // Build a blob URL for both images and PDFs so quick-view
              // works for either kind. Reuse the image preview URL when
              // it already exists.
              const viewUrl = sheetPreviews[f.name] || (f.type ? URL.createObjectURL(f) : null);
              const isImage = f.type && f.type.startsWith('image/');
              const isRenaming = renamingIdx === idx;
              const suggestion = suggestedSheetName();
              return (
                <div key={`${f.name}-${idx}`} className="p-3 rounded-xl border border-emerald-300 bg-emerald-50">
                  <div className="flex items-center gap-3">
                    {isImage ? (
                      <img src={sheetPreviews[f.name]} alt="" className="w-12 h-12 rounded-lg object-cover flex-shrink-0" />
                    ) : (
                      <div className="w-12 h-12 rounded-lg bg-stone-200 flex items-center justify-center flex-shrink-0">
                        <FileText size={20} className="text-stone-500" />
                      </div>
                    )}
                    <div className="flex-1 min-w-0">
                      {isRenaming ? (
                        <input
                          autoFocus
                          value={renamingValue}
                          onChange={e => setRenamingValue(e.target.value)}
                          onBlur={() => {
                            renameSheetFile(idx, renamingValue);
                            setRenamingIdx(null);
                          }}
                          onKeyDown={e => {
                            if (e.key === 'Enter') {
                              renameSheetFile(idx, renamingValue);
                              setRenamingIdx(null);
                            }
                            if (e.key === 'Escape') {
                              setRenamingIdx(null);
                            }
                          }}
                          className="w-full px-2 py-1 rounded-md border border-emerald-400 bg-white text-sm text-stone-900" />
                      ) : (
                        <button
                          onClick={() => { setRenamingIdx(idx); setRenamingValue(f.name.replace(/\.[^.]+$/, '')); }}
                          className="text-sm font-medium text-emerald-900 truncate text-left w-full hover:underline"
                          title="Tap to rename">
                          {f.name}
                        </button>
                      )}
                      <div className="text-[10px] font-mono text-emerald-700 flex items-center gap-1 mt-0.5">
                        <span>{(f.size / 1024).toFixed(0)} KB · {f.type === 'application/pdf' ? 'PDF' : 'Image'}</span>
                        {/* Suggested name button — appears when bedrooms
                           are selected and the current name doesn't
                           already match the suggestion. One tap renames
                           the file. */}
                        {suggestion && !f.name.startsWith(suggestion) && (
                          <button
                            onClick={() => renameSheetFile(idx, suggestion)}
                            className="ml-1 px-1.5 py-0.5 rounded bg-emerald-200 text-emerald-900 hover:bg-emerald-300"
                            title="Rename using selected apartment/bedroom">
                            Use: {suggestion}
                          </button>
                        )}
                      </div>
                    </div>
                    {/* Rename pencil — alternate way to enter edit mode */}
                    <button
                      onClick={() => { setRenamingIdx(idx); setRenamingValue(f.name.replace(/\.[^.]+$/, '')); }}
                      className="p-2 rounded-lg hover:bg-emerald-100 text-emerald-700 flex-shrink-0"
                      title="Rename">
                      <Edit2 size={16} />
                    </button>
                    {/* Quick view: opens an overlay preview so the
                       uploader can confirm which sheet is which. Tap
                       the backdrop to close. */}
                    {viewUrl && (
                      <button onClick={() => setQuickView({ file: f, url: viewUrl })}
                        className="p-2 rounded-lg hover:bg-emerald-100 text-emerald-700 flex-shrink-0"
                        title="Quick view">
                        <Eye size={16} />
                      </button>
                    )}
                    <button onClick={() => removeSheetFile(idx)}
                      className="p-2 rounded-lg hover:bg-red-100 text-red-600 flex-shrink-0"
                      title="Remove">
                      <X size={16} />
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* Dropzone — always shown, lets uploader add more */}
        <label className="block">
          <input type="file" accept="image/*,application/pdf" className="hidden" multiple
            onChange={e => {
              // Snapshot files into a plain array FIRST. Setting
              // e.target.value below wipes e.target.files, so any
              // async (React state) read of it would get nothing.
              const snapshot = Array.from(e.target.files || []);
              e.target.value = ''; // allow re-picking the same file later
              addSheetFiles(snapshot);
            }} />
          <div className="px-4 py-6 rounded-2xl border-2 border-dashed border-stone-300 text-center text-stone-600 hover:border-stone-500 cursor-pointer">
            <Camera size={24} className="mx-auto mb-2 text-stone-400" />
            <div className="font-medium text-sm">
              {sheetFiles.length === 0 ? 'Tap to attach sheet photos or PDFs' : 'Add another sheet'}
            </div>
            <div className="text-xs mt-1 text-stone-500">
              {sheetFiles.length === 0 ? 'Or skip this step' : 'You can attach as many as you need'}
            </div>
          </div>
        </label>
      </div>
    );
  };

  // -----------------------------------------------------------------
  // Step 1 — Apartment + bedrooms
  //
  // Mode toggle FIRST. The apartment tree stays hidden until the
  // uploader picks Single or Multi mode. Once mode is picked, every
  // apartment in the property renders with its bedrooms inline as
  // checkbox cards (legacy style). Single mode: tapping a bedroom
  // replaces any previously checked bedroom across the whole tree.
  // Multi mode: tap freely, including across different apartments.
  // -----------------------------------------------------------------
  const renderUnitPicker = () => {
    // Filter apartments by the search text — applied to the LABEL
    const q = unitSearch.trim().toLowerCase();
    const visibleUnits = units.filter(u => !q || (u.label || '').toLowerCase().includes(q));
    // Map of unitId → its bedrooms (sorted by trailing number)
    const partiesByUnit = {};
    parties.forEach(p => {
      if (!partiesByUnit[p.unit_id]) partiesByUnit[p.unit_id] = [];
      partiesByUnit[p.unit_id].push(p);
    });
    Object.keys(partiesByUnit).forEach(k => {
      partiesByUnit[k].sort((a, b) => {
        const an = parseInt((a.label || '').match(/(\d+)/)?.[1] || '0', 10);
        const bn = parseInt((b.label || '').match(/(\d+)/)?.[1] || '0', 10);
        return an - bn;
      });
    });

    // "Select all bedrooms in this apartment" (multi mode only)
    const toggleAllInUnit = (unit) => {
      if (uploadMode !== 'multi') return;
      const ps = partiesByUnit[unit.id] || [];
      const allSelected = ps.length > 0 && ps.every(p => selectedParties[p.id]);
      setSelectedParties(prev => {
        const next = { ...prev };
        if (allSelected) {
          ps.forEach(p => { delete next[p.id]; });
        } else {
          ps.forEach(p => { next[p.id] = true; });
        }
        return next;
      });
      // Also seed config defaults for any newly selected bedrooms
      if (!allSelected) ps.forEach(p => ensureConfigShell(p.id));
    };

    return (
      <div>
        <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-1">Step 2 · Send to</div>
        <div className="text-sm text-stone-600 mb-2">
          Are you uploading for one bedroom or multiple bedrooms?
        </div>
        <div className="grid grid-cols-2 gap-2 mb-4">
          <button onClick={() => {
              // Switching modes clears selections + per-bedroom config.
              // In particular, 4 bedrooms checked in multi mode can't
              // survive a switch to single mode (which permits only 1).
              if (uploadMode !== 'single') {
                setSelectedParties({});
                setConfig({});
                setActivePartyId(null);
              }
              setUploadMode('single');
            }}
            className={`px-4 py-3 rounded-xl border-2 transition-colors ${uploadMode === 'single' ? 'bg-amber-50 border-amber-500 text-amber-900' : 'bg-white border-stone-200 text-stone-700'}`}>
            <div className="font-bold">Single bedroom</div>
            <div className="text-[10px] font-mono text-stone-500 mt-1">One person's checkout / spot check</div>
          </button>
          <button onClick={() => {
              if (uploadMode !== 'multi') {
                setSelectedParties({});
                setConfig({});
                setActivePartyId(null);
              }
              setUploadMode('multi');
            }}
            className={`px-4 py-3 rounded-xl border-2 transition-colors ${uploadMode === 'multi' ? 'bg-amber-50 border-amber-500 text-amber-900' : 'bg-white border-stone-200 text-stone-700'}`}>
            <div className="font-bold">Multiple bedrooms</div>
            <div className="text-[10px] font-mono text-stone-500 mt-1">Up to 4 roommates / full apartment</div>
          </button>
        </div>

        {/* Apartment tree — hidden until a mode is picked. Once visible
           it lives in a single scrollable region so nothing hides
           behind the action bar. */}
        {uploadMode && (
          <div className="border-t-2 border-stone-200 pt-4">
            <input value={unitSearch} onChange={e => setUnitSearch(e.target.value)}
              placeholder="Filter apartments…"
              className="w-full px-4 py-2.5 rounded-xl border border-stone-300 bg-white text-sm mb-3" />
            <div className="space-y-2">
              {visibleUnits.length === 0 && (
                <div className="text-center py-8 text-stone-400 text-sm">
                  {units.length === 0 ? 'No apartments set up for this property.' : 'No apartments match.'}
                </div>
              )}
              {visibleUnits.map(u => {
                const ps = partiesByUnit[u.id] || [];
                const someSelected = ps.some(p => selectedParties[p.id]);
                const allSelected = ps.length > 0 && ps.every(p => selectedParties[p.id]);
                return (
                  <div key={u.id} className={`bg-white rounded-xl border-2 p-3 ${someSelected ? 'border-amber-300' : 'border-stone-200'}`}>
                    {/* Apartment header — clickable in multi mode to
                       select/deselect all bedrooms in this apartment */}
                    <div className="flex items-center gap-2 mb-2">
                      {uploadMode === 'multi' ? (
                        <button onClick={() => toggleAllInUnit(u)}
                          className="flex items-center gap-2 flex-1 text-left">
                          <div className={`w-5 h-5 rounded border-2 flex items-center justify-center flex-shrink-0 ${
                            allSelected ? 'bg-amber-600 border-amber-600 text-white'
                            : someSelected ? 'bg-amber-100 border-amber-600'
                            : 'border-stone-300'
                          }`}>
                            {allSelected && <Check size={12} />}
                            {!allSelected && someSelected && <div className="w-2 h-2 bg-amber-600 rounded-sm" />}
                          </div>
                          <span className="text-sm font-bold text-stone-900">{u.label}</span>
                        </button>
                      ) : (
                        <span className="text-sm font-bold text-stone-900 flex-1">{u.label}</span>
                      )}
                      <span className="text-[10px] font-mono text-stone-500">
                        {ps.length} bedroom{ps.length === 1 ? '' : 's'}
                      </span>
                    </div>
                    {/* Bedrooms — 2-column grid like the legacy form.
                       Each checkbox is independently tappable so the
                       uploader can pick just the rooms that need work. */}
                    {ps.length > 0 && (
                      <div className="grid grid-cols-2 gap-1.5">
                        {ps.map(p => {
                          const checked = !!selectedParties[p.id];
                          const bathroomNum = bathroomNumberForBedroom(p.label);
                          return (
                            <button key={p.id} onClick={() => togglePartySelection(p.id)}
                              className={`flex items-center gap-2 px-2.5 py-2 rounded-lg border-2 text-left transition-colors ${
                                checked ? 'border-amber-600 bg-amber-50' : 'border-stone-200 bg-white hover:border-stone-400'
                              }`}>
                              <div className={`w-4 h-4 rounded border-2 flex items-center justify-center flex-shrink-0 ${checked ? 'border-amber-600 bg-amber-600 text-white' : 'border-stone-300'}`}>
                                {checked && <Check size={10} />}
                              </div>
                              <div className="min-w-0 flex-1">
                                <div className="text-xs font-medium text-stone-900 truncate">{p.label}</div>
                                {bathroomNum && (
                                  <div className="text-[9px] font-mono text-stone-500 truncate">Bath {bathroomNum}</div>
                                )}
                              </div>
                            </button>
                          );
                        })}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
            {/* Summary line at the bottom — shows what's selected so
               the uploader can scan before tapping Next. */}
            {Object.keys(selectedParties).filter(k => selectedParties[k]).length > 0 && (
              <div className="mt-3 p-3 rounded-xl bg-amber-50 border border-amber-200">
                <div className="text-[10px] uppercase tracking-wider font-mono text-amber-700 mb-1">
                  Creating {Object.keys(selectedParties).filter(k => selectedParties[k]).length} assignment{Object.keys(selectedParties).filter(k => selectedParties[k]).length === 1 ? '' : 's'}:
                </div>
                <div className="text-xs text-amber-900">
                  {Object.keys(selectedParties).filter(k => selectedParties[k]).map(id => {
                    const p = parties.find(x => x.id === id);
                    const u = units.find(uu => uu.id === p?.unit_id);
                    return `${u?.label || ''} · ${p?.label || ''}`;
                  }).join(', ')}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  const renderSheetTypePicker = () => {
    return (
      <div>
        <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-3">Step 3 · Which sheet type?</div>
        <div className="space-y-3">
          <button onClick={() => setSheetType('cleaning_check')}
            className={`w-full text-left p-4 rounded-2xl border-2 transition-colors ${sheetType === 'cleaning_check' ? 'bg-amber-50 border-amber-500' : 'bg-white border-stone-200 hover:border-stone-400'}`}>
            <div className="font-serif text-lg text-stone-900 font-bold">Cleaning check</div>
          </button>
          <button onClick={() => setSheetType('move_out_clean')}
            className={`w-full text-left p-4 rounded-2xl border-2 transition-colors ${sheetType === 'move_out_clean' ? 'bg-amber-50 border-amber-500' : 'bg-white border-stone-200 hover:border-stone-400'}`}>
            <div className="font-serif text-lg text-stone-900 font-bold">Move-out clean</div>
          </button>
        </div>
      </div>
    );
  };

  // -- Step 5: Configure ------------------------------------------------
  // Bedroom tabs across the top (sorted by bedroom number).
  // Inside each bedroom: Pass/Fail Entire toggle row + section tabs
  // (Bedroom / Vanity / Bathroom / General) with the active section's
  // content below. Section tabs reduce vertical scroll by collapsing
  // everything that isn't the active section.
  const renderConfigure = () => {
    const selectedIds = Object.keys(selectedParties).filter(k => selectedParties[k]);
    // Sort by apartment label first, then by bedroom number within
    // that apartment — so multi-apartment selections read naturally.
    const sortBedrooms = (a, b) => {
      const pa = parties.find(p => p.id === a);
      const pb = parties.find(p => p.id === b);
      const ua = units.find(u => u.id === pa?.unit_id);
      const ub = units.find(u => u.id === pb?.unit_id);
      const cmpUnit = naturalCompare(ua?.label || '', ub?.label || '');
      if (cmpUnit !== 0) return cmpUnit;
      const an = parseInt((pa?.label || '').match(/(\d+)/)?.[1] || '0', 10);
      const bn = parseInt((pb?.label || '').match(/(\d+)/)?.[1] || '0', 10);
      return an - bn;
    };
    const sortedIds = [...selectedIds].sort(sortBedrooms);
    // Show apartment label on tabs only if multiple apartments are selected
    const uniqueUnitIds = new Set(selectedIds.map(id => parties.find(p => p.id === id)?.unit_id));
    const showAptLabel = uniqueUnitIds.size > 1;

    return (
      <div>
        <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-1">Step 4 · Configure each bedroom</div>
        <div className="text-sm text-stone-600 mb-3">Tap a bedroom tab, then mark sections as passed or check the items that need cleaning.</div>

        {/* Which template is loaded — confirms move-out vs cleaning-check. */}
        <div className={`mb-3 px-3 py-2 rounded-lg text-[11px] font-mono flex items-center gap-2 ${templateSet?.sheet_type === 'move_out_clean' ? 'bg-emerald-50 text-emerald-800 border border-emerald-200' : 'bg-stone-100 text-stone-600'}`}>
          Template: {templateSet?.sheet_type === 'move_out_clean' ? 'Move-out (granular)' : (templateSet?.name || 'Cleaning-check / default')} · {items.length} items{templateLoading ? ' · loading…' : ''}
        </div>

        {/* Sheet strip — only shows when one or more sheets were
           uploaded in step 0. Lets the uploader quick-view each sheet
           and tap one to attach it to the currently active bedroom.
           Replaces the dropdown approach for assigning sheets. The
           dropdown still lives inside the bedroom config below for
           accessibility, but this strip is the faster path. */}
        {sheetFiles.length > 0 && (
          <div className="mb-3 p-2 bg-stone-100 rounded-xl">
            <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1.5 px-1">
              Sheets — tap card to assign to {parties.find(p => p.id === activePartyId)?.label || 'active bedroom'}
            </div>
            <div className="flex gap-2 overflow-x-auto pb-1">
              {sheetFiles.map((f, idx) => {
                const isImage = f.type && f.type.startsWith('image/');
                const previewUrl = sheetPreviews[f.name];
                const assignedToActive = activePartyId && config[activePartyId]?.sheetFileName === f.name;
                const isRenaming = renamingIdx === idx;
                return (
                  <div key={`${f.name}-${idx}`}
                    className={`flex-shrink-0 w-32 rounded-lg border-2 overflow-hidden bg-white transition-colors ${
                      assignedToActive ? 'border-amber-500' : 'border-stone-200'
                    }`}>
                    <button
                      onClick={() => {
                        // Tapping the body of the card toggles the
                        // assignment for the currently active bedroom.
                        if (!activePartyId) return;
                        const current = config[activePartyId]?.sheetFileName;
                        setSheetForBedroom(activePartyId, current === f.name ? null : f.name);
                      }}
                      className="w-full text-left">
                      <div className="aspect-[4/3] bg-stone-100 flex items-center justify-center">
                        {isImage && previewUrl ? (
                          <img src={previewUrl} alt={f.name} className="w-full h-full object-cover" />
                        ) : (
                          <FileText size={28} className="text-stone-400" />
                        )}
                      </div>
                    </button>
                    {/* Inline rename input OR truncated filename label */}
                    {isRenaming ? (
                      <input autoFocus
                        value={renamingValue}
                        onChange={e => setRenamingValue(e.target.value)}
                        onBlur={() => { renameSheetFile(idx, renamingValue); setRenamingIdx(null); }}
                        onKeyDown={e => {
                          if (e.key === 'Enter') { renameSheetFile(idx, renamingValue); setRenamingIdx(null); }
                          if (e.key === 'Escape') setRenamingIdx(null);
                        }}
                        className="w-full px-1.5 py-1 text-[10px] font-mono border-y border-stone-300 bg-white text-stone-900" />
                    ) : (
                      <div className="px-1.5 py-1 text-[10px] font-mono truncate text-stone-700">
                        {f.name}
                      </div>
                    )}
                    {/* Action row: quick view + rename + replace.
                       Replace opens a hidden file input so the user
                       can swap the image without re-doing the whole
                       upload step. The new file inherits the assigned
                       bedroom selection. */}
                    <div className="flex items-stretch border-t border-stone-200">
                      <button
                        onClick={() => setQuickView({ file: f, url: previewUrl || (f.type ? URL.createObjectURL(f) : null) })}
                        className="flex-1 py-1.5 hover:bg-stone-50 flex items-center justify-center"
                        title="Quick view">
                        <Eye size={12} className="text-stone-600" />
                      </button>
                      <div className="w-px bg-stone-200" />
                      <button
                        onClick={() => { setRenamingIdx(idx); setRenamingValue(f.name.replace(/\.[^.]+$/, '')); }}
                        className="flex-1 py-1.5 hover:bg-stone-50 flex items-center justify-center"
                        title="Rename">
                        <Edit2 size={12} className="text-stone-600" />
                      </button>
                      <div className="w-px bg-stone-200" />
                      <label
                        className="flex-1 py-1.5 hover:bg-stone-50 flex items-center justify-center cursor-pointer"
                        title="Replace">
                        <input type="file" accept="image/*,application/pdf" className="hidden"
                          onChange={e => {
                            const replacement = e.target.files?.[0];
                            e.target.value = '';
                            if (!replacement) return;
                            // Preserve the original NAME so any bedroom
                            // sheet assignments still point at the
                            // right entry. Wrap the new file with the
                            // existing name + extension.
                            const origName = f.name;
                            const wrapped = new File([replacement], origName, {
                              type: replacement.type,
                              lastModified: replacement.lastModified,
                            });
                            setSheetFiles(prev => {
                              const next = [...prev];
                              next[idx] = wrapped;
                              return next;
                            });
                          }} />
                        <Camera size={12} className="text-stone-600" />
                      </label>
                    </div>
                    <div className="px-1.5 py-1 text-[9px] font-mono text-center bg-stone-50 border-t border-stone-200">
                      {assignedToActive
                        ? <span className="text-amber-700">✓ assigned</span>
                        : <span className="text-stone-400">tap card</span>}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Bedroom tabs */}
        <div className="flex gap-2 mb-3 overflow-x-auto pb-1">
          {sortedIds.map(id => {
            const p = parties.find(x => x.id === id);
            const u = units.find(uu => uu.id === p?.unit_id);
            const c = config[id];
            const isActive = activePartyId === id;
            const isPass = c?.mode === 'pass';
            const isFailAll = c?.mode === 'fail_entire';
            const checkCount = c?.checked ? Object.keys(c.checked).length : 0;
            const passedSecs = Object.keys(c?.passedSections || {}).length;
            // Bedroom is incomplete if any of its 4 sections isn't done.
            // We surface the red dot on the tab itself so the uploader
            // can see WHICH bedrooms still need work without having to
            // click into each one. Mirrors the per-section dot logic
            // and is gated by nextAttempted for the same reason.
            const bedroomIncomplete = !sectionsForBedroomComplete(id).every(Boolean);
            const showBedroomError = nextAttempted && bedroomIncomplete;
            const labelExtra = isPass ? '· Pass'
              : isFailAll ? '· Fail all'
              : checkCount > 0 ? `· ${checkCount} items`
              : passedSecs > 0 ? `· ${passedSecs} passed`
              : '';
            return (
              <button key={id} onClick={() => setActivePartyId(id)}
                className={`relative px-3 py-2 rounded-xl border-2 text-sm whitespace-nowrap flex-shrink-0 transition-colors ${
                  isActive ? 'bg-amber-50 border-amber-500'
                  : isPass ? 'bg-emerald-50 border-emerald-300'
                  : isFailAll ? 'bg-red-50 border-red-300'
                  : 'bg-white border-stone-200'
                }`}>
                {showBedroomError && (
                  <span className="absolute top-1 right-1 w-2.5 h-2.5 rounded-full bg-red-500" title="Needs attention" />
                )}
                {showAptLabel && (
                  <div className="text-[9px] font-mono text-stone-500 uppercase tracking-wider">{u?.label}</div>
                )}
                <div className="font-mono font-bold text-stone-900">{p?.label}</div>
                <div className="text-[10px] font-mono text-stone-500">{labelExtra || ' '}</div>
              </button>
            );
          })}
        </div>
        {activePartyId && renderBedroomConfig(activePartyId)}
      </div>
    );
  };

  const renderBedroomConfig = (partyId) => {
    const c = config[partyId] || { mode: 'configure', checked: {}, passedSections: {} };
    const party = parties.find(x => x.id === partyId);
    const bathroomNum = bathroomNumberForBedroom(party?.label);
    const activeSection = c.activeSection || 'bedroom';

    // Helper to set the active section for THIS bedroom (stored on config)
    const setActiveSection = (key) => {
      setConfig(prev => ({
        ...prev,
        [partyId]: { ...(prev[partyId] || { mode: 'configure', checked: {} }), activeSection: key },
      }));
    };

    if (c.mode === 'pass') {
      return (
        <div className="p-4 rounded-2xl bg-emerald-50 border-2 border-emerald-500">
          <div className="flex items-center gap-2 mb-2">
            <div className="w-6 h-6 rounded-full bg-emerald-600 text-white flex items-center justify-center">
              <Check size={14} />
            </div>
            <div className="font-serif text-lg text-emerald-900 font-bold">Passed — no assignment</div>
          </div>
          <div className="text-sm text-emerald-800 mb-3">This bedroom doesn't need any cleaning. No assignment will be created for it.</div>
          <button onClick={() => setMode(partyId, 'pass')}
            className="px-3 py-2 rounded-lg bg-white border border-emerald-400 text-emerald-800 text-sm font-medium">
            Un-pass and configure instead
          </button>
        </div>
      );
    }

    // Section tabs definition. Bedroom and vanity have no variant; bathroom and
    // general use the variant set on the config.
    const sections = [
      { key: 'bedroom',  label: 'Bedroom',  variantKey: 'default' },
      { key: 'vanity',   label: 'Vanity',   variantKey: 'default' },
      { key: 'bathroom', label: 'Bathroom', variantKey: c.bathroomVariant },
      { key: 'general',  label: 'General',  variantKey: c.generalVariant },
    ];

    const passedSecs = c.passedSections || {};
    const failedSecs = c.failedSections || {};
    const checked = c.checked || {};

    // Count for tabs: items checked in this section
    const sectionCount = (key) => Object.keys(checked).filter(k => k.startsWith(`${key}:`)).length;

    const isPassMode = c.mode === 'pass'; // can't actually hit here but defensive
    const isFailMode = c.mode === 'fail_entire';

    return (
      <div className="space-y-3">
        {/* Cleaning type + sheet assignment row. Cleaning type defaults
           from the sheet type chosen at step 3 (cleaning_check →
           cleaning_check; move_out_clean → move_out_check) but the
           uploader can override per bedroom — useful when one bedroom
           needs a deep clean and another only needs a recheck. The
           dropdown is the existing ASSIGNMENT_TYPES list. */}
        <div className={`grid ${sheetFiles.length > 1 ? 'sm:grid-cols-2' : ''} gap-2`}>
          <div>
            <label className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1 block">Cleaning type</label>
            <select value={c.cleaningType || (sheetType === 'cleaning_check' ? 'cleaning_check' : 'move_out_check')}
              onChange={e => setCleaningType(partyId, e.target.value)}
              className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm">
              {ASSIGNMENT_TYPES.map(t => (
                <option key={t.value} value={t.value}>{t.label}</option>
              ))}
            </select>
          </div>
          {/* Per-bedroom sheet assignment — only shown when there's
             more than one sheet uploaded. With a single sheet it's
             auto-attached to every bedroom; with multiple, the
             uploader picks which one goes to which bedroom. */}
          {sheetFiles.length > 1 && (
            <div>
              <label className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1 block">Sheet for this bedroom</label>
              <select value={c.sheetFileName || ''}
                onChange={e => setSheetForBedroom(partyId, e.target.value || null)}
                className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm">
                <option value="">No sheet</option>
                {sheetFiles.map(f => (
                  <option key={f.name} value={f.name}>{f.name}</option>
                ))}
              </select>
            </div>
          )}
        </div>

        {/* Pass / Fail-Entire toggle row. Both buttons are clearly
           clickable and show pressed state when active. Clicking the
           active one again toggles it back off. */}
        <div className="flex gap-2">
          <button onClick={() => setMode(partyId, 'pass')}
            className={`flex-1 py-2.5 rounded-xl border-2 text-sm font-bold flex items-center justify-center gap-1.5 transition-colors ${
              isPassMode
                ? 'bg-emerald-600 border-emerald-700 text-white shadow-inner'
                : 'border-emerald-300 bg-emerald-50 hover:bg-emerald-100 text-emerald-800'
            }`}>
            <Check size={14} /> Pass — no work
          </button>
          <button onClick={() => setMode(partyId, 'fail_entire')}
            className={`flex-1 py-2.5 rounded-xl border-2 text-sm font-bold flex items-center justify-center gap-1.5 transition-colors ${
              isFailMode
                ? 'bg-red-600 border-red-700 text-white shadow-inner'
                : 'border-red-300 bg-red-50 hover:bg-red-100 text-red-800'
            }`}>
            <AlertCircle size={14} /> Fail entire bedroom
          </button>
        </div>
        {isFailMode && (
          <div className="text-[11px] font-mono text-red-700 -mt-1 px-1">
            All items in every section are checked. Tap again to clear.
          </div>
        )}

        {/* Section tabs (Bedroom / Vanity / Bathroom / General). A
           red dot appears on any section that isn't done yet — but
           only AFTER the uploader has tried to advance, so we don't
           scream at them on first arrival. */}
        <div className="flex gap-1 bg-stone-100 p-1 rounded-xl overflow-x-auto">
          {sections.map((s, idx) => {
            const cnt = sectionCount(s.key);
            const isPassed = !!passedSecs[s.key];
            const isFailed = !!(failedSecs || {})[s.key];
            const isActive = activeSection === s.key;
            const sectionDoneFlags = sectionsForBedroomComplete(partyId);
            const isIncomplete = !sectionDoneFlags[idx];
            const showError = nextAttempted && isIncomplete;
            return (
              <button key={s.key} onClick={() => setActiveSection(s.key)}
                className={`relative flex-1 min-w-fit py-2 px-3 rounded-lg text-xs font-medium whitespace-nowrap transition-colors ${
                  isActive
                    ? (isPassed ? 'bg-emerald-100 text-emerald-900 font-bold shadow-sm'
                       : isFailed ? 'bg-red-100 text-red-900 font-bold shadow-sm'
                       : 'bg-white text-stone-900 font-bold shadow-sm')
                    : (isPassed ? 'text-emerald-700'
                       : isFailed ? 'text-red-700'
                       : 'text-stone-600')
                }`}>
                {showError && (
                  <span className="absolute top-1 right-1 w-2 h-2 rounded-full bg-red-500" title="Needs an action" />
                )}
                <div>{s.label}</div>
                <div className="text-[9px] font-mono opacity-70">
                  {isPassed ? 'passed'
                   : isFailed ? 'failed all'
                   : cnt > 0 ? `${cnt} items`
                   : (showError ? 'needs action' : ' ')}
                </div>
              </button>
            );
          })}
        </div>

        {/* Active section content */}
        {renderSectionContent(partyId, activeSection, sections, bathroomNum)}
      </div>
    );
  };

  // Render the content for whichever section tab is active inside a
  // bedroom. For Bathroom and General, the variant picker shows above
  // the checklist; for Bedroom and Vanity, the checklist is universal.
  const renderSectionContent = (partyId, sectionKey, sections, bathroomNum) => {
    const c = config[partyId] || { checked: {}, passedSections: {}, failedSections: {} };
    const checked = c.checked || {};
    const passed = !!(c.passedSections || {})[sectionKey];
    const failed = !!(c.failedSections || {})[sectionKey];
    const section = sections.find(s => s.key === sectionKey);

    // Pick variant — bathroom and general need one before items render.
    const variantKey = sectionKey === 'bathroom' ? c.bathroomVariant
      : sectionKey === 'general' ? c.generalVariant
      : 'default';
    const variant = variantKey ? variantBySectionKey(sectionKey, variantKey) : null;
    const items = variant ? itemsForVariant(variant.id) : [];

    return (
      <div className="space-y-3">
        {/* Per-section Pass All / Fail All toggle row — mirrors the
           bedroom-level Pass/Fail row but scoped to this section. The
           cleaner can mark a section fully passed (no work) or fully
           failed (every item checked). Both are mutually exclusive.
           Tapping the active one again clears it. */}
        <div className="flex gap-2">
          <button onClick={() => toggleSectionPass(partyId, sectionKey)}
            className={`flex-1 py-2.5 rounded-xl border-2 text-sm font-bold flex items-center justify-center gap-1.5 transition-colors ${
              passed
                ? 'bg-emerald-600 border-emerald-700 text-white shadow-inner'
                : 'border-emerald-300 bg-emerald-50 hover:bg-emerald-100 text-emerald-800'
            }`}>
            <Check size={14} /> {passed ? `Passed all ${section?.label || ''}` : `Pass all ${section?.label || ''}`}
          </button>
          <button onClick={() => toggleSectionFail(partyId, sectionKey)}
            className={`flex-1 py-2.5 rounded-xl border-2 text-sm font-bold flex items-center justify-center gap-1.5 transition-colors ${
              failed
                ? 'bg-red-600 border-red-700 text-white shadow-inner'
                : 'border-red-300 bg-red-50 hover:bg-red-100 text-red-800'
            }`}>
            <AlertCircle size={14} /> {failed ? `Failed all ${section?.label || ''}` : `Fail all ${section?.label || ''}`}
          </button>
        </div>
        {passed && (
          <div className="text-[11px] font-mono text-emerald-700 -mt-1 px-1">
            Nothing to clean in {section?.label?.toLowerCase()} — tap again to clear.
          </div>
        )}
        {failed && (
          <div className="text-[11px] font-mono text-red-700 -mt-1 px-1">
            Every {section?.label?.toLowerCase()} item is checked. Tap again to clear.
          </div>
        )}

        {/* Variant picker for bathroom and general sections.
           IMPORTANT: still shown even when the section is passed or
           failed — the cleaner's responsibility for which general
           area (Kitchen, LR, Fridge, Vents) was theirs is metadata
           that matters separately from whether there was work. The
           Request modal later needs this variant to know what items
           the cleaner *could* request, even if nothing was assigned. */}
        {sectionKey === 'bathroom' && (
          <div className="p-3 rounded-xl bg-stone-50 border border-stone-200">
            <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-2">
              Bathroom responsibility{bathroomNum ? ` (this is Bathroom ${bathroomNum})` : ''}
              {!c.bathroomVariant && (
                <span className="ml-2 normal-case text-red-700 font-bold">· pick one</span>
              )}
            </div>
            <div className="flex gap-2">
              {variantsBySection('bathroom').map(v => (
                <button key={v.id} onClick={() => setBathroomVariantWithAutofill(partyId, v.variant_key)}
                  className={`flex-1 px-3 py-2 rounded-lg border-2 text-sm font-medium transition-colors ${c.bathroomVariant === v.variant_key ? 'bg-amber-50 border-amber-500 text-amber-900' : 'bg-white border-stone-200 text-stone-700'}`}>
                  {/* Rename "tub side" → "tub responsibility" per request */}
                  {v.label.replace(/ side$/i, ' responsibility')}
                </button>
              ))}
            </div>
          </div>
        )}
        {sectionKey === 'general' && (() => {
          // Variants already taken by OTHER bedrooms in the same
          // apartment. Each bedroom gets a UNIQUE General variant
          // (LR=A, Fridge=B, Vents=C, Kitchen=D) so we surface the
          // conflicts directly on the picker. Picking a taken
          // variant is allowed (UX is not blocking — submit
          // validation will catch it) but the button shows red so
          // the uploader can fix it before submitting.
          const thisParty = parties.find(p => p.id === partyId);
          const thisUnitId = thisParty?.unit_id;
          const takenByOthers = new Map(); // variantKey -> bedroomLabel
          if (thisUnitId) {
            Object.entries(config).forEach(([otherPid, oc]) => {
              if (otherPid === partyId) return;
              if (!oc?.generalVariant) return;
              if (oc?.mode === 'pass') return;
              const otherParty = parties.find(p => p.id === otherPid);
              if (!otherParty || otherParty.unit_id !== thisUnitId) return;
              if (!selectedParties[otherPid]) return;
              takenByOthers.set(oc.generalVariant, otherParty.label || otherPid);
            });
          }
          return (
            <div className="p-3 rounded-xl bg-stone-50 border border-stone-200">
              <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-2">
                General area
                {!c.generalVariant && (
                  <span className="ml-2 normal-case text-red-700 font-bold">· pick one</span>
                )}
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                {variantsBySection('general').map(v => {
                  const taken = takenByOthers.get(v.variant_key);
                  const isThis = c.generalVariant === v.variant_key;
                  const isConflict = taken && isThis;
                  return (
                    <button key={v.id} onClick={() => setGeneralVariant(partyId, v.variant_key)}
                      className={`text-left px-3 py-2 rounded-lg border-2 text-sm font-medium transition-colors ${
                        isConflict ? 'bg-red-50 border-red-400 text-red-900' :
                        isThis ? 'bg-amber-50 border-amber-500 text-amber-900' :
                        taken ? 'bg-stone-100 border-stone-300 text-stone-500' :
                        'bg-white border-stone-200 text-stone-700'
                      }`}>
                      <div className="flex items-center justify-between gap-2">
                        <span>{v.label}</span>
                        {taken && (
                          <span className="text-[9px] uppercase tracking-wider font-mono px-1.5 py-0.5 rounded-full bg-stone-200 text-stone-600 whitespace-nowrap">
                            {isThis ? 'CONFLICT' : taken}
                          </span>
                        )}
                      </div>
                    </button>
                  );
                })}
              </div>
              {!c.generalVariant && (
                <div className="mt-2 text-[11px] font-mono text-red-700">
                  Each bedroom in this apartment gets a unique General area.
                </div>
              )}
            </div>
          );
        })()}

        {/* Items checklist — only shown when section isn't passed AND
           variant is picked (for bathroom/general). */}
        {!passed && (
          variant ? (
            <div className="rounded-xl bg-white border-2 border-stone-200">
              <div className="px-3 py-2 border-b border-stone-200 bg-stone-50 flex items-center justify-between">
                <div className="font-serif text-sm text-stone-900 font-bold">{section.label} items</div>
                <div className="text-[10px] font-mono text-stone-500">
                  {items.filter(i => checked[`${sectionKey}:${i.item_key}`]).length}/{items.length}
                </div>
              </div>
              <div className="p-2 grid grid-cols-1 sm:grid-cols-2 gap-1 max-h-[50vh] overflow-y-auto">
                {items.map(item => {
                  const key = `${sectionKey}:${item.item_key}`;
                  const isChecked = !!checked[key];
                  return (
                    <button key={item.id} onClick={() => toggleItem(partyId, sectionKey, item.item_key)}
                      className={`w-full text-left px-2 py-2 rounded-lg flex items-center gap-2 transition-colors ${isChecked ? 'bg-amber-50' : 'hover:bg-stone-50'}`}>
                      <div className={`w-4 h-4 rounded border-2 flex items-center justify-center flex-shrink-0 ${isChecked ? 'bg-amber-600 border-amber-600 text-white' : 'border-stone-300'}`}>
                        {isChecked && <Check size={10} />}
                      </div>
                      <div className="text-xs text-stone-800 leading-snug">{item.label}</div>
                    </button>
                  );
                })}
                {/* Custom (uploader-added) items for this section */}
                {Object.keys(c.customLabels || {}).filter(k => k.startsWith(`${sectionKey}:`)).map(k => {
                  const isChecked = !!checked[k];
                  const itemKey = k.slice(sectionKey.length + 1);
                  return (
                    <div key={k} className={`w-full px-2 py-2 rounded-lg flex items-center gap-2 ${isChecked ? 'bg-amber-50' : 'bg-stone-50'}`}>
                      <button onClick={() => toggleItem(partyId, sectionKey, itemKey)} className="flex items-center gap-2 flex-1 text-left min-w-0">
                        <div className={`w-4 h-4 rounded border-2 flex items-center justify-center flex-shrink-0 ${isChecked ? 'bg-amber-600 border-amber-600 text-white' : 'border-stone-300'}`}>
                          {isChecked && <Check size={10} />}
                        </div>
                        <div className="text-xs text-stone-800 leading-snug truncate">{c.customLabels[k]}</div>
                      </button>
                      <button onClick={() => removeCustomItem(partyId, k)} className="p-0.5 rounded text-stone-400 hover:text-red-600 flex-shrink-0" title="Remove"><X size={13} /></button>
                    </div>
                  );
                })}
              </div>
              {/* Add a custom item not on the template — for this assignment only */}
              <div className="px-2 pb-2 pt-2 border-t border-stone-100 flex gap-2">
                <input
                  value={customText[`${partyId}:${sectionKey}`] || ''}
                  onChange={e => setCustomText(prev => ({ ...prev, [`${partyId}:${sectionKey}`]: e.target.value }))}
                  onKeyDown={e => { if (e.key === 'Enter') { addCustomItem(partyId, sectionKey, customText[`${partyId}:${sectionKey}`]); setCustomText(prev => ({ ...prev, [`${partyId}:${sectionKey}`]: '' })); } }}
                  placeholder="Add an item not on the list…"
                  className="flex-1 px-3 py-2 rounded-lg border border-stone-300 bg-white text-xs" />
                <button
                  onClick={() => { addCustomItem(partyId, sectionKey, customText[`${partyId}:${sectionKey}`]); setCustomText(prev => ({ ...prev, [`${partyId}:${sectionKey}`]: '' })); }}
                  className="px-3 py-2 rounded-lg bg-stone-900 text-white text-xs font-medium flex items-center gap-1 flex-shrink-0">
                  <Plus size={12} /> Add
                </button>
              </div>
            </div>
          ) : (
            <div className="p-3 rounded-xl bg-amber-50 border border-amber-200 text-sm text-amber-800">
              Pick {sectionKey === 'bathroom' ? 'a bathroom responsibility' : 'a general area'} above to see its items.
            </div>
          )
        )}
      </div>
    );
  };

  // -- Main render ------------------------------------------------------
  // pb-[136px] = action bar (~68px) + manager tab bar (~64px) so nothing
  // is hidden when the wizard renders inside ManagerShell, which has its
  // own bottom tab bar.
  return (
    <>
    <div className="min-h-screen bg-stone-50 pb-[136px]">
      <div className="px-5 py-4 border-b border-stone-200 bg-white sticky top-0 z-10">
        <div className="flex items-center gap-3 mb-3">
          <button onClick={() => { if (step > 0) setStep(step - 1); else onCancel(); }}
            className="p-2 -ml-2 rounded-full hover:bg-stone-100"
            title="Back">
            <ArrowLeft size={20} />
          </button>
          <div className="flex-1 min-w-0">
            <div className="text-xs uppercase tracking-wider font-mono text-stone-500">{property.name}</div>
            <div className="font-serif text-lg text-stone-900 font-bold">New checklist assignment</div>
          </div>
        </div>
        <ProgressBar steps={stepLabels} currentStep={step} complete={submitted}
          onStepClick={(targetStep) => { if (!submitted) setStep(targetStep); }} />
      </div>

      {/* Step content. The wizard root has pb-[136px] so the fixed
         action bar AND the manager tab bar below it don't hide any
         content. */}
      <div className="px-5 py-5">
        {step === 0 && renderSheetUpload()}
        {step === 1 && renderUnitPicker()}
        {step === 2 && renderSheetTypePicker()}
        {step === 3 && renderConfigure()}
        {step === 4 && (
          <div>
            <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-2">Step 5 · Review</div>
            <div className="space-y-2 mb-4">
              {sheetFiles.length > 0 && (
                <ReviewLine label="Sheets attached" value={
                  sheetFiles.length === 1 ? sheetFiles[0].name : `${sheetFiles.length} files`
                } />
              )}
              <ReviewLine label="Apartments" value={
                Array.from(new Set(
                  Object.keys(selectedParties)
                    .filter(k => selectedParties[k])
                    .map(k => {
                      const p = parties.find(x => x.id === k);
                      const u = units.find(uu => uu.id === p?.unit_id);
                      return u?.label;
                    })
                    .filter(Boolean)
                )).join(', ') || '—'
              } />
              <ReviewLine label="Mode" value={uploadMode === 'single' ? 'Single bedroom' : 'Multiple bedrooms'} />
              <ReviewLine label="Sheet type" value={sheetType === 'cleaning_check' ? 'Cleaning check' : 'Move-out clean'} />
              <ReviewLine label="Bedrooms" value={
                Object.keys(selectedParties).filter(k => selectedParties[k]).map(k => {
                  const p = parties.find(x => x.id === k);
                  const u = units.find(uu => uu.id === p?.unit_id);
                  const c = config[k];
                  const prefix = `${u?.label || ''} · ${p?.label || ''}`;
                  if (c?.mode === 'pass') return `${prefix} (Pass)`;
                  if (c?.mode === 'fail_entire') return `${prefix} (Fail all)`;
                  const n = c?.checked ? Object.keys(c.checked).length : 0;
                  const passedSecs = Object.keys(c?.passedSections || {}).length;
                  const parts = [];
                  if (n > 0) parts.push(`${n} items`);
                  if (passedSecs > 0) parts.push(`${passedSecs} sec. passed`);
                  return `${prefix} (${parts.join(', ') || 'no items'})`;
                }).join(', ')
              } />
            </div>
            {error && (
              <div className="mb-3 p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
                <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
              </div>
            )}
            {submitted && (() => {
              const assignmentCount = Object.keys(selectedParties)
                .filter(k => selectedParties[k] && config[k] && config[k].mode !== 'pass').length;
              const itemCount = Object.keys(selectedParties)
                .filter(k => selectedParties[k] && config[k] && config[k].mode !== 'pass')
                .reduce((sum, k) => sum + Object.keys(config[k].checked || {}).length, 0);
              return (
                <div className="mb-3 p-3 rounded-xl bg-emerald-50 border-2 border-emerald-300 text-emerald-800 text-sm font-medium flex items-center gap-2">
                  <Check size={16} />
                  <span>
                    Created {assignmentCount} assignment{assignmentCount === 1 ? '' : 's'} with {itemCount} checklist item{itemCount === 1 ? '' : 's'}. Returning to your list…
                  </span>
                </div>
              );
            })()}
          </div>
        )}
      </div>

      {/* Action bar — fixed above the manager tab bar (~64px tall)
         when this wizard renders inside ManagerShell. z-30 matches
      {/* Bottom action bar. Stays above the manager tab bar via the
         z-30 + bottom-[64px] offset. Back button is on the left so the
         user can step back one wizard step without hunting for the
         tiny arrow at the top header. */}
      <div className="fixed bottom-[64px] left-0 right-0 bg-white border-t border-stone-200 px-5 py-3 flex gap-2 z-30 shadow-[0_-4px_12px_rgba(0,0,0,0.06)]">
        <button
          onClick={() => { if (step > 0) setStep(step - 1); else onCancel(); }}
          className="px-4 py-3 rounded-xl bg-stone-100 hover:bg-stone-200 text-stone-700 text-sm font-medium flex items-center gap-1.5 active:scale-95">
          <ArrowLeft size={14} /> Back
        </button>
        {step < 4 && (
          <button
            onClick={() => {
              if (canAdvanceFromStep()) {
                setNextAttempted(false);
                setStep(step + 1);
              } else if (step === 3) {
                // On the configure step we let the button stay tappable
                // so the user gets visible feedback (red dots on the
                // section tabs). For other steps the disabled state is
                // still meaningful.
                setNextAttempted(true);
              }
            }}
            disabled={step !== 3 && !canAdvanceFromStep()}
            className={`flex-1 py-3 rounded-xl text-sm font-medium ${
              !canAdvanceFromStep() && step === 3
                ? 'bg-stone-400 text-stone-50'
                : 'bg-stone-900 text-stone-50 disabled:opacity-50'
            }`}>
            {step === 0 && sheetFiles.length === 0 ? 'Skip & continue'
              : step === 3 && !canAdvanceFromStep() ? 'Finish each section first'
              : 'Next'}
          </button>
        )}
        {step === 4 && !submitted && (
          <button onClick={submit} disabled={busy}
            className="flex-1 py-3 rounded-xl bg-emerald-600 hover:bg-emerald-700 text-white text-sm font-medium disabled:opacity-50">
            {busy ? 'Creating…' : 'Create assignments'}
          </button>
        )}
      </div>
    </div>
    {/* Sheet quick-view overlay — opened from the eye icon on any
       sheet card. Closes when the user taps outside the image. */}
    {quickView && (
      <SheetQuickViewModal file={quickView.file} url={quickView.url}
        onClose={() => setQuickView(null)} />
    )}
    </>
  );
}

function ReviewLine({ label, value }) {
  return (
    <div className="flex items-baseline gap-2 px-3 py-2 rounded-xl bg-white border border-stone-200">
      <span className="text-[10px] uppercase tracking-wider font-mono text-stone-500 w-24 flex-shrink-0">{label}</span>
      <span className="text-sm text-stone-900 break-words">{value}</span>
    </div>
  );
}

// =================================================================
// ASSIGNMENT DETAIL — full view for owner/manager
// =================================================================
function AssignmentDetail({ property, assignment: assignmentInit, employee, onBack }) {
  const [assignment, setAssignment] = useState(assignmentInit);
  const [targets, setTargets] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [busy, setBusy] = useState(false);
  const [confirmingDelete, setConfirmingDelete] = useState(false);

  const reload = async () => {
    const { data: a } = await supabase.from('assignments').select('*').eq('id', assignmentInit.id).maybeSingle();
    if (a) setAssignment(a);
    const { data: ts, error: tErr } = await supabase
      .from('assignment_targets')
      .select('*, unit:units(label), party:parties(label, full_name), completer:employees!completed_by(name), assignedTo:employees!assigned_to(id, name)')
      .eq('assignment_id', assignmentInit.id);
    if (tErr) console.error('[AssignmentDetail] targets load error:', tErr);
    setTargets(ts || []);
    // Load employees for the assign-to dropdown (active only)
    const { data: emps } = await supabase.from('employees')
      .select('id, name, role').eq('active', true)
      .in('role', ['employee', 'manager']).order('name');
    setEmployees(emps || []);
    setLoaded(true);
  };

  // Toggle priority on a single target — instant DB write + local update.
  const togglePriority = async (target) => {
    const next = !target.priority;
    setTargets(prev => prev.map(t => t.id === target.id ? { ...t, priority: next } : t));
    const { error } = await supabase.from('assignment_targets')
      .update({ priority: next }).eq('id', target.id);
    if (error) {
      alert('Could not update priority: ' + error.message);
      setTargets(prev => prev.map(t => t.id === target.id ? { ...t, priority: !next } : t));
    }
  };

  // Change assignee on a single target. Empty string = unassign (anyone).
  const updateAssignee = async (target, employeeId) => {
    const newAssigneeId = employeeId || null;
    const newAssignee = newAssigneeId ? employees.find(e => e.id === newAssigneeId) : null;
    setTargets(prev => prev.map(t => t.id === target.id
      ? { ...t, assigned_to: newAssigneeId, assignedTo: newAssignee || null }
      : t));
    const { error } = await supabase.from('assignment_targets')
      .update({ assigned_to: newAssigneeId }).eq('id', target.id);
    if (error) {
      alert('Could not update assignee: ' + error.message);
      reload(); // rollback by reloading
    }
  };
  useEffect(() => { reload(); /* eslint-disable-next-line */ }, []);
  useAssignmentSync(reload, 'asgn-detail');

  const deleteAssignment = async () => {
    setBusy(true);
    // SOFT delete — stamp deleted_at/deleted_by instead of removing the
    // row, so a mistaken delete can be undone. We intentionally do NOT
    // remove the storage file or the target rows; a restore just clears
    // deleted_at. A future purge job hard-deletes old soft-deleted ones.
    const { error } = await supabase.from('assignments')
      .update({ deleted_at: new Date().toISOString(), deleted_by: employee?.id || null })
      .eq('id', assignment.id);
    setBusy(false);
    if (error) { alert('Could not delete: ' + error.message); return; }
    onBack();
  };

  const sortedTargets = (targets || []).slice().sort((a, b) => {
    const ua = a.unit?.label || ''; const ub = b.unit?.label || '';
    if (ua !== ub) return naturalCompare(ua, ub);
    return naturalCompare(a.party?.label || '', b.party?.label || '');
  });

  return (
    <div className="pb-24">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div className="flex-1 min-w-0">
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono truncate">{property.name}</div>
          <div className="font-serif text-xl text-stone-900 truncate">{assignment.title}</div>
        </div>
      </div>
      {(assignment.assignment_type || assignment.scheduled_date) && (
        <div className="flex gap-2 flex-wrap px-5 pt-3">
          <AssignmentTypeChip type={assignment.assignment_type} />
          {assignment.scheduled_date && (
            <span className="inline-flex items-center gap-1 px-2.5 py-1 rounded-full bg-stone-200 text-stone-800 text-xs font-mono">
              <Calendar size={11} /> {fmtDateWithDay(assignment.scheduled_date)}
            </span>
          )}
        </div>
      )}
      <div className="px-5 pt-4 space-y-2">
        <SpanishTranslationPanel assignment={assignment} viewerRole={employee?.role} />
        <TranslateButton texts={
          assignment.extracted_text && assignment.extracted_text.trim()
            ? [assignment.title, assignment.notes, assignment.extracted_text].filter(Boolean)
            : [assignment.title, assignment.notes].filter(Boolean)
        } />
      </div>
      <div className="px-5 pt-4 space-y-5">
        {/* Document preview/link */}
        <div className="p-4 rounded-2xl bg-white border border-stone-200">
          <div className="flex items-center gap-3 mb-3">
            {assignment.file_kind === 'pdf'
              ? <FileText size={20} className="text-stone-600" />
              : <ImageIcon size={20} className="text-stone-600" />}
            <div className="flex-1">
              <div className="font-serif text-base text-stone-900">Assignment file</div>
              <div className="text-xs text-stone-500 font-mono">{assignment.file_kind?.toUpperCase()} · uploaded {fmtDate(assignment.created_at)}</div>
            </div>
          </div>
          {assignment.file_kind === 'image' && (
            <img loading="lazy" src={assignment.file_url} alt="" className="w-full max-h-[60vh] object-contain rounded-xl mb-3 bg-stone-100" />
          )}
          <a href={assignment.file_url} target="_blank" rel="noreferrer"
            className="w-full inline-flex items-center justify-center gap-2 py-2.5 rounded-xl bg-stone-900 text-stone-50 text-sm font-medium">
            <Eye size={14} /> Open in new tab
          </a>
        </div>

        {/* Notes */}
        {assignment.notes && (
          <div className="p-4 rounded-2xl bg-amber-50 border border-amber-200">
            <div className="text-xs uppercase tracking-wider font-mono text-amber-700 mb-1">Notes</div>
            <div className="text-sm text-stone-800 whitespace-pre-wrap">{assignment.notes}</div>
          </div>
        )}

        {/* Targets list */}
        <div>
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-3">
            Targets ({targets.length})
          </div>
          {!loaded ? <Splash text="Loading…" /> : sortedTargets.length === 0 ? (
            <div className="text-center py-8 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
              No targets.
            </div>
          ) : (
            <div className="space-y-2">
              {sortedTargets.map(t => {
                const s = ASSIGNMENT_STATUSES[t.status] || ASSIGNMENT_STATUSES.pending;
                return (
                  <div key={t.id} className="p-3 rounded-xl bg-white border border-stone-200">
                    <div className="flex items-start justify-between gap-2 flex-wrap">
                      <div className="flex-1 min-w-0">
                        <div className="font-serif text-base text-stone-900">
                          {t.unit?.label ? <>{t.unit.label}{t.party?.label ? ` · ${t.party.label}` : ''}</> : 'Whole property'}
                        </div>
                        {t.party?.full_name && <div className="text-xs text-stone-500">{t.party.full_name}</div>}
                        {t.status_notes && (
                          <div className="text-xs text-stone-600 italic mt-1">"{t.status_notes}"</div>
                        )}
                        {t.completed_at && (
                          <div className="text-xs text-stone-500 font-mono mt-1">
                            Done {fmtDateWithDay(t.completed_at)}{t.completer?.name && ` by ${t.completer.name}`}
                          </div>
                        )}
                      </div>
                      <span className={`text-[10px] uppercase tracking-wider font-mono px-2 py-1 rounded-full border ${s.color}`}>
                        {s.label}
                      </span>
                    </div>
                    {/* Owner controls for priority + assignee. Hidden when
                       the target is already done (no point flagging done
                       work as priority). */}
                    {t.status !== 'done' && (
                      <div className="mt-2 pt-2 border-t border-stone-100 flex items-center gap-2 flex-wrap">
                        <button onClick={() => togglePriority(t)}
                          className={`text-[10px] uppercase tracking-wider font-mono px-2 py-1 rounded-full inline-flex items-center gap-1 transition-colors ${t.priority ? 'bg-red-100 text-red-800 border border-red-300 font-bold' : 'bg-stone-100 text-stone-500 border border-stone-200 hover:bg-stone-200'}`}>
                          <AlertCircle size={10} /> {t.priority ? 'Priority' : 'Mark priority'}
                        </button>
                        <select value={t.assigned_to || ''}
                          onChange={(e) => updateAssignee(t, e.target.value)}
                          className="text-[10px] uppercase tracking-wider font-mono px-2 py-1 rounded-full bg-white border border-stone-300 text-stone-700">
                          <option value="">Assign to: Anyone</option>
                          {employees.map(emp => (
                            <option key={emp.id} value={emp.id}>{emp.name}{emp.role === 'manager' ? ' (manager)' : ''}</option>
                          ))}
                        </select>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Delete — gated behind the manage_assignments_admin
           capability. Owners always have it; others need it granted
           in their permissions. Soft delete, so it's recoverable. */}
        {can(employee, 'manage_assignments_admin') && (
        <div className="pt-4 border-t border-stone-200">
          {!confirmingDelete ? (
            <button onClick={() => setConfirmingDelete(true)}
              className="w-full py-3 rounded-2xl border-2 border-red-200 text-red-700 text-sm font-medium flex items-center justify-center gap-2">
              <Trash2 size={14} /> Delete this assignment
            </button>
          ) : (
            <DeleteConfirmModal
              title="Delete this assignment?"
              description="This hides the assignment from cleaners and the assignments list. It's recoverable — nothing is permanently erased, so you can restore it later if this was a mistake."
              itemSummary={assignment.title}
              busy={busy}
              onConfirm={deleteAssignment}
              onClose={() => setConfirmingDelete(false)} />
          )}
        </div>
        )}
      </div>
    </div>
  );
}

// =================================================================
// CLEANER-SIDE: AssignmentBanner shows pending assignments for the
// current context (unit + party, or whole property).
// onUpdate is called after a status change so parent can refresh.
// =================================================================
// AssignmentBanner — inline list of assignments for a given context.
// Props:
//   propertyId, unitId, partyId — what context to filter by
//   employee — current user
//   showDone — if true, includes done assignments
//   onUpdate — called after any status change so parent can refresh
function AssignmentBanner({ propertyId, unitId, partyId, employee, showDone = false, onUpdate, onOpenBedroomHistory }) {
  const [targets, setTargets] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [opened, setOpened] = useState(null);
  const [statusModal, setStatusModal] = useState(null);
  const [reassignTarget, setReassignTarget] = useState(null);
  const [busy, setBusy] = useState(false);
  const [collapsed, setCollapsed] = useState(false);
  const [editDueId, setEditDueId] = useState(null);
  const canEditDatesB = can(employee, 'edit_due_dates');
  const todayKeyG = localTodayKey();
  const saveDueB = async (id, date) => {
    setEditDueId(null);
    if (id) { await supabase.from('assignments').update({ scheduled_date: date || null }).eq('id', id); load(); }
  };

  const load = async () => {
    let q = supabase
      .from('assignment_targets')
      .select('*, assignment:assignments!inner(id, title, notes, file_url, file_kind, customer_id, active, source, pm_status, deleted_at, extracted_text, spanish_translation, translation_status, template_set_id, sheet_type, bathroom_variant, general_variant, assignment_type, scheduled_date, created_at), unit:units(id, label), party:parties(id, label), starter:employees!started_by(name), completer:employees!completed_by(name), assignedTo:employees!assigned_to(id, name)');

    if (!showDone) q = q.not('status', 'in', '(done,blocked)');

    if (unitId && partyId) {
      q = q.or(`and(unit_id.eq.${unitId},party_id.eq.${partyId}),and(unit_id.is.null,party_id.is.null)`);
    } else if (unitId) {
      q = q.or(`unit_id.eq.${unitId},and(unit_id.is.null,party_id.is.null)`);
    } else {
      q = q.is('unit_id', null).is('party_id', null);
    }

    const { data, error } = await q;
    if (error) {
      console.error('[AssignmentBanner] load error:', error);
    }
    // Hide non-approved PM assignments from cleaners — they should only see what's approved
    const filtered = (data || []).filter(t =>
      t.assignment?.customer_id === propertyId &&
      t.assignment?.active &&
      !t.assignment?.deleted_at &&
      (t.assignment?.source !== 'pm' || t.assignment?.pm_status === 'approved')
    );
    // Priority items first, then by status (pending/in_progress before done)
    filtered.sort((a, b) => {
      const ap = a.priority ? 1 : 0;
      const bp = b.priority ? 1 : 0;
      if (ap !== bp) return bp - ap;
      return 0;
    });
    setTargets(filtered);
    setLoaded(true);
  };
  useEffect(() => { load(); /* eslint-disable-next-line */ }, [propertyId, unitId, partyId, showDone]);
  useAssignmentSync(load, 'asgn-banner');

  const updateStatus = async (target, newStatus, statusNotes) => {
    // Snapshot of values used for both the optimistic update AND the DB
    // patch. By computing them up front we avoid a race where the user
    // double-taps and the second click captures a stale target.
    const completedNow = newStatus === 'done' ? new Date().toISOString() : null;
    const startedNow = (newStatus === 'in_progress' && !target.started_at)
      ? new Date().toISOString() : null;
    const wasDone = target.status === 'done';

    // OPTIMISTIC UPDATE — flip the local UI immediately so the cleaner
    // never sees a "click did nothing" gap. The DB write below makes it
    // durable; realtime sync corrects any divergence. Done is a hard
    // commit: nothing in this code path can put it back to pending /
    // paused / in_progress without an explicit user action.
    setTargets(prev => prev.map(t => {
      if (t.id !== target.id) return t;
      const next = { ...t, status: newStatus };
      if (newStatus === 'in_progress') {
        if (!t.started_at) next.started_at = startedNow;
        next.started_by = employee?.id || null;
      }
      if (newStatus === 'done') {
        next.completed_at = completedNow;
        next.completed_by = employee?.id || null;
      } else if (wasDone) {
        // Re-opening a done assignment wipes completion
        next.completed_at = null;
        next.completed_by = null;
      }
      if (newStatus === 'pending' && (t.status === 'paused' || t.status === 'in_progress' || t.status === 'blocked')) {
        next.started_at = null;
        next.started_by = null;
      }
      if (statusNotes !== undefined) next.status_notes = statusNotes || null;
      return next;
    }));

    setBusy(true);
    // Auto-handoff: if cleaner is starting a new assignment and they have an OTHER
    // in_progress assignment on a different bedroom, mark that one done first.
    if (newStatus === 'in_progress' && employee?.id) {
      try {
        const { data: otherActive } = await supabase
          .from('assignment_targets')
          .select('id, unit_id, party_id')
          .eq('status', 'in_progress')
          .eq('started_by', employee.id)
          .neq('id', target.id);
        const switching = (otherActive || []).filter(o =>
          // Only auto-finish if it's on a DIFFERENT bedroom
          o.unit_id !== target.unit_id || o.party_id !== target.party_id
        );
        if (switching.length > 0) {
          const nowIso = new Date().toISOString();
          await supabase.from('assignment_targets')
            .update({ status: 'done', completed_at: nowIso, completed_by: employee.id })
            .in('id', switching.map(s => s.id));
        }
      } catch (e) {
        console.warn('[auto-handoff] failed', e);
      }
    }
    const patch = { status: newStatus };
    if (newStatus === 'in_progress') {
      if (!target.started_at) patch.started_at = startedNow;
      patch.started_by = employee?.id || null;
    }
    if (newStatus === 'done') {
      patch.completed_at = completedNow;
      patch.completed_by = employee?.id || null;
    } else if (wasDone) {
      patch.completed_at = null;
      patch.completed_by = null;
    }
    // Move-to-pending from any started/in-progress/paused state should
    // clear the started_by/started_at so the assignment appears fully
    // unstarted in the Pending tab — matches the "undo a mistaken start"
    // mental model. Without this the Pending card would still show
    // "Started by X" which is misleading.
    if (newStatus === 'pending' && (target.status === 'paused' || target.status === 'in_progress' || target.status === 'blocked')) {
      patch.started_at = null;
      patch.started_by = null;
    }
    if (statusNotes !== undefined) patch.status_notes = statusNotes || null;

    const { error } = await supabase.from('assignment_targets').update(patch).eq('id', target.id);
    setBusy(false);
    if (error) {
      // Roll back optimistic on failure — keep the user truthful
      setTargets(prev => prev.map(t => t.id === target.id ? target : t));
      alert('Could not update: ' + error.message);
      return;
    }
    setStatusModal(null);
    load();
    if (onUpdate) onUpdate();
  };

  // Flip the priority flag on a single target. Per-target (not per-
  // assignment) since AssignmentCard shows one card per target. Owners
  // can toggle right from the capsule without opening the detail.
  const togglePriority = async (target) => {
    const next = !target.priority;
    setTargets(prev => prev.map(t => t.id === target.id ? { ...t, priority: next } : t));
    const { error } = await supabase.from('assignment_targets')
      .update({ priority: next }).eq('id', target.id);
    if (error) {
      alert('Could not update priority: ' + error.message);
      setTargets(prev => prev.map(t => t.id === target.id ? { ...t, priority: !next } : t));
    } else if (onUpdate) {
      onUpdate();
    }
  };

  // Bulk wrappers — used by the bedroom-level summary card so
  // Mark complete / Mark priority / Blocked work across every item
  // in a single tap. Optimistic + single DB write per action.
  const bulkUpdateStatus = async (rows, newStatus, statusNotes) => {
    if (!rows || rows.length === 0) return;
    const ids = rows.map(r => r.id);
    setTargets(prev => prev.map(t => ids.includes(t.id) ? { ...t, status: newStatus } : t));
    setBusy(true);
    const patch = { status: newStatus };
    if (newStatus === 'in_progress') {
      patch.started_at = new Date().toISOString();
      patch.started_by = employee?.id || null;
    }
    if (newStatus === 'done') {
      patch.completed_at = new Date().toISOString();
      patch.completed_by = employee?.id || null;
    } else {
      patch.completed_at = null; patch.completed_by = null;
    }
    if (newStatus === 'pending') { patch.started_at = null; patch.started_by = null; }
    if (statusNotes !== undefined) patch.status_notes = statusNotes || null;
    const { error } = await supabase.from('assignment_targets').update(patch).in('id', ids);
    setBusy(false);
    if (error) { load(); alert('Could not update: ' + error.message); return; }
    if (onUpdate) onUpdate();
    load();
  };
  const bulkTogglePriority = async (rows) => {
    if (!rows || rows.length === 0) return;
    const anyOn = rows.some(r => r.priority);
    const next = !anyOn;
    const ids = rows.map(r => r.id);
    setTargets(prev => prev.map(t => ids.includes(t.id) ? { ...t, priority: next } : t));
    const { error } = await supabase.from('assignment_targets').update({ priority: next }).in('id', ids);
    if (error) { alert('Could not update priority: ' + error.message); load(); }
    else if (onUpdate) onUpdate();
  };

  if (!loaded || targets.length === 0) return null;

  // Group checklist-style targets (template_set_id is set) under their
  // parent assignment so the banner shows ONE card per inspection
  // sheet instead of one per item. Legacy targets (no template) stay
  // as individual cards because each IS the unit of work.
  // Returns: { groups: [{ assignment, items: [...], legacy: bool }] }
  const buildGroups = (list) => {
    const byAssignmentId = new Map();
    list.forEach(t => {
      const aid = t.assignment?.id;
      const isChecklist = !!t.assignment?.template_set_id;
      const key = isChecklist ? `cl:${aid}` : `lg:${t.id}`;
      if (!byAssignmentId.has(key)) {
        byAssignmentId.set(key, {
          key,
          assignment: t.assignment,
          isChecklist,
          items: [],
          // Use the first target as the "representative" for actions
          // like View doc / start-by-section that operate at parent level.
          representative: t,
        });
      }
      byAssignmentId.get(key).items.push(t);
    });
    return Array.from(byAssignmentId.values());
  };

  return (
    <div className="mx-2 sm:mx-4 mt-4 p-3 sm:p-4 rounded-2xl bg-blue-50 border-2 border-blue-200">
      <button onClick={() => setCollapsed(c => !c)}
        className={`w-full flex items-center gap-2 active:opacity-80 ${collapsed ? '' : 'mb-3'}`}>
        <FileText size={16} className="text-blue-700 flex-shrink-0" />
        <span className="text-xs uppercase tracking-wider text-blue-800 font-mono flex-1 text-left">
          {(() => {
            const groups = buildGroups(targets);
            const assignmentCount = groups.length;
            return `${assignmentCount} assignment${assignmentCount === 1 ? '' : 's'} · ${targets.length} item${targets.length === 1 ? '' : 's'}`;
          })()}
        </span>
        <ChevronRight size={14} className={`text-blue-700 transition-transform ${collapsed ? '' : 'rotate-90'}`} />
      </button>
      {!collapsed && (() => {
        const groups = buildGroups(targets);
        // Split priority and non-priority so the visual divider matches
        // the rest of the app — priority items live at the top, then a
        // small "everything else" separator. A group is "priority" if
        // ANY of its items are priority + not done. Legacy (single
        // target) groups behave exactly as before.
        const groupIsPriority = (g) => g.items.some(t => t.priority && t.status !== 'done');
        const priorityGroups = groups.filter(groupIsPriority);
        const restGroups = groups.filter(g => !groupIsPriority(g));
        // Render a LEGACY group as its single card (existing behavior).
        // Render a CHECKLIST group as a summary card with item counts
        // and a "View items" button that opens ChecklistAssignmentView.
        const renderGroup = (g) => {
          if (!g.isChecklist) return renderCard(g.items[0]);
          return renderChecklistGroupCard(g);
        };
        const renderCard = (t) => (
          <AssignmentCard key={t.id} target={t} busy={busy} propertyId={propertyId}
            onView={() => setOpened(t)}
            onStart={() => updateStatus(t, 'in_progress')}
            onPause={() => updateStatus(t, 'paused')}
            onMoveToPending={() => updateStatus(t, 'pending')}
            onDone={() => updateStatus(t, 'done')}
            onReopen={() => updateStatus(t, 'pending')}
            onBlocked={() => setStatusModal({ target: t })}
            onReassign={() => setReassignTarget(t)}
            onTogglePriority={togglePriority}
              canMarkDone={can(employee, 'mark_assignments_done') || t.started_by === employee?.id}
              canMarkDoneAlways={can(employee, 'mark_assignments_done')}
              currentEmployeeId={employee?.id}
              canEditDates={can(employee, 'edit_due_dates')}
              onSetDueDate={async (aid, date) => { if (aid) { await supabase.from('assignments').update({ scheduled_date: date }).eq('id', aid); load(); } }}
            onOpenBedroomHistory={onOpenBedroomHistory} />
        );
        // Checklist group card: ONE card representing a whole inspection
        // sheet. Shows progress + a View items button. Tapping View
        // items opens ChecklistAssignmentView with full per-item
        // controls. Pause / Start operate on ALL items in the group.
        const renderChecklistGroupCard = (g) => {
          const a = g.assignment;
          const items = g.items;
          const rep = g.representative;
          const counts = {
            pending:     items.filter(i => i.status === 'pending').length,
            in_progress: items.filter(i => i.status === 'in_progress').length,
            done:        items.filter(i => i.status === 'done').length,
            paused:      items.filter(i => i.status === 'paused').length,
            blocked:     items.filter(i => i.status === 'blocked').length,
          };
          const total = items.length;
          const isAllDone = counts.done === total;
          // Section breakdown — "57 items · Bedroom (16) · Vanity (12) · …"
          const sectionCounts = {
            bedroom:  items.filter(i => (i.template_section || '').toLowerCase() === 'bedroom').length,
            vanity:   items.filter(i => (i.template_section || '').toLowerCase() === 'vanity').length,
            bathroom: items.filter(i => (i.template_section || '').toLowerCase() === 'bathroom').length,
            general:  items.filter(i => (i.template_section || '').toLowerCase() === 'general').length,
          };
          const knownSectioned = sectionCounts.bedroom + sectionCounts.vanity + sectionCounts.bathroom + sectionCounts.general;
          const otherCount = total - knownSectioned;
          const sectionBits = [];
          if (sectionCounts.bedroom)  sectionBits.push(`Bedroom (${sectionCounts.bedroom})`);
          if (sectionCounts.vanity)   sectionBits.push(`Vanity (${sectionCounts.vanity})`);
          if (sectionCounts.bathroom) sectionBits.push(`Bathroom (${sectionCounts.bathroom})`);
          if (sectionCounts.general)  sectionBits.push(`General (${sectionCounts.general})`);
          if (otherCount > 0)         sectionBits.push(`Other (${otherCount})`);
          // Aggregated priority + status for the chips on the right
          const anyPriority = items.some(i => i.priority);
          const statusOrder = ['pending', 'in_progress', 'paused', 'blocked', 'done'];
          const dominantStatus = statusOrder.find(s => items.some(i => i.status === s)) || 'pending';
          const statusPill = ASSIGNMENT_STATUSES[dominantStatus] || ASSIGNMENT_STATUSES.pending;
          // Item-level rows the cleaner can act on in BULK
          const openItems = items.filter(i => i.status !== 'done');
          return (
            <div key={g.key} className="p-3 sm:p-4 rounded-xl bg-white border border-stone-200">
              {/* === HEADER: bedroom title + chips on right ===
                 Layout mirrors the AssignmentList card exactly so
                 the cleaner sees the same chrome everywhere. */}
              <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-1.5 sm:gap-2 mb-2">
                <div className="flex-1 min-w-0">
                  {(rep?.unit?.label || rep?.party?.label) ? (
                    <div className="font-serif text-lg text-stone-900 leading-tight break-words">
                      <span className="font-bold">{rep?.unit?.label || 'No unit'}</span>
                      {rep?.party?.label && (
                        <>
                          <span className="text-stone-400 mx-1.5">·</span>
                          <span className="italic">{rep.party.label}</span>
                        </>
                      )}
                    </div>
                  ) : (
                    <div className="font-serif text-lg text-stone-900 font-bold">Checklist assignment</div>
                  )}
                </div>
                <div className="flex flex-col sm:flex-row sm:items-center gap-1.5 flex-shrink-0 sm:max-w-[60%]">
                  {/* Mini-row 1: Priority + status — Mark Priority is
                     a bulk toggle here since the card represents N items. */}
                  <div className="flex items-center gap-1.5 flex-wrap justify-end">
                    {!isAllDone ? (
                      <button onClick={(e) => { e.stopPropagation(); bulkTogglePriority(items); }} disabled={busy}
                        className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 transition-colors disabled:opacity-50 ${anyPriority
                            ? 'bg-red-100 text-red-800 border-red-300 font-bold hover:bg-red-200'
                            : 'bg-stone-100 text-stone-500 border-stone-200 hover:bg-stone-200'}`}>
                        <AlertCircle size={10} /> {anyPriority ? 'Priority' : 'Mark priority'}
                      </button>
                    ) : (
                      <PriorityChip on={anyPriority && !isAllDone} />
                    )}
                    <span className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border ${statusPill.color}`}>
                      {statusPill.label}
                    </span>
                    {!isAllDone && (editDueId === a?.id ? (
                      <input type="date" autoFocus value={a?.scheduled_date || ''}
                        onChange={(e) => saveDueB(a?.id, e.target.value)}
                        onBlur={() => setEditDueId(null)}
                        onClick={(e) => e.stopPropagation()}
                        className="text-[10px] font-mono px-1.5 py-0.5 rounded border border-stone-400 bg-white" />
                    ) : canEditDatesB ? (
                      <button onClick={(e) => { e.stopPropagation(); setEditDueId(a?.id); }}
                        className={`text-[10px] font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 ${a?.scheduled_date
                          ? (a.scheduled_date < todayKeyG ? 'bg-red-100 text-red-700 border-red-200'
                             : a.scheduled_date === todayKeyG ? 'bg-emerald-100 text-emerald-800 border-emerald-200'
                             : 'bg-stone-100 text-stone-600 border-stone-200')
                          : 'bg-white text-stone-500 border-dashed border-stone-300'}`}>
                        <Calendar size={9} /> {a?.scheduled_date
                          ? (a.scheduled_date < todayKeyG ? `Overdue · ${fmtDueDate(a.scheduled_date)}`
                             : a.scheduled_date === todayKeyG ? 'Today'
                             : fmtDueDate(a.scheduled_date))
                          : 'Set due date'}
                      </button>
                    ) : (a?.scheduled_date ? (
                      <span className="text-[10px] font-mono px-2 py-0.5 rounded-full border bg-stone-100 text-stone-600 border-stone-200 inline-flex items-center gap-1">
                        <Calendar size={9} /> {a.scheduled_date === todayKeyG ? 'Today' : fmtDueDate(a.scheduled_date)}
                      </span>
                    ) : null))}
                  </div>
                  {/* Mini-row 2: View doc + History */}
                  <div className="flex items-center gap-1.5 flex-wrap justify-end">
                    <button onClick={() => setOpened(rep)}
                      className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1">
                      <Eye size={10} /> Quick glance
                    </button>
                    {onOpenBedroomHistory && rep?.unit_id && rep?.party_id && (
                      <button onClick={() => onOpenBedroomHistory({
                          unitId: rep.unit_id, unitLabel: rep.unit?.label,
                          partyId: rep.party_id, partyLabel: rep.party?.label
                        })} disabled={busy}
                        className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1 disabled:opacity-50">
                        <Clock size={10} /> History
                      </button>
                    )}
                  </div>
                </div>
              </div>

              {/* === TITLE + TYPE + SECTION BREAKDOWN === */}
              <div className="mb-2">
                <div className="font-serif text-sm text-stone-700">{a?.title || 'Checklist assignment'}</div>
                {a?.assignment_type && (
                  <div className="mt-1">
                    <AssignmentTypeChip type={a.assignment_type} />
                  </div>
                )}
                <div className="text-[11px] font-mono text-stone-500 mt-1">
                  {total} {total === 1 ? 'item' : 'items'}
                  {sectionBits.length > 0 && <> · {sectionBits.join(' · ')}</>}
                </div>
              </div>

              {/* === DONE / IN PROGRESS / PENDING chips ===
                 Kept per request — useful glance for "how far am I?". */}
              <div className="flex flex-wrap gap-1.5 mb-3">
                <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-stone-100 text-stone-700">
                  {counts.done}/{total} done
                </span>
                {counts.in_progress > 0 && (
                  <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-amber-100 text-amber-800">
                    {counts.in_progress} in progress
                  </span>
                )}
                {counts.pending > 0 && (
                  <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-stone-100 text-stone-600">
                    {counts.pending} pending
                  </span>
                )}
                {counts.paused > 0 && (
                  <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-blue-100 text-blue-700">
                    {counts.paused} paused
                  </span>
                )}
                {counts.blocked > 0 && (
                  <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-red-100 text-red-700">
                    {counts.blocked} blocked
                  </span>
                )}
              </div>

              {/* === ACTION BUTTON ROW ===
                 Start / Mark complete / Blocked / Reassign — same set
                 the AssignmentList card shows. Bulk semantics:
                 Mark complete + Blocked apply to every open item.
                 Reassign opens the modal on the representative target
                 (template-based assignments are 1 per bedroom so this
                 is the right one to act on). */}
              <div className="flex gap-2 flex-wrap">
                {!isAllDone && (can(employee, 'mark_assignments_done')) && (
                  <button onClick={async () => {
                    if (!confirm(`Close out this entire bedroom? Marks ${openItems.length} item${openItems.length === 1 ? '' : 's'} complete and ends the work block if one is open.`)) return;
                    await bulkUpdateStatus(openItems, 'done');
                    // Also close any open work_block at this exact
                    // bedroom for this property. "Close out the bedroom"
                    // means the cleaner is done here — the timer should
                    // stop too. We scope to (employee_id, unit_id,
                    // party_id, customer_id) so we never touch someone
                    // else's open block at the same bedroom.
                    if (rep?.unit_id && rep?.party_id && employee?.id) {
                      try {
                        const { data: openBlocks } = await supabase
                          .from('work_blocks')
                          .select('id, shift:shifts!inner(employee_id, customer_id)')
                          .eq('unit_id', rep.unit_id)
                          .eq('party_id', rep.party_id)
                          .is('end_time', null);
                        const mine = (openBlocks || []).filter(b =>
                          b.shift?.employee_id === employee.id &&
                          b.shift?.customer_id === propertyId
                        );
                        if (mine.length > 0) {
                          await supabase.from('work_blocks')
                            .update({ end_time: new Date().toISOString() })
                            .in('id', mine.map(b => b.id));
                          if (onUpdate) onUpdate();
                        }
                      } catch (e) {
                        console.warn('[banner mark-complete] could not close work block', e);
                      }
                    }
                  }} disabled={busy}
                    className="h-9 px-3 rounded-lg bg-emerald-600 hover:bg-emerald-700 text-white text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                    <Check size={12} /> Mark complete
                  </button>
                )}
                {!isAllDone && (
                  <button onClick={() => setStatusModal({ target: rep, bulkRows: openItems })} disabled={busy}
                    className="h-9 px-3 rounded-lg border border-red-200 hover:bg-red-50 text-red-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                    <AlertCircle size={12} /> Blocked
                  </button>
                )}
                {!isAllDone && (
                  <button onClick={() => setReassignTarget(rep)} disabled={busy}
                    className="h-9 px-3 rounded-lg border border-stone-300 hover:bg-stone-50 text-stone-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                    <User size={12} /> Reassign
                  </button>
                )}
              </div>
            </div>
          );
        };
        return (
          <div className="space-y-2">
            {priorityGroups.length > 0 && (
              <>
                <div className="flex items-center gap-2 px-1">
                  <AlertCircle size={12} className="text-red-700 flex-shrink-0" />
                  <span className="text-[10px] uppercase tracking-wider font-mono font-bold text-red-700">
                    Priority — do these first ({priorityGroups.length})
                  </span>
                  <div className="flex-1 h-px bg-red-200" />
                </div>
                {priorityGroups.map(renderGroup)}
              </>
            )}
            {priorityGroups.length > 0 && restGroups.length > 0 && (
              <div className="py-1 flex items-center gap-2 px-1">
                <div className="flex-1 h-px bg-blue-200" />
                <span className="text-[10px] uppercase tracking-wider font-mono text-blue-700">Everything else</span>
                <div className="flex-1 h-px bg-blue-200" />
              </div>
            )}
            {restGroups.map(renderGroup)}
          </div>
        );
      })()}

      {opened && (
        opened.assignment?.template_set_id
          ? <ChecklistAssignmentView assignment={opened.assignment}
              employee={employee}
              onClose={() => setOpened(null)}
              onOpenSheet={opened.assignment?.file_url
                ? () => window.open(opened.assignment.file_url, '_blank', 'noopener')
                : null} />
          : <AssignmentViewer target={opened} employee={employee} onClose={() => setOpened(null)} />
      )}
      {statusModal && (
        <BlockedNoteModal target={statusModal.target}
          onSave={(notes) => {
            if (statusModal.bulkRows && statusModal.bulkRows.length > 0) {
              bulkUpdateStatus(statusModal.bulkRows, 'blocked', notes);
              setStatusModal(null);
            } else {
              updateStatus(statusModal.target, 'blocked', notes);
            }
          }}
          onClose={() => setStatusModal(null)}
          busy={busy} />
      )}
      {reassignTarget && (
        <ReassignModal target={reassignTarget} propertyId={propertyId}
          onSaved={() => { setReassignTarget(null); load(); if (onUpdate) onUpdate(); }}
          onClose={() => setReassignTarget(null)} />
      )}
    </div>
  );
}

// Reusable card for one assignment target, used in banner + panel
function AssignmentCard({ target, busy, onView, onStart, onPause, onMoveToPending, onDone, onReopen, onBlocked, onReassign, onGoToBedroom, onOpenBedroomHistory, onTogglePriority, canMarkDone = true, canMarkDoneAlways = false, currentEmployeeId, propertyId, canEditDates = false, onSetDueDate }) {
  const t = target;
  const s = ASSIGNMENT_STATUSES[t.status] || ASSIGNMENT_STATUSES.pending;
  const isDone = t.status === 'done';
  const [editingDate, setEditingDate] = useState(false);
  const [localDate, setLocalDate] = useState(t.assignment?.scheduled_date || '');
  useEffect(() => { setLocalDate(t.assignment?.scheduled_date || ''); }, [t.assignment?.scheduled_date]);
  const commitDate = async (val) => {
    setLocalDate(val);
    setEditingDate(false);
    if (onSetDueDate) await onSetDueDate(t.assignment_id || t.assignment?.id, val || null);
  };
  // Title is always tappable as long as we have a bedroom to navigate
  // to — even Done assignments. Tapping a Done one is useful for
  // peeking at history or re-checking the bedroom.
  const canGo = onGoToBedroom && t.unit_id && t.party_id;
  const [activeCleaners, setActiveCleaners] = useState([]);

  // Pull who's currently working at this target's unit+party (active work blocks today)
  useEffect(() => {
    if (!t.unit_id || !t.party_id || isDone) { setActiveCleaners([]); return; }
    (async () => {
      const todayStart = new Date(); todayStart.setHours(0, 0, 0, 0);
      const { data } = await supabase
        .from('work_blocks')
        .select('id, end_time, shift:shifts!inner(employee:employees(id, name), customer_id)')
        .eq('unit_id', t.unit_id).eq('party_id', t.party_id)
        .eq('is_preview', false)
        .gte('start_time', todayStart.toISOString())
        .is('end_time', null);
      const cleaners = (data || [])
        .filter(b => b.shift?.customer_id === propertyId)
        .map(b => b.shift?.employee?.name)
        .filter(Boolean);
      // dedupe
      setActiveCleaners([...new Set(cleaners)]);
    })();
  }, [t.unit_id, t.party_id, isDone, propertyId, t.status]);

  return (
    <div className={`p-2.5 sm:p-3 rounded-xl border ${isDone ? 'bg-stone-50 border-stone-200 opacity-90' : 'bg-white border-stone-200'}`}>
      {/* === HEADER ROW =================================================
         On mobile the title takes a full-width row of its own and the
         chip group (priority / status / view doc / history) drops to
         the line below — that's the only way to guarantee long
         apartment labels never get cut off on a phone. From `sm:`
         and up there's enough horizontal room to put the title on
         the left and chips on the right. */}
      <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-1.5 sm:gap-2 mb-2">
        <div className="flex-1 min-w-0">
          {(t.unit?.label || t.party?.label) ? (
            canGo ? (
              // Bedroom title is the primary navigation target on the
              // card — tapping the bold "B4-115 · Bedroom 2" header
              // jumps the cleaner straight into that bedroom (same
              // path as the Start / Go to this bedroom buttons).
              // Underline-on-hover hint so it reads as tappable.
              <button onClick={onGoToBedroom} disabled={busy}
                className="block text-left w-full font-serif text-lg text-stone-900 leading-tight break-words hover:underline disabled:opacity-50">
                <span className="font-bold">{t.unit?.label || 'No unit'}</span>
                {t.party?.label && (
                  <>
                    <span className="text-stone-400 mx-1.5">·</span>
                    <span className="italic">{t.party.label}</span>
                  </>
                )}
              </button>
            ) : (
              <div className="font-serif text-lg text-stone-900 leading-tight break-words">
                <span className="font-bold">{t.unit?.label || 'No unit'}</span>
                {t.party?.label && (
                  <>
                    <span className="text-stone-400 mx-1.5">·</span>
                    <span className="italic">{t.party.label}</span>
                  </>
                )}
              </div>
            )
          ) : (
            <div className="font-serif text-lg text-stone-900 font-bold">Whole property</div>
          )}
        </div>
        <div className="flex flex-col sm:flex-row sm:items-center gap-1.5 flex-shrink-0 sm:max-w-[60%]">
          {/* Mini-row 1: Priority + Status — right-aligned. */}
          <div className="flex items-center gap-1.5 flex-wrap justify-end">
            {/* Priority toggle (gray ↔ red) when parent passes it; else
               read-only chip. */}
            {!isDone && onTogglePriority ? (
              <button
                onClick={(e) => { e.stopPropagation(); onTogglePriority(t); }}
                disabled={busy}
                className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 transition-colors disabled:opacity-50 ${t.priority
                    ? 'bg-red-100 text-red-800 border-red-300 font-bold hover:bg-red-200'
                    : 'bg-stone-100 text-stone-500 border-stone-200 hover:bg-stone-200'}`}>
                <AlertCircle size={10} /> {t.priority ? 'Priority' : 'Mark priority'}
              </button>
            ) : (
              <PriorityChip on={t.priority && !isDone} />
            )}
            {/* Status pill — read-only, just a visual cue. */}
            <span className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border ${s.color}`}>
              {s.label}
            </span>
            {/* Due-date signal — tappable to reschedule when permitted. */}
            {!isDone && (() => {
              const kind = assignmentDueKind(localDate);
              const cls = kind === 'overdue' ? 'bg-red-100 text-red-700 border-red-200'
                : kind === 'today' ? 'bg-emerald-100 text-emerald-800 border-emerald-200'
                : 'bg-stone-100 text-stone-600 border-stone-200';
              const label = !localDate ? 'Set date'
                : kind === 'overdue' ? `Overdue · ${fmtDueDate(localDate)}`
                : kind === 'today' ? 'Today'
                : fmtDueDate(localDate);
              if (editingDate && canEditDates) {
                return (
                  <input type="date" autoFocus value={localDate}
                    onChange={(e) => commitDate(e.target.value)}
                    onBlur={() => setEditingDate(false)}
                    className="text-[10px] font-mono px-1.5 py-0.5 rounded-lg border border-stone-400 bg-white" />
                );
              }
              if (canEditDates) {
                return (
                  <button onClick={() => setEditingDate(true)}
                    className={`text-[10px] font-mono px-2 py-0.5 rounded-full border flex items-center gap-1 ${localDate ? cls : 'bg-white text-stone-500 border-dashed border-stone-300'}`}>
                    <Calendar size={9} /> {label}
                  </button>
                );
              }
              if (!localDate) return null;
              return (
                <span className={`text-[10px] font-mono px-2 py-0.5 rounded-full border flex items-center gap-1 ${cls}`}>
                  <Calendar size={9} /> {label}
                </span>
              );
            })()}
          </div>
          {/* Mini-row 2: View doc + History — right-aligned. Stays a
             separate mini-row so the chip pairs never split awkwardly:
             priority sits next to status, view doc next to history. */}
          <div className="flex items-center gap-1.5 flex-wrap justify-end">
            <button onClick={onView}
              className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1">
              <Eye size={10} /> Quick glance
            </button>
            {onOpenBedroomHistory && t.unit_id && t.party_id && (
              <button onClick={() => onOpenBedroomHistory({
                  unitId: t.unit_id, unitLabel: t.unit?.label,
                  partyId: t.party_id, partyLabel: t.party?.label
                })} disabled={busy}
                className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1 disabled:opacity-50">
                <Clock size={10} /> History
              </button>
            )}
          </div>
        </div>
      </div>

      {/* === TITLE + TYPE ===============================================
         Assignment title (move-out check / standard / etc), cleaning
         type chip, assignee. Tappable when canGo so cleaner can jump
         from the title alone. */}
      <div className="mb-2">
        {canGo ? (
          <button onClick={onGoToBedroom} disabled={busy}
            className="text-left w-full font-serif text-sm text-stone-700 hover:underline disabled:opacity-50">
            {t.assignment?.title}
          </button>
        ) : (
          <div className="font-serif text-sm text-stone-700">{t.assignment?.title}</div>
        )}
        {(t.assignment?.assignment_type || (t.assignedTo?.name && !isDone)) && (
          <div className="mt-1 flex items-center gap-1.5 flex-wrap">
            <AssignmentTypeChip type={t.assignment?.assignment_type} />
            {t.assignedTo?.name && !isDone && (
              <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-purple-100 text-purple-800 border border-purple-300 inline-flex items-center gap-1">
                <User size={10} /> {t.assignedTo.name}
              </span>
            )}
          </div>
        )}
        {t.assignment?.notes && (
          <div className="text-xs text-stone-600 mt-1 line-clamp-2">{t.assignment.notes}</div>
        )}
        {t.status === 'in_progress' && t.starter?.name && (
          <div className="text-xs text-amber-700 font-mono mt-1">
            Started by {t.starter.name}{t.started_at && ` · ${fmtClock(t.started_at)}`}
          </div>
        )}
        {t.status === 'paused' && t.starter?.name && (
          <div className="text-xs text-blue-700 font-mono mt-1 flex items-center gap-1">
            <Pause size={10} />
            Paused by {t.starter.name}
          </div>
        )}
        {activeCleaners.length > 0 && (
          <div className="text-xs text-emerald-700 font-mono mt-1 flex items-center gap-1">
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
            {activeCleaners.length === 1 ? `${activeCleaners[0]} is here` : `${activeCleaners.length} cleaners here: ${activeCleaners.join(', ')}`}
          </div>
        )}
        {isDone && t.completed_at && (
          <div className="text-xs text-emerald-700 font-mono mt-1">
            {t.completer?.name ? `Done by ${t.completer.name} · ` : 'Done '}{fmtDateWithDay(t.completed_at)} {fmtClock(t.completed_at)}
          </div>
        )}
        {t.status_notes && (
          <div className="text-xs text-red-700 italic mt-1">"{t.status_notes}"</div>
        )}
      </div>

      {/* === ACTION BUTTON ROW =========================================
         All buttons share h-9 / px-3 / text-xs / inline-flex so they
         line up symmetrically regardless of which subset is showing.
         Order: Start → Pause → Move to pending → Done → Reopen →
         Blocked → Reassign. Reassign no longer has ml-auto so the
         row stays uniform. */}
      <div className="flex gap-2 flex-wrap">
        {(t.status === 'pending' || t.status === 'blocked' || t.status === 'in_progress' || t.status === 'paused') && (() => {
          // "I'm on it too" only makes sense when SOMEONE ELSE is on it.
          // If the current cleaner started this assignment, show a
          // disabled gray "You're on it" pill so they see the state
          // without a misleading button to "join themselves".
          const iStartedThis = t.status === 'in_progress'
            && currentEmployeeId
            && t.started_by === currentEmployeeId;
          if (iStartedThis) {
            return (
              <button disabled
                className="h-9 px-3 rounded-lg bg-stone-200 text-stone-500 text-xs font-medium flex items-center gap-1 cursor-not-allowed">
                <Check size={12} /> You're on it
              </button>
            );
          }
          const label = t.status === 'in_progress' ? "I'm on it too"
            : t.status === 'paused' ? 'Resume' : 'Start';
          return (
            <button onClick={onStart} disabled={busy}
              className="h-9 px-3 rounded-lg bg-amber-600 hover:bg-amber-700 text-white text-xs font-medium flex items-center gap-1 disabled:opacity-50">
              <Play size={12} /> {label}
            </button>
          );
        })()}
        {onPause && (t.status === 'in_progress') && (
          <button onClick={onPause} disabled={busy}
            className="h-9 px-3 rounded-lg border border-blue-200 hover:bg-blue-50 text-blue-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
            <Pause size={12} /> Pause
          </button>
        )}
        {onMoveToPending && t.status === 'paused' && (
          <button onClick={onMoveToPending} disabled={busy}
            className="h-9 px-3 rounded-lg border border-stone-300 hover:bg-stone-50 text-stone-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
            <ArrowLeft size={12} /> Move to pending
          </button>
        )}
        {(t.status === 'pending' || t.status === 'in_progress' || t.status === 'blocked' || t.status === 'paused') && canMarkDone && (() => {
          // On Pending we keep the button VISIBLE but disabled — the
          // cleaner sees the action exists, just needs to Start first.
          // This avoids the confusing "button vanished" feeling.
          // EXCEPTION: users with full mark_assignments_done permission
          // (owners / managers) can mark complete WITHOUT starting first,
          // so we never disable the button for them.
          const pendingDisabled = t.status === 'pending' && !canMarkDoneAlways;
          return (
            <button onClick={onDone} disabled={busy || pendingDisabled}
              title={pendingDisabled ? 'Start this assignment before marking it complete' : ''}
              className={`h-9 px-3 rounded-lg text-xs font-medium flex items-center gap-1 ${pendingDisabled
                ? 'bg-stone-200 text-stone-500 cursor-not-allowed'
                : 'bg-emerald-600 hover:bg-emerald-700 text-white disabled:opacity-50'}`}>
              <Check size={12} /> Mark complete
            </button>
          );
        })()}
        {(isDone || t.status === 'blocked') && (
          <button onClick={onReopen} disabled={busy}
            className="h-9 px-3 rounded-lg border border-stone-300 hover:bg-stone-50 text-stone-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
            <Play size={12} /> Reopen
          </button>
        )}
        {(t.status === 'pending' || t.status === 'in_progress' || t.status === 'paused') && (
          <button onClick={onBlocked} disabled={busy}
            className="h-9 px-3 rounded-lg border border-red-200 hover:bg-red-50 text-red-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
            <AlertCircle size={12} /> Blocked
          </button>
        )}
        {onReassign && (t.unit_id || t.party_id) && (
          <button onClick={onReassign} disabled={busy}
            className="h-9 px-3 rounded-lg border border-stone-300 hover:bg-stone-50 text-stone-600 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
            <Edit2 size={12} /> Reassign
          </button>
        )}
      </div>

      {/* === PRIMARY CTA ================================================
         "Go to this bedroom" is intentionally the only larger button
         to stand out as the main workflow action for cleaners. Hidden
         on Done assignments since there's nothing to do. */}
      {canGo && !isDone && (
        <button onClick={onGoToBedroom} disabled={busy}
          className="mt-2 w-full px-3 py-2.5 rounded-lg bg-stone-900 hover:bg-stone-800 text-stone-50 text-sm font-medium flex items-center justify-center gap-2 disabled:opacity-50">
          Go to this bedroom <ChevronRight size={14} />
        </button>
      )}
    </div>
  );
}

// AssignmentsPanel — full tabbed view for the property hub.
// Tabs: Pending | Paused | In Progress | Done
function AssignmentsPanel({ propertyId, employee, refreshKey, onGoToBedroom, onOpenBedroomHistory, onJoinBlock }) {
  const [tab, setTab] = useState('pending');
  const [counts, setCounts] = useState({ pending: 0, paused: 0, in_progress: 0, done: 0, blocked: 0, mine: 0 });

  const loadCounts = async () => {
    const PAGE = 1000;
    let data = [];
    for (let from = 0; ; from += PAGE) {
      const { data: page, error: pErr } = await supabase
        .from('assignment_targets')
        .select('status, completed_by, completed_at, unit_id, party_id, assignment_id, recheck_passed_at, assignment:assignments!inner(customer_id, active, source, pm_status, deleted_at)')
        .eq('assignment.customer_id', propertyId)
        .eq('assignment.active', true)
          .is('assignment.deleted_at', null)
        .order('id', { ascending: true })
        .range(from, from + PAGE - 1);
      if (pErr) break;
      data = data.concat(page || []);
      if (!page || page.length < PAGE) break;
      if (from > 200000) break;
    }
    const filtered = (data || []).filter(t =>
      !t.assignment?.deleted_at &&
      (t.assignment?.source !== 'pm' || t.assignment?.pm_status === 'approved')
    );
    // Count UNIQUE assignments per status. Each assignment gets bucketed
    // ONCE based on its DOMINANT status (in_progress > paused > blocked
    // > pending > done). This is the counterpart to the dominant-status
    // logic in load() — both key by assignment_id so a cleaning-check
    // and a move-out check at the same bedroom count as two separate
    // jobs. They must agree or the badge says "1 pending" while the
    // tab shows something else.
    const asgnKey = (t) => t.assignment_id || `${t.unit_id || ''}::${t.party_id || ''}`;
    const statusesByAsgn = new Map();
    filtered.forEach(t => {
      const k = asgnKey(t);
      if (!statusesByAsgn.has(k)) statusesByAsgn.set(k, new Set());
      statusesByAsgn.get(k).add(t.status);
    });
    const dominantOrder = ['in_progress', 'paused', 'blocked', 'pending', 'done'];
    const sets = { pending: new Set(), paused: new Set(), in_progress: new Set(), done: new Set(), blocked: new Set(), mine: new Set(), recheck_passed: new Set() };
    statusesByAsgn.forEach((statusSet, k) => {
      const dom = dominantOrder.find(s => statusSet.has(s)) || 'pending';
      if (sets[dom]) sets[dom].add(k);
    });
    // "Mine" still depends on which items the viewing cleaner finished
    // today — it's a derived view, so we walk the items separately.
    const todayStart = new Date(); todayStart.setHours(0, 0, 0, 0);
    filtered.forEach(t => {
      if (t.recheck_passed_at) sets.recheck_passed.add(asgnKey(t));
      if (t.completed_by && employee?.id && t.completed_by === employee.id && t.completed_at) {
        const ca = new Date(t.completed_at);
        if (ca >= todayStart) sets.mine.add(asgnKey(t));
      }
    });
    setCounts({
      pending: sets.pending.size,
      paused: sets.paused.size,
      in_progress: sets.in_progress.size,
      done: sets.done.size,
      blocked: sets.blocked.size,
      mine: sets.mine.size,
      recheck_passed: sets.recheck_passed.size,
    });
  };
  useEffect(() => { loadCounts(); }, [propertyId, refreshKey]);
  // Tab badges need to refresh on every DB change too, not just on
  // propertyId / refreshKey. Without this hook the counts went stale
  // the moment a cleaner started a workblock — the card itself moved
  // to In progress (because load() re-ran on the same sync) but the
  // badges still read the old numbers until you tabbed away and back.
  useAssignmentSync(loadCounts, 'asgn-panel-counts');

  return (
    <div className="px-2 sm:px-4 mt-4">
      <div className="flex items-center gap-2 mb-3">
        <FileText size={14} className="text-stone-500" />
        <span className="text-xs uppercase tracking-wider text-stone-500 font-mono">Assignments</span>
      </div>
      <div className="flex gap-1 mb-3 bg-stone-100 p-1 rounded-xl overflow-x-auto">
        <button onClick={() => setTab('pending')}
          className={`flex-1 min-w-fit py-2 px-2 rounded-lg text-xs font-medium transition-colors whitespace-nowrap ${tab === 'pending' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
          Pending{counts.pending > 0 && ` (${counts.pending})`}
        </button>
        <button onClick={() => setTab('paused')}
          className={`flex-1 min-w-fit py-2 px-2 rounded-lg text-xs font-medium transition-colors whitespace-nowrap ${tab === 'paused' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
          Paused{counts.paused > 0 && ` (${counts.paused})`}
        </button>
        <button onClick={() => setTab('in_progress')}
          className={`flex-1 min-w-fit py-2 px-2 rounded-lg text-xs font-medium transition-colors whitespace-nowrap ${tab === 'in_progress' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
          In progress{counts.in_progress > 0 && ` (${counts.in_progress})`}
        </button>
        <button onClick={() => setTab('done')}
          className={`flex-1 min-w-fit py-2 px-2 rounded-lg text-xs font-medium transition-colors whitespace-nowrap ${tab === 'done' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
          Done{counts.done > 0 && ` (${counts.done})`}
          {counts.blocked > 0 && (
            <span className="ml-1 text-[10px] font-mono text-red-700">· {counts.blocked}⊘</span>
          )}
        </button>
        {/* Mine tab — items the current cleaner personally completed today.
           Hidden if the cleaner has no completions yet so the row stays
           compact for owners/managers viewing the same panel. */}
        {counts.mine > 0 && (
          <button onClick={() => setTab('mine')}
            className={`flex-1 min-w-fit py-2 px-2 rounded-lg text-xs font-medium transition-colors whitespace-nowrap ${tab === 'mine' ? 'bg-amber-50 shadow-sm text-amber-900 font-bold' : 'text-stone-500'}`}>
            Mine ({counts.mine})
          </button>
        )}
        {/* Passed recheck — items the PM marked passed on recheck
           (tenant did it themselves). Owner audit bucket so they
           can review what was removed from the cleaning workflow.
           Hidden when zero so the row stays compact. */}
        {counts.recheck_passed > 0 && (
          <button onClick={() => setTab('recheck_passed')}
            className={`flex-1 min-w-fit py-2 px-2 rounded-lg text-xs font-medium transition-colors whitespace-nowrap ${tab === 'recheck_passed' ? 'bg-purple-50 shadow-sm text-purple-900 font-bold' : 'text-stone-500'}`}>
            Passed recheck ({counts.recheck_passed})
          </button>
        )}
      </div>
      <AssignmentTabContent propertyId={propertyId} employee={employee} statusFilter={tab}
        onUpdate={loadCounts} onGoToBedroom={onGoToBedroom} onOpenBedroomHistory={onOpenBedroomHistory}
        onJoinBlock={onJoinBlock} />
    </div>
  );
}

// SuggestedTabContent — proximity-ranked "what to clean next" view.
// Anchors on the cleaner's most-recent work block (open or closed today)
// and ranks suggestions: same apartment → same floor → same building →
// other building starting on floor 3. If no anchor exists, defaults to
// floor-3 first across the property.
function SuggestedTabContent({ propertyId, employee, onGoToBedroom, onOpenBedroomHistory, onJoinBlock }) {
  const [loaded, setLoaded] = useState(false);
  const [anchor, setAnchor] = useState(null);
  const [groups, setGroups] = useState({ sameApt: [], sameFloor: [], sameBuilding: [], otherBuilding: [] });
  const [busy, setBusy] = useState(false);
  // Action modals — one bedroom card at a time may want to open a Blocked-note
  // modal or a Reassign modal. We hold them here at the tab level since the
  // cards themselves are just renderers.
  const [opened, setOpened] = useState(null);     // representative target for View Doc
  const [statusModal, setStatusModal] = useState(null);   // { target, bulkRows }
  const [reassignTarget, setReassignTarget] = useState(null);
  // Per-section collapse. Same apartment + Same floor open by default,
  // Same building + Other buildings collapsed.
  const [collapsed, setCollapsed] = useState({
    sameApt: false, sameFloor: false, sameBuilding: true, otherBuilding: true,
  });
  const [reloadKey, setReloadKey] = useState(0);
  const reload = () => setReloadKey(k => k + 1);
  const [editDueId, setEditDueId] = useState(null);
  const canEditDatesS = can(employee, 'edit_due_dates');
  const todayKeyS = localTodayKey();
  const saveDueS = async (id, date) => {
    setEditDueId(null);
    if (id) { await supabase.from('assignments').update({ scheduled_date: date || null }).eq('id', id); reload(); }
  };
  // Realtime: pick up workblocks opening/closing and target status
  // changes from other cleaners so the "X is here" chip + status pill
  // appear within seconds rather than after a manual refresh.
  useAssignmentSync(reload, 'suggested-tab');

  // Label parsers — same as NextUpModal
  const buildingFromLabel = (label) => {
    if (!label) return null;
    const m = label.match(/^B(\d+)/i);
    return m ? m[1] : null;
  };
  const unitNumberFromLabel = (label) => {
    if (!label) return null;
    const m = label.match(/-(\d+)/);
    return m ? parseInt(m[1], 10) : null;
  };

  useEffect(() => {
    if (!propertyId || !employee?.id) return;
    (async () => {
      setLoaded(false);
      // 1) Anchor — cleaner's most recent block at this property
      const { data: myBlocks } = await supabase
        .from('work_blocks')
        .select('id, unit_id, party_id, end_time, start_time, unit:units(label), party:parties(label), shift:shifts!inner(customer_id, employee_id)')
        .order('start_time', { ascending: false })
        .limit(20);
      const mine = (myBlocks || []).filter(b =>
        b.shift?.customer_id === propertyId && b.shift?.employee_id === employee.id
      );
      const recent = mine[0];
      const anchorObj = recent ? {
        unitId: recent.unit_id,
        partyId: recent.party_id,
        unitLabel: recent.unit?.label || '',
        partyLabel: recent.party?.label || '',
        building: buildingFromLabel(recent.unit?.label),
        floor: floorFromLabel(recent.unit?.label),
        unitNum: unitNumberFromLabel(recent.unit?.label),
        wasOpen: !recent.end_time,
      } : null;

      // 2) Units + parties + full target detail + open work blocks
      const [unitsRes, partiesRes, targetsRes, blocksRes] = await Promise.all([
        supabase.from('units').select('id, label, active').eq('customer_id', propertyId).eq('active', true),
        supabase.from('parties').select('id, label, unit_id, sort_order, active'),
        supabase.from('assignment_targets')
          .select('*, assignment:assignments!inner(id, title, notes, file_url, file_kind, customer_id, active, source, pm_status, deleted_at, assignment_type, template_set_id, sheet_type, general_variant, bathroom_variant, scheduled_date, created_at), unit:units(id, label), party:parties(id, label), starter:employees!started_by(name), completer:employees!completed_by(name), assignedTo:employees!assigned_to(id, name)')
          .not('status', 'in', '(done,blocked)'),
        // Open work blocks property-wide for the "who's here" chips.
        // main_section is pulled so each chip can label which section
        // the cleaner is working — relevant once cleaners split a
        // bedroom across sections.
        supabase.from('work_blocks')
          .select('id, unit_id, party_id, main_section, shift:shifts!inner(customer_id, employee:employees(id, name))')
          .is('end_time', null),
      ]);
      const units = unitsRes.data || [];
      const parties = (partiesRes.data || []).filter(p => p.active !== false);
      const openTargets = (targetsRes.data || []).filter(t => {
        const a = t.assignment;
        if (!a || a.customer_id !== propertyId) return false;
        if (a.active === false) return false;
        if (a.source === 'pm' && a.pm_status !== 'approved') return false;
        return true;
      });
      const openBlocks = (blocksRes.data || []).filter(b =>
        b.shift?.customer_id === propertyId &&
        b.shift?.employee?.id && b.shift.employee.id !== employee.id
      );

      // Group open targets by bedroom (party_id)
      const targetsByParty = new Map();
      openTargets.forEach(t => {
        if (!t.party_id) return;
        if (!targetsByParty.has(t.party_id)) targetsByParty.set(t.party_id, []);
        targetsByParty.get(t.party_id).push(t);
      });
      // Build "who's here" map — keyed by party_id, contains [{ name, partyLabel(if relevant) }]
      // For the chip we just need the cleaner's name; the bedroom IS the card.
      const whosHereByParty = new Map();
      openBlocks.forEach(b => {
        if (!b.party_id) return;
        if (!whosHereByParty.has(b.party_id)) whosHereByParty.set(b.party_id, []);
        whosHereByParty.get(b.party_id).push({
          name: b.shift.employee.name,
          workBlockId: b.id,
          mainSection: b.main_section, // null for legacy blocks; UI hides badge in that case
        });
      });

      const unitMap = new Map(units.map(u => [u.id, u]));
      const candidates = parties
        .filter(p => targetsByParty.has(p.id))
        .filter(p => !anchorObj || p.id !== anchorObj.partyId)
        .map(p => {
          const unit = unitMap.get(p.unit_id);
          if (!unit) return null;
          const items = targetsByParty.get(p.id) || [];
          const hasPriority = items.some(i => i.priority);
          return {
            partyId: p.id,
            partyLabel: p.label,
            unitId: unit.id,
            unitLabel: unit.label,
            building: buildingFromLabel(unit.label),
            floor: floorFromLabel(unit.label),
            unitNum: unitNumberFromLabel(unit.label),
            items,
            hasPriority,
            whosHere: whosHereByParty.get(p.id) || [],
          };
        })
        .filter(Boolean);

      // Bucket
      const sameApt = anchorObj ? candidates.filter(c => c.unitId === anchorObj.unitId) : [];
      const sameFloor = anchorObj ? candidates.filter(c =>
        c.unitId !== anchorObj.unitId && c.building === anchorObj.building && c.floor === anchorObj.floor
      ) : [];
      const sameBuilding = anchorObj ? candidates.filter(c =>
        c.building === anchorObj.building && c.floor !== anchorObj.floor
      ) : [];
      const otherBuilding = anchorObj ? candidates.filter(c => c.building !== anchorObj.building) : [...candidates];

      // Sorts (same as before)
      sameFloor.sort((a, b) => {
        if (a.hasPriority !== b.hasPriority) return a.hasPriority ? -1 : 1;
        const da = Math.abs((a.unitNum || 0) - (anchorObj?.unitNum || 0));
        const db = Math.abs((b.unitNum || 0) - (anchorObj?.unitNum || 0));
        return da - db;
      });
      sameBuilding.sort((a, b) => {
        if (a.hasPriority !== b.hasPriority) return a.hasPriority ? -1 : 1;
        const fa = Math.abs((a.floor ?? 99) - (anchorObj?.floor ?? 0));
        const fb = Math.abs((b.floor ?? 99) - (anchorObj?.floor ?? 0));
        if (fa !== fb) return fa - fb;
        return (a.unitNum || 0) - (b.unitNum || 0);
      });
      const distFromThree = (f) => {
        if (f == null) return 99;
        if (f === 3) return 0;
        if (f < 3) return 3 - f;
        return (f - 3) + 3;
      };
      otherBuilding.sort((a, b) => {
        if (a.hasPriority !== b.hasPriority) return a.hasPriority ? -1 : 1;
        if (a.building !== b.building) return (a.building || '').localeCompare(b.building || '');
        const da = distFromThree(a.floor);
        const db = distFromThree(b.floor);
        if (da !== db) return da - db;
        return (a.unitNum || 0) - (b.unitNum || 0);
      });

      setAnchor(anchorObj);
      setGroups({ sameApt, sameFloor, sameBuilding, otherBuilding });
      setLoaded(true);
    })();
  }, [propertyId, employee?.id, reloadKey]);

  // Bulk handlers — operate on a single bedroom's items. Mirror of the
  // helpers in AssignmentBanner/AssignmentTabContent. Optimistic + single
  // DB write, then trigger a reload so counts settle.
  const bulkUpdateStatus = async (rows, newStatus, statusNotes) => {
    if (!rows || rows.length === 0) return;
    const ids = rows.map(r => r.id);
    setBusy(true);
    const patch = { status: newStatus };
    if (newStatus === 'in_progress') {
      patch.started_at = new Date().toISOString();
      patch.started_by = employee?.id || null;
    }
    if (newStatus === 'done') {
      patch.completed_at = new Date().toISOString();
      patch.completed_by = employee?.id || null;
    } else {
      patch.completed_at = null; patch.completed_by = null;
    }
    if (newStatus === 'pending') { patch.started_at = null; patch.started_by = null; }
    if (statusNotes !== undefined) patch.status_notes = statusNotes || null;
    const { error } = await supabase.from('assignment_targets').update(patch).in('id', ids);
    setBusy(false);
    if (error) { alert('Could not update: ' + error.message); reload(); return; }
    reload();
  };
  const bulkTogglePriority = async (rows) => {
    if (!rows || rows.length === 0) return;
    const anyOn = rows.some(r => r.priority);
    const next = !anyOn;
    const ids = rows.map(r => r.id);
    const { error } = await supabase.from('assignment_targets').update({ priority: next }).in('id', ids);
    if (error) { alert('Could not update priority: ' + error.message); }
    reload();
  };

  // Bedroom card — matches renderChecklistGroupCard from AssignmentBanner.
  // Shows the full bulk-card chrome plus the "{name} is here" chip when
  // another cleaner has an open block at this bedroom.
  const renderBedroomCard = (c) => {
    const items = c.items;
    const rep = items[0];
    if (!rep) return null;
    const counts = {
      pending:     items.filter(i => i.status === 'pending').length,
      in_progress: items.filter(i => i.status === 'in_progress').length,
      paused:      items.filter(i => i.status === 'paused').length,
      blocked:     items.filter(i => i.status === 'blocked').length,
      done:        0,
    };
    const total = items.length;
    const sectionCounts = {
      bedroom:  items.filter(i => (i.template_section || '').toLowerCase() === 'bedroom').length,
      vanity:   items.filter(i => (i.template_section || '').toLowerCase() === 'vanity').length,
      bathroom: items.filter(i => (i.template_section || '').toLowerCase() === 'bathroom').length,
      general:  items.filter(i => (i.template_section || '').toLowerCase() === 'general').length,
    };
    const knownSectioned = sectionCounts.bedroom + sectionCounts.vanity + sectionCounts.bathroom + sectionCounts.general;
    const otherCount = total - knownSectioned;
    const sectionBits = [];
    if (sectionCounts.bedroom)  sectionBits.push(`Bedroom (${sectionCounts.bedroom})`);
    if (sectionCounts.vanity)   sectionBits.push(`Vanity (${sectionCounts.vanity})`);
    if (sectionCounts.bathroom) sectionBits.push(`Bathroom (${sectionCounts.bathroom})`);
    if (sectionCounts.general)  sectionBits.push(`General (${sectionCounts.general})`);
    if (otherCount > 0)         sectionBits.push(`Other (${otherCount})`);
    const statusOrder = ['pending', 'in_progress', 'paused', 'blocked'];
    const dominantStatus = statusOrder.find(s => items.some(i => i.status === s)) || 'pending';
    const statusPill = ASSIGNMENT_STATUSES[dominantStatus] || ASSIGNMENT_STATUSES.pending;
    const goTo = () => {
      if (!onGoToBedroom) return;
      onGoToBedroom({
        unit_id: c.unitId,
        party_id: c.partyId,
        unit: { id: c.unitId, label: c.unitLabel },
        party: { id: c.partyId, label: c.partyLabel },
      });
    };
    return (
      <div key={c.partyId} className="p-3 sm:p-4 rounded-xl bg-white border border-stone-200">
        {/* === HEADER === */}
        <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-1.5 sm:gap-2 mb-2">
          <div className="flex-1 min-w-0">
            <button onClick={goTo} disabled={busy}
              className="block text-left w-full font-serif text-lg text-stone-900 leading-tight break-words hover:underline disabled:opacity-50">
              <span className="font-bold">{c.unitLabel}</span>
              <span className="text-stone-400 mx-1.5">·</span>
              <span className="italic">{c.partyLabel}</span>
            </button>
          </div>
          <div className="flex flex-col sm:flex-row sm:items-center gap-1.5 flex-shrink-0 sm:max-w-[60%]">
            <div className="flex items-center gap-1.5 flex-wrap justify-end">
              <button onClick={(e) => { e.stopPropagation(); bulkTogglePriority(items); }} disabled={busy}
                className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 transition-colors disabled:opacity-50 ${c.hasPriority
                    ? 'bg-red-100 text-red-800 border-red-300 font-bold hover:bg-red-200'
                    : 'bg-stone-100 text-stone-500 border-stone-200 hover:bg-stone-200'}`}>
                <AlertCircle size={10} /> {c.hasPriority ? 'Priority' : 'Mark priority'}
              </button>
              <span className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border ${statusPill.color}`}>
                {statusPill.label}
              </span>
              {(editDueId === rep.assignment?.id ? (
                <input type="date" autoFocus value={rep.assignment?.scheduled_date || ''}
                  onChange={(e) => saveDueS(rep.assignment?.id, e.target.value)}
                  onBlur={() => setEditDueId(null)}
                  onClick={(e) => e.stopPropagation()}
                  className="text-[10px] font-mono px-1.5 py-0.5 rounded border border-stone-400 bg-white" />
              ) : canEditDatesS ? (
                <button onClick={(e) => { e.stopPropagation(); setEditDueId(rep.assignment?.id); }}
                  className={`text-[10px] font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 ${rep.assignment?.scheduled_date
                    ? (rep.assignment.scheduled_date < todayKeyS ? 'bg-red-100 text-red-700 border-red-200'
                       : rep.assignment.scheduled_date === todayKeyS ? 'bg-emerald-100 text-emerald-800 border-emerald-200'
                       : 'bg-stone-100 text-stone-600 border-stone-200')
                    : 'bg-white text-stone-500 border-dashed border-stone-300'}`}>
                  <Calendar size={9} /> {rep.assignment?.scheduled_date
                    ? (rep.assignment.scheduled_date < todayKeyS ? `Overdue · ${fmtDueDate(rep.assignment.scheduled_date)}`
                       : rep.assignment.scheduled_date === todayKeyS ? 'Today'
                       : fmtDueDate(rep.assignment.scheduled_date))
                    : 'Set due date'}
                </button>
              ) : (rep.assignment?.scheduled_date ? (
                <span className="text-[10px] font-mono px-2 py-0.5 rounded-full border bg-stone-100 text-stone-600 border-stone-200 inline-flex items-center gap-1">
                  <Calendar size={9} /> {rep.assignment.scheduled_date === todayKeyS ? 'Today' : fmtDueDate(rep.assignment.scheduled_date)}
                </span>
              ) : null))}
            </div>
            <div className="flex items-center gap-1.5 flex-wrap justify-end">
              <button onClick={() => setOpened(rep)}
                className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1">
                <Eye size={10} /> Quick glance
              </button>
              {onOpenBedroomHistory && (
                <button onClick={() => onOpenBedroomHistory({
                    unitId: c.unitId, unitLabel: c.unitLabel,
                    partyId: c.partyId, partyLabel: c.partyLabel,
                  })} disabled={busy}
                  className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1 disabled:opacity-50">
                  <Clock size={10} /> History
                </button>
              )}
            </div>
          </div>
        </div>

        {/* "Who's here" chip — shown when another cleaner has an open block
           at this bedroom. Compact pill row above the title/breakdown.
           Each name gets a Join button so the helper can jump straight
           into that workblock as a participant. */}
        {c.whosHere && c.whosHere.length > 0 && (
          <div className="mb-2 flex items-center gap-1.5 flex-wrap">
            <span className="text-[10px] uppercase tracking-wider font-mono text-amber-900 font-bold">
              ●
            </span>
            {c.whosHere.map((w, i) => (
              <span key={i} className="inline-flex items-center gap-1">
                <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-amber-100 text-amber-900 border border-amber-300 font-bold">
                  {w.name}{w.mainSection ? ` · ${w.mainSection}` : ''} is here
                </span>
                {onJoinBlock && w.workBlockId && (
                  <button onClick={(e) => { e.stopPropagation(); onJoinBlock({ id: w.workBlockId }); }}
                    className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-900 hover:bg-stone-800 text-stone-50 font-bold inline-flex items-center gap-1 active:scale-95">
                    <Plus size={9} /> Join
                  </button>
                )}
              </span>
            ))}
          </div>
        )}

        {/* === TITLE + TYPE + SECTION BREAKDOWN === */}
        <div className="mb-2">
          <div className="font-serif text-sm text-stone-700">{rep.assignment?.title || 'Checklist assignment'}</div>
          {rep.assignment?.assignment_type && (
            <div className="mt-1">
              <AssignmentTypeChip type={rep.assignment.assignment_type} />
            </div>
          )}
          <div className="text-[11px] font-mono text-stone-500 mt-1">
            {total} {total === 1 ? 'item' : 'items'}
            {sectionBits.length > 0 && <> · {sectionBits.join(' · ')}</>}
          </div>
        </div>

        {/* === Status chips row === */}
        <div className="flex flex-wrap gap-1.5 mb-3">
          {counts.in_progress > 0 && (
            <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-amber-100 text-amber-800">
              {counts.in_progress} in progress
            </span>
          )}
          {counts.pending > 0 && (
            <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-stone-100 text-stone-600">
              {counts.pending} pending
            </span>
          )}
          {counts.paused > 0 && (
            <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-blue-100 text-blue-700">
              {counts.paused} paused
            </span>
          )}
          {counts.blocked > 0 && (
            <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-red-100 text-red-700">
              {counts.blocked} blocked
            </span>
          )}
        </div>

        {/* === Action buttons === */}
        <div className="flex gap-2 flex-wrap mb-3">
          {(can(employee, 'mark_assignments_done')) && (
            <button onClick={() => {
              if (confirm(`Mark all ${items.length} item${items.length === 1 ? '' : 's'} at ${c.unitLabel} · ${c.partyLabel} complete?`)) {
                bulkUpdateStatus(items, 'done');
              }
            }} disabled={busy}
              className="h-9 px-3 rounded-lg bg-emerald-600 hover:bg-emerald-700 text-white text-xs font-medium flex items-center gap-1 disabled:opacity-50">
              <Check size={12} /> Mark complete
            </button>
          )}
          <button onClick={() => setStatusModal({ target: rep, bulkRows: items })} disabled={busy}
            className="h-9 px-3 rounded-lg border border-red-200 hover:bg-red-50 text-red-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
            <AlertCircle size={12} /> Blocked
          </button>
          <button onClick={() => setReassignTarget(rep)} disabled={busy}
            className="h-9 px-3 rounded-lg border border-stone-300 hover:bg-stone-50 text-stone-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
            <User size={12} /> Reassign
          </button>
        </div>

        {/* Go to this bedroom — primary action bar */}
        <button onClick={goTo}
          className="w-full py-2.5 rounded-lg bg-stone-900 text-stone-50 text-sm font-medium flex items-center justify-center gap-1.5 active:scale-98 transition-transform">
          Go to this bedroom <ChevronRight size={14} />
        </button>
      </div>
    );
  };

  // Collapsible section
  const Section = ({ id, title, items, limit = 5 }) => {
    if (!items || items.length === 0) return null;
    const isOpen = !collapsed[id];
    const shown = items.slice(0, limit);
    return (
      <div>
        <button onClick={() => setCollapsed(prev => ({ ...prev, [id]: !prev[id] }))}
          className="w-full flex items-center gap-2 mb-2 px-1 py-1.5 hover:bg-stone-50 rounded transition-colors text-left">
          <ChevronRight size={14} className={`text-stone-500 flex-shrink-0 transition-transform ${isOpen ? 'rotate-90' : ''}`} />
          <span className="text-sm font-bold text-stone-800 tracking-wide">{title}</span>
          <span className="text-xs font-mono text-stone-500">({items.length})</span>
          <div className="flex-1 h-px bg-stone-300" />
        </button>
        {isOpen && (
          <div className="space-y-2">
            {shown.map(renderBedroomCard)}
            {items.length > limit && (
              <div className="text-[11px] font-mono text-stone-500 italic px-1 py-1">
                + {items.length - limit} more bedroom{items.length - limit === 1 ? '' : 's'}
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  if (!loaded) return <div className="text-center py-12 text-stone-400 text-sm">Finding the closest work…</div>;

  const total = groups.sameApt.length + groups.sameFloor.length + groups.sameBuilding.length + groups.otherBuilding.length;
  if (total === 0) {
    return (
      <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
        Nothing else to clean at this property. Nice work!
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Anchor banner */}
      {anchor ? (
        <div className="p-3 rounded-xl bg-stone-100 border border-stone-200">
          <div className="text-[10px] uppercase tracking-wider font-mono text-stone-600 mb-0.5">
            Suggesting from
          </div>
          <div className="text-sm text-stone-900">
            <span className="font-bold">{anchor.unitLabel}</span>
            {anchor.partyLabel && <> · <span className="italic">{anchor.partyLabel}</span></>}
            <span className="text-stone-500 text-xs ml-2">
              {anchor.wasOpen ? '(your current bedroom)' : '(your most recent bedroom)'}
            </span>
          </div>
        </div>
      ) : (
        <div className="p-3 rounded-xl bg-stone-100 border border-stone-200">
          <div className="text-xs text-stone-700">
            You haven't started yet today. We're suggesting the 3rd floor of each building first, then working down.
          </div>
        </div>
      )}
      <Section id="sameApt"      title={anchor ? `Same apartment (${anchor.unitLabel})` : 'Start here'} items={groups.sameApt} />
      <Section id="sameFloor"    title="Same floor"        items={groups.sameFloor} />
      <Section id="sameBuilding" title="Same building"     items={groups.sameBuilding} />
      <Section id="otherBuilding" title={anchor ? 'Other buildings — starting on floor 3' : 'All buildings — starting on floor 3'} items={groups.otherBuilding} />

      {/* Modals */}
      {opened && (
        opened.assignment?.template_set_id
          ? <ChecklistAssignmentView assignment={opened.assignment}
              employee={employee}
              onClose={() => setOpened(null)}
              onOpenSheet={opened.assignment?.file_url
                ? () => window.open(opened.assignment.file_url, '_blank', 'noopener')
                : null} />
          : <AssignmentViewer target={opened} employee={employee} onClose={() => setOpened(null)} />
      )}
      {statusModal && (
        <BlockedNoteModal target={statusModal.target}
          onSave={(notes) => {
            if (statusModal.bulkRows && statusModal.bulkRows.length > 0) {
              bulkUpdateStatus(statusModal.bulkRows, 'blocked', notes);
            } else {
              bulkUpdateStatus([statusModal.target], 'blocked', notes);
            }
            setStatusModal(null);
          }}
          onClose={() => setStatusModal(null)}
          busy={busy} />
      )}
      {reassignTarget && (
        <ReassignModal target={reassignTarget} propertyId={propertyId}
          onSaved={() => { setReassignTarget(null); reload(); }}
          onClose={() => setReassignTarget(null)} />
      )}
    </div>
  );
}

function AssignmentTabContent({ propertyId, employee, statusFilter, onUpdate, onGoToBedroom, onOpenBedroomHistory, onJoinBlock }) {
  const [targets, setTargets] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [opened, setOpened] = useState(null);
  const [statusModal, setStatusModal] = useState(null);
  const [reassignTarget, setReassignTarget] = useState(null);
  const [busy, setBusy] = useState(false);
  const [filterBuildings, setFilterBuildings] = useState(new Set()); // multi-select building keys; empty = all
  const [collapsedBuildings, setCollapsedBuildings] = useState({}); // { B3: true } = collapsed
  // Floor collapse keyed by `${building}::${floor}`. Default expanded.
  const [collapsedFloors, setCollapsedFloors] = useState({});

  // Filters — apply on top of the loaded targets
  const [filtersOpen, setFiltersOpen] = useState(false);
  // Filters use Sets so the user can pick multiple values at once
  // (e.g. "show both Matias and Eli"). Empty Set means "no filter".
  const [filterTypes, setFilterTypes] = useState(new Set());        // assignment_type values
  const [filterCleaners, setFilterCleaners] = useState(new Set());  // employee ids
  // Completed-date RANGE filter (Done view). Empty string = no bound on
  // that side. Replaces the old day-of / last-3 / older quick tabs.
  const [dateFrom, setDateFrom] = useState(''); // YYYY-MM-DD inclusive start
  const [dateTo, setDateTo] = useState('');     // YYYY-MM-DD inclusive end
  const [filterCategories, setFilterCategories] = useState(new Set()); // task categories like 'bedroom'
  const [editDueId, setEditDueId] = useState(null);
  const canEditDatesT = can(employee, 'edit_due_dates');
  const todayKeyT = localTodayKey();
  const saveDueT = async (id, date) => {
    setEditDueId(null);
    if (id) { await supabase.from('assignments').update({ scheduled_date: date || null }).eq('id', id); load(); }
  };

  // Track which unit-bundles are expanded on the Pending view
  const [bundleOpen, setBundleOpen] = useState({}); // { unitId: boolean }

  const [loadError, setLoadError] = useState(null);

  // Open workblocks across this property — keyed by party_id so the
  // bedroom card can show a "[Name] · section is here" chip with a
  // Join button. Without this, a cleaner browsing Pending / In progress
  // had no Join affordance from the bedroom card itself; they had to
  // dive into the section picker (or use the Suggested tab). The
  // realtime sync (useAssignmentSync) reloads this when work_blocks
  // changes — so when another cleaner opens or closes a workblock,
  // every viewer's bedroom cards reflect it within a second or two.
  const [whosHereByParty, setWhosHereByParty] = useState(new Map());
  const loadWhosHere = async () => {
    const { data } = await supabase.from('work_blocks')
      .select('id, party_id, main_section, shift:shifts!inner(customer_id, employee:employees(id, name))')
      .is('end_time', null);
    const m = new Map();
    (data || []).forEach(b => {
      if (b.shift?.customer_id !== propertyId) return;
      if (!b.party_id) return;
      // Exclude the viewing cleaner's own workblock — they don't need
      // to "join" themselves; the active workblock pill at the top of
      // the cleaner shell already surfaces it.
      if (b.shift?.employee?.id === employee?.id) return;
      if (!m.has(b.party_id)) m.set(b.party_id, []);
      m.get(b.party_id).push({
        name: b.shift?.employee?.name || '?',
        workBlockId: b.id,
        mainSection: b.main_section,
      });
    });
    setWhosHereByParty(m);
  };
  useEffect(() => { loadWhosHere(); /* eslint-disable-next-line */ }, [propertyId]);
  useAssignmentSync(loadWhosHere, 'asgn-tab-whoshere');

  const load = async () => {
    setLoadError(null);
    // "Mine" and "recheck_passed" are derived from status='done' with
    // extra clientside filtering. We treat them as Done-tab variants
    // for the dominant-status logic below.
    const isMineOrRecheck = statusFilter === 'mine' || statusFilter === 'recheck_passed';
    const isDoneTab = statusFilter === 'done' || isMineOrRecheck;
    // Load EVERY relevant target at this property in one query — not
    // just items whose status matches the current tab. We need the
    // full per-bedroom status mix to compute the dominant status and
    // place each bedroom card in exactly ONE tab. This is the fix for
    // "card shows up in both Pending and In progress" — that bug was
    // a direct symptom of the previous per-item-status query.
    // Page through ALL matching targets in 1000-row chunks. Supabase
    // enforces a hard server-side max-rows ceiling (~1000) that
    // .limit() can't exceed, so a single query silently truncates once
    // a property has 1000+ target rows (a move-out check alone is 6-10
    // rows; a busy property blows past 1000 fast). That truncation was
    // the "184 jobs but only 48 visible / 998 rows" bug. We loop with
    // .range() until a page comes back short, guaranteeing we collect
    // every row. The !inner join + customer_id eq narrows server-side
    // where supported; we still re-filter client-side as a safety net.
    const PAGE = 1000;
    let data = [];
    let error = null;
    for (let from = 0; ; from += PAGE) {
      const { data: page, error: pErr } = await supabase
        .from('assignment_targets')
        .select('*, assignment:assignments!inner(id, title, notes, file_url, file_kind, customer_id, active, source, pm_status, deleted_at, extracted_text, spanish_translation, translation_status, assignment_type, scheduled_date, sheet_type, template_set_id, bathroom_variant, general_variant, created_at), unit:units(id, label), party:parties(id, label), starter:employees!started_by(id, name), completer:employees!completed_by(id, name), assignedTo:employees!assigned_to(id, name)')
        .eq('assignment.customer_id', propertyId)
        .eq('assignment.active', true)
          .is('assignment.deleted_at', null)
        .order('id', { ascending: true })
        .range(from, from + PAGE - 1);
      if (pErr) { error = pErr; break; }
      data = data.concat(page || []);
      // Last page reached when fewer than a full page returned.
      if (!page || page.length < PAGE) break;
      // Hard safety stop so a logic error can never infinite-loop.
      if (from > 200000) break;
    }
    if (error) {
      console.error('[Assignments] load error:', error);
      setLoadError(error.message);
      setTargets([]); setLoaded(true);
      return;
    }
    // Customer / active / PM-approval filter — same as before. Items
    // not visible to cleaners get dropped here.
    let allRelevant = (data || []).filter(t =>
      t.assignment?.customer_id === propertyId &&
      t.assignment?.active &&
      !t.assignment?.deleted_at &&
      (t.assignment?.source !== 'pm' || t.assignment?.pm_status === 'approved')
    );

    // Compute dominant status per ASSIGNMENT (not per bedroom). Each
    // assignment is an independent job with its own lifecycle — a
    // cleaning-check done last week and a move-out check pending this
    // week at the SAME bedroom are two separate assignments and one
    // must never override the other. Keying by assignment_id (instead
    // of unit_id::party_id) keeps them distinct. Priority order:
    // in_progress > paused > blocked > pending > done determines which
    // tab the assignment lands in.
    const asgnKey = (t) => t.assignment_id || `${t.unit_id || ''}::${t.party_id || ''}`;
    const dominantOrder = ['in_progress', 'paused', 'blocked', 'pending', 'done'];
    const statusesByAsgn = new Map();
    allRelevant.forEach(t => {
      const k = asgnKey(t);
      if (!statusesByAsgn.has(k)) statusesByAsgn.set(k, new Set());
      statusesByAsgn.get(k).add(t.status);
    });
    const dominantByAsgn = new Map();
    statusesByAsgn.forEach((statusSet, k) => {
      const winner = dominantOrder.find(s => statusSet.has(s)) || 'pending';
      dominantByAsgn.set(k, winner);
    });

    // Filter to assignments whose dominant status matches the current
    // tab. For "mine" / "recheck_passed" / Done we still keep everything
    // status=done since those are derived views — extra clientside
    // narrowing happens below.
    let filtered;
    if (isDoneTab) {
      filtered = allRelevant.filter(t => t.status === 'done' || t.status === 'blocked');
    } else {
      filtered = allRelevant.filter(t => dominantByAsgn.get(asgnKey(t)) === statusFilter);
    }
    // "Mine" view: only items I personally completed today
    if (statusFilter === 'mine') {
      const todayStart = new Date(); todayStart.setHours(0, 0, 0, 0);
      filtered = filtered.filter(t =>
        t.completed_by && employee?.id && t.completed_by === employee.id
        && t.completed_at && new Date(t.completed_at) >= todayStart
      );
    }
    if (statusFilter === 'recheck_passed') {
      filtered = filtered.filter(t => t.recheck_passed_at);
    }
    if (statusFilter === 'done') {
      // Sort Done by building → unit → bedroom (natural compare on the
      // unit label so "B1-101" comes before "B1-102" before "B2-101").
      // Owner uses Done to verify specific apartments, so spatial order
      // beats temporal order for findability. Time-bucketing (Day of /
      // Last 3d / Older) still groups by date — within each bucket the
      // items are now ordered by apartment.
      filtered.sort((a, b) =>
        naturalCompare(a.unit?.label || '', b.unit?.label || '')
        || naturalCompare(a.party?.label || '', b.party?.label || '')
      );
    } else if (statusFilter === 'paused') {
      // Paused tab: assignments paused BY the current user sort to the
      // top (most useful — they can resume their own work first), then
      // everyone else's paused work alphabetically by unit/party.
      // "Paused by" is inferred from started_by since the cleaner who
      // started is the one who paused. Priority still wins overall.
      const myId = employee?.id;
      filtered.sort((a, b) => {
        const ap = a.priority ? 1 : 0;
        const bp = b.priority ? 1 : 0;
        if (ap !== bp) return bp - ap;
        const aMine = myId && a.started_by === myId ? 0 : 1;
        const bMine = myId && b.started_by === myId ? 0 : 1;
        if (aMine !== bMine) return aMine - bMine;
        return naturalCompare(a.unit?.label || '', b.unit?.label || '')
          || naturalCompare(a.party?.label || '', b.party?.label || '');
      });
    } else {
      // Overdue → today → undated → upcoming, then priority, then
      // natural unit/party order, so cleaners see today's work first.
      filtered.sort((a, b) => {
        const ra = assignmentDueRank(a.assignment?.scheduled_date);
        const rb = assignmentDueRank(b.assignment?.scheduled_date);
        if (ra !== rb) return ra - rb;
        const ap = a.priority ? 1 : 0;
        const bp = b.priority ? 1 : 0;
        if (ap !== bp) return bp - ap;
        return naturalCompare(a.unit?.label || '', b.unit?.label || '')
          || naturalCompare(a.party?.label || '', b.party?.label || '');
      });
    }
    setTargets(filtered);
    setLoaded(true);
  };
  useEffect(() => { load(); /* eslint-disable-next-line */ }, [propertyId, statusFilter]);
  useAssignmentSync(load, 'asgn-tab');

  // Map of "<unit_id>:<party_id>" → Set of task categories ever worked
  // at that bedroom for this property. Used by the category filter so
  // the owner can ask "show me bedrooms where bathroom work happened."
  const [tasksByBedroom, setTasksByBedroom] = useState({});
  useEffect(() => {
    if (!propertyId) return;
    (async () => {
      // Pull every task for this property via the work_block → shift chain
      const { data } = await supabase.from('tasks')
        .select('category, work_block:work_blocks!inner(unit_id, party_id, shift:shifts!inner(customer_id))')
        .not('category', 'is', null);
      const map = {};
      (data || []).forEach(t => {
        const wb = t.work_block;
        if (!wb || wb.shift?.customer_id !== propertyId) return;
        if (!wb.unit_id || !wb.party_id) return;
        const key = `${wb.unit_id}:${wb.party_id}`;
        if (!map[key]) map[key] = new Set();
        map[key].add(t.category);
      });
      setTasksByBedroom(map);
    })();
  }, [propertyId, targets.length]);

  // Cutoff retired: every assignment now renders as ONE bedroom-level
  // bulk card with the section breakdown. The old per-item rendering
  // (one card per assignment_target) caused the "16 cards for one
  // bedroom" surprise when items spanned multiple sections. Bedroom
  // cards now always read as one card per (apartment, bedroom),
  // matching the cleaner's mental model of "this bedroom is one job".
  const isPostCutoff = (_t) => true;

  // Bulk wrappers that act on every target at a bedroom. Optimistic
  // update + single .in() call, then re-load. Used by the new
  // bedroom-level card so the cleaner can mark-complete / block /
  // re-prioritize a whole bedroom in one tap.
  const bulkUpdateStatus = async (rows, newStatus, statusNotes) => {
    if (!rows || rows.length === 0) return;
    const ids = rows.map(r => r.id);
    const movedOffTab = newStatus !== statusFilter;
    if (movedOffTab) {
      setTargets(prev => prev.filter(t => !ids.includes(t.id)));
    } else {
      setTargets(prev => prev.map(t => ids.includes(t.id) ? { ...t, status: newStatus } : t));
    }
    setBusy(true);
    const patch = { status: newStatus };
    if (newStatus === 'in_progress') {
      patch.started_at = new Date().toISOString();
      patch.started_by = employee?.id || null;
    }
    if (newStatus === 'done') {
      patch.completed_at = new Date().toISOString();
      patch.completed_by = employee?.id || null;
    } else {
      patch.completed_at = null; patch.completed_by = null;
    }
    if (newStatus === 'pending') {
      patch.started_at = null;
      patch.started_by = null;
    }
    if (statusNotes !== undefined) patch.status_notes = statusNotes || null;
    const { error } = await supabase.from('assignment_targets').update(patch).in('id', ids);
    setBusy(false);
    if (error) { load(); alert('Could not update: ' + error.message); return; }
    load();
    if (onUpdate) onUpdate();
  };

  const bulkTogglePriority = async (rows) => {
    if (!rows || rows.length === 0) return;
    const anyOn = rows.some(r => r.priority);
    const next = !anyOn;
    const ids = rows.map(r => r.id);
    setTargets(prev => prev.map(t => ids.includes(t.id) ? { ...t, priority: next } : t));
    const { error } = await supabase.from('assignment_targets').update({ priority: next }).in('id', ids);
    if (error) { alert('Could not update priority: ' + error.message); load(); }
  };

  const updateStatus = async (target, newStatus, statusNotes) => {
    // OPTIMISTIC: since this tab filters by statusFilter, an item that
    // just changed status no longer belongs in the current view —
    // remove it immediately so the cleaner sees the result of their
    // tap with zero delay. Reload below fetches the authoritative
    // state; realtime reconciles any discrepancy.
    const movedOffTab = newStatus !== statusFilter;
    if (movedOffTab) {
      setTargets(prev => prev.filter(t => t.id !== target.id));
    } else {
      setTargets(prev => prev.map(t => t.id === target.id ? { ...t, status: newStatus } : t));
    }

    setBusy(true);
    const patch = { status: newStatus };
    if (newStatus === 'in_progress') {
      if (!target.started_at) patch.started_at = new Date().toISOString();
      patch.started_by = employee?.id || null;
    }
    if (newStatus === 'done') {
      patch.completed_at = new Date().toISOString();
      patch.completed_by = employee?.id || null;
    } else if (target.status === 'done') {
      patch.completed_at = null; patch.completed_by = null;
    }
    // Move-to-pending wipes started_by/at so the assignment appears
    // fully unstarted in the Pending tab.
    if (newStatus === 'pending' && (target.status === 'paused' || target.status === 'in_progress' || target.status === 'blocked')) {
      patch.started_at = null;
      patch.started_by = null;
    }
    if (statusNotes !== undefined) patch.status_notes = statusNotes || null;
    const { error } = await supabase.from('assignment_targets').update(patch).eq('id', target.id);
    setBusy(false);
    if (error) {
      // Roll back optimistic on failure so the user sees the truth
      load();
      alert('Could not update: ' + error.message);
      return;
    }
    setStatusModal(null);
    load();
    if (onUpdate) onUpdate();
  };

  // Flip the priority flag on a single target. Same per-target model
  // as elsewhere — one card = one target, one toggle. Optimistic
  // update so the chip flips instantly; rolls back on DB error.
  const togglePriority = async (target) => {
    const next = !target.priority;
    setTargets(prev => prev.map(t => t.id === target.id ? { ...t, priority: next } : t));
    const { error } = await supabase.from('assignment_targets')
      .update({ priority: next }).eq('id', target.id);
    if (error) {
      alert('Could not update priority: ' + error.message);
      setTargets(prev => prev.map(t => t.id === target.id ? { ...t, priority: !next } : t));
    } else if (onUpdate) {
      onUpdate();
    }
  };

  // Tapping "Start" / "Resume" / "Go to this bedroom" on an assignment
  // card no longer mutates status. It just navigates to the prep
  // screen. The cleaner confirms with the big Start cleaning button
  // there — that's the SINGLE confirmation point. confirmPendingStart
  // → autoStartAssignmentsAtBedroom is what actually flips pending/
  // paused targets to in_progress. This stops "I clicked Go and now
  // the assignment is in_progress even though I didn't start work."
  const startAndGo = async (target) => {
    if (onGoToBedroom && target.unit_id && target.party_id) {
      onGoToBedroom(target);
    }
  };

  if (!loaded) return <div className="text-center py-8 text-stone-400 text-xs">Loading…</div>;
  if (loadError) {
    return (
      <div className="p-4 rounded-2xl bg-red-50 border border-red-200 text-red-700 text-sm">
        <div className="flex items-start gap-2 mb-1">
          <AlertCircle size={16} className="flex-shrink-0 mt-0.5" />
          <span className="font-medium">Couldn't load assignments</span>
        </div>
        <div className="text-xs font-mono mt-2">{loadError}</div>
      </div>
    );
  }
  if (targets.length === 0) {
    const empties = {
      pending: 'No pending assignments.',
      paused: 'No paused assignments.',
      in_progress: 'No assignments are in progress.',
      done: 'No completed assignments yet.'
    };
    return (
      <div className="text-center py-8 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
        {empties[statusFilter]}
      </div>
    );
  }

  // Apply user filters (type / cleaner / day) before grouping.
  // We build "filteredTargets" once and feed it to all downstream
  // grouping/rendering logic.
  const todayKey = (() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
  })();
  const filteredTargets = targets.filter(t => {
    // Type filter (multi-select)
    if (filterTypes.size > 0) {
      const typ = t.assignment?.assignment_type || '';
      if (!filterTypes.has(typ)) return false;
    }
    // Cleaner filter — matches starter OR completer
    if (filterCleaners.size > 0) {
      const ids = [t.starter?.id, t.completer?.id].filter(Boolean);
      const hit = ids.some(id => filterCleaners.has(id));
      if (!hit) return false;
    }
    // Completed-date RANGE filter (Done view). Inclusive on both ends;
    // a blank side means "no bound". Filters on the day the work was
    // actually completed. Items without a completed date drop out when
    // any bound is set (they live under Pending anyway).
    if (dateFrom || dateTo) {
      const cd = t.completed_at ? new Date(t.completed_at).toISOString().slice(0, 10) : null;
      if (!cd) return false;
      if (dateFrom && cd < dateFrom) return false;
      if (dateTo && cd > dateTo) return false;
    }
    // Category filter — checks if any task at this bedroom matches
    if (filterCategories.size > 0) {
      if (!t.unit_id || !t.party_id) return false;
      const key = `${t.unit_id}:${t.party_id}`;
      const cats = tasksByBedroom[key];
      if (!cats) return false;
      const hit = Array.from(filterCategories).some(c => cats.has(c));
      if (!hit) return false;
    }
    return true;
  });

  // Compute available filter values from the FULL (pre-filter) target set
  // so dropdowns don't lose options after filtering down.
  const availableTypes = [...new Set(targets.map(t => t.assignment?.assignment_type).filter(Boolean))];
  const availableCleaners = (() => {
    const map = new Map();
    targets.forEach(t => {
      if (t.starter?.id) map.set(t.starter.id, t.starter);
      if (t.completer?.id) map.set(t.completer.id, t.completer);
    });
    return Array.from(map.values()).sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  })();
  const availableCategories = (() => {
    const cats = new Set();
    Object.values(tasksByBedroom).forEach(s => s.forEach(c => cats.add(c)));
    // Only show categories that actually exist in the data
    return TASK_CATEGORIES.filter(c => cats.has(c.id));
  })();
  const activeFilterCount =
    (filterTypes.size > 0 ? 1 : 0) +
    (filterCleaners.size > 0 ? 1 : 0) +
    ((dateFrom || dateTo) ? 1 : 0) +
    (filterCategories.size > 0 ? 1 : 0);

  // Toggle helpers — add/remove a value from a Set state
  const toggleSetValue = (setter) => (value) => setter(prev => {
    const next = new Set(prev);
    if (next.has(value)) next.delete(value);
    else next.add(value);
    return next;
  });
  const toggleType = toggleSetValue(setFilterTypes);
  const toggleCleaner = toggleSetValue(setFilterCleaners);
  const toggleCategory = toggleSetValue(setFilterCategories);

  // Owner approval for cleaner-requested items. The work may already be
  // done — this is an after-the-fact decision (e.g. for billing). Approve
  // marks the request settled; Reject flags it so it can be excluded.
  // Acts on the still-pending requests in the passed-in item list.
  const reviewRequest = async (items, decision) => {
    const ids = (items || [])
      .filter(t => t.requested_by && (t.request_status || 'pending') === 'pending')
      .map(t => t.id);
    if (ids.length === 0) return;
    const { error } = await supabase.from('assignment_targets')
      .update({ request_status: decision })
      .in('id', ids);
    if (error) { alert('Could not update request: ' + error.message); return; }
    load();
    if (onUpdate) onUpdate();
  };

  // Group targets by building, derived from the unit label (e.g. "B3-205" -> "B3")
  // Targets without a unit go into a "No unit" bucket
  const buildings = {};
  filteredTargets.forEach(t => {
    const b = buildingFromLabel(t.unit?.label) || '—';
    if (!buildings[b]) buildings[b] = [];
    buildings[b].push(t);
  });
  const buildingKeys = Object.keys(buildings).sort(naturalCompare);
  const visibleBuildings = filterBuildings.size === 0 ? buildingKeys : buildingKeys.filter(k => filterBuildings.has(k));
  const toggleCollapse = (b) => setCollapsedBuildings(prev => ({ ...prev, [b]: !prev[b] }));
  const toggleBuilding = (b) => setFilterBuildings(prev => {
    const next = new Set(prev);
    if (next.has(b)) next.delete(b); else next.add(b);
    return next;
  });
  // Done-family tabs get the completed-date range picker.
  const isDoneView = statusFilter === 'done' || statusFilter === 'mine' || statusFilter === 'recheck_passed';

  // Count DISTINCT assignments in a target list. Each assignment is an
  // independent job — a cleaning-check and a move-out check at the same
  // bedroom are two separate assignments and count as two. This matches
  // the owner-side count (one per assignment) so "96 open" on owner ==
  // what the cleaner sees. Falls back to bedroom key for any legacy
  // target missing an assignment_id.
  const countBedrooms = (list) => {
    const s = new Set();
    (list || []).forEach(t => s.add(t.assignment_id || `${t.unit_id || ''}::${t.party_id || ''}`));
    return s.size;
  };

  // GLOBAL PRIORITY BLOCK (Pending tab only): pull priority items out
  // of their per-building bucket and show them as one section at the
  // top. Without this, priority items get hidden inside each building
  // (e.g. priority in B2 stuck behind 5 normal B1 items). Building
  // filter still applies so filtering to "Building 1" only shows B1's
  // priority at the top.
  const globalPriorityItems = statusFilter === 'pending'
    ? visibleBuildings.flatMap(b => buildings[b])
        // "Do these first" should only include items still needing
        // attention — done and blocked items have no first-do-this
        // urgency and were appearing in the section because the load
        // includes ALL targets at bedrooms whose dominant status is
        // pending (which is intentional for the bulk card view, but
        // wrong here).
        .filter(t => t.priority && t.status !== 'done' && t.status !== 'blocked')
    : [];

  // For Done tab: bucket by age using local-date math.
  //   Day of:      completed today (local timezone)
  //   Last 3 days: completed 1, 2, or 3 days ago
  //   4+ days:     completed 4+ days ago
  // Using local-date comparison (not wall-clock subtraction) so a job
  // completed late last night still shows under "Day of" today.
  const todayLocal = (() => {
    const d = new Date();
    return new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime();
  })();
  const DAY_MS = 24 * 60 * 60 * 1000;
  const bucketByAge = (items) => {
    const buckets = { dayOf: [], last3: [], older: [] };
    items.forEach(t => {
      const ts = t.completed_at ? new Date(t.completed_at).getTime() : 0;
      if (!ts) { buckets.older.push(t); return; }
      const completedLocal = (() => {
        const d = new Date(ts);
        return new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime();
      })();
      const daysAgo = Math.round((todayLocal - completedLocal) / DAY_MS);
      if (daysAgo <= 0) buckets.dayOf.push(t);
      else if (daysAgo <= 3) buckets.last3.push(t);
      else buckets.older.push(t);
    });
    return buckets;
  };

  // For Pending view, bundle by unit when there are multiple per unit
  // ("3 assignments in B1-101"). Single-assignment units stay as plain
  // cards. The bundle is a collapsible group so the list stays short.
  const toggleBundle = (unitId) => setBundleOpen(prev => ({ ...prev, [unitId]: !prev[unitId] }));

  // Render a single grouped/bundled list. Extracted into a helper so we
  // can call it twice on the Pending tab — once for priority items
  // (top), once for the rest — with a visual separator between.
  const renderGroupedItems = (items) => {
    if (items.length === 0) return null;

    // Group by unit_id (apartment). Items without a unit go in their own bucket.
    const groups = new Map(); // unitId or 'no-unit' -> { unit, items: [] }
    items.forEach(t => {
      const key = t.unit_id || 'no-unit';
      if (!groups.has(key)) {
        groups.set(key, { unit: t.unit, unitId: t.unit_id, items: [] });
      }
      groups.get(key).items.push(t);
    });

    // Sort apartments strictly by their label (natural compare). Per
    // the owner's request, multi-assignment apartments no longer
    // automatically jump to the top — order stays numerical so the
    // cleaner reads top-down 101, 102, 103, 201, 202, etc.
    const entries = Array.from(groups.entries()).sort((a, b) =>
      naturalCompare(a[1].unit?.label || '', b[1].unit?.label || '')
    );

    return (
      <div className="space-y-2">
        {entries.map(([key, group]) => {
          // Distinct ASSIGNMENTS (jobs) in this apartment with open
          // work. The chip on the apartment pill counts jobs, not item
          // rows (which can hit the hundreds in a Fail-Entire scenario)
          // and not bedrooms (since one bedroom can carry a cleaning-
          // check AND a move-out check as two separate jobs). This
          // makes the chip number match the number of cards the cleaner
          // sees when they expand the apartment.
          const asgnIds = new Set();
          group.items.forEach(t => asgnIds.add(t.assignment_id || `${t.party_id || 'no-party'}`));
          const bedroomCount = asgnIds.size;

          // Single-job + single-item apartments render as a plain
          // card with no extra nesting. Saves a click.
          if (group.items.length === 1) {
            const t = group.items[0];
            return (
              <AssignmentCard key={t.id} target={t} busy={busy} propertyId={propertyId}
                onView={() => setOpened(t)}
                onStart={() => startAndGo(t)}
                onPause={() => updateStatus(t, 'paused')}
              onMoveToPending={() => updateStatus(t, 'pending')}
                onDone={() => updateStatus(t, 'done')}
                onReopen={() => updateStatus(t, 'pending')}
                onBlocked={() => setStatusModal({ target: t })}
                onReassign={() => setReassignTarget(t)}
                onTogglePriority={togglePriority}
              canMarkDone={can(employee, 'mark_assignments_done') || t.started_by === employee?.id}
              canMarkDoneAlways={can(employee, 'mark_assignments_done')}
              currentEmployeeId={employee?.id}
                onGoToBedroom={onGoToBedroom ? () => startAndGo(t) : null}
                canEditDates={can(employee, 'edit_due_dates')}
                onSetDueDate={async (aid, date) => { if (aid) { await supabase.from('assignments').update({ scheduled_date: date }).eq('id', aid); load(); } }}
                onOpenBedroomHistory={onOpenBedroomHistory} />
            );
          }
          // Apartment-level expandable card. When expanded, we don't
          // dump every item — we group by BEDROOM (party_id) and
          // then by main SECTION inside each bedroom. Three taps
          // total to reach the item: apartment → bedroom → section.
          const isOpen = !!bundleOpen[key];
          const unitLabel = group.unit?.label || (key === 'no-unit' ? 'No unit' : key);
          const bundleHasPriority = group.items.some(t => t.priority);
          // Most-urgent due status across this apartment's jobs.
          const unitDueKinds = group.items.map(t => assignmentDueKind(t.assignment?.scheduled_date)).filter(Boolean);
          const unitDue = unitDueKinds.includes('overdue') ? 'overdue'
            : unitDueKinds.includes('today') ? 'today'
            : unitDueKinds.includes('upcoming') ? 'upcoming' : null;
          const earliestUpcoming = group.items
            .map(t => t.assignment?.scheduled_date)
            .filter(d => d && assignmentDueKind(d) === 'upcoming')
            .sort()[0];
          // Build the assignment → section breakdown for the expanded
          // view. We key by party_id + assignment_id (NOT just party_id)
          // so two independent assignments at the same bedroom — e.g. a
          // cleaning-check done last week and a move-out check pending
          // this week — render as TWO separate cards. Each assignment is
          // its own job with its own lifecycle; marking one done must
          // never affect the other.
          const byBedroom = new Map(); // `${partyId}::${assignmentId}` -> { party, items, sections }
          group.items.forEach(t => {
            const pid = t.party_id || 'no-party';
            const aid = t.assignment_id || 'no-asgn';
            const groupKey = `${pid}::${aid}`;
            if (!byBedroom.has(groupKey)) {
              byBedroom.set(groupKey, {
                party: t.party,
                partyId: t.party_id,
                assignmentId: t.assignment_id,
                assignment: t.assignment,
                items: [],
                sectionItems: { bedroom: [], vanity: [], bathroom: [], general: [] },
                hasPriority: false,
              });
            }
            const b = byBedroom.get(groupKey);
            b.items.push(t);
            const sec = (t.template_section || '').toLowerCase();
            if (b.sectionItems[sec]) b.sectionItems[sec].push(t);
            if (t.priority) b.hasPriority = true;
          });
          // Sort by bedroom label, then by assignment creation so a
          // bedroom's multiple assignments appear in a stable order.
          const bedroomEntries = Array.from(byBedroom.entries()).sort((a, b) =>
            naturalCompare(a[1].party?.label || '', b[1].party?.label || '')
            || naturalCompare(a[1].assignment?.created_at || '', b[1].assignment?.created_at || '')
          );
          return (
            <div key={key} className="rounded-xl border-2 border-amber-200 bg-amber-50/40 overflow-hidden">
              <button onClick={() => toggleBundle(key)}
                className="w-full px-4 py-3 flex items-center justify-between hover:bg-amber-50">
                <div className="flex items-center gap-2 min-w-0">
                  <Building2 size={16} className="text-amber-700 flex-shrink-0" />
                  <span className="font-serif text-base text-stone-900 truncate">{unitLabel}</span>
                  <span className="text-xs font-mono px-2 py-0.5 rounded-full bg-amber-600 text-white font-bold flex-shrink-0">
                    {bedroomCount} job{bedroomCount === 1 ? '' : 's'}
                  </span>
                  {unitDue === 'overdue' && <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-red-100 text-red-700 flex-shrink-0">Overdue</span>}
                  {unitDue === 'today' && <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-emerald-100 text-emerald-800 flex-shrink-0">Today</span>}
                  {unitDue === 'upcoming' && earliestUpcoming && <span className="text-[10px] font-mono px-2 py-0.5 rounded-full bg-stone-200 text-stone-600 flex-shrink-0">{fmtDateWithDay(earliestUpcoming)}</span>}
                  {bundleHasPriority && <PriorityChip on={true} size="xs" />}
                </div>
                <ChevronRight size={14} className={`text-amber-700 flex-shrink-0 transition-transform ${isOpen ? 'rotate-90' : ''}`} />
              </button>
              {isOpen && (
                <div className="px-3 pb-3 space-y-2 border-t border-amber-100 pt-3">
                  {bedroomEntries.map(([groupKey, bed]) => {
                    // Real party_id for this entry — used for whosHere
                    // lookups (which are per-bedroom) and as a stable
                    // React key suffix. The map key is partyId::asgnId
                    // so two assignments at one bedroom stay separate.
                    const pid = bed.partyId || 'no-party';
                    const bedLabel = shortenBedroom(bed.party?.label || (pid === 'no-party' ? 'Unassigned' : pid));
                    const sectionCounts = {
                      bedroom: bed.sectionItems.bedroom.length,
                      vanity: bed.sectionItems.vanity.length,
                      bathroom: bed.sectionItems.bathroom.length,
                      general: bed.sectionItems.general.length,
                    };
                    // Items not in any of the 4 known sections (legacy
                    // targets with no template_section, or one-offs).
                    const knownSectioned =
                      sectionCounts.bedroom + sectionCounts.vanity +
                      sectionCounts.bathroom + sectionCounts.general;
                    const otherCount = bed.items.length - knownSectioned;
                    const sectionBits = [];
                    if (sectionCounts.bedroom)  sectionBits.push(`Bedroom (${sectionCounts.bedroom})`);
                    if (sectionCounts.vanity)   sectionBits.push(`Vanity (${sectionCounts.vanity})`);
                    if (sectionCounts.bathroom) sectionBits.push(`Bathroom (${sectionCounts.bathroom})`);
                    if (sectionCounts.general)  sectionBits.push(`General (${sectionCounts.general})`);
                    if (otherCount > 0)         sectionBits.push(`Other (${otherCount})`);

                    // Split this bedroom's items by cutoff. LEGACY
                    // (pre-cutoff) items render as the original per-item
                    // AssignmentCards — that's the contract the user
                    // asked for, so the Mon-Wed assignments behave
                    // exactly the way the cleaners are already used
                    // to. NEW (post-cutoff) items collapse into ONE
                    // bedroom-level card with the section breakdown +
                    // bulk action buttons.
                    const legacyItems = bed.items.filter(t => !isPostCutoff(t));
                    const newItems = bed.items.filter(t => isPostCutoff(t));

                    const firstTarget = bed.items[0];
                    const canGoToBedroom = !!(onGoToBedroom && firstTarget?.unit_id && firstTarget?.party_id);

                    // Build the bedroom-level bulk card (only when there
                    // are NEW items at this bedroom). We compute a few
                    // derived flags from the new-items subset:
                    //  - hasPriority: any new item has priority on
                    //  - statusBucket: the dominant status to display
                    //    in the read-only pill (pending wins, then
                    //    in_progress, then paused, then blocked, then done)
                    //  - allDone: every new item is already done
                    //  - canBulkComplete: at least one item can move to
                    //    done (i.e. not already done)
                    let bulkCard = null;
                    if (newItems.length > 0) {
                      const anyPriority = newItems.some(t => t.priority);
                      // Whether any item at this bedroom is a cleaner
                      // request waiting on owner review. Drives the
                      // amber "Requested" banner at the top of the
                      // card so the owner sees there's something new
                      // to approve here.
                      const hasRequestedItems = newItems.some(t => t.requested_by);
                      const pendingReview = newItems.filter(t => t.requested_by && (t.request_status || 'pending') === 'pending');
                      const hasPendingReview = pendingReview.length > 0;
                      const reviewedApproved = newItems.some(t => t.requested_by && t.request_status === 'approved');
                      const reviewedRejected = newItems.some(t => t.requested_by && t.request_status === 'rejected');
                      const statusOrder = ['pending', 'in_progress', 'paused', 'blocked', 'done'];
                      const dominantStatus =
                        statusOrder.find(s => newItems.some(t => t.status === s)) || 'pending';
                      const statusPill = ASSIGNMENT_STATUSES[dominantStatus] || ASSIGNMENT_STATUSES.pending;
                      const allDone = newItems.every(t => t.status === 'done');
                      const canBulkComplete = !allDone && can(employee, 'mark_assignments_done');
                      // For View Doc and Reassign we pick the first
                      // target's assignment as the representative.
                      // Bedroom-level uploads are 1 assignment per
                      // bedroom in the new model so this is correct
                      // 99% of the time; the rare exception (multiple
                      // assignments at one bedroom) still gets a
                      // useful "open one of them" affordance.
                      bulkCard = (
                        <div key={`bulk-${groupKey}`} className="rounded-xl border border-stone-200 bg-white p-3">
                          {/* Cleaner request banner — shows at the very
                             top of the card whenever a cleaner has
                             submitted a request at this bedroom that's
                             still pending. Drops a clear "needs review"
                             signal in front of the owner without
                             interrupting the rest of the card. */}
                          {/* Cleaner request banner — when there are
                             requests awaiting review, show Approve /
                             Reject. Once reviewed, it collapses to a
                             quiet status line. The requested items are
                             already on the cleaner's list regardless;
                             this is owner sign-off after the fact. */}
                          {hasPendingReview ? (
                            <div className="mb-2 px-2 py-1.5 rounded-md bg-amber-100 border border-amber-300">
                              <div className="flex items-center gap-1.5 mb-1.5">
                                <span className="w-1.5 h-1.5 rounded-full bg-amber-600 animate-pulse" />
                                <span className="text-[10px] uppercase tracking-wider font-mono text-amber-900 font-bold">
                                  Cleaner requested {pendingReview.length} item{pendingReview.length === 1 ? '' : 's'} — review
                                </span>
                              </div>
                              <div className="flex gap-1.5">
                                <button onClick={() => reviewRequest(newItems, 'approved')} disabled={busy}
                                  className="flex-1 py-1 rounded-md bg-emerald-600 hover:bg-emerald-700 text-white text-[11px] font-bold flex items-center justify-center gap-1 disabled:opacity-50">
                                  <Check size={12} /> Approve
                                </button>
                                <button onClick={() => reviewRequest(newItems, 'rejected')} disabled={busy}
                                  className="flex-1 py-1 rounded-md bg-white hover:bg-stone-100 border border-stone-300 text-stone-700 text-[11px] font-bold flex items-center justify-center gap-1 disabled:opacity-50">
                                  <X size={12} /> Reject
                                </button>
                              </div>
                            </div>
                          ) : hasRequestedItems && (reviewedApproved || reviewedRejected) ? (
                            <div className="mb-2 flex items-center gap-1.5 px-2 py-1 rounded-md bg-stone-100 border border-stone-200">
                              {reviewedApproved && !reviewedRejected ? (
                                <span className="text-[10px] uppercase tracking-wider font-mono text-emerald-700 font-bold flex items-center gap-1"><Check size={11} /> Request approved</span>
                              ) : reviewedRejected && !reviewedApproved ? (
                                <span className="text-[10px] uppercase tracking-wider font-mono text-stone-500 font-bold flex items-center gap-1"><X size={11} /> Request rejected</span>
                              ) : (
                                <span className="text-[10px] uppercase tracking-wider font-mono text-stone-500 font-bold">Request reviewed</span>
                              )}
                            </div>
                          ) : null}
                          {/* "Who's here" chips — only shows when ANOTHER
                             cleaner has an open workblock at this bedroom.
                             Each chip carries the cleaner's name + section
                             they're working + a Join button so the viewer
                             can hop in without going through the picker
                             flow. Self-chip is filtered out in loadWhosHere
                             since "Join yourself" makes no sense. */}
                          {(whosHereByParty.get(pid) || []).length > 0 && (
                            <div className="mb-2 flex items-center gap-1.5 flex-wrap">
                              <span className="text-[10px] uppercase tracking-wider font-mono text-amber-900 font-bold">
                                ●
                              </span>
                              {(whosHereByParty.get(pid) || []).map((w, i) => (
                                <span key={i} className="inline-flex items-center gap-1">
                                  <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-amber-100 text-amber-900 border border-amber-300 font-bold">
                                    {w.name}{w.mainSection ? ` · ${w.mainSection}` : ''} is here
                                  </span>
                                  {onJoinBlock && w.workBlockId && (
                                    <button onClick={(e) => { e.stopPropagation(); onJoinBlock({ id: w.workBlockId }); }}
                                      className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-900 hover:bg-stone-800 text-stone-50 font-bold inline-flex items-center gap-1 active:scale-95">
                                      <Plus size={9} /> Join
                                    </button>
                                  )}
                                </span>
                              ))}
                            </div>
                          )}
                          {/* === HEADER: title + chips === */}
                          <div className="flex items-start justify-between gap-2 mb-2">
                            <div className="flex-1 min-w-0">
                              {canGoToBedroom ? (
                                <button onClick={() => startAndGo(firstTarget)} disabled={busy}
                                  className="block text-left w-full font-serif text-base text-stone-900 leading-tight break-words hover:underline disabled:opacity-50">
                                  <span className="font-bold">{group.unit?.label || unitLabel}</span>
                                  <span className="text-stone-400 mx-1.5">·</span>
                                  <span className="italic">{bedLabel}</span>
                                </button>
                              ) : (
                                <div className="font-serif text-base text-stone-900 leading-tight break-words">
                                  <span className="font-bold">{group.unit?.label || unitLabel}</span>
                                  <span className="text-stone-400 mx-1.5">·</span>
                                  <span className="italic">{bedLabel}</span>
                                </div>
                              )}
                            </div>
                            <div className="flex flex-col items-end gap-1 flex-shrink-0">
                              <div className="flex items-center gap-1.5 flex-wrap justify-end">
                                <button onClick={(e) => { e.stopPropagation(); bulkTogglePriority(newItems); }} disabled={busy}
                                  className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 transition-colors disabled:opacity-50 ${anyPriority
                                      ? 'bg-red-100 text-red-800 border-red-300 font-bold hover:bg-red-200'
                                      : 'bg-stone-100 text-stone-500 border-stone-200 hover:bg-stone-200'}`}>
                                  <AlertCircle size={10} /> {anyPriority ? 'Priority' : 'Mark priority'}
                                </button>
                                <span className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border ${statusPill.color}`}>
                                  {statusPill.label}
                                </span>
                                {(() => {
                                  const asg = (newItems[0] || firstTarget)?.assignment;
                                  const sd = asg?.scheduled_date;
                                  if (editDueId === asg?.id) return (
                                    <input type="date" autoFocus value={sd || ''}
                                      onChange={(e) => saveDueT(asg?.id, e.target.value)}
                                      onBlur={() => setEditDueId(null)}
                                      onClick={(e) => e.stopPropagation()}
                                      className="text-[10px] font-mono px-1.5 py-0.5 rounded border border-stone-400 bg-white" />
                                  );
                                  if (canEditDatesT) return (
                                    <button onClick={(e) => { e.stopPropagation(); setEditDueId(asg?.id); }}
                                      className={`text-[10px] font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 ${sd
                                        ? (sd < todayKeyT ? 'bg-red-100 text-red-700 border-red-200'
                                           : sd === todayKeyT ? 'bg-emerald-100 text-emerald-800 border-emerald-200'
                                           : 'bg-stone-100 text-stone-600 border-stone-200')
                                        : 'bg-white text-stone-500 border-dashed border-stone-300'}`}>
                                      <Calendar size={9} /> {sd
                                        ? (sd < todayKeyT ? `Overdue · ${fmtDueDate(sd)}` : sd === todayKeyT ? 'Today' : fmtDueDate(sd))
                                        : 'Set due date'}
                                    </button>
                                  );
                                  return sd ? (
                                    <span className="text-[10px] font-mono px-2 py-0.5 rounded-full border bg-stone-100 text-stone-600 border-stone-200 inline-flex items-center gap-1">
                                      <Calendar size={9} /> {sd === todayKeyT ? 'Today' : fmtDueDate(sd)}
                                    </span>
                                  ) : null;
                                })()}
                              </div>
                              <div className="flex items-center gap-1.5 flex-wrap justify-end">
                                <button onClick={(e) => { e.stopPropagation(); setOpened(firstTarget); }}
                                  className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1">
                                  <Eye size={10} /> Quick glance
                                </button>
                                {onOpenBedroomHistory && firstTarget?.unit_id && firstTarget?.party_id && (
                                  <button onClick={(e) => { e.stopPropagation(); onOpenBedroomHistory({
                                      unitId: firstTarget.unit_id, unitLabel: group.unit?.label,
                                      partyId: firstTarget.party_id, partyLabel: bedLabel,
                                    }); }} disabled={busy}
                                    className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1 disabled:opacity-50">
                                    <Clock size={10} /> History
                                  </button>
                                )}
                              </div>
                            </div>
                          </div>
                          {/* === ASSIGNMENT TITLE + TYPE + SECTION BREAKDOWN === */}
                          <div className="mb-2">
                            <div className="font-serif text-sm text-stone-700">
                              {shortenBedroom(firstTarget?.assignment?.title) || 'Cleaning assignment'}
                            </div>
                            {firstTarget?.assignment?.assignment_type && (
                              <div className="mt-1">
                                <AssignmentTypeChip type={firstTarget.assignment.assignment_type} />
                              </div>
                            )}
                            <div className="text-[11px] font-mono text-stone-500 mt-1">
                              {newItems.length} {newItems.length === 1 ? 'item' : 'items'}
                              {sectionBits.length > 0 && (
                                <> · {sectionBits.join(' · ')}</>
                              )}
                            </div>
                          </div>
                          {/* === BULK ACTION BUTTONS ===
                             Start = navigate to bedroom (no status flip).
                             Pause = flip in_progress items to paused so the
                                     cleaner can step away and return without
                                     losing the timer/credit. Visible on In
                                     progress tab only — Pending has nothing
                                     to pause, Done/Blocked are terminal.
                             Resume = flip paused items back to in_progress.
                                      Visible on Paused tab.
                             Mark complete = bulk mark all to done (with confirm).
                             Blocked = bulk mark all blocked (note via modal on first
                                       target as proxy; we apply the same note to all).
                             Reassign = opens reassign modal on the first target.
                                        It's a per-target modal so handling N targets
                                        sequentially would be ugly; keeping it on
                                        one. Most apt cases have 1 assignment per
                                        bedroom in the new model anyway. */}
                          <div className="flex gap-2 flex-wrap">
                            {!allDone && canGoToBedroom && (
                              <button onClick={() => startAndGo(firstTarget)} disabled={busy}
                                className="h-9 px-3 rounded-lg bg-amber-600 hover:bg-amber-700 text-white text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                                <Play size={12} /> Start
                              </button>
                            )}
                            {/* Pause: only visible when there's actually
                               something running at this bedroom. The bulk
                               filter picks the in_progress items and
                               flips them to paused, preserving started_by /
                               started_at so the audit trail stays honest. */}
                            {newItems.some(t => t.status === 'in_progress') && (
                              <button onClick={() => {
                                const running = newItems.filter(t => t.status === 'in_progress');
                                bulkUpdateStatus(running, 'paused');
                              }} disabled={busy}
                                className="h-9 px-3 rounded-lg border border-blue-300 hover:bg-blue-50 text-blue-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                                <Pause size={12} /> Pause
                              </button>
                            )}
                            {/* Resume: pulls paused items back to in_progress
                               so the cleaner picks up where they left off. */}
                            {newItems.some(t => t.status === 'paused') && (
                              <button onClick={() => {
                                const paused = newItems.filter(t => t.status === 'paused');
                                bulkUpdateStatus(paused, 'in_progress');
                              }} disabled={busy}
                                className="h-9 px-3 rounded-lg border border-amber-300 hover:bg-amber-50 text-amber-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                                <Play size={12} /> Resume
                              </button>
                            )}
                            {canBulkComplete && (
                              <button onClick={async () => {
                                if (!confirm(`Mark all ${newItems.length} items at ${bedLabel} complete?`)) return;
                                await bulkUpdateStatus(newItems, 'done');
                                // Also close any open workblock this cleaner
                                // owns at this bedroom. Saying "everything
                                // is done" with a workblock still ticking
                                // was contradictory and forced the cleaner
                                // to remember to close it manually.
                                if (employee?.id) {
                                  const unitId = newItems[0]?.unit_id;
                                  const partyId = newItems[0]?.party_id;
                                  if (unitId && partyId) {
                                    try {
                                      const { data: openBlocks } = await supabase.from('work_blocks')
                                        .select('id, shift:shifts!inner(employee_id)')
                                        .eq('unit_id', unitId).eq('party_id', partyId)
                                        .is('end_time', null);
                                      const myOpen = (openBlocks || []).filter(b => b.shift?.employee_id === employee.id);
                                      if (myOpen.length > 0) {
                                        const ts = new Date().toISOString();
                                        await supabase.from('work_blocks')
                                          .update({ end_time: ts })
                                          .in('id', myOpen.map(b => b.id));
                                      }
                                    } catch (e) {
                                      console.warn('[Finished all tasks] could not close own workblock', e);
                                    }
                                  }
                                }
                              }} disabled={busy}
                                className="h-9 px-3 rounded-lg bg-emerald-600 hover:bg-emerald-700 text-white text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                                <Check size={12} /> Finished all tasks
                              </button>
                            )}
                            {!allDone && (
                              <button onClick={() => setStatusModal({ target: firstTarget, bulkRows: newItems })} disabled={busy}
                                className="h-9 px-3 rounded-lg border border-red-200 hover:bg-red-50 text-red-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                                <AlertCircle size={12} /> Blocked
                              </button>
                            )}
                            {!allDone && (
                              <button onClick={() => setReassignTarget(firstTarget)} disabled={busy}
                                className="h-9 px-3 rounded-lg border border-stone-300 hover:bg-stone-50 text-stone-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                                <User size={12} /> Reassign
                              </button>
                            )}
                          </div>
                          {/* === Go to this bedroom (full-width bottom) === */}
                          {canGoToBedroom && (
                            <button onClick={() => startAndGo(firstTarget)}
                              className="w-full mt-3 py-2.5 rounded-lg bg-stone-900 text-stone-50 text-sm font-medium flex items-center justify-center gap-1.5 active:scale-98 transition-transform">
                              Go to this bedroom <ChevronRight size={14} />
                            </button>
                          )}
                        </div>
                      );
                    }
                    return (
                      <React.Fragment key={groupKey}>
                        {/* Legacy items at this bedroom — keep the
                           original per-item rendering so Mon-Wed
                           assignments stay exactly as the cleaners
                           are used to. */}
                        {legacyItems.map(t => (
                          <AssignmentCard key={t.id} target={t} busy={busy} propertyId={propertyId}
                            onView={() => setOpened(t)}
                            onStart={() => startAndGo(t)}
                            onPause={() => updateStatus(t, 'paused')}
                            onMoveToPending={() => updateStatus(t, 'pending')}
                            onDone={() => updateStatus(t, 'done')}
                            onReopen={() => updateStatus(t, 'pending')}
                            onBlocked={() => setStatusModal({ target: t })}
                            onReassign={() => setReassignTarget(t)}
                            onTogglePriority={togglePriority}
                            canMarkDone={can(employee, 'mark_assignments_done') || t.started_by === employee?.id}
              canMarkDoneAlways={can(employee, 'mark_assignments_done')}
                            currentEmployeeId={employee?.id}
                            onGoToBedroom={onGoToBedroom ? () => startAndGo(t) : null}
                            canEditDates={can(employee, 'edit_due_dates')}
                            onSetDueDate={async (aid, date) => { if (aid) { await supabase.from('assignments').update({ scheduled_date: date }).eq('id', aid); load(); } }}
                            onOpenBedroomHistory={onOpenBedroomHistory} />
                        ))}
                        {/* NEW items at this bedroom: ONE bedroom-level
                           bulk card with section breakdown + all the
                           same action buttons as legacy. */}
                        {bulkCard}
                      </React.Fragment>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  const renderAssignmentList = (items) => {
    // For non-Pending tabs we previously rendered each assignment_target
    // as a separate AssignmentCard. That meant a bedroom with 16 items
    // showed up as 16 cards on In progress / Paused / Blocked, which is
    // exactly the "ton of cards" the cleaner reported. Routing every
    // tab through renderGroupedItems collapses those rows down to ONE
    // bedroom-level card with the bulk-action chrome — same model as
    // Pending. We keep the priority-split below for the Pending tab
    // only since priority callouts are most useful when planning what
    // to do next.
    if (statusFilter !== 'pending') {
      return renderGroupedItems(items);
    }

    // PENDING TAB: split priority vs the rest, render with visual divider.
    // Done / blocked excluded from priority since they've already been
    // resolved — "do these first" implies work still to do.
    const priorityItems = items.filter(t => t.priority && t.status !== 'done' && t.status !== 'blocked');
    const normalItems = items.filter(t => !t.priority);

    return (
      <div className="space-y-2">
        {priorityItems.length > 0 && (
          <>
            <div className="flex items-center gap-2 px-1">
              <AlertCircle size={12} className="text-red-700 flex-shrink-0" />
              <span className="text-[10px] uppercase tracking-wider font-mono font-bold text-red-700">
                Priority — do these first ({priorityItems.length})
              </span>
              <div className="flex-1 h-px bg-red-200" />
            </div>
            {renderGroupedItems(priorityItems)}
          </>
        )}
        {priorityItems.length > 0 && normalItems.length > 0 && (
          <div className="py-2 flex items-center gap-2 px-1">
            <div className="flex-1 h-px bg-stone-200" />
            <span className="text-[10px] uppercase tracking-wider font-mono text-stone-400">Everything else</span>
            <div className="flex-1 h-px bg-stone-200" />
          </div>
        )}
        {normalItems.length > 0 && renderGroupedItems(normalItems)}
      </div>
    );
  };

  // Done items are already narrowed by the completed-date range (if any)
  // up in filteredTargets, so here we just render the list — no more
  // day-of / last-3 / older sub-tabs.
  const renderDoneBuckets = (items) => {
    if (!items || items.length === 0) {
      return (
        <div className="text-center py-8 text-stone-400 text-xs border-2 border-dashed border-stone-200 rounded-2xl">
          Nothing matches these filters.
        </div>
      );
    }
    return renderAssignmentList(items);
  };

  return (
    <div>
      {/* Filters bar: toggle to expand, pills inside. Counts active filters
         on the button so the user knows when filters are narrowing things. */}
      {targets.length > 0 && (availableTypes.length > 1 || availableCleaners.length > 0 || availableCategories.length > 0 || isDoneView) && (
        <div className="mb-3">
          <button onClick={() => setFiltersOpen(o => !o)}
            className={`w-full flex items-center justify-between px-3 py-2 rounded-xl border transition-colors ${activeFilterCount > 0 ? 'bg-amber-50 border-amber-300 text-amber-900' : 'bg-white border-stone-200 text-stone-600 hover:border-stone-400'}`}>
            <div className="flex items-center gap-2">
              <Settings size={14} />
              <span className="text-xs uppercase tracking-wider font-mono">
                Filters{activeFilterCount > 0 ? ` (${activeFilterCount})` : ''}
              </span>
              <span className="text-[10px] font-mono text-stone-500">
                Showing {countBedrooms(filteredTargets)} of {countBedrooms(targets)}
              </span>
            </div>
            <ChevronRight size={14} className={`transition-transform ${filtersOpen ? 'rotate-90' : ''}`} />
          </button>
          {filtersOpen && (
            <div className="p-3 rounded-xl bg-stone-50 border border-stone-200 mt-1 space-y-3">
              {/* Type — multi-select chips. Click to add/remove from filter. */}
              {availableTypes.length > 1 && (
                <div>
                  <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1">Cleaning type</div>
                  <div className="flex gap-1.5 flex-wrap">
                    {availableTypes.map(typeVal => {
                      const active = filterTypes.has(typeVal);
                      return (
                        <button key={typeVal} onClick={() => toggleType(typeVal)}
                          className={`px-2.5 py-1 rounded-full text-xs font-mono flex items-center gap-1 ${active ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-300 text-stone-600'}`}>
                          {active && <Check size={10} />}
                          {assignmentTypeLabel(typeVal)}
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}
              {/* Cleaner — multi-select chips */}
              {availableCleaners.length > 0 && (
                <div>
                  <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1">Cleaner (started or completed)</div>
                  <div className="flex gap-1.5 flex-wrap">
                    {availableCleaners.map(c => {
                      const active = filterCleaners.has(c.id);
                      return (
                        <button key={c.id} onClick={() => toggleCleaner(c.id)}
                          className={`px-2.5 py-1 rounded-full text-xs font-mono flex items-center gap-1 ${active ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-300 text-stone-600'}`}>
                          {active && <Check size={10} />}
                          {c.name}
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}
              {/* Task category — what kind of work happened at the bedroom */}
              {availableCategories.length > 0 && (
                <div>
                  <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1">
                    Task category (where work was logged)
                  </div>
                  <div className="flex gap-1.5 flex-wrap">
                    {availableCategories.map(c => {
                      const active = filterCategories.has(c.id);
                      return (
                        <button key={c.id} onClick={() => toggleCategory(c.id)}
                          className={`px-2.5 py-1 rounded-full text-xs font-mono flex items-center gap-1 ${active ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-300 text-stone-600'}`}>
                          {active && <Check size={10} />}
                          {c.label}
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}
              {/* Completed-date RANGE — pick a start and end day. Leave a
                 side blank for an open-ended range. Only shown on the
                 Done-family tabs where completed dates exist. */}
              {isDoneView && (
                <div>
                  <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1">Completed between</div>
                  <div className="flex gap-2 flex-wrap items-center">
                    <label className="flex items-center gap-1 text-xs font-mono text-stone-600">
                      <span className="text-stone-400">From</span>
                      <input type="date" value={dateFrom} max={dateTo || undefined}
                        onChange={(e) => setDateFrom(e.target.value)}
                        className="px-2 py-1 rounded-lg border border-stone-300 bg-white text-stone-700" />
                    </label>
                    <label className="flex items-center gap-1 text-xs font-mono text-stone-600">
                      <span className="text-stone-400">To</span>
                      <input type="date" value={dateTo} min={dateFrom || undefined}
                        onChange={(e) => setDateTo(e.target.value)}
                        className="px-2 py-1 rounded-lg border border-stone-300 bg-white text-stone-700" />
                    </label>
                    {(dateFrom || dateTo) && (
                      <button onClick={() => { setDateFrom(''); setDateTo(''); }}
                        className="px-2.5 py-1 rounded-full text-xs font-mono bg-stone-200 text-stone-600 hover:bg-stone-300">
                        Clear dates
                      </button>
                    )}
                  </div>
                  <div className="text-[10px] font-mono text-stone-400 mt-1">
                    Leave blank to show all. Pick the same day twice for one day, or a span for a range.
                  </div>
                </div>
              )}
              {activeFilterCount > 0 && (
                <button onClick={() => {
                  setFilterTypes(new Set()); setFilterCleaners(new Set());
                  setDateFrom(''); setDateTo(''); setFilterCategories(new Set());
                }}
                  className="text-[10px] uppercase tracking-wider font-mono text-amber-700 hover:text-amber-900">
                  Clear all filters
                </button>
              )}
            </div>
          )}
        </div>
      )}

      {/* Building filter pills — multi-select. Empty = all buildings. */}
      {buildingKeys.length > 1 && (
        <div className="flex gap-1.5 mb-3 overflow-x-auto pb-1 -mx-1 px-1">
          <button onClick={() => setFilterBuildings(new Set())}
            className={`px-3 py-1 rounded-full text-xs font-mono whitespace-nowrap ${filterBuildings.size === 0 ? 'bg-stone-900 text-stone-50' : 'bg-stone-100 text-stone-600'}`}>
            All ({countBedrooms(filteredTargets)})
          </button>
          {buildingKeys.map(b => {
            const on = filterBuildings.has(b);
            return (
              <button key={b} onClick={() => toggleBuilding(b)}
                className={`px-3 py-1 rounded-full text-xs font-mono whitespace-nowrap flex items-center gap-1 ${on ? 'bg-stone-900 text-stone-50' : 'bg-stone-100 text-stone-600'}`}>
                {on && <Check size={10} />}
                {b === '—' ? 'No unit' : b} ({countBedrooms(buildings[b])})
              </button>
            );
          })}
        </div>
      )}

      <div className="space-y-4">
        {/* Global priority section — shows all priority items across
           buildings as a single block at the top of Pending. Pulled out
           of the per-building loop so they're never hidden behind a
           building they don't belong to.
           CRITICAL: priority items render as FLAT CARDS (no bundling,
           no collapse). The whole point of priority is "do this first" —
           if we hide priority items inside collapsed apartment bundles,
           the user has to tap to find them. Flat cards = every priority
           visible at a glance. */}
        {globalPriorityItems.length > 0 && (
          <div className="rounded-2xl border-2 border-red-300 bg-red-50/50 p-3">
            <div className="flex items-center gap-2 mb-2 px-1">
              <AlertCircle size={14} className="text-red-700 flex-shrink-0" />
              <span className="text-xs uppercase tracking-wider font-mono font-bold text-red-700">
                Priority — do these first ({countBedrooms(globalPriorityItems)})
              </span>
              <div className="flex-1 h-px bg-red-200" />
            </div>
            {/* Route priority items through renderGroupedItems so each
               BEDROOM collapses to one card — not one card per target.
               Move-out checks flag every one of their 8 items as
               priority, which previously rendered the same bedroom 8
               times. The count above and the cards below now both
               reflect distinct bedrooms. */}
            {renderGroupedItems(globalPriorityItems)}
          </div>
        )}

        {visibleBuildings.map(b => {
          const items = buildings[b];
          // When global priority section is showing, exclude priority
          // items from the building loop so they don't appear twice.
          const itemsForBuilding = globalPriorityItems.length > 0
            ? items.filter(t => !t.priority)
            : items;
          // If a building has ONLY priority items, skip rendering its
          // section entirely — its items are all in the top block.
          if (itemsForBuilding.length === 0) return null;
          const collapsed = !!collapsedBuildings[b];
          // Only show group header if there's more than 1 building total
          const showHeader = buildingKeys.length > 1;

          // Sub-group by FLOOR (first digit of the apartment number).
          // The owner asked for Floor 1 → Floor 2 → Floor 3 sections
          // so the cleaner reads the building top-down in the order
          // they'd physically walk it. Items without a parseable floor
          // (e.g. property-level no-unit) land in a "—" bucket.
          const byFloor = {};
          itemsForBuilding.forEach(t => {
            const f = floorFromLabel(t.unit?.label);
            const key = f != null ? String(f) : '—';
            if (!byFloor[key]) byFloor[key] = [];
            byFloor[key].push(t);
          });
          const floorKeys = Object.keys(byFloor).sort((a, b) => {
            if (a === '—') return 1;
            if (b === '—') return -1;
            return parseInt(a, 10) - parseInt(b, 10);
          });
          // If there's only one floor's worth of items, skip the floor
          // labels — they'd be noise.
          const showFloorHeaders = floorKeys.length > 1;

          return (
            <div key={b}>
              {showHeader && (
                <button onClick={() => toggleCollapse(b)}
                  className="w-full flex items-center justify-between mb-2 px-1 py-2 hover:bg-stone-50 rounded">
                  <div className="flex items-center gap-2">
                    <Building2 size={18} className="text-stone-700" />
                    <span className="font-serif text-base text-stone-900 font-bold">
                      {b === '—' ? 'No unit' : `Building ${b.replace(/^B/i, '')}`}
                    </span>
                    <span className="text-xs font-mono text-stone-500">({countBedrooms(itemsForBuilding)})</span>
                  </div>
                  <ChevronRight size={16} className={`text-stone-500 transition-transform ${collapsed ? '' : 'rotate-90'}`} />
                </button>
              )}
              {!collapsed && (
                statusFilter === 'done'
                  ? renderDoneBuckets(itemsForBuilding)
                  : showFloorHeaders ? (
                      <div className="space-y-3">
                        {floorKeys.map(fk => {
                          const floorKey = `${b}::${fk}`;
                          const floorOpen = !collapsedFloors[floorKey];
                          return (
                            <div key={fk}>
                              <button
                                onClick={() => setCollapsedFloors(prev => ({ ...prev, [floorKey]: !prev[floorKey] }))}
                                className="w-full flex items-center gap-2 mb-1.5 px-1 hover:bg-stone-50 rounded transition-colors text-left">
                                <ChevronRight size={12} className={`text-stone-500 flex-shrink-0 transition-transform ${floorOpen ? 'rotate-90' : ''}`} />
                                <span className="text-sm font-bold text-stone-800 tracking-wide">
                                  {fk === '—' ? 'Other' : `Floor ${fk}`}
                                </span>
                                <span className="text-xs font-mono text-stone-500">({countBedrooms(byFloor[fk])})</span>
                                <div className="flex-1 h-px bg-stone-300" />
                              </button>
                              {floorOpen && renderAssignmentList(byFloor[fk])}
                            </div>
                          );
                        })}
                      </div>
                    ) : (
                      renderAssignmentList(itemsForBuilding)
                    )
              )}
            </div>
          );
        })}
      </div>

      {opened && (
        opened.assignment?.template_set_id
          ? <ChecklistAssignmentView assignment={opened.assignment}
              employee={employee}
              onClose={() => setOpened(null)}
              onOpenSheet={opened.assignment?.file_url
                ? () => window.open(opened.assignment.file_url, '_blank', 'noopener')
                : null} />
          : <AssignmentViewer target={opened} employee={employee} onClose={() => setOpened(null)} />
      )}
      {statusModal && (
        <BlockedNoteModal target={statusModal.target}
          onSave={(notes) => {
            // When the bedroom-level "Blocked" button opens this modal
            // it sets bulkRows = every new item at the bedroom. We
            // apply the same blocked + note to all of them in one call.
            // Per-item Blocked (legacy AssignmentCard) doesn't set
            // bulkRows, so it falls back to single-target update.
            if (statusModal.bulkRows && statusModal.bulkRows.length > 0) {
              bulkUpdateStatus(statusModal.bulkRows, 'blocked', notes);
              setStatusModal(null);
            } else {
              updateStatus(statusModal.target, 'blocked', notes);
            }
          }}
          onClose={() => setStatusModal(null)}
          busy={busy} />
      )}
      {reassignTarget && (
        <ReassignModal target={reassignTarget} propertyId={propertyId}
          onSaved={() => { setReassignTarget(null); load(); if (onUpdate) onUpdate(); }}
          onClose={() => setReassignTarget(null)} />
      )}
    </div>
  );
}

// ReassignModal — change unit/party for an assignment target
// SwitchBedroomModal — shown when a cleaner taps a different bedroom
// while they already have an open work block. Gives 3 explicit
// choices: Stay (cancel), Pause and switch (resumable), Finish and
// switch (close out the current bedroom).
// NextUpModal — appears after a cleaner finishes a bedroom. Suggests
// what to clean next, ranked: (1) same apartment, (2) same floor,
// (3) same building, (4) next building starting on the third floor.
// "Who's here" — also surfaces other cleaners working at the same
// apartment so the cleaner can walk over and help.
function NextUpModal({ from, employeeId, onPick, onClose }) {
  const [data, setData] = useState({ loading: true, sameApt: [], sameFloor: [], sameBuilding: [], otherBuilding: [], otherCleaners: [] });

  // Pull a parsing helper for building/floor out of a label like B3-205
  // (B<building>-<floor><unit>). We use the existing floorFromLabel
  // for floor, and a tiny inline regex for building.
  const buildingFromLabel = (label) => {
    if (!label) return null;
    const m = label.match(/^B(\d+)/i);
    return m ? m[1] : null;
  };
  const unitNumberFromLabel = (label) => {
    if (!label) return null;
    // Number after the dash, e.g. "B3-205" → 205
    const m = label.match(/-(\d+)/);
    return m ? parseInt(m[1], 10) : null;
  };
  const fromBuilding = buildingFromLabel(from.unitLabel);
  const fromFloor = floorFromLabel(from.unitLabel);
  const fromUnitNum = unitNumberFromLabel(from.unitLabel);

  useEffect(() => {
    if (!from?.propertyId) return;
    (async () => {
      // 1) Load every unit + party for the property so we can compute
      //    which bedrooms still have open targets and where they live.
      const [unitsRes, partiesRes, targetsRes, blocksRes] = await Promise.all([
        supabase.from('units')
          .select('id, label, active')
          .eq('customer_id', from.propertyId).eq('active', true),
        supabase.from('parties')
          .select('id, label, unit_id, sort_order, active'),
        supabase.from('assignment_targets')
          .select('unit_id, party_id, status, assignment:assignments!inner(customer_id, active, source, pm_status, deleted_at)')
          .not('status', 'in', '(done,blocked)'),
        // Open work blocks at this property so we can show "who's here"
        supabase.from('work_blocks')
          .select('unit_id, party_id, shift:shifts!inner(customer_id, employee:employees(id, name))')
          .is('end_time', null),
      ]);
      const units = (unitsRes.data || []);
      const parties = (partiesRes.data || []).filter(p => p.active !== false);
      // Filter targets to active + this property
      const openTargets = (targetsRes.data || []).filter(t => {
        const a = t.assignment;
        if (!a || a.customer_id !== from.propertyId) return false;
        if (a.active === false) return false;
        if (a.source === 'pm' && a.pm_status !== 'approved') return false;
        return true;
      });
      // Bedrooms with open work (party_id set)
      const bedroomsWithWork = new Set();
      openTargets.forEach(t => { if (t.party_id) bedroomsWithWork.add(t.party_id); });
      // Map unit → unit label
      const unitMap = new Map(units.map(u => [u.id, u]));
      // Build candidate list: parties in apartments at this property
      // that have open work, EXCLUDING the bedroom we just finished.
      const candidates = parties
        .filter(p => p.id !== from.partyId)
        .filter(p => bedroomsWithWork.has(p.id))
        .map(p => {
          const unit = unitMap.get(p.unit_id);
          if (!unit) return null;
          return {
            partyId: p.id,
            partyLabel: p.label,
            unitId: unit.id,
            unitLabel: unit.label,
            building: buildingFromLabel(unit.label),
            floor: floorFromLabel(unit.label),
            unitNum: unitNumberFromLabel(unit.label),
          };
        })
        .filter(Boolean);

      // Bucket
      const sameApt = candidates.filter(c => c.unitId === from.unitId);
      const sameFloor = candidates.filter(c => c.unitId !== from.unitId && c.building === fromBuilding && c.floor === fromFloor);
      const sameBuilding = candidates.filter(c => c.building === fromBuilding && c.floor !== fromFloor);
      const otherBuilding = candidates.filter(c => c.building !== fromBuilding);

      // Same-floor: sort by closest unit number
      sameFloor.sort((a, b) => {
        const da = Math.abs((a.unitNum || 0) - (fromUnitNum || 0));
        const db = Math.abs((b.unitNum || 0) - (fromUnitNum || 0));
        return da - db;
      });
      // Same-building (different floor): nearest floor first, then unit
      sameBuilding.sort((a, b) => {
        const fa = Math.abs((a.floor ?? 99) - (fromFloor ?? 0));
        const fb = Math.abs((b.floor ?? 99) - (fromFloor ?? 0));
        if (fa !== fb) return fa - fb;
        return (a.unitNum || 0) - (b.unitNum || 0);
      });
      // Other-building: per user's request — start on 3rd floor, then
      // descend (3 → 2 → 1 → 4+). Sort by abs distance from floor 3.
      const distanceFromThree = (f) => {
        if (f == null) return 99;
        // Penalty for going above 3 so we prefer 3,2,1 order then 4,5,…
        if (f === 3) return 0;
        if (f < 3) return 3 - f;        // 2 → 1, 1 → 2
        return (f - 3) + 3;              // 4 → 4, 5 → 5 (after 3,2,1)
      };
      otherBuilding.sort((a, b) => {
        if (a.building !== b.building) return (a.building || '').localeCompare(b.building || '');
        const da = distanceFromThree(a.floor);
        const db = distanceFromThree(b.floor);
        if (da !== db) return da - db;
        return (a.unitNum || 0) - (b.unitNum || 0);
      });

      // Who else is here — cleaners with open blocks in the same apt
      const otherCleaners = (blocksRes.data || [])
        .filter(b => b.shift?.customer_id === from.propertyId)
        .filter(b => b.unit_id === from.unitId)
        .filter(b => b.shift?.employee?.id && b.shift.employee.id !== employeeId)
        .map(b => ({
          name: b.shift.employee.name,
          partyId: b.party_id,
          partyLabel: parties.find(p => p.id === b.party_id)?.label || '',
        }));

      setData({ loading: false, sameApt, sameFloor, sameBuilding, otherBuilding, otherCleaners });
    })();
  }, [from?.propertyId, from?.unitId, from?.partyId, employeeId]);

  const Bucket = ({ title, items, limit = 5 }) => {
    if (!items || items.length === 0) return null;
    const shown = items.slice(0, limit);
    return (
      <div>
        <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1 px-1">
          {title} <span className="text-stone-400">· {items.length}</span>
        </div>
        <div className="space-y-1.5">
          {shown.map(c => (
            <button key={c.partyId} onClick={() => onPick(c)}
              className="w-full p-3 rounded-xl bg-white border border-stone-200 hover:border-stone-900 text-left active:scale-98 transition-all">
              <div className="flex items-center justify-between gap-2">
                <div className="flex items-center gap-2 min-w-0">
                  <span className="font-serif text-sm text-stone-900 font-bold">{c.unitLabel}</span>
                  <span className="text-stone-400">·</span>
                  <span className="italic text-stone-700">{c.partyLabel}</span>
                </div>
                <ChevronRight size={14} className="text-stone-400 flex-shrink-0" />
              </div>
            </button>
          ))}
          {items.length > limit && (
            <div className="text-[10px] font-mono text-stone-500 italic px-1">
              + {items.length - limit} more
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl flex flex-col max-h-[90vh]">
        <div className="p-5 border-b border-stone-200">
          <div className="font-serif text-xl text-stone-900 mb-1">Nice work in {from.partyLabel}</div>
          <div className="text-sm text-stone-600">
            What's next? Closer suggestions are at the top.
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {data.loading ? (
            <div className="text-center py-8 text-stone-400 text-sm">Finding next bedrooms…</div>
          ) : (
            <>
              {/* Who else is at this apartment — comes first per user's request */}
              {data.otherCleaners.length > 0 && (
                <div className="p-3 rounded-xl bg-amber-50 border border-amber-200">
                  <div className="text-[10px] uppercase tracking-wider font-mono text-amber-900 font-bold mb-1">
                    Who's at {from.unitLabel}
                  </div>
                  <div className="space-y-0.5">
                    {data.otherCleaners.map((c, i) => (
                      <div key={i} className="text-sm text-stone-800">
                        <span className="font-bold">{c.name}</span>
                        {c.partyLabel && <span className="text-stone-600"> · {c.partyLabel}</span>}
                      </div>
                    ))}
                  </div>
                  <div className="text-[11px] text-amber-800 mt-1.5 italic">
                    You could walk over and ask if they need help.
                  </div>
                </div>
              )}
              <Bucket title={`Same apartment (${from.unitLabel})`} items={data.sameApt} />
              <Bucket title={`Same floor`} items={data.sameFloor} />
              <Bucket title={`Same building`} items={data.sameBuilding} />
              <Bucket title={`Other buildings — starting on floor 3`} items={data.otherBuilding} />
              {data.sameApt.length + data.sameFloor.length + data.sameBuilding.length + data.otherBuilding.length === 0 && (
                <div className="text-center py-8 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
                  Looks like all the bedrooms are taken care of. Nice job!
                </div>
              )}
            </>
          )}
        </div>
        <div className="p-5 border-t border-stone-200">
          <button onClick={onClose}
            className="w-full py-3 rounded-2xl border-2 border-stone-300 hover:bg-stone-100 text-stone-700 text-sm font-medium">
            Back to assignments
          </button>
        </div>
      </div>
    </div>
  );
}

function SwitchBedroomModal({ fromUnitLabel, fromPartyLabel, toUnitLabel, toPartyLabel, onStay, onPause, onFinish, busy }) {
  const from = `${fromUnitLabel || ''}${fromUnitLabel && fromPartyLabel ? ' · ' : ''}${fromPartyLabel || ''}`;
  const to   = `${toUnitLabel   || ''}${toUnitLabel   && toPartyLabel   ? ' · ' : ''}${toPartyLabel   || ''}`;
  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl flex flex-col">
        <div className="p-5 border-b border-stone-200">
          <div className="font-serif text-xl text-stone-900 mb-1">You're still in {from}</div>
          <div className="text-sm text-stone-600">
            Switching to <span className="font-bold text-stone-900">{to}</span> will end the work block in {from}. Pick what to do with the items you started there.
          </div>
        </div>
        <div className="p-5 space-y-2.5">
          {/* Finish — close the current bedroom out for good */}
          <button onClick={onFinish} disabled={busy}
            className="w-full p-4 rounded-2xl border-2 border-emerald-300 bg-emerald-50 hover:bg-emerald-100 text-left disabled:opacity-50">
            <div className="flex items-center gap-2 mb-1">
              <Check size={16} className="text-emerald-700" />
              <span className="font-serif text-base text-stone-900 font-bold">Finish in {fromPartyLabel || 'this bedroom'}</span>
            </div>
            <div className="text-xs text-stone-600">
              Mark every item you started in {from} as complete, end the work block, then take me to {to}.
            </div>
          </button>
          {/* Pause — close the block but keep items resumable */}
          <button onClick={onPause} disabled={busy}
            className="w-full p-4 rounded-2xl border-2 border-blue-300 bg-blue-50 hover:bg-blue-100 text-left disabled:opacity-50">
            <div className="flex items-center gap-2 mb-1">
              <Pause size={16} className="text-blue-700" />
              <span className="font-serif text-base text-stone-900 font-bold">Pause and switch</span>
            </div>
            <div className="text-xs text-stone-600">
              Pause the items you started in {from} (you can resume them later), end the work block, then take me to {to}.
            </div>
          </button>
          {/* Stay — cancel the switch */}
          <button onClick={onStay} disabled={busy}
            className="w-full p-4 rounded-2xl border-2 border-stone-300 bg-white hover:bg-stone-50 text-left disabled:opacity-50">
            <div className="flex items-center gap-2 mb-1">
              <ArrowLeft size={16} className="text-stone-700" />
              <span className="font-serif text-base text-stone-900 font-bold">Stay in {fromPartyLabel || 'this bedroom'}</span>
            </div>
            <div className="text-xs text-stone-600">
              Keep working on {from}. Nothing changes.
            </div>
          </button>
        </div>
      </div>
    </div>
  );
}

function ReassignModal({ target, propertyId, onSaved, onClose }) {
  const [units, setUnits] = useState([]);
  const [unitId, setUnitId] = useState(target.unit_id || '');
  const [partyId, setPartyId] = useState(target.party_id || '');
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => { (async () => {
    const { data } = await supabase.from('units')
      .select('*, parties(id, label, full_name, active, sort_order)')
      .eq('customer_id', propertyId).eq('active', true)
      .order('sort_order').order('label');
    setUnits((data || []).slice().sort((a, b) => naturalCompare(a.label, b.label)));
  })(); }, [propertyId]);

  const parties = (units.find(u => u.id === unitId)?.parties || [])
    .filter(p => p.active).sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));

  const save = async () => {
    if (!unitId || !partyId) { setError('Pick a unit and a party.'); return; }
    if (unitId === target.unit_id && partyId === target.party_id) {
      setError("That's already where this is assigned. Pick a different spot.");
      return;
    }
    setBusy(true);
    try {
      const newUnit = units.find(u => u.id === unitId);
      const newParty = (newUnit?.parties || []).find(p => p.id === partyId);
      const newUnitLabel = newUnit?.label || '';
      const newPartyLabel = newParty?.label || '';

      // Move EVERY target belonging to this assignment — not just the
      // single target row behind the tapped card. A cleaning-check has
      // 8-16 targets at one bedroom; updating only one left the rest
      // behind, which is why a reassign looked like it "didn't work"
      // and needed 2-3 tries. We scope by assignment_id when available,
      // falling back to the (unit,party) pair for legacy rows.
      const asgnId = target.assignment_id || target.assignment?.id;
      let upd = supabase.from('assignment_targets').update({ unit_id: unitId, party_id: partyId });
      if (asgnId) {
        upd = upd.eq('assignment_id', asgnId);
      } else {
        upd = upd.eq('unit_id', target.unit_id).eq('party_id', target.party_id);
      }
      const { error: e } = await upd;
      if (e) { setError(e.message); setBusy(false); return; }

      // Rewrite the assignment title's location so it reflects the new
      // apartment + bedroom instead of keeping the stale old name (#4a).
      // Titles follow the pattern "<Type> · <Unit> · <Bedroom>". We
      // rebuild from the assignment_type + new labels when we can; if
      // the title doesn't match that shape we leave it alone to avoid
      // clobbering a custom name.
      if (asgnId) {
        const { data: asgn } = await supabase.from('assignments')
          .select('id, title, assignment_type').eq('id', asgnId).maybeSingle();
        if (asgn) {
          const typeLabel = (asgn.assignment_type || '')
            .replace(/_/g, ' ')
            .replace(/\b\w/g, c => c.toUpperCase());
          // Only auto-rewrite titles that look auto-generated (contain
          // " · "). Custom titles without that separator are preserved.
          if ((asgn.title || '').includes(' · ')) {
            const newTitle = [typeLabel || 'Assignment', newUnitLabel, newPartyLabel]
              .filter(Boolean).join(' · ');
            await supabase.from('assignments').update({ title: newTitle }).eq('id', asgnId);
          }
        }
      }
      setBusy(false);
      onSaved();
    } catch (err) {
      setError(err.message || String(err));
      setBusy(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl flex flex-col">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div>
            <div className="font-serif text-xl text-stone-900">Reassign</div>
            <div className="text-xs text-stone-500 font-mono mt-0.5 truncate">{target.assignment?.title}</div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="p-5 space-y-4">
          <p className="text-sm text-stone-600">
            Currently assigned to <strong>{target.unit?.label || '?'}{target.party?.label && ` · ${target.party.label}`}</strong>. Pick where this should go instead:
          </p>
          <div>
            <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Unit</label>
            <select value={unitId} onChange={(e) => { setUnitId(e.target.value); setPartyId(''); }}
              className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white">
              <option value="">— Pick a unit —</option>
              {units.map(u => <option key={u.id} value={u.id}>{u.label}</option>)}
            </select>
          </div>
          {unitId && (
            <div>
              <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Bedroom</label>
              <select value={partyId} onChange={(e) => setPartyId(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white">
                <option value="">— Pick a bedroom —</option>
                {parties.map(p => <option key={p.id} value={p.id}>{p.label}{p.full_name ? ` (${p.full_name})` : ''}</option>)}
              </select>
            </div>
          )}
          {error && (
            <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
              <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
            </div>
          )}
        </div>
        <div className="p-5 border-t border-stone-200 flex gap-2">
          <button onClick={onClose} disabled={busy}
            className="flex-1 py-3 rounded-2xl bg-stone-100 text-stone-700 font-medium">Cancel</button>
          <button onClick={save} disabled={busy}
            className="flex-1 py-3 rounded-2xl bg-stone-900 text-stone-50 font-medium disabled:opacity-50">
            {busy ? 'Saving…' : 'Reassign'}
          </button>
        </div>
      </div>
    </div>
  );
}

// MoveBlockModal — move a work_block's data (notes, tasks, photos) from
// one bedroom to another by updating its unit_id + party_id. Useful
// when a cleaner opened the wrong bedroom and put their work there.
// Tasks/photos cascade via foreign keys so they follow the block.
function MoveBlockModal({ block, propertyId, onSaved, onClose }) {
  const [units, setUnits] = useState([]);
  const [unitId, setUnitId] = useState('');
  const [partyId, setPartyId] = useState('');
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => { (async () => {
    const { data } = await supabase.from('units')
      .select('*, parties(id, label, full_name, active, sort_order)')
      .eq('customer_id', propertyId).eq('active', true)
      .order('sort_order').order('label');
    setUnits((data || []).slice().sort((a, b) => naturalCompare(a.label, b.label)));
  })(); }, [propertyId]);

  const parties = (units.find(u => u.id === unitId)?.parties || [])
    .filter(p => p.active).sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));

  const save = async () => {
    if (!unitId || !partyId) { setError('Pick a unit and a bedroom.'); return; }
    if (unitId === block.unit_id && partyId === block.party_id) {
      setError("That's already where this block is. Pick a different bedroom.");
      return;
    }
    setBusy(true);
    // Conflict check: if there's already a work_block under this shift
    // at the target bedroom, ask before merging the two histories.
    // The user can always close one out manually first if they want
    // separate records.
    const { data: existing } = await supabase.from('work_blocks')
      .select('id, end_time, start_time')
      .eq('shift_id', block.shift_id)
      .eq('unit_id', unitId)
      .eq('party_id', partyId);
    if (existing && existing.length > 0) {
      setBusy(false);
      const hasOpen = existing.some(b => !b.end_time);
      const msg = hasOpen
        ? `There's already an OPEN work block at this bedroom in this shift. Move anyway? You'll end up with two blocks there — close one manually after.`
        : `There's already a completed work block at this bedroom in this shift. Move anyway? You'll end up with two blocks there.`;
      if (!confirm(msg)) return;
      setBusy(true);
    }
    const { error: e } = await supabase.from('work_blocks')
      .update({ unit_id: unitId, party_id: partyId })
      .eq('id', block.id);
    setBusy(false);
    if (e) { setError(e.message); return; }
    onSaved();
  };

  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl flex flex-col">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div>
            <div className="font-serif text-xl text-stone-900">Move work to a different bedroom</div>
            <div className="text-xs text-stone-500 font-mono mt-0.5 truncate">
              Currently: {block.unit?.label}{block.party?.label && ` · ${block.party.label}`}
            </div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="p-5 space-y-4">
          <div className="p-3 rounded-xl bg-amber-50 border border-amber-200 text-xs text-amber-900">
            All notes, tasks, and photos from this work block will move with it. The old bedroom will be left as-is (no leftover data).
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Move to unit</label>
            <select value={unitId} onChange={(e) => { setUnitId(e.target.value); setPartyId(''); }}
              className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white">
              <option value="">— Pick a unit —</option>
              {units.map(u => <option key={u.id} value={u.id}>{u.label}</option>)}
            </select>
          </div>
          {unitId && (
            <div>
              <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Bedroom</label>
              <select value={partyId} onChange={(e) => setPartyId(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white">
                <option value="">— Pick a bedroom —</option>
                {parties.map(p => <option key={p.id} value={p.id}>{p.label}{p.full_name ? ` (${p.full_name})` : ''}</option>)}
              </select>
            </div>
          )}
          {error && (
            <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
              <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
            </div>
          )}
        </div>
        <div className="p-5 border-t border-stone-200 flex gap-2">
          <button onClick={onClose} disabled={busy}
            className="flex-1 py-3 rounded-2xl bg-stone-100 text-stone-700 font-medium">Cancel</button>
          <button onClick={save} disabled={busy}
            className="flex-1 py-3 rounded-2xl bg-stone-900 text-stone-50 font-medium disabled:opacity-50">
            {busy ? 'Moving…' : 'Move work here'}
          </button>
        </div>
      </div>
    </div>
  );
}

// =================================================================
// ZOOMABLE IMAGE — image viewer that fits the screen by default
// and lets the user toggle to actual size for scroll/zoom inspection.
// =================================================================
function ZoomableImage({ src, alt }) {
  const [zoomed, setZoomed] = useState(false);
  return (
    <div className="w-full h-full flex items-start justify-center p-2">
      <img
        loading="lazy"
        src={src}
        alt={alt || ''}
        onClick={() => setZoomed(z => !z)}
        className={zoomed
          ? "cursor-zoom-out max-w-none"
          : "cursor-zoom-in max-w-full max-h-[80vh] object-contain rounded-xl shadow-lg"}
        style={zoomed ? { touchAction: 'pinch-zoom' } : {}}
      />
    </div>
  );
}

function AssignmentViewer({ target, onClose, employee }) {
  const a = target.assignment;
  // For "other language" translation: prefer extracted_text (the full OCR output)
  // if available, otherwise fall back to title + notes.
  const translateTexts = a.extracted_text && a.extracted_text.trim()
    ? [a.title, a.notes, a.extracted_text].filter(Boolean)
    : [a.title, a.notes].filter(Boolean);

  // Bedroom-scoped target panel. We re-query targets at THIS bedroom
  // (unit + party that the row was opened from) so the audit Quick
  // glance shows the same status + notes + actions the cleaner-side
  // ChecklistAssignmentView Quick glance offers. Previously this
  // viewer only showed the file — blocked items with reasons were
  // invisible unless the owner clicked all the way in.
  const [bedroomTargets, setBedroomTargets] = useState([]);
  const [busyId, setBusyId] = useState(null);
  const loadTargets = async () => {
    // Resolve bedroom keys — different callers populate the scalar
    // FK columns vs the nested objects. The audit view's SELECT,
    // for example, only joins unit:units(id, label) without picking
    // unit_id as a scalar, so without this fallback the query
    // .eq('unit_id', undefined) returns nothing and the panel never
    // renders. This was the root cause of "the blocked indicator
    // still doesn't show in Quick glance from the audit".
    const unitId = target.unit_id || target.unit?.id || null;
    const partyId = target.party_id || target.party?.id || null;
    if (!unitId || !partyId || !a?.id) return;
    const { data } = await supabase
      .from('assignment_targets')
      .select('*')
      .eq('assignment_id', a.id)
      .eq('unit_id', unitId)
      .eq('party_id', partyId);
    setBedroomTargets(data || []);
  };
  useEffect(() => { loadTargets(); }, [target.id]);

  // Permission gates — match how AssignmentCard decides who can do what.
  // Owner / manager can always act. Cleaners need explicit permission
  // (mark_assignments_done) to mark done. Anyone with an employee
  // identity can Reopen since it just sends an item back to pending.
  const isStaff = employee?.role === 'owner' || employee?.role === 'manager';
  const canMarkDone = isStaff || can(employee, 'mark_assignments_done');
  const canReopen = !!employee?.id;

  const setStatus = async (t, newStatus) => {
    if (busyId) return;
    setBusyId(t.id);
    const patch = { status: newStatus };
    if (newStatus === 'done') {
      patch.completed_at = new Date().toISOString();
      patch.completed_by = employee?.id || null;
    } else if (t.status === 'done') {
      patch.completed_at = null;
      patch.completed_by = null;
    }
    if (newStatus === 'pending') {
      // Clear blocked notes when reopening so the next cleaner sees
      // a fresh slate; the audit trail still has the photos / block
      // history if anyone needs to know why it was blocked before.
      patch.status_notes = null;
      patch.started_at = null;
      patch.started_by = null;
    }
    setBedroomTargets(prev => prev.map(x => x.id === t.id ? { ...x, ...patch } : x));
    const { error } = await supabase.from('assignment_targets').update(patch).eq('id', t.id);
    setBusyId(null);
    if (error) {
      alert('Could not update: ' + error.message);
      loadTargets(); // re-fetch authoritative
    }
  };

  const labelForT = (t) => {
    if (t.status_notes && (t.template_item_key?.startsWith?.('requested:') || t.template_item_key?.startsWith?.('custom_'))) return t.status_notes;
    const k = t.template_item_key || '';
    return k.replace(/^[a-z_]+:/, '').replace(/_/g, ' ').replace(/^./, c => c.toUpperCase()) || 'Item';
  };

  // Visual color for the status dot
  const dotFor = (t) => {
    if (t.recheck_passed_at) return { color: 'bg-purple-500', label: 'recheck-passed' };
    if (t.status === 'done') return { color: 'bg-emerald-500', label: 'done' };
    if (t.status === 'in_progress') return { color: 'bg-amber-500', label: 'in progress' };
    if (t.status === 'paused') return { color: 'bg-amber-300', label: 'paused' };
    if (t.status === 'blocked') return { color: 'bg-red-500', label: 'blocked' };
    return { color: 'bg-stone-300', label: 'pending' };
  };

  // Modal-with-backdrop layout (was full-screen). Cleaner can tap the
  // dark area around the card to close, same as tapping the X.
  return (
    <div onClick={onClose}
      className="fixed inset-0 bg-stone-900/70 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div onClick={(e) => e.stopPropagation()}
        className="bg-stone-50 w-full sm:max-w-2xl sm:rounded-3xl rounded-t-3xl flex flex-col max-h-[90vh] overflow-hidden">
        <div className="p-4 text-stone-50 bg-stone-900 sm:rounded-t-3xl">
          <div className="flex items-start justify-between gap-2">
            <div className="flex-1 min-w-0">
              <div className="font-serif text-lg truncate">{a.title}</div>
              {/* Bedroom context — so the owner knows which bedroom's
                 items the panel below refers to. */}
              {(target.unit?.label || target.party?.label) && (
                <div className="text-xs text-stone-300 mt-0.5 font-mono">
                  {target.unit?.label}{target.party?.label && ` · ${target.party.label}`}
                </div>
              )}
              {a.notes && <div className="text-xs text-stone-400 mt-0.5 whitespace-pre-wrap break-words">{a.notes}</div>}
            </div>
            <button onClick={onClose} className="p-2 rounded-full bg-stone-800 flex-shrink-0">
              <X size={20} />
            </button>
          </div>
          <SpanishTranslationPanel assignment={a} />
          <TranslateButton texts={translateTexts} />
        </div>
        {/* Item / target panel — surfaces blocked items + reasons +
           Reopen / Mark done actions. Sits above the file so the
           owner sees the actionable info before having to scroll
           through a PDF. Only shown when we have bedroom context. */}
        {bedroomTargets.length > 0 && (
          <div className="p-3 bg-white border-b border-stone-200">
            <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-2">
              Items at this bedroom ({bedroomTargets.length})
            </div>
            <div className="space-y-1.5">
              {bedroomTargets.map(t => {
                const d = dotFor(t);
                const isBlocked = t.status === 'blocked';
                const isDone = t.status === 'done';
                return (
                  <div key={t.id} className={`text-sm rounded-lg ${isBlocked ? 'bg-red-50 border border-red-200 p-2' : 'p-1'}`}>
                    <div className="flex items-center gap-2">
                      <span className={`w-2 h-2 rounded-full ${d.color} flex-shrink-0`} title={d.label} />
                      <span className={`flex-1 min-w-0 ${isDone ? 'text-stone-500 line-through' : 'text-stone-900'}`}>
                        {labelForT(t)}
                      </span>
                      {isBlocked && (
                        <span className="text-[9px] uppercase tracking-widest font-mono px-1.5 py-0.5 rounded-full bg-red-200 text-red-800 flex-shrink-0">
                          Blocked
                        </span>
                      )}
                      {isDone && (
                        <span className="text-[9px] uppercase tracking-widest font-mono px-1.5 py-0.5 rounded-full bg-emerald-100 text-emerald-800 flex-shrink-0">
                          Done
                        </span>
                      )}
                    </div>
                    {/* Blocked reason — the part the user specifically
                       called out as invisible from the audit. */}
                    {isBlocked && t.status_notes && (
                      <div className="text-xs text-red-700 italic mt-1 pl-4">
                        "{t.status_notes}"
                      </div>
                    )}
                    {/* Action row. Reopen shows for done/blocked/paused
                       to any signed-in user. Mark done shows for
                       anything that isn't already done, gated on
                       canMarkDone (owners + managers + cleaners with
                       explicit permission). */}
                    {(canReopen || canMarkDone) && (
                      <div className="flex items-center gap-1.5 mt-1.5 pl-4">
                        {canReopen && (isBlocked || isDone || t.status === 'paused') && (
                          <button onClick={() => setStatus(t, 'pending')}
                            disabled={busyId === t.id}
                            className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1 disabled:opacity-50">
                            <Play size={10} /> Reopen
                          </button>
                        )}
                        {canMarkDone && !isDone && (
                          <button onClick={() => setStatus(t, 'done')}
                            disabled={busyId === t.id}
                            className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-emerald-100 hover:bg-emerald-200 text-emerald-800 flex items-center gap-1 disabled:opacity-50">
                            <Check size={10} /> Mark done
                          </button>
                        )}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}
        <div className="flex-1 overflow-auto bg-stone-100">
          {a.file_url ? (
            a.file_kind === 'image' ? (
              <ZoomableImage src={a.file_url} alt={a.title} />
            ) : (
              <iframe src={a.file_url} className="w-full h-full min-h-[60vh]" title={a.title} />
            )
          ) : (
            <div className="p-8 text-center text-stone-400 text-sm">
              No file attached to this assignment.
            </div>
          )}
        </div>
        {a.file_url && (
          <div className="p-4 bg-stone-900">
            <a href={a.file_url} target="_blank" rel="noreferrer"
              className="w-full inline-flex items-center justify-center gap-2 py-3 rounded-xl bg-stone-50 text-stone-900 text-sm font-medium">
              <Download size={14} /> Open / download
            </a>
          </div>
        )}
      </div>
    </div>
  );
}

// =================================================================
// CHECKLIST ASSIGNMENT VIEW — cleaner-side view of a template-driven
// assignment. Shows the 4 main sections (Bedroom / Vanity / Bathroom
// / General) with their items as a checklist. Tapping an item flips
// its status:
//   pending     → in_progress (claim it)
//   in_progress → done        (mark complete)
//   done        → re-open prompt
//
// A 3-state toggle filters which items show:
//   - Not started (pending) — shown by default, also lists other
//     assignments at this bedroom in case the cleaner wants to bounce
//   - Working on now (in_progress) — what the cleaner is actively doing
//   - Done — completed items, with a re-open option
//
// Status changes write directly to assignment_targets and rely on the
// existing realtime sync to push updates to other viewers.
// =================================================================
function ChecklistAssignmentView({ assignment, employee, onClose, onOpenSheet, quickGlance = false }) {
  const [targets, setTargets] = useState([]);
  const [templateInfo, setTemplateInfo] = useState({ variants: [], items: [] });
  const [otherAssignments, setOtherAssignments] = useState([]);
  // Work blocks at this exact bedroom — used by the Working on now
  // and Done tabs which now show block-level history instead of
  // per-item status.
  const [workBlocks, setWorkBlocks] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [tab, setTab] = useState('not_started'); // 'not_started' | 'in_progress' | 'done'
  // Sub-tab inside "Not started" — lets the cleaner view items
  // by main section (Bedroom / Vanity / Bathroom / General) as a
  // read-style filter. Default 'all' keeps the original behaviour
  // for cleaners who don't tap a section pill.
  const [sectionFilter, setSectionFilter] = useState('all');
  const [busyId, setBusyId] = useState(null);
  // Bulk-action busy + "request new item" modal — these surface the
  // owner-requested missing controls (pause whole assignment, request
  // an additional item the inspection sheet didn't cover, etc.)
  const [bulkBusy, setBulkBusy] = useState(false);
  const [requestModalOpen, setRequestModalOpen] = useState(false);

  // -----------------------------------------------------------------
  // Load targets (the actual checklist items) + template metadata so
  // we can display human-friendly item labels.
  // -----------------------------------------------------------------
  const load = async () => {
    const { data: tData } = await supabase
      .from('assignment_targets')
      .select('*, unit:units(label), party:parties(label)')
      .eq('assignment_id', assignment.id);
    setTargets(tData || []);

    // Template metadata — only fetch if the assignment uses a template
    if (assignment.template_set_id) {
      const { data: vData } = await supabase
        .from('section_template_variants')
        .select('*').eq('set_id', assignment.template_set_id);
      const variantIds = (vData || []).map(v => v.id);
      let iData = [];
      if (variantIds.length > 0) {
        const { data } = await supabase
          .from('section_template_items')
          .select('*').in('variant_id', variantIds);
        iData = data || [];
      }
      setTemplateInfo({ variants: vData || [], items: iData });
    }

    // Other open assignments at the same bedroom — for the "Not started"
    // tab footer so the cleaner can hop to a sibling without going home.
    const firstTarget = (tData || [])[0];
    if (firstTarget?.unit_id && firstTarget?.party_id) {
      const { data: others } = await supabase
        .from('assignments')
        .select('id, title, assignment_type, sheet_type, template_set_id, source, pm_status, active, customer_id, targets:assignment_targets!inner(id, status, unit_id, party_id)')
        .neq('id', assignment.id)
        .eq('targets.unit_id', firstTarget.unit_id)
        .eq('targets.party_id', firstTarget.party_id)
        .eq('active', true);
      // Filter to assignments with non-done targets at this bedroom
      const filtered = (others || []).filter(a => {
        if (a.source === 'pm' && a.pm_status !== 'approved') return false;
        return (a.targets || []).some(t => t.status !== 'done');
      });
      setOtherAssignments(filtered);
    }

    // Load work_blocks at this bedroom for the Working on now / Done
    // tabs. The user wants those tabs to show work_blocks scoped to
    // THIS bedroom (open ones in Working on now, closed ones in
    // Done), not assignment_target rows. Items inside a block can
    // be tapped to navigate into the block for detail.
    if (firstTarget?.unit_id && firstTarget?.party_id) {
      // unit_id + party_id already scopes to this exact bedroom which
      // belongs to exactly one property; the customer_id JOIN check we
      // had earlier was redundant AND was filtering everything out
      // whenever the embed didn't resolve. Drop it and trust the
      // bedroom-level scope. Also drop the is_preview filter — preview
      // blocks at this bedroom should also show so the owner testing
      // the app can see what they've started.
      const { data: blocks, error: blocksErr } = await supabase
        .from('work_blocks')
        .select('id, start_time, end_time, work_notes, is_preview, shift:shifts(employee:employees(id, name)), tasks(id, name, category, end_time)')
        .eq('unit_id', firstTarget.unit_id)
        .eq('party_id', firstTarget.party_id)
        .order('start_time', { ascending: false });
      if (blocksErr) {
        console.warn('[ChecklistAssignmentView] work_blocks load error:', blocksErr);
      }
      setWorkBlocks(blocks || []);
    }

    setLoaded(true);
  };

  useEffect(() => { load(); /* eslint-disable-next-line */ }, [assignment.id]);
  useAssignmentSync(load, 'checklist-view');

  // -----------------------------------------------------------------
  // Helper: friendly item label from template + section/key on a target
  // -----------------------------------------------------------------
  const labelForTarget = (target) => {
    if (!target.template_section || !target.template_item_key) return null;
    // For Bedroom/Vanity, variant key is 'default'. For Bathroom and
    // General, variant key is on the assignment.
    let variantKey = 'default';
    if (target.template_section === 'bathroom') variantKey = assignment.bathroom_variant;
    if (target.template_section === 'general') variantKey = assignment.general_variant;
    const variant = templateInfo.variants.find(v =>
      v.section_key === target.template_section && v.variant_key === variantKey
    );
    if (!variant) return null;
    const item = templateInfo.items.find(i =>
      i.variant_id === variant.id && i.item_key === target.template_item_key
    );
    return item?.label || null;
  };

  // -----------------------------------------------------------------
  // Advance / toggle a target's status. Optimistic UI for snappiness.
  // -----------------------------------------------------------------
  const setStatus = async (target, newStatus) => {
    if (busyId) return;
    setBusyId(target.id);
    const patch = { status: newStatus };
    if (newStatus === 'in_progress') {
      if (!target.started_at) patch.started_at = new Date().toISOString();
      patch.started_by = employee?.id || null;
    }
    if (newStatus === 'done') {
      patch.completed_at = new Date().toISOString();
      patch.completed_by = employee?.id || null;
    } else if (target.status === 'done') {
      patch.completed_at = null;
      patch.completed_by = null;
    }
    if (newStatus === 'pending') {
      patch.started_at = null;
      patch.started_by = null;
    }
    // Optimistic update
    setTargets(prev => prev.map(t => t.id === target.id ? { ...t, ...patch } : t));
    const { error } = await supabase.from('assignment_targets').update(patch).eq('id', target.id);
    setBusyId(null);
    if (error) {
      alert('Could not update: ' + error.message);
      load(); // re-fetch authoritative
    }
  };

  // -----------------------------------------------------------------
  // Group filtered targets by template_section so the cleaner sees
  // logical chunks (Bedroom items together, Bathroom items together).
  // -----------------------------------------------------------------
  const sectionOrder = ['bedroom', 'vanity', 'bathroom', 'general'];
  const sectionLabel = {
    bedroom: 'Bedroom', vanity: 'Vanity', bathroom: 'Bathroom', general: 'General',
  };

  const counts = {
    not_started: targets.filter(t => t.status === 'pending').length,
    in_progress: targets.filter(t => t.status === 'in_progress').length,
    done: targets.filter(t => t.status === 'done').length,
    blocked: targets.filter(t => t.status === 'blocked').length,
    // Block-level counts for the new Working on now / Done tab semantics.
    open_blocks: workBlocks.filter(b => !b.end_time).length,
    closed_blocks: workBlocks.filter(b => !!b.end_time).length,
  };
  const filterStatus = tab === 'not_started' ? 'pending' : tab;
  const visibleTargets = targets.filter(t => t.status === filterStatus);

  const grouped = {};
  sectionOrder.forEach(s => { grouped[s] = []; });
  visibleTargets.forEach(t => {
    const s = t.template_section || 'bedroom';
    if (!grouped[s]) grouped[s] = [];
    grouped[s].push(t);
  });

  // Progress: % of items done over total
  const total = targets.length;
  const doneCount = counts.done;
  const isAllDone = total > 0 && doneCount === total;

  // Bedroom label for header
  const bedroomLabel = targets[0]?.party?.label;
  const unitLabel = targets[0]?.unit?.label;
  // Bathroom helper for clarity
  const bathroomNum = bathroomNumberForBedroom(bedroomLabel);

  // -----------------------------------------------------------------
  // Render an item row — READ-ONLY in this view. The View-doc destination
  // is now a quick reference: cleaner sees what needs cleaning by
  // section but cannot advance status. Status changes happen via the
  // bedroom-level bulk card or the work-block picker — that's the
  // single source of truth for who started what.
  // -----------------------------------------------------------------
  const renderItemRow = (t) => {
    const label = labelForTarget(t) || `Item ${t.template_item_key || t.id.slice(0, 6)}`;
    const isDone = t.status === 'done';
    const isInProgress = t.status === 'in_progress';
    const colorClass = isDone
      ? 'bg-emerald-50 border-emerald-200'
      : isInProgress
        ? 'bg-amber-50 border-amber-300'
        : 'bg-white border-stone-200';
    return (
      <div key={t.id}
        className={`w-full text-left p-3 rounded-xl border-2 ${colorClass}`}>
        <div className="flex items-center gap-3">
          <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${isDone ? 'bg-emerald-600 border-emerald-600 text-white' : isInProgress ? 'bg-amber-500 border-amber-500 text-white' : 'border-stone-300'}`}>
            {isDone ? <Check size={12} /> : isInProgress ? <Play size={10} /> : null}
          </div>
          <div className="flex-1 min-w-0">
            <div className={`text-sm ${isDone ? 'text-emerald-900 line-through' : 'text-stone-900'}`}>{label}</div>
            {t.status_notes && (
              <div className="text-xs text-red-700 italic mt-0.5">"{t.status_notes}"</div>
            )}
          </div>
          {t.priority && !isDone && (
            <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-1 rounded-full bg-red-50 border border-red-200 text-red-700 font-bold flex items-center gap-1">
              <AlertCircle size={10} /> Priority
            </span>
          )}
        </div>
      </div>
    );
  };

  if (!loaded) {
    return (
      <div className="fixed inset-0 bg-stone-50 z-50 flex items-center justify-center text-stone-400 text-sm">
        Loading checklist…
      </div>
    );
  }

  // Quick glance body — read-only summary of items grouped by main
  // section (Bedroom / Vanity / Bathroom / General). Each item gets
  // a status dot (done / in_progress / pending) so the owner can scan
  // completion at a glance without all the cleaner-side controls.
  // Rendered when the quickGlance prop is true.
  const quickGlanceBody = (() => {
    const labelForT = (t) => {
      if (t.status_notes && (t.template_item_key?.startsWith?.('requested:') || t.template_item_key?.startsWith?.('custom_'))) return t.status_notes;
      const k = t.template_item_key || '';
      return k.replace(/^[a-z_]+:/, '').replace(/_/g, ' ').replace(/^./, c => c.toUpperCase()) || 'Item';
    };
    const dotFor = (t) => {
      if (t.recheck_passed_at) return { color: 'bg-purple-500', label: 'recheck-passed' };
      if (t.status === 'done') return { color: 'bg-emerald-500', label: 'done' };
      if (t.status === 'in_progress') return { color: 'bg-amber-500', label: 'in progress' };
      if (t.status === 'paused') return { color: 'bg-amber-300', label: 'paused' };
      if (t.status === 'blocked') return { color: 'bg-red-500', label: 'blocked' };
      return { color: 'bg-stone-300', label: 'pending' };
    };
    // Owner / manager can take action straight from the quick glance.
    // Cleaners just read. The setStatus handler is the same one the
    // checklist already uses for per-item status changes.
    const canActOnItems = employee?.role === 'owner' || employee?.role === 'manager';
    const sections = { bedroom: [], vanity: [], bathroom: [], general: [], other: [] };
    targets.forEach(t => {
      const sec = (t.template_section || 'other').toLowerCase();
      (sections[sec] || sections.other).push(t);
    });
    const order = ['bedroom', 'vanity', 'bathroom', 'general', 'other'];
    const labels = { bedroom: 'Bedroom', vanity: 'Vanity', bathroom: 'Bathroom', general: 'General', other: 'Other' };
    return (
      <div className="p-4 space-y-3">
        {order.map(secKey => {
          const items = sections[secKey];
          if (!items || items.length === 0) return null;
          const doneCount = items.filter(i => i.status === 'done').length;
          const blockedCount = items.filter(i => i.status === 'blocked').length;
          return (
            <div key={secKey} className="rounded-2xl bg-white border border-stone-200 p-3">
              <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-2">
                {labels[secKey]} <span className="text-stone-400">({doneCount}/{items.length} done</span>
                {blockedCount > 0 && (
                  <span className="text-red-700"> · {blockedCount} blocked</span>
                )}
                <span className="text-stone-400">)</span>
              </div>
              <div className="space-y-1.5">
                {items.map(t => {
                  const d = dotFor(t);
                  const isBlocked = t.status === 'blocked';
                  const isDone = t.status === 'done';
                  // Blocked items get a red highlight strip on the left
                  // and the cleaner's reason shown inline so the owner
                  // doesn't have to navigate elsewhere to see "why".
                  return (
                    <div key={t.id} className={`text-sm rounded-lg ${isBlocked ? 'bg-red-50 border border-red-200 p-2' : ''}`}>
                      <div className="flex items-center gap-2">
                        <span className={`w-2 h-2 rounded-full ${d.color} flex-shrink-0`} title={d.label} />
                        <span className={`flex-1 min-w-0 ${isDone ? 'text-stone-500 line-through' : 'text-stone-900'}`}>
                          {labelForT(t)}
                        </span>
                        {isBlocked && (
                          <span className="text-[9px] uppercase tracking-widest font-mono px-1.5 py-0.5 rounded-full bg-red-200 text-red-800 flex-shrink-0">
                            Blocked
                          </span>
                        )}
                      </div>
                      {/* Show the cleaner's reason when blocked. Italic + indented
                         so it reads as commentary on the row above. */}
                      {isBlocked && t.status_notes && (
                        <div className="text-xs text-red-700 italic mt-1 pl-4">
                          "{t.status_notes}"
                        </div>
                      )}
                      {/* Owner / manager-only inline actions. Reopen routes
                         the target back to pending; Mark done forces it to
                         done (e.g. owner accepts a blocked item as actually
                         resolved or wants to override a stuck pending). */}
                      {canActOnItems && (isBlocked || isDone || t.status === 'paused' || t.status === 'in_progress') && (
                        <div className="flex items-center gap-1.5 mt-1.5 pl-4">
                          {(isBlocked || isDone || t.status === 'paused') && (
                            <button onClick={() => setStatus(t, 'pending')}
                              disabled={busyId === t.id}
                              className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-stone-100 hover:bg-stone-200 text-stone-700 flex items-center gap-1 disabled:opacity-50">
                              <Play size={10} /> Reopen
                            </button>
                          )}
                          {!isDone && (
                            <button onClick={() => setStatus(t, 'done')}
                              disabled={busyId === t.id}
                              className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-emerald-100 hover:bg-emerald-200 text-emerald-800 flex items-center gap-1 disabled:opacity-50">
                              <Check size={10} /> Mark done
                            </button>
                          )}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>
    );
  })();

  return (
    quickGlance ? (
      // Quick glance modal — owner audit view uses this. Backdrop
      // around a sized card; tap backdrop to close. The CleanerProgress
      // bar is hidden since this isn't part of the cleaner's journey.
      <div onClick={onClose}
        className="fixed inset-0 bg-stone-900/70 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
        <div onClick={(e) => e.stopPropagation()}
          className="bg-stone-50 w-full sm:max-w-2xl sm:rounded-3xl rounded-t-3xl flex flex-col max-h-[90vh] overflow-hidden">
          <div className="p-4 border-b border-stone-200 flex items-start justify-between gap-2">
            <div className="flex-1 min-w-0">
              <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">Quick glance</div>
              <div className="font-serif text-lg text-stone-900 truncate">{assignment.title}</div>
            </div>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100 flex-shrink-0">
              <X size={20} className="text-stone-600" />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto">
            {quickGlanceBody}
          </div>
        </div>
      </div>
    ) : (
    <div className="fixed inset-0 bg-stone-50 z-50 flex flex-col">
      {/* Global cleaner progress bar — same 5 segments as the rest of
         the app. Inside an assignment the cleaner has filled the first
         3 segments (Property, Assignment, Items). "Working" is filled
         when they have items in progress; "Complete" turns green when
         everything is done. */}
      <CleanerProgressBar
        segments={[
          { label: 'Property', filled: true, onClick: onClose },
          { label: 'Assignment', filled: true, onClick: onClose },
          { label: 'Items', filled: doneCount > 0 || counts.in_progress > 0, isCurrent: !isAllDone },
          { label: 'Working', filled: counts.in_progress > 0 || doneCount > 0 },
          { label: 'Complete', filled: isAllDone, complete: isAllDone },
        ]}
        inActiveWork={counts.in_progress > 0} />
      {/* Header */}
      <div className="bg-stone-900 text-stone-50 px-5 py-4 sticky top-0 z-10">
        <div className="flex items-center justify-between mb-2">
          <button onClick={onClose}
            className="p-2 -ml-2 rounded-full bg-stone-800 hover:bg-stone-700">
            <ArrowLeft size={20} />
          </button>
          {onOpenSheet && assignment.file_url && (
            <button onClick={onOpenSheet}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-stone-800 hover:bg-stone-700 text-stone-50 text-xs font-medium">
              <Eye size={12} /> View attachment
            </button>
          )}
        </div>
        <div className="text-xs uppercase tracking-wider font-mono text-stone-400">
          {assignment.sheet_type === 'cleaning_check' ? 'Cleaning check' : 'Move-out clean'}
        </div>
        <div className="font-serif text-xl font-bold leading-tight break-words">
          {unitLabel}{bedroomLabel && (<>
            <span className="text-stone-400 mx-1.5">·</span>
            <span className="italic">{bedroomLabel}</span>
          </>)}
        </div>
        {bathroomNum && (
          <div className="text-[11px] text-amber-300 font-mono mt-1">
            Bathroom {bathroomNum} (shared between bedrooms {bathroomNum === 1 ? '1 & 2' : '3 & 4'})
          </div>
        )}
        {/* Inline progress text — replaces the previous per-assignment
           progress bar since the global bar now shows workflow state. */}
        <div className="mt-3 text-[11px] font-mono text-stone-400">
          {doneCount} of {total} items done
          {counts.in_progress > 0 && ` · ${counts.in_progress} in progress`}
          {isAllDone && <span className="text-emerald-400 font-bold ml-1">✓ All done!</span>}
        </div>
        {/* Bulk action row — start all pending items, pause all in-progress
           ones, request a new item that's not on the sheet. Mirrors the
           legacy AssignmentCard buttons so cleaners aren't missing
           workflow controls when they open the checklist view. */}
        <div className="mt-3 flex flex-wrap gap-1.5">
          {(counts.not_started > 0 || counts.paused > 0) && (
            <button
              onClick={async () => {
                if (bulkBusy) return;
                setBulkBusy(true);
                const eligible = targets.filter(t => t.status === 'pending' || t.status === 'paused');
                for (const t of eligible) {
                  await updateStatus(t, 'in_progress');
                }
                setBulkBusy(false);
              }}
              disabled={bulkBusy}
              className="px-3 py-1.5 rounded-full bg-amber-600 hover:bg-amber-700 text-white text-xs font-medium flex items-center gap-1.5 disabled:opacity-50">
              <Play size={12} /> Start all
            </button>
          )}
          {counts.in_progress > 0 && (
            <button
              onClick={async () => {
                if (bulkBusy) return;
                setBulkBusy(true);
                const eligible = targets.filter(t => t.status === 'in_progress');
                for (const t of eligible) {
                  await updateStatus(t, 'paused');
                }
                setBulkBusy(false);
              }}
              disabled={bulkBusy}
              className="px-3 py-1.5 rounded-full bg-stone-800 hover:bg-stone-700 text-stone-50 text-xs font-medium flex items-center gap-1.5 disabled:opacity-50">
              <Pause size={12} /> Pause all
            </button>
          )}
          <button
            onClick={() => setRequestModalOpen(true)}
            className="px-3 py-1.5 rounded-full bg-stone-800 hover:bg-stone-700 text-stone-50 text-xs font-medium flex items-center gap-1.5">
            <Plus size={12} /> Request item
          </button>
        </div>
      </div>

      {/* Tab toggle */}
      <div className="flex gap-1 px-3 py-3 bg-stone-100">
        <button onClick={() => setTab('not_started')}
          className={`flex-1 py-2 px-3 rounded-lg text-xs font-medium ${tab === 'not_started' ? 'bg-white shadow-sm text-stone-900 font-bold' : 'text-stone-600'}`}>
          Not started {counts.not_started > 0 && `(${counts.not_started})`}
        </button>
        <button onClick={() => setTab('in_progress')}
          className={`flex-1 py-2 px-3 rounded-lg text-xs font-medium ${tab === 'in_progress' ? 'bg-amber-50 shadow-sm text-amber-900 font-bold' : 'text-stone-600'}`}>
          Working on now {counts.open_blocks > 0 && `(${counts.open_blocks})`}
        </button>
        <button onClick={() => setTab('done')}
          className={`flex-1 py-2 px-3 rounded-lg text-xs font-medium ${tab === 'done' ? 'bg-emerald-50 shadow-sm text-emerald-900 font-bold' : 'text-stone-600'}`}>
          Done {counts.closed_blocks > 0 && `(${counts.closed_blocks})`}
        </button>
      </div>

      {/* Section sub-tabs — only show on Not Started. They filter
         which section's items are visible below. "All" = original
         behavior (every section grouped). Tap a section pill to
         see just Bedroom items, just Vanity items, etc. — a
         quick-view by area. Counts come from grouped[s] which is
         already scoped to the current tab's pending items. */}
      {tab === 'not_started' && counts.not_started > 0 && (
        <div className="flex gap-1.5 px-3 pt-2 pb-1 overflow-x-auto -mx-0">
          <button onClick={() => setSectionFilter('all')}
            className={`px-3 py-1 rounded-full text-xs font-mono whitespace-nowrap ${sectionFilter === 'all' ? 'bg-stone-900 text-stone-50 font-bold' : 'bg-stone-100 text-stone-600 hover:bg-stone-200'}`}>
            All ({counts.not_started})
          </button>
          {sectionOrder.map(s => {
            const n = grouped[s]?.length || 0;
            if (n === 0) return null;
            const active = sectionFilter === s;
            return (
              <button key={s} onClick={() => setSectionFilter(s)}
                className={`px-3 py-1 rounded-full text-xs font-mono whitespace-nowrap ${active ? 'bg-stone-900 text-stone-50 font-bold' : 'bg-stone-100 text-stone-600 hover:bg-stone-200'}`}>
                {sectionLabel[s]} ({n})
              </button>
            );
          })}
        </div>
      )}

      {/* Body */}
      <div className="flex-1 overflow-y-auto px-3 py-3 pb-24">
        {(() => {
          // Working on now / Done tabs now render WORK BLOCKS scoped
          // to THIS bedroom, not item-status rows. Open blocks live
          // under Working on now; closed blocks under Done. Tapping
          // a block card surfaces its tasks (the work the cleaner
          // logged inside that block). Items remain non-interactive
          // here — this view is a quick reference, not a control panel.
          if (tab === 'in_progress' || tab === 'done') {
            const wantsOpen = tab === 'in_progress';
            const blocks = workBlocks.filter(b => wantsOpen ? !b.end_time : !!b.end_time);
            if (blocks.length === 0) {
              return (
                <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
                  {wantsOpen
                    ? 'No work blocks open at this bedroom right now.'
                    : 'No completed work blocks for this bedroom yet.'}
                </div>
              );
            }
            return (
              <div className="space-y-2">
                {blocks.map(b => {
                  const start = b.start_time ? new Date(b.start_time) : null;
                  const end = b.end_time ? new Date(b.end_time) : null;
                  const durMs = end ? end - start : (start ? Date.now() - start.getTime() : 0);
                  const hrs = Math.floor(durMs / 3600000);
                  const mins = Math.floor((durMs % 3600000) / 60000);
                  const durLabel = `${hrs > 0 ? hrs + 'h ' : ''}${mins}m`;
                  const taskCount = (b.tasks || []).length;
                  const cleaner = b.shift?.employee?.name || 'Unknown';
                  return (
                    <div key={b.id}
                      className={`p-3 rounded-xl border-2 ${wantsOpen ? 'bg-amber-50 border-amber-300' : 'bg-white border-stone-200'}`}>
                      <div className="flex items-center justify-between gap-2 mb-1">
                        <div className="font-serif text-sm text-stone-900 font-bold">
                          {cleaner}
                        </div>
                        <span className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full ${wantsOpen ? 'bg-amber-100 text-amber-800 border border-amber-300' : 'bg-emerald-100 text-emerald-800 border border-emerald-300'}`}>
                          {wantsOpen ? 'In progress' : 'Done'}
                        </span>
                      </div>
                      <div className="text-[11px] font-mono text-stone-500">
                        {start && start.toLocaleString([], { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' })}
                        {' · '}{durLabel}
                        {taskCount > 0 && <> · {taskCount} task{taskCount === 1 ? '' : 's'}</>}
                      </div>
                      {b.work_notes && (
                        <div className="text-xs text-stone-700 mt-1 italic">"{b.work_notes}"</div>
                      )}
                      {taskCount > 0 && (
                        <ul className="mt-2 text-xs text-stone-700 space-y-0.5 pl-3 border-l-2 border-stone-200">
                          {b.tasks.map(t => (
                            <li key={t.id} className="flex items-center gap-1.5">
                              <span className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${t.end_time ? 'bg-emerald-500' : 'bg-amber-500'}`} />
                              <span className={t.end_time ? 'line-through text-stone-500' : ''}>{t.name || t.category || '(unnamed)'}</span>
                            </li>
                          ))}
                        </ul>
                      )}
                    </div>
                  );
                })}
              </div>
            );
          }
          // Not started tab — keep the existing grouped, read-only,
          // section-filterable layout. visibleTargets / grouped were
          // computed against status='pending' above.
          if (visibleTargets.length === 0) {
            return (
              <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
                No items to start. Either everything is in progress or already done.
              </div>
            );
          }
          return (
            <div className="space-y-4">
              {sectionOrder
                .filter(s => grouped[s].length > 0)
                .filter(s => sectionFilter === 'all' || sectionFilter === s)
                .map(s => (
                <div key={s}>
                  <div className="text-sm font-bold text-stone-800 tracking-wide mb-1.5 px-1">
                    {sectionLabel[s]} <span className="text-xs font-mono text-stone-500">({grouped[s].length})</span>
                  </div>
                  {/* Two-column grid keeps the quick-view short
                     so the cleaner doesn't have to scroll a whole
                     bedroom's worth of items. The rows are
                     read-only anyway so density is fine. */}
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-1.5">
                    {grouped[s].map(renderItemRow)}
                  </div>
                </div>
              ))}
            </div>
          );
        })()}

        {/* Other assignments at this bedroom — only show on Not Started
           tab so the cleaner can hop between sibling assignments
           without going back to the property home. */}
        {tab === 'not_started' && otherAssignments.length > 0 && (
          <div className="mt-6 pt-4 border-t border-stone-200">
            <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-2 px-1">
              Other assignments at this bedroom
            </div>
            <div className="space-y-1.5">
              {otherAssignments.map(oa => (
                <div key={oa.id} className="p-3 rounded-xl bg-white border border-stone-200">
                  <div className="font-serif text-sm text-stone-900 mb-1">{oa.title}</div>
                  <div className="text-[10px] font-mono text-stone-500">
                    {oa.sheet_type === 'cleaning_check' ? 'Cleaning check'
                      : oa.sheet_type === 'move_out_clean' ? 'Move-out clean'
                      : 'Legacy upload'}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Footer hint */}
      <div className="bg-stone-900 px-5 py-3">
        <div className="text-[10px] uppercase tracking-wider font-mono text-stone-400 text-center">
          Tap any item to advance · {tab === 'not_started' ? 'Pending → In progress' : tab === 'in_progress' ? 'In progress → Done' : 'Done → Re-open'}
        </div>
      </div>
      {/* Request-item modal — cleaner taps "Request item" to log an
         extra cleaning task that wasn't on the inspection sheet. We
         insert a new assignment_target on this assignment with a
         status_notes payload describing the request. Manager/owner
         sees it next to the rest of the items. */}
      {requestModalOpen && (
        <RequestNewItemModal
          assignment={assignment}
          employee={employee}
          onClose={() => setRequestModalOpen(false)}
          onSaved={() => { setRequestModalOpen(false); load(); }} />
      )}
    </div>
    )
  );
}

// Quick-entry modal for a cleaner to request an additional item on a
// checklist assignment when the inspection sheet missed something.
// Creates a new assignment_target on the parent assignment under a
// pseudo template_section of 'requested' so it surfaces distinctly.
function RequestNewItemModal({ assignment, employee, onClose, onSaved }) {
  const [text, setText] = useState('');
  const [section, setSection] = useState('bedroom');
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState('');
  const save = async () => {
    const trimmed = text.trim();
    if (!trimmed) { setErr('Describe what needs cleaning.'); return; }
    if (busy) return;
    setBusy(true); setErr('');
    // Pull the assignment's unit/party from any existing target on it
    // so the request lives at the same bedroom.
    const { data: sib } = await supabase.from('assignment_targets')
      .select('unit_id, party_id').eq('assignment_id', assignment.id).limit(1).maybeSingle();
    const { error } = await supabase.from('assignment_targets').insert({
      assignment_id: assignment.id,
      unit_id: sib?.unit_id || null,
      party_id: sib?.party_id || null,
      status: 'pending',
      template_section: section,
      // Use a clearly-marked custom item key so it's obvious downstream
      // that this came from a cleaner request and not a template seed.
      template_item_key: `requested:${Date.now()}`,
      status_notes: trimmed,
    });
    setBusy(false);
    if (error) { setErr('Could not save: ' + error.message); return; }
    onSaved();
  };
  return (
    <div className="fixed inset-0 bg-stone-900/80 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl flex flex-col">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div>
            <div className="font-serif text-xl text-stone-900">Request a new item</div>
            <div className="text-xs text-stone-500 font-mono mt-0.5">
              Add a cleaning task not on the sheet
            </div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="p-5 space-y-4">
          <div>
            <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">Section</label>
            <div className="grid grid-cols-4 gap-1">
              {[
                { id: 'bedroom', label: 'Bedroom' },
                { id: 'vanity', label: 'Vanity' },
                { id: 'bathroom', label: 'Bathroom' },
                { id: 'general', label: 'General' },
              ].map(s => (
                <button key={s.id} onClick={() => setSection(s.id)}
                  className={`py-2 px-2 rounded-lg border-2 text-xs font-medium ${section === s.id ? 'border-amber-500 bg-amber-50 text-amber-900' : 'border-stone-200 bg-white text-stone-700'}`}>
                  {s.label}
                </button>
              ))}
            </div>
          </div>
          <div>
            <label className="text-[10px] uppercase tracking-wider text-stone-500 font-mono mb-1 block">What needs cleaning?</label>
            <textarea
              value={text}
              onChange={e => setText(e.target.value)}
              rows={3}
              placeholder="e.g. Sticky stain on the ceiling near the vent"
              className="w-full px-3 py-2.5 rounded-xl border border-stone-300 bg-white text-sm focus:outline-none focus:border-stone-900 resize-none" />
          </div>
          {err && (
            <div className="text-xs text-red-700 bg-red-50 border border-red-200 rounded-lg px-3 py-2">{err}</div>
          )}
        </div>
        <div className="p-5 pt-0 flex gap-2">
          <button onClick={onClose} disabled={busy}
            className="flex-1 py-3 rounded-xl border border-stone-300 text-stone-700 font-medium text-sm disabled:opacity-50">
            Cancel
          </button>
          <button onClick={save} disabled={busy || !text.trim()}
            className="flex-1 py-3 rounded-xl bg-stone-900 text-stone-50 font-medium text-sm disabled:opacity-50">
            {busy ? 'Saving…' : 'Add item'}
          </button>
        </div>
      </div>
    </div>
  );
}

function BlockedNoteModal({ target, onSave, onClose, busy }) {
  const [note, setNote] = useState(target.status_notes || '');
  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl flex flex-col">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div className="font-serif text-xl text-stone-900">What's blocking?</div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="p-5">
          <div className="mb-3 p-3 rounded-xl bg-amber-50 border border-amber-200 text-amber-900 text-xs flex gap-2">
            <AlertCircle size={15} className="flex-shrink-0 mt-0.5" />
            <span>Heads up — marking this blocked <b>closes the entire assignment</b> for this bedroom and sends it to your manager. Only use this when you can't finish the work (e.g. tenant home, no access).</span>
          </div>
          <textarea value={note} onChange={(e) => setNote(e.target.value)}
            rows={4} placeholder="e.g. Tenant home, couldn't get in. Need new key."
            className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white focus:outline-none focus:border-stone-900 text-stone-900 resize-none" />
          <p className="text-xs text-stone-500 mt-2">
            This note will be visible to managers so they can resolve the issue.
          </p>
        </div>
        <div className="p-5 border-t border-stone-200 flex gap-2">
          <button onClick={onClose} disabled={busy}
            className="flex-1 py-3 rounded-2xl bg-stone-100 text-stone-700 font-medium">
            Cancel
          </button>
          <button onClick={() => onSave(note)} disabled={busy}
            className="flex-1 py-3 rounded-2xl bg-red-600 text-white font-medium disabled:opacity-50">
            {busy ? 'Saving…' : 'Mark blocked'}
          </button>
        </div>
      </div>
    </div>
  );
}

// =================================================================
// LIVE CLEANERS SHEET — bottom sheet shown when manager taps
// "On the clock" stat card. Lists all active shifts with what each
// cleaner is doing right now.
// =================================================================
function LiveCleanersSheet({ viewer, onClose, onOpenShift }) {
  const [shifts, setShifts] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [busyId, setBusyId] = useState(null);
  const canForceOut = viewer && (viewer.role === 'owner' || viewer.role === 'manager');

  const loadFn = async () => {
    const { data } = await supabase
      .from('shifts')
      .select('*, employee:employees(id, name), customer:customers(id, name), work_blocks(id, start_time, end_time, unit:units(label), party:parties(label))')
      .is('end_time', null)
      .eq('is_preview', false)  // Don't show preview shifts as on-the-clock
      .order('start_time', { ascending: true });
    setShifts(data || []);
    setLoaded(true);
  };

  useEffect(() => {
    let cancelled = false;
    const load = async () => {
      if (cancelled) return;
      await loadFn();
    };
    load();
    // Refresh every 15 seconds to keep the durations live
    const id = setInterval(load, 15000);
    return () => { cancelled = true; clearInterval(id); };
  }, []);

  useTick(true);

  // Force-end someone's shift. Ends any open work block first, then
  // closes the shift. Confirmed because it's irreversible without a
  // manual reopen.
  const forceClockOut = async (s) => {
    if (!confirm(`Force clock out ${s.employee?.name || 'this cleaner'}? Any active work block will end now.`)) return;
    setBusyId(s.id);
    try {
      const activeBlock = (s.work_blocks || []).find(b => !b.end_time);
      if (activeBlock) {
        await supabase.from('work_blocks').update({ end_time: new Date().toISOString() }).eq('id', activeBlock.id);
      }
      await supabase.from('shifts').update({ end_time: new Date().toISOString() }).eq('id', s.id);
      await loadFn();
    } catch (e) {
      alert('Could not clock out: ' + (e.message || e));
    }
    setBusyId(null);
  };

  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl max-h-[85vh] flex flex-col">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div>
            <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">Live</div>
            <div className="font-serif text-xl text-stone-900">On the clock right now</div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-5">
          {!loaded ? (
            <div className="text-center py-12 text-stone-400 text-sm">Loading…</div>
          ) : shifts.length === 0 ? (
            <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
              Nobody on the clock right now.
            </div>
          ) : (
            <div className="space-y-2">
              {shifts.map(s => {
                const shiftDur = Date.now() - new Date(s.start_time).getTime();
                // Find current active work block (no end_time)
                const activeBlock = (s.work_blocks || []).find(b => !b.end_time);
                const blockDur = activeBlock ? Date.now() - new Date(activeBlock.start_time).getTime() : 0;
                const completedBlocks = (s.work_blocks || []).filter(b => b.end_time).length;
                const isBusy = busyId === s.id;
                return (
                  <div key={s.id}
                    className="w-full text-left p-4 rounded-2xl bg-white border border-stone-200 hover:border-stone-400 transition-colors">
                    <div className="flex items-start justify-between mb-2 gap-2">
                      <button onClick={() => onOpenShift(s)} className="flex items-center gap-2 min-w-0 flex-1 text-left">
                        <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse flex-shrink-0" />
                        <span className="font-serif text-lg text-stone-900 truncate">{s.employee?.name}</span>
                      </button>
                      <span className="text-xs font-mono text-stone-500 flex-shrink-0">
                        {fmtTimeShort(shiftDur)}
                      </span>
                    </div>
                    {s.customer && (
                      <div className="text-xs text-amber-700 font-mono mb-1 flex items-center gap-1.5">
                        <Building2 size={11} /> {s.customer.name}
                      </div>
                    )}
                    {activeBlock ? (
                      <div className="text-xs text-stone-700 font-mono flex items-center gap-1.5 flex-wrap">
                        <span className="px-2 py-0.5 rounded-full bg-amber-100 text-amber-800 text-[10px] uppercase tracking-wider">
                          Cleaning
                        </span>
                        <span>{activeBlock.unit?.label}{activeBlock.party?.label && ` · ${activeBlock.party.label}`}</span>
                        <span className="text-stone-500">· {fmtTimeShort(blockDur)}</span>
                      </div>
                    ) : (
                      <div className="text-xs text-stone-500 font-mono">
                        At property
                        {completedBlocks > 0 && ` · ${completedBlocks} ${completedBlocks === 1 ? 'apt cleaned' : 'apts cleaned'}`}
                      </div>
                    )}
                    {/* Owner/manager action bar — force clock-out + open shift detail */}
                    {canForceOut && (
                      <div className="mt-3 pt-3 border-t border-stone-100 flex items-center justify-between gap-2">
                        <button onClick={() => onOpenShift(s)}
                          className="text-[10px] uppercase tracking-wider font-mono text-stone-600 hover:text-stone-900 flex items-center gap-1">
                          Open shift <ChevronRight size={10} />
                        </button>
                        <button onClick={() => forceClockOut(s)} disabled={isBusy}
                          className="h-9 px-3 rounded-lg border border-red-200 hover:bg-red-50 text-red-700 text-xs font-medium flex items-center gap-1 disabled:opacity-50">
                          {isBusy ? <div className="w-3 h-3 border-2 border-red-700 border-t-transparent rounded-full animate-spin" /> : <LogOut size={12} />}
                          Force clock out
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
        <div className="p-3 text-center text-[10px] font-mono text-stone-400 border-t border-stone-200">
          Auto-refreshes every 15 seconds · tap a cleaner to see their shift
        </div>
      </div>
    </div>
  );
}

// =================================================================
// ALL OPEN ASSIGNMENTS — cross-property overview for owners/managers
// Lists every assignment with at least one non-done target,
// grouped by property, with status counts and a "what's still open" summary.
// =================================================================
function AllOpenAssignments({ employee, onBack, onOpenAssignment }) {
  const [data, setData] = useState([]);   // grouped: [{ property, assignments: [...] }]
  const [loaded, setLoaded] = useState(false);
  const [loadError, setLoadError] = useState(null);
  const [statusFilter, setStatusFilter] = useState('all'); // all | pending | in_progress | blocked

  const load = async () => {
    setLoadError(null);
    const { data: aData, error: aErr } = await supabase
      .from('assignments')
      .select('*, property:customers(id, name, property_type), targets:assignment_targets(id, status, unit:units(label), party:parties(label), starter:employees!started_by(name), completer:employees!completed_by(name))')
      .eq('active', true)
      .order('created_at', { ascending: false });
    if (aErr) {
      console.error('[AllOpenAssignments] load error:', aErr);
      setLoadError(aErr.message);
      setData([]); setLoaded(true);
      return;
    }

    // Keep only assignments with at least one non-done target
    const openOnly = (aData || []).filter(a => (a.targets || []).some(t => t.status !== 'done'));

    // Group by property
    const byProp = {};
    openOnly.forEach(a => {
      const pId = a.property?.id;
      if (!pId) return;
      if (!byProp[pId]) byProp[pId] = { property: a.property, assignments: [] };
      // Decorate with counts
      const counts = { pending: 0, in_progress: 0, done: 0, blocked: 0 };
      (a.targets || []).forEach(t => { counts[t.status] = (counts[t.status] || 0) + 1; });
      byProp[pId].assignments.push({ ...a, counts });
    });

    const grouped = Object.values(byProp).sort((x, y) =>
      naturalCompare(x.property.name, y.property.name));
    setData(grouped);
    setLoaded(true);
  };
  useEffect(() => { load(); }, []);
  useAssignmentSync(load, 'asgn-all-open');

  // Filter at the per-target level for the status filter (visual only)
  const filterMatch = (a) => {
    if (statusFilter === 'all') return true;
    return (a.targets || []).some(t => t.status === statusFilter);
  };

  const totalOpen = data.reduce((s, g) => s + g.assignments.filter(filterMatch).length, 0);

  return (
    <div className="pb-24">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div>
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">All properties</div>
          <div className="font-serif text-xl text-stone-900">Open assignments</div>
        </div>
      </div>

      <div className="px-5 pt-6">
        <div className="text-stone-500 text-sm mb-4">
          {totalOpen === 0 ? 'Nothing open right now' : `${totalOpen} ${totalOpen === 1 ? 'assignment' : 'assignments'} with open work`}
        </div>

        {/* Status filter pills */}
        <div className="flex gap-2 mb-5 overflow-x-auto pb-1 -mx-1 px-1">
          {[
            { id: 'all', label: 'All open' },
            { id: 'pending', label: 'Pending' },
            { id: 'in_progress', label: 'In progress' },
            { id: 'blocked', label: 'Blocked' },
          ].map(f => (
            <button key={f.id} onClick={() => setStatusFilter(f.id)}
              className={`px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap ${statusFilter === f.id ? 'bg-stone-900 text-stone-50' : 'bg-stone-100 text-stone-600'}`}>
              {f.label}
            </button>
          ))}
        </div>

        {loadError && (
          <div className="p-4 rounded-2xl bg-red-50 border border-red-200 text-red-700 text-sm mb-4">
            <div className="flex items-start gap-2 mb-1">
              <AlertCircle size={16} className="flex-shrink-0 mt-0.5" />
              <span className="font-medium">Couldn't load</span>
            </div>
            <div className="text-xs font-mono mt-2">{loadError}</div>
          </div>
        )}

        {!loaded ? <Splash text="Loading…" /> : totalOpen === 0 ? (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            {statusFilter === 'all'
              ? 'No open assignments across any property. Everything is done!'
              : `No assignments are currently ${statusFilter.replace('_', ' ')}.`}
          </div>
        ) : (
          <div className="space-y-6">
            {data.map(group => {
              const filtered = group.assignments.filter(filterMatch);
              if (filtered.length === 0) return null;

              // Sub-group filtered assignments by building (derived from first target's unit label)
              const isMulti = group.property.property_type === 'multi_unit';
              const buildings = {};
              filtered.forEach(a => {
                const firstUnit = (a.targets || []).find(t => t.unit?.label)?.unit?.label;
                const b = isMulti ? (buildingFromLabel(firstUnit) || '—') : '—';
                if (!buildings[b]) buildings[b] = [];
                buildings[b].push(a);
              });
              const buildingKeys = Object.keys(buildings).sort(naturalCompare);
              const showSubGroups = isMulti && buildingKeys.length > 1;

              return (
                <div key={group.property.id}>
                  <div className="flex items-baseline justify-between mb-3 pb-2 border-b border-stone-200">
                    <h3 className="font-serif text-lg text-stone-900 flex items-center gap-2">
                      <Building2 size={14} /> {group.property.name}
                    </h3>
                    <span className="text-xs font-mono text-stone-500">
                      {filtered.length} {filtered.length === 1 ? 'open' : 'open'}
                    </span>
                  </div>

                  {buildingKeys.map(b => {
                    const items = buildings[b];
                    return (
                      <div key={b} className="mb-4">
                        {showSubGroups && (
                          <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-2 px-1 flex items-center gap-1.5">
                            <Building2 size={11} />
                            {b === '—' ? 'No unit' : `Building ${b.replace(/^B/i, '')}`}
                            <span className="text-stone-400">({items.length})</span>
                          </div>
                        )}
                        <div className="space-y-2">
                          {items.map(a => {
                            const openTargets = (a.targets || []).filter(t => t.status !== 'done');
                            const inProgressBy = openTargets
                              .filter(t => t.status === 'in_progress' && t.starter?.name)
                              .map(t => t.starter.name);
                            const uniqStarters = [...new Set(inProgressBy)];
                            const hasBlocked = a.counts.blocked > 0;
                            return (
                              <button key={a.id} onClick={() => onOpenAssignment(group.property, a)}
                                className={`w-full text-left p-4 rounded-2xl border transition-colors ${hasBlocked ? 'bg-red-50/50 border-red-200 hover:border-red-400' : 'bg-white border-stone-200 hover:border-stone-400'}`}>
                                <div className="flex items-start justify-between gap-2">
                                  <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1 flex-wrap">
                                      {a.file_kind === 'pdf'
                                        ? <FileText size={13} className="text-stone-500 flex-shrink-0" />
                                        : <ImageIcon size={13} className="text-stone-500 flex-shrink-0" />}
                                      <span className="font-serif text-base text-stone-900 truncate">{a.title}</span>
                                      {hasBlocked && (
                                        <span className="text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full bg-red-100 text-red-700">
                                          ⚠ Blocked
                                        </span>
                                      )}
                                    </div>
                                    <div className="text-xs text-stone-500 font-mono">
                                      {a.counts.done}/{a.targets?.length || 0} done
                                      {a.counts.in_progress > 0 && ` · ${a.counts.in_progress} in progress`}
                                      {a.counts.pending > 0 && ` · ${a.counts.pending} pending`}
                                      {a.counts.blocked > 0 && ` · ${a.counts.blocked} blocked`}
                                    </div>
                                    {uniqStarters.length > 0 && (
                                      <div className="text-xs text-amber-700 mt-1">
                                        {uniqStarters.length === 1
                                          ? `${uniqStarters[0]} is working on this`
                                          : `${uniqStarters.length} cleaners: ${uniqStarters.join(', ')}`}
                                      </div>
                                    )}
                                  </div>
                                  <ChevronRight size={16} className="text-stone-400 flex-shrink-0" />
                                </div>
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    );
                  })}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

// =================================================================
// PORTAL — PM PHOTO UPLOAD TAB
// Property manager uploads a photo (or set of photos) for owner review.
// =================================================================
function PortalPhotoUploadTab({ property, portalKind }) {
  const isMulti = property.property_type === 'multi_unit';
  const [units, setUnits] = useState([]);
  const [unitId, setUnitId] = useState('');
  const [parties, setParties] = useState([]);
  const [partyId, setPartyId] = useState('');
  const [title, setTitle] = useState('');
  const [notes, setNotes] = useState('');
  const [file, setFile] = useState(null);
  const [busy, setBusy] = useState(false);
  const [progress, setProgress] = useState('');
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');
  const [history, setHistory] = useState([]);
  const [zoomPhoto, setZoomPhoto] = useState(null);

  useEffect(() => {
    if (!isMulti) return;
    (async () => {
      const { data } = await supabase.from('units')
        .select('*, parties(id, label, full_name, active, sort_order)')
        .eq('customer_id', property.id).eq('active', true)
        .order('sort_order').order('label');
      setUnits((data || []).slice().sort((a, b) => naturalCompare(a.label, b.label)));
    })();
  }, [property.id, isMulti]);

  useEffect(() => {
    if (!unitId) { setParties([]); return; }
    const u = units.find(x => x.id === unitId);
    setParties((u?.parties || []).filter(p => p.active).sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0)));
  }, [unitId, units]);

  // Load history of PM photos for this property
  const loadHistory = async () => {
    const { data } = await supabase.from('pm_photos')
      .select('*, unit:units(label), party:parties(label)')
      .eq('customer_id', property.id)
      .neq('status', 'archived')
      .order('created_at', { ascending: false })
      .limit(20);
    setHistory(data || []);
  };
  useEffect(() => { loadHistory(); }, [property.id]);

  const reset = () => {
    setTitle(''); setNotes(''); setFile(null);
    setUnitId(''); setPartyId('');
    setError(''); setProgress('');
  };

  const handleFile = (e) => {
    const f = e.target.files?.[0];
    if (f && !f.type.startsWith('image/')) {
      setError('Please choose an image file (JPG, PNG, etc).');
      return;
    }
    setFile(f || null);
    setError('');
  };

  const save = async () => {
    setError('');
    if (!file) { setError('Choose a photo first.'); return; }
    setBusy(true);
    try {
      setProgress('Uploading photo…');
      const { path, publicUrl } = await uploadPmFile(file, property.id);
      setProgress('Saving…');
      const { error: e } = await supabase.from('pm_photos').insert({
        customer_id: property.id,
        unit_id: unitId || null,
        party_id: partyId || null,
        title: title.trim() || null,
        notes: notes.trim() || null,
        photo_url: publicUrl,
        photo_path: path,
        status: 'new',
        actor_kind: portalKind || 'pm'
      });
      if (e) throw e;
      setSuccess(true);
      reset();
      loadHistory();
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      setError(err.message || String(err));
    } finally {
      setBusy(false); setProgress('');
    }
  };

  return (
    <div className="px-5 pt-6 space-y-5">
      <div>
        <h2 className="font-serif text-2xl text-stone-900 mb-1">Send a photo</h2>
        <p className="text-sm text-stone-600">
          Upload photos you want the cleaning team to see — damage, items left behind, anything worth flagging.
        </p>
      </div>

      <div>
        <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Title (optional)</label>
        <input type="text" value={title} onChange={(e) => setTitle(e.target.value)}
          placeholder="e.g. Damage in master bath" maxLength={120}
          className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white text-stone-900" />
      </div>

      <div>
        <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Notes (optional)</label>
        <textarea value={notes} onChange={(e) => setNotes(e.target.value)} rows={3}
          placeholder="Add any context the cleaners should know…"
          className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white text-stone-900 resize-none" />
      </div>

      {isMulti && (
        <>
          <div>
            <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Unit (optional)</label>
            <SearchableUnitPicker
              units={units}
              value={unitId}
              placeholder="— Whole property —"
              onChange={(newUnitId) => {
                setUnitId(newUnitId); setPartyId('');
                const u = units.find(x => x.id === newUnitId);
                if (u) {
                  const stripped = title.replace(/^[^—]+ — /, '');
                  setTitle(`${u.label} — ${stripped}`);
                }
              }} />
            {unitId && (
              <button type="button" onClick={() => { setUnitId(''); setPartyId(''); }}
                className="text-xs font-mono text-stone-500 mt-1 hover:text-stone-900">
                ← Clear (apply to whole property)
              </button>
            )}
          </div>
          {unitId && parties.length > 0 && (
            <div>
              <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Bedroom (optional)</label>
              <select value={partyId} onChange={(e) => {
                  const newPartyId = e.target.value;
                  setPartyId(newPartyId);
                  const u = units.find(x => x.id === unitId);
                  const p = (u?.parties || []).find(x => x.id === newPartyId);
                  if (u) {
                    const stripped = title.replace(/^[^—]+ — /, '');
                    setTitle(`${u.label}${p ? ` · ${p.label}` : ''} — ${stripped}`);
                  }
                }}
                className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white">
                <option value="">— Any —</option>
                {parties.map(p => <option key={p.id} value={p.id}>{p.label}{p.full_name ? ` (${p.full_name})` : ''}</option>)}
              </select>
            </div>
          )}
        </>
      )}

      <div>
        <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Photo</label>
        <label className={`block w-full p-6 border-2 border-dashed rounded-2xl text-center cursor-pointer transition-colors ${file ? 'border-emerald-300 bg-emerald-50' : 'border-stone-300 hover:border-stone-900'}`}>
          {file ? (
            <>
              <Check size={28} className="mx-auto mb-2 text-emerald-600" />
              <div className="text-stone-900 font-medium text-sm">{file.name}</div>
              <div className="text-xs text-stone-500 mt-0.5">{(file.size / 1024).toFixed(1)} KB · tap to change</div>
            </>
          ) : (
            <>
              <Camera size={28} className="mx-auto mb-2 text-stone-400" />
              <div className="text-stone-700 font-medium text-sm">Choose a photo</div>
              <div className="text-xs text-stone-500 mt-0.5">Max {ASSIGNMENT_MAX_SIZE_MB}MB</div>
            </>
          )}
          <input type="file" accept="image/*" onChange={handleFile} className="hidden" />
        </label>
      </div>

      {error && (
        <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
          <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
        </div>
      )}
      {busy && progress && (
        <div className="p-3 rounded-xl bg-stone-100 text-stone-700 text-sm font-mono flex items-center gap-3">
          <div className="w-4 h-4 border-2 border-stone-700 border-t-transparent rounded-full animate-spin flex-shrink-0" />
          {progress}
        </div>
      )}
      {success && (
        <div className="p-3 rounded-xl bg-emerald-50 border border-emerald-200 text-emerald-800 text-sm flex items-center gap-2">
          <Check size={16} /> Photo sent. The cleaning team will see it.
        </div>
      )}

      <button onClick={save} disabled={busy || !file}
        className="w-full py-4 rounded-2xl bg-stone-900 text-stone-50 font-medium disabled:opacity-50">
        {busy ? 'Sending…' : 'Send photo'}
      </button>

      {/* Recent uploads */}
      {history.length > 0 && (
        <div className="pt-6 border-t border-stone-200">
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-3">
            Recently sent ({history.length})
          </div>
          <div className="space-y-3">
            {history.map(p => (
              <div key={p.id} className="p-3 rounded-2xl bg-white border border-stone-200">
                <div className="flex gap-3">
                  <button onClick={() => setZoomPhoto(p)}
                    className="flex-shrink-0 w-20 h-20 rounded-xl overflow-hidden bg-stone-100">
                    <img loading="lazy" src={p.photo_url} alt={p.title || ''} className="w-full h-full object-cover" />
                  </button>
                  <div className="flex-1 min-w-0">
                    {p.title && (
                      <div className="font-serif text-sm text-stone-900 truncate mb-0.5">{p.title}</div>
                    )}
                    {(p.unit?.label || p.party?.label) && (
                      <div className="text-[10px] font-mono text-stone-500 mb-1">
                        {p.unit?.label}{p.party?.label && ` · ${p.party.label}`}
                      </div>
                    )}
                    {p.notes && (
                      <div className="text-xs text-stone-600 line-clamp-2 mb-1">{p.notes}</div>
                    )}
                    <div className="flex items-center gap-2 text-[10px] font-mono">
                      <span className="text-stone-400">{fmtDate(p.created_at)}</span>
                      <span className={`px-1.5 py-0.5 rounded-full ${p.status === 'seen' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                        {p.status === 'seen' ? 'Seen by owner' : 'Awaiting review'}
                      </span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Photo zoom modal */}
      {zoomPhoto && (
        <div className="fixed inset-0 bg-stone-900/95 z-50 flex flex-col">
          <div className="flex items-center justify-between p-4 text-stone-50 bg-stone-900 flex-shrink-0">
            <div className="text-sm font-mono truncate flex-1">{zoomPhoto.title || 'Photo'}</div>
            <button onClick={() => setZoomPhoto(null)} className="p-2 rounded-full bg-stone-800 ml-2 flex-shrink-0">
              <X size={20} />
            </button>
          </div>
          <div className="flex-1 overflow-auto p-4">
            <img loading="lazy" src={zoomPhoto.photo_url} alt="" className="w-full h-auto rounded-xl" />
            {zoomPhoto.notes && (
              <div className="mt-3 p-3 rounded-xl bg-stone-800 text-stone-200 text-sm whitespace-pre-wrap">
                {zoomPhoto.notes}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// =================================================================
// PORTAL — PM ASSIGNMENTS TAB
// Property manager creates/edits/submits assignment drafts; once
// approved they become read-only.
// =================================================================
function PortalAssignmentsTab({ property, portalKind, portalUser }) {
  const [assignments, setAssignments] = useState([]);
  const [loaded, setLoaded] = useState(false);
  // Added 'wizard' kind so the PM can open the new ChecklistAssignmentWizard.
  // Legacy upload (PortalAssignmentForm) still reachable via the greyed-out
  // button below — but only if the owner explicitly turned the permission
  // on for this PM (portalUser.allow_legacy_uploads).
  const [view, setView] = useState({ kind: 'list' });
  const [search, setSearch] = useState('');

  const allowLegacy = !!portalUser?.allow_legacy_uploads;

  const load = async () => {
    const { data } = await supabase.from('assignments')
      .select('*, targets:assignment_targets(id, status, priority, unit:units(label), party:parties(label))')
      .eq('customer_id', property.id)
      .eq('source', 'pm')
      .order('created_at', { ascending: false });
    setAssignments(data || []);
    setLoaded(true);
  };
  useEffect(() => { load(); }, [property.id]);

  if (view.kind === 'wizard') {
    return <ChecklistAssignmentWizard property={property}
      employee={null}                          /* no staff employee in PM context */
      actorKind={portalKind || 'pm'}
      portalUser={portalUser}
      onCancel={() => setView({ kind: 'list' })}
      onSaved={() => { setView({ kind: 'list' }); load(); }} />;
  }
  if (view.kind === 'new') {
    return <PortalAssignmentForm property={property} portalKind={portalKind}
      onCancel={() => setView({ kind: 'list' })}
      onSaved={() => { setView({ kind: 'list' }); load(); }} />;
  }
  if (view.kind === 'edit') {
    return <PortalAssignmentForm property={property} assignment={view.assignment} portalKind={portalKind}
      onCancel={() => setView({ kind: 'list' })}
      onSaved={() => { setView({ kind: 'list' }); load(); }} />;
  }
  if (view.kind === 'detail') {
    return <PortalAssignmentDetail property={property} assignment={view.assignment} portalUser={portalUser}
      onBack={() => { setView({ kind: 'list' }); load(); }}
      onEdit={() => setView({ kind: 'edit', assignment: view.assignment })} />;
  }

  // Decorate assignments with priority + primary unit label for search/grouping
  const decorated = assignments.map(a => {
    const targets = a.targets || [];
    const hasPriority = targets.some(t => t.priority);
    const firstUnitLabel = targets.find(t => t.unit?.label)?.unit?.label || '';
    return { ...a, hasPriority, firstUnitLabel };
  });

  // Search across title, notes, unit, bedroom
  const q = search.trim().toLowerCase();
  const matchesSearch = (a) => {
    if (!q) return true;
    if ((a.title || '').toLowerCase().includes(q)) return true;
    if ((a.notes || '').toLowerCase().includes(q)) return true;
    if ((a.firstUnitLabel || '').toLowerCase().includes(q)) return true;
    return (a.targets || []).some(t => (t.party?.label || '').toLowerCase().includes(q));
  };
  const visible = decorated.filter(matchesSearch);

  const groups = {
    draft: visible.filter(a => a.pm_status === 'draft'),
    pending: visible.filter(a => a.pm_status === 'pending'),
    approved: visible.filter(a => a.pm_status === 'approved'),
    rejected: visible.filter(a => a.pm_status === 'rejected'),
  };

  return (
    <div className="px-5 pt-6 space-y-5">
      <div>
        <h2 className="font-serif text-2xl text-stone-900 mb-1">Your assignments</h2>
        <p className="text-sm text-stone-600">
          Create assignments for the cleaning team. They take effect once approved.
        </p>
      </div>

      {/* Primary upload — the new checklist wizard. This is the
         recommended path for every PM. Maps the assignment to specific
         bedroom items with structured templates instead of a free-form
         file upload. */}
      <button onClick={() => setView({ kind: 'wizard' })}
        className="w-full py-4 rounded-2xl bg-stone-900 text-stone-50 font-medium flex items-center justify-center gap-2">
        <Plus size={18} /> New assignment
      </button>

      {/* Legacy upload — greyed out by default. Owner can re-enable it
         per-PM via portalUser.allow_legacy_uploads. We always show the
         button so PMs see this exists but understand it's gated behind
         owner permission. */}
      <button onClick={() => allowLegacy && setView({ kind: 'new' })}
        disabled={!allowLegacy}
        title={allowLegacy
          ? 'Upload a file or photo as the source for an assignment (legacy flow).'
          : 'Disabled by the owner. Ask them to enable legacy uploads for your account if you need this option.'}
        className={`w-full py-2.5 rounded-xl text-xs font-medium flex items-center justify-center gap-1.5 border ${allowLegacy
          ? 'bg-stone-50 border-stone-300 text-stone-700 hover:bg-stone-100'
          : 'bg-stone-100 border-stone-200 text-stone-400 cursor-not-allowed'}`}>
        <FileText size={12} />
        {allowLegacy
          ? 'Legacy file upload'
          : 'Legacy file upload (disabled by owner)'}
      </button>

      {/* Search — filters across title, unit, bedroom, notes. PMs don't
         need cleaner/category filters but search by apartment/building
         is universally useful. */}
      {assignments.length > 0 && (
        <input type="text" value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder={`Search ${assignments.length} assignment${assignments.length === 1 ? '' : 's'} (apartment, bedroom, title)…`}
          className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white focus:outline-none focus:border-stone-900 text-stone-900 text-sm" />
      )}

      {!loaded ? <Splash text="Loading…" /> : assignments.length === 0 ? (
        <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
          You haven't created any assignments yet.
        </div>
      ) : visible.length === 0 ? (
        <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
          No assignments match "{search}".
        </div>
      ) : (
        <>
          <PortalAssignmentSection title="Drafts" subtitle="You can still edit these" items={groups.draft}
            color="stone" onOpen={(a) => setView({ kind: 'detail', assignment: a })} />
          <PortalAssignmentSection title="Pending review" subtitle="Waiting for the owner to approve" items={groups.pending}
            color="amber" onOpen={(a) => setView({ kind: 'detail', assignment: a })} />
          <PortalAssignmentSection title="Needs changes" subtitle="Owner asked for changes — edit and resubmit" items={groups.rejected}
            color="red" onOpen={(a) => setView({ kind: 'detail', assignment: a })} />
          <PortalAssignmentSection title="Approved" subtitle="Active — visible to the cleaning team" items={groups.approved}
            color="emerald" onOpen={(a) => setView({ kind: 'detail', assignment: a })} />
        </>
      )}
    </div>
  );
}

function PortalAssignmentSection({ title, subtitle, items, color, onOpen }) {
  if (items.length === 0) return null;
  const colors = {
    stone: 'border-stone-300 bg-stone-50',
    amber: 'border-amber-300 bg-amber-50',
    red: 'border-red-300 bg-red-50',
    emerald: 'border-emerald-300 bg-emerald-50',
  };
  return (
    <div>
      <div className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2">
        {title} ({items.length})
      </div>
      <p className="text-xs text-stone-500 mb-3">{subtitle}</p>
      <div className="space-y-2">
        {items.map(a => (
          <button key={a.id} onClick={() => onOpen(a)}
            className={`w-full text-left p-4 rounded-2xl border-2 hover:border-stone-900 transition-colors ${colors[color]}`}>
            <div className="flex items-start justify-between gap-2">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  {a.file_kind === 'pdf'
                    ? <FileText size={14} className="text-stone-600 flex-shrink-0" />
                    : <ImageIcon size={14} className="text-stone-600 flex-shrink-0" />}
                  <span className="font-serif text-base text-stone-900 truncate">{a.title}</span>
                </div>
                {/* Priority + cleaning-type chips so PMs see urgency
                   and what kind of clean was requested at a glance. */}
                {(a.hasPriority || a.assignment_type) && (
                  <div className="flex items-center gap-1.5 flex-wrap mb-1">
                    <PriorityChip on={a.hasPriority} />
                    <AssignmentTypeChip type={a.assignment_type} />
                  </div>
                )}
                <div className="text-xs text-stone-500 font-mono">
                  {fmtDate(a.created_at)} · {a.targets?.length || 0} {a.targets?.length === 1 ? 'target' : 'targets'}
                </div>
                {a.pm_rejection_reason && (
                  <div className="text-xs text-red-700 italic mt-1">"{a.pm_rejection_reason}"</div>
                )}
              </div>
              <ChevronRight size={16} className="text-stone-400 flex-shrink-0" />
            </div>
          </button>
        ))}
      </div>
    </div>
  );
}

// PM-side form for creating or editing an assignment
function PortalAssignmentForm({ property, assignment, portalKind, onCancel, onSaved }) {
  const isMulti = property.property_type === 'multi_unit';
  const isEdit = !!assignment;
  const [title, setTitle] = useState(assignment?.title || '');
  const [notes, setNotes] = useState(assignment?.notes || '');
  // Empty default forces the user to actively pick a type
  const [assignmentType, setAssignmentType] = useState(assignment?.assignment_type || '');
  const [scheduledDate, setScheduledDate] = useState(assignment?.scheduled_date || '');
  const [file, setFile] = useState(null); // a NEW file (replaces existing)
  const [keepExistingFile, setKeepExistingFile] = useState(isEdit);
  // Priority — PMs can flag urgent submissions. Carries through to the
  // cleaner's view once the owner approves. Owner can still un-flag
  // during approval if they disagree with the urgency.
  const [priority, setPriority] = useState(false);
  // Scope: 'specific' (single bedroom), 'multiple' (several bedrooms),
  // 'property' (whole property). Multi mode added to mirror the owner-side
  // form so PMs can fan out one assignment to many bedrooms at once.
  const [scope, setScope] = useState(isMulti ? 'specific' : 'property');
  const [units, setUnits] = useState([]);
  const [unitId, setUnitId] = useState('');
  const [partyId, setPartyId] = useState('');
  const [parties, setParties] = useState([]);
  // Multi-target state — array of { unitId, partyId } pairs
  const [multipleTargets, setMultipleTargets] = useState([]);
  const [unitSearch, setUnitSearch] = useState('');
  const [busy, setBusy] = useState(false);
  const [progress, setProgress] = useState('');
  const [error, setError] = useState('');

  // On edit, load priority from any of the existing targets
  // (all targets of one assignment share priority in practice)
  useEffect(() => {
    if (!isEdit || !assignment?.id) return;
    (async () => {
      const { data } = await supabase.from('assignment_targets')
        .select('priority').eq('assignment_id', assignment.id).limit(1).maybeSingle();
      if (data?.priority) setPriority(true);
    })();
  }, [isEdit, assignment?.id]);

  const toggleTarget = (uId, pId) => {
    setMultipleTargets(prev => {
      const exists = prev.some(t => t.unitId === uId && (t.partyId || null) === (pId || null));
      return exists
        ? prev.filter(t => !(t.unitId === uId && (t.partyId || null) === (pId || null)))
        : [...prev, { unitId: uId, partyId: pId || null }];
    });
  };

  const toggleAllInUnit = (unit) => {
    setMultipleTargets(prev => {
      const activeParties = (unit.parties || []).filter(p => p.active);
      const allSelected = activeParties.length > 0 && activeParties.every(p =>
        prev.some(t => t.unitId === unit.id && (t.partyId || null) === p.id));
      return allSelected
        ? prev.filter(t => t.unitId !== unit.id)
        : [
            ...prev.filter(t => t.unitId !== unit.id),
            ...activeParties.map(p => ({ unitId: unit.id, partyId: p.id })),
          ];
    });
  };

  // Load units for multi-unit properties
  useEffect(() => {
    if (!isMulti) return;
    (async () => {
      const { data } = await supabase.from('units')
        .select('*, parties(id, label, full_name, active, sort_order)')
        .eq('customer_id', property.id).eq('active', true)
        .order('sort_order').order('label');
      // Common areas (clubhouse, gym) first, then everything else alphabetical
      setUnits((data || []).slice().sort((a, b) => {
        const aCommon = a.kind === 'common_area';
        const bCommon = b.kind === 'common_area';
        if (aCommon && !bCommon) return -1;
        if (!aCommon && bCommon) return 1;
        return naturalCompare(a.label, b.label);
      }));
    })();
  }, [property.id, isMulti]);

  // If editing, load all existing targets and pre-populate the right
  // scope (single vs multiple bedrooms vs whole property).
  useEffect(() => {
    if (!isEdit || !assignment) return;
    (async () => {
      const { data } = await supabase.from('assignment_targets')
        .select('unit_id, party_id').eq('assignment_id', assignment.id);
      const targets = data || [];
      if (targets.length === 0) return;
      // Whole property → single row with null unit/party
      if (targets.length === 1 && !targets[0].unit_id && !targets[0].party_id) {
        setScope('property');
        return;
      }
      // Multiple targets → multi mode
      if (targets.length > 1) {
        setScope('multiple');
        setMultipleTargets(targets.map(t => ({ unitId: t.unit_id, partyId: t.party_id })));
        return;
      }
      // Single specific target
      const t = targets[0];
      setScope('specific');
      if (t.unit_id) setUnitId(t.unit_id);
      if (t.party_id) setPartyId(t.party_id);
    })();
  }, [isEdit, assignment]);

  useEffect(() => {
    if (!unitId) { setParties([]); return; }
    const u = units.find(x => x.id === unitId);
    setParties((u?.parties || []).filter(p => p.active).sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0)));
  }, [unitId, units]);

  const handleFile = (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    const isOk = f.type === 'application/pdf' || f.type.startsWith('image/');
    if (!isOk) { setError('Only PDFs and images.'); return; }
    setFile(f); setKeepExistingFile(false); setError('');
  };

  const save = async (submitForApproval) => {
    setError('');
    if (!keepExistingFile && !file) { setError('Pick a PDF or image first.'); return; }
    if (!assignmentType) { setError('Pick a cleaning type.'); return; }
    if (isMulti) {
      if (scope === 'specific' && (!unitId || !partyId)) {
        setError('Pick a unit and bedroom.'); return;
      }
      if (scope === 'multiple' && multipleTargets.length === 0) {
        setError('Pick at least one bedroom.'); return;
      }
    }
    setBusy(true);
    try {
      let filePayload = null;
      if (file) {
        setProgress('Uploading file…');
        const { path, publicUrl, kind } = await uploadPmFile(file, property.id);
        filePayload = { file_path: path, file_url: publicUrl, file_kind: kind };
      }

      const newStatus = submitForApproval ? 'pending' : 'draft';

      if (isEdit) {
        setProgress('Saving changes…');
        const patch = {
          title: title.trim() || assignmentTypeLabel(assignmentType),
          notes: notes.trim() || null,
          assignment_type: assignmentType,
          scheduled_date: scheduledDate || null,
          pm_status: newStatus,
          pm_rejection_reason: null  // clear any prior rejection note on resubmit
        };
        if (filePayload) {
          // delete the old file before replacing
          if (assignment.file_path) await deletePmFile(assignment.file_path);
          Object.assign(patch, filePayload);
          // Reset translation status — we'll re-translate the new file
          patch.translation_status = 'pending';
          patch.extracted_text = null;
          patch.spanish_translation = null;
          patch.translation_error = null;
        }
        const { error: e1 } = await supabase.from('assignments').update(patch).eq('id', assignment.id);
        if (e1) throw e1;

        // If the file was replaced, kick off auto-translation for the new file
        if (filePayload?.file_url && filePayload?.file_kind) {
          autoTranslateAssignment(assignment.id, filePayload.file_url, filePayload.file_kind);
        }

        // Replace targets with the new selection
        await supabase.from('assignment_targets').delete().eq('assignment_id', assignment.id);
        let targetRows;
        if (!isMulti || scope === 'property') {
          targetRows = [{ assignment_id: assignment.id, unit_id: null, party_id: null, status: 'pending', priority }];
        } else if (scope === 'multiple') {
          targetRows = multipleTargets.map(t => ({
            assignment_id: assignment.id, unit_id: t.unitId, party_id: t.partyId, status: 'pending', priority
          }));
        } else {
          targetRows = [{ assignment_id: assignment.id, unit_id: unitId, party_id: partyId, status: 'pending', priority }];
        }
        const { error: e2 } = await supabase.from('assignment_targets').insert(targetRows);
        if (e2) throw e2;
      } else {
        // Build the list of targets we'll create assignments for. In
        // multi mode each gets its own assignments row with a per-bedroom
        // title like "B1-101-1" so each cleaner sees their own clean
        // identifier; the file URL is shared across all of them.
        const targets = (() => {
          if (!isMulti || scope === 'property') {
            return [{
              unit_id: null, party_id: null,
              title: title.trim() || assignmentTypeLabel(assignmentType),
            }];
          }
          if (scope === 'multiple') {
            return multipleTargets.map(t => {
              const u = units.find(uu => uu.id === t.unitId);
              const p = (u?.parties || []).find(pp => pp.id === t.partyId);
              return {
                unit_id: t.unitId,
                party_id: t.partyId,
                title: buildTargetTitle(u?.label, p?.label) || assignmentTypeLabel(assignmentType),
              };
            });
          }
          return [{
            unit_id: unitId, party_id: partyId,
            title: title.trim() || assignmentTypeLabel(assignmentType),
          }];
        })();

        let firstCreatedId = null;
        for (let t = 0; t < targets.length; t++) {
          const target = targets[t];
          setProgress(targets.length > 1
            ? `Creating assignment ${t + 1} of ${targets.length}…`
            : 'Creating assignment…');
          const { data: created, error: e1 } = await supabase.from('assignments').insert({
            customer_id: property.id,
            title: target.title,
            notes: notes.trim() || null,
            assignment_type: assignmentType,
            scheduled_date: scheduledDate || null,
            source: 'pm',
            pm_status: newStatus,
            active: true,
            actor_kind: portalKind || 'pm',
            ...filePayload,
          }).select().single();
          if (e1) throw e1;

          // Fire translation once for the first sibling (file is shared)
          if (t === 0 && filePayload?.file_url && filePayload?.file_kind) {
            autoTranslateAssignment(created.id, filePayload.file_url, filePayload.file_kind);
            firstCreatedId = created.id;
          }

          const { error: e2 } = await supabase.from('assignment_targets').insert({
            assignment_id: created.id,
            unit_id: target.unit_id,
            party_id: target.party_id,
            status: 'pending',
            priority,
          });
          if (e2) throw e2;
        }
      }
      onSaved();
    } catch (err) {
      setError(err.message || String(err));
      setBusy(false);
    }
  };

  return (
    <div className="min-h-screen bg-stone-50 pb-12">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200">
        <button onClick={onCancel} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div>
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">{property.name}</div>
          <div className="font-serif text-xl text-stone-900">
            {isEdit ? 'Edit assignment' : 'New assignment'}
          </div>
        </div>
      </div>

      <div className="px-5 pt-6 space-y-5">
        {/* File first — the user wants this to be the very first thing
           they handle, matching the owner-side flow. */}
        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">
            File (PDF or image) <span className="text-red-600 normal-case">*</span>
          </label>
          {keepExistingFile && assignment?.file_url && (
            <div className="mb-2 p-3 rounded-xl bg-stone-100 flex items-center gap-2 text-sm">
              {assignment.file_kind === 'pdf' ? <FileText size={16} /> : <ImageIcon size={16} />}
              <span className="flex-1 truncate text-stone-700">Existing file</span>
              <a href={assignment.file_url} target="_blank" rel="noreferrer"
                className="text-xs text-amber-700 font-mono">View</a>
              <button type="button" onClick={() => setKeepExistingFile(false)}
                className="text-xs text-stone-500 font-mono">Replace</button>
            </div>
          )}
          {!keepExistingFile && (
            <label className={`block w-full p-6 border-2 border-dashed rounded-2xl text-center cursor-pointer ${file ? 'border-emerald-300 bg-emerald-50' : 'border-stone-300'}`}>
              {file ? (
                <>
                  <Check size={24} className="mx-auto mb-1 text-emerald-600" />
                  <div className="text-sm text-stone-900">{file.name}</div>
                  <div className="text-xs text-stone-500">{(file.size / 1024).toFixed(1)} KB</div>
                </>
              ) : (
                <>
                  <FileText size={24} className="mx-auto mb-1 text-stone-400" />
                  <div className="text-sm text-stone-700">Choose PDF or image</div>
                </>
              )}
              <input type="file" accept="application/pdf,image/*" onChange={handleFile} className="hidden" />
            </label>
          )}
        </div>

        {/* Type — empty default forces an active pick */}
        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">
            Type <span className="text-red-600 normal-case">*</span>
          </label>
          <select value={assignmentType} onChange={(e) => setAssignmentType(e.target.value)}
            className={`w-full px-4 py-3 rounded-xl border bg-white ${assignmentType ? 'border-stone-300' : 'border-amber-400'}`}>
            <option value="">Pick a type…</option>
            {ASSIGNMENT_TYPES.map(t => (
              <option key={t.value} value={t.value}>{t.label}</option>
            ))}
          </select>
        </div>

        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">
            Scheduled for <span className="text-stone-400 normal-case">(optional)</span>
          </label>
          <input type="date" value={scheduledDate} onChange={(e) => setScheduledDate(e.target.value)}
            className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white" />
          <div className="text-[11px] text-stone-500 mt-1">
            The Summit Clean team can adjust this if needed.
          </div>
        </div>

        {/* Priority toggle — PM flags urgency. Owner can un-flag during
           approval if they disagree. */}
        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">
            Urgency
          </label>
          <button type="button" onClick={() => setPriority(p => !p)}
            className={`w-full px-4 py-3 rounded-xl border text-sm flex items-center justify-center gap-2 transition-colors ${priority ? 'border-red-400 bg-red-50 text-red-800' : 'border-stone-300 bg-white text-stone-600'}`}>
            {priority ? <AlertCircle size={14} /> : null}
            {priority ? 'Marked as priority — please do first' : 'Mark as priority (optional)'}
          </button>
          <div className="text-[11px] text-stone-500 mt-1">
            Use sparingly. The team gets a red badge on priority items and they sort to the top.
          </div>
        </div>

        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">
            Title <span className="text-stone-400 normal-case">{scope === 'multiple' ? '(auto-filled per bedroom)' : '(optional)'}</span>
          </label>
          <input type="text" value={title} onChange={(e) => setTitle(e.target.value)}
            placeholder={scope === 'multiple' ? 'Auto-filled per bedroom on save' : 'Pick a unit + bedroom to auto-fill'}
            disabled={scope === 'multiple'}
            className={`w-full px-4 py-3 rounded-xl border border-stone-300 bg-white ${scope === 'multiple' ? 'opacity-60 bg-stone-50' : ''}`} />
          {assignmentType && (
            <div className="mt-1.5 text-[11px] font-mono text-stone-500">
              Cleaning type: <span className="text-amber-700 font-medium">{assignmentTypeLabel(assignmentType)}</span>
            </div>
          )}
        </div>

        <div>
          <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Notes / instructions</label>
          <textarea value={notes} onChange={(e) => setNotes(e.target.value)} rows={4}
            placeholder="What needs to be done…"
            className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white resize-none" />
        </div>

        {isMulti && (
          <>
            <div>
              <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Where?</label>
              <div className="grid grid-cols-3 gap-2">
                <button type="button" onClick={() => { setScope('specific'); setMultipleTargets([]); }}
                  className={`p-3 rounded-xl border-2 text-left ${scope === 'specific' ? 'border-stone-900 bg-white' : 'border-stone-200 bg-white/50'}`}>
                  <div className="font-medium text-xs">One bedroom</div>
                </button>
                <button type="button" onClick={() => { setScope('multiple'); setUnitId(''); setPartyId(''); }}
                  className={`p-3 rounded-xl border-2 text-left ${scope === 'multiple' ? 'border-stone-900 bg-white' : 'border-stone-200 bg-white/50'}`}>
                  <div className="font-medium text-xs">Multiple bedrooms</div>
                </button>
                <button type="button" onClick={() => { setScope('property'); setUnitId(''); setPartyId(''); setMultipleTargets([]); }}
                  className={`p-3 rounded-xl border-2 text-left ${scope === 'property' ? 'border-stone-900 bg-white' : 'border-stone-200 bg-white/50'}`}>
                  <div className="font-medium text-xs">Whole property</div>
                </button>
              </div>
            </div>
            {scope === 'specific' && (
              <>
                <div>
                  <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Unit</label>
                  <SearchableUnitPicker
                    units={units}
                    value={unitId}
                    placeholder="— Pick a unit —"
                    onChange={(newUnitId) => {
                      setUnitId(newUnitId); setPartyId('');
                      const u = units.find(x => x.id === newUnitId);
                      // Auto-fill title only if it's empty or matches the
                      // previous auto value (so we don't clobber custom edits).
                      const prevU = units.find(x => x.id === unitId);
                      const prevP = (prevU?.parties || []).find(x => x.id === partyId);
                      const prevAuto = buildTargetTitle(prevU?.label, prevP?.label);
                      if (!title || title === prevAuto) {
                        setTitle(buildTargetTitle(u?.label, ''));
                      }
                    }} />
                </div>
                {unitId && (
                  <div>
                    <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">Bedroom</label>
                    <select value={partyId} onChange={(e) => {
                        const newPartyId = e.target.value;
                        setPartyId(newPartyId);
                        const u = units.find(x => x.id === unitId);
                        const p = (u?.parties || []).find(x => x.id === newPartyId);
                        const prevP = (u?.parties || []).find(x => x.id === partyId);
                        const prevAuto = buildTargetTitle(u?.label, prevP?.label);
                        if (!title || title === prevAuto) {
                          setTitle(buildTargetTitle(u?.label, p?.label));
                        }
                      }}
                      className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white">
                      <option value="">— Pick a bedroom —</option>
                      {parties.map(p => <option key={p.id} value={p.id}>{p.label}{p.full_name ? ` (${p.full_name})` : ''}</option>)}
                    </select>
                  </div>
                )}
              </>
            )}
            {scope === 'multiple' && (
              <div>
                <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">
                  Pick bedrooms
                </label>
                <div className="space-y-1.5 max-h-72 overflow-y-auto border border-stone-200 rounded-xl p-2 bg-stone-50">
                  <input type="text" value={unitSearch} onChange={(e) => setUnitSearch(e.target.value)}
                    placeholder="Filter units…"
                    className="w-full px-2 py-1.5 rounded-lg border border-stone-300 bg-white text-xs mb-1" />
                  {(() => {
                    const q = unitSearch.trim().toLowerCase();
                    const filteredUnits = q
                      ? units.filter(u => (u.label || '').toLowerCase().includes(q))
                      : units;
                    if (filteredUnits.length === 0) {
                      return <div className="text-center py-3 text-stone-400 text-xs italic">
                        {units.length === 0 ? 'No units in this property.' : 'No units match your search.'}
                      </div>;
                    }
                    return filteredUnits.map(u => {
                      const activeParties = (u.parties || []).filter(p => p.active).sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));
                      const allSelected = activeParties.length > 0 && activeParties.every(p =>
                        multipleTargets.some(t => t.unitId === u.id && (t.partyId || null) === p.id));
                      const someSelected = activeParties.some(p =>
                        multipleTargets.some(t => t.unitId === u.id && (t.partyId || null) === p.id));
                      return (
                        <div key={u.id} className="bg-white rounded-lg border border-stone-200 p-2">
                          <button type="button" onClick={() => toggleAllInUnit(u)}
                            className="w-full flex items-center gap-2 mb-1 text-left">
                            <div className={`w-4 h-4 rounded border-2 flex-shrink-0 flex items-center justify-center ${allSelected ? 'border-amber-600 bg-amber-600' : someSelected ? 'border-amber-600 bg-amber-100' : 'border-stone-300'}`}>
                              {allSelected && <Check size={11} className="text-white" />}
                              {!allSelected && someSelected && <div className="w-2 h-2 bg-amber-600 rounded-sm" />}
                            </div>
                            <span className="text-xs font-medium text-stone-900">{u.label}</span>
                            <span className="text-[10px] font-mono text-stone-400 ml-auto">
                              {activeParties.length} bedroom{activeParties.length === 1 ? '' : 's'}
                            </span>
                          </button>
                          {activeParties.length > 0 && (
                            <div className="ml-6 grid grid-cols-2 gap-1">
                              {activeParties.map(p => {
                                const checked = multipleTargets.some(t => t.unitId === u.id && (t.partyId || null) === p.id);
                                return (
                                  <button key={p.id} type="button" onClick={() => toggleTarget(u.id, p.id)}
                                    className={`flex items-center gap-1.5 px-2 py-1 rounded-lg text-left border ${checked ? 'border-amber-600 bg-amber-50' : 'border-stone-200 bg-white hover:border-stone-400'}`}>
                                    <div className={`w-3.5 h-3.5 rounded border-2 flex-shrink-0 flex items-center justify-center ${checked ? 'border-amber-600 bg-amber-600' : 'border-stone-300'}`}>
                                      {checked && <Check size={9} className="text-white" />}
                                    </div>
                                    <span className="text-[11px] text-stone-900 truncate">{p.label}</span>
                                  </button>
                                );
                              })}
                            </div>
                          )}
                        </div>
                      );
                    });
                  })()}
                  {multipleTargets.length > 0 && (() => {
                    const generated = multipleTargets.map(t => {
                      const u = units.find(uu => uu.id === t.unitId);
                      const p = (u?.parties || []).find(pp => pp.id === t.partyId);
                      return buildTargetTitle(u?.label, p?.label);
                    });
                    const preview = generated.slice(0, 4).join(', ');
                    const more = generated.length > 4 ? `, +${generated.length - 4} more` : '';
                    return (
                      <div className="text-[10px] font-mono text-amber-700 px-1 pt-1 border-t border-stone-200">
                        <div>
                          Creating {multipleTargets.length} assignment{multipleTargets.length === 1 ? '' : 's'}:
                        </div>
                        <div className="text-amber-900 mt-0.5">{preview}{more}</div>
                        {assignmentType && (
                          <div className="text-stone-500 mt-0.5">
                            Type: <span className="text-amber-700">{assignmentTypeLabel(assignmentType)}</span>
                          </div>
                        )}
                      </div>
                    );
                  })()}
                </div>
              </div>
            )}
          </>
        )}

        {error && (
          <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
            <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
          </div>
        )}
        {busy && progress && (
          <div className="p-3 rounded-xl bg-stone-100 text-stone-700 text-sm font-mono flex items-center gap-3">
            <div className="w-4 h-4 border-2 border-stone-700 border-t-transparent rounded-full animate-spin flex-shrink-0" />
            {progress}
          </div>
        )}

        <div className="space-y-2 pt-2">
          <button onClick={() => save(true)} disabled={busy}
            className="w-full py-4 rounded-2xl bg-stone-900 text-stone-50 font-medium disabled:opacity-50">
            {busy ? 'Working…' : 'Submit for approval'}
          </button>
          <button onClick={() => save(false)} disabled={busy}
            className="w-full py-3 rounded-2xl bg-stone-100 text-stone-700 text-sm font-medium disabled:opacity-50">
            Save as draft
          </button>
        </div>
        <p className="text-xs text-stone-500 text-center">
          Drafts can be edited freely. Once you submit for approval, you can't edit until the owner reviews.
        </p>
      </div>
    </div>
  );
}

// PM-side detail/view of one of their assignments
// RecheckRequestModal — PM uses this on an APPROVED assignment to
// tell the owner "the tenant cleaned items X, Y, Z themselves on
// recheck; you don't need to clean those anymore." Lists the open
// items (status != done AND not already recheck-passed); PM ticks
// which ones now pass. Submits a recheck_request that the owner
// approves from their Inbox, which then marks those items done +
// recheck_passed so cleaners stop seeing them.
function RecheckRequestModal({ assignment, property, portalUser, onClose, onSaved }) {
  const [targets, setTargets] = useState([]);
  const [selected, setSelected] = useState(new Set());
  const [notes, setNotes] = useState('');
  const [loaded, setLoaded] = useState(false);
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    (async () => {
      // Load open targets (not done, not already recheck-passed).
      // These are the ones the PM can choose to pass on recheck.
      const { data } = await supabase.from('assignment_targets')
        .select('id, status, template_section, template_item_key, status_notes, unit:units(label), party:parties(label), recheck_passed_at')
        .eq('assignment_id', assignment.id)
        .not('status', 'in', '(done,blocked)')
        .is('recheck_passed_at', null);
      setTargets(data || []);
      setLoaded(true);
    })();
  }, [assignment.id]);

  const labelForTarget = (t) => {
    if (t.status_notes && (t.template_item_key?.startsWith?.('requested:') || t.template_item_key?.startsWith?.('custom_'))) return t.status_notes;
    const key = t.template_item_key || '';
    if (!key) return 'Item';
    return key.replace(/^[a-z]+:/, '').replace(/_/g, ' ').replace(/^./, c => c.toUpperCase());
  };

  // Group by bedroom so the PM scans by location instead of a flat list
  const grouped = (() => {
    const m = new Map();
    targets.forEach(t => {
      const k = `${t.unit?.label || ''}::${t.party?.label || ''}`;
      if (!m.has(k)) m.set(k, { unitLabel: t.unit?.label || '', partyLabel: t.party?.label || '', items: [] });
      m.get(k).items.push(t);
    });
    return Array.from(m.values());
  })();

  const toggle = (id) => {
    setSelected(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const submit = async () => {
    if (selected.size === 0) { setError('Pick at least one item the tenant passed.'); return; }
    setError(''); setBusy(true);
    try {
      // 1) Find the portal_user id from the URL/session — passed in
      //    via assignment for this build we'll read from the property
      //    metadata. Simpler: leave created_by null; the owner inbox
      //    will still show the assignment + property which is enough
      //    attribution for now.
      const { data: req, error: e1 } = await supabase.from('recheck_requests').insert({
        assignment_id: assignment.id,
        created_by: portalUser?.id || null,
        pm_status: 'pending',
        notes: notes.trim() || null,
      }).select('id').single();
      if (e1) throw e1;
      // 2) Insert the item rows
      const itemRows = Array.from(selected).map(tid => ({
        recheck_request_id: req.id,
        assignment_target_id: tid,
      }));
      const { error: e2 } = await supabase.from('recheck_request_items').insert(itemRows);
      if (e2) throw e2;
      onSaved();
    } catch (e) {
      setError(e.message || String(e));
    }
    setBusy(false);
  };

  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-lg sm:rounded-3xl rounded-t-3xl flex flex-col max-h-[90vh]">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div className="min-w-0 flex-1">
            <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">Recheck request</div>
            <div className="font-serif text-xl text-stone-900 truncate">{assignment.title}</div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100 flex-shrink-0">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-5">
          <div className="text-sm text-stone-700 mb-4">
            Tick every item the tenant passed on recheck. The owner will approve, then those items leave the cleaning team's workflow.
          </div>
          {!loaded ? (
            <div className="text-center py-12 text-stone-400 text-sm">Loading items…</div>
          ) : targets.length === 0 ? (
            <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
              No open items to pass on recheck.
            </div>
          ) : (
            <div className="space-y-4">
              {grouped.map((g, idx) => (
                <div key={idx}>
                  <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-1.5">
                    {g.unitLabel}{g.partyLabel && ` · ${g.partyLabel}`} <span className="text-stone-400">({g.items.length})</span>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-1.5">
                    {g.items.map(t => {
                      const checked = selected.has(t.id);
                      return (
                        <button key={t.id} type="button" onClick={() => toggle(t.id)}
                          className={`flex items-start gap-2 px-3 py-2.5 rounded-xl border-2 text-left ${checked ? 'border-emerald-500 bg-emerald-50' : 'border-stone-200 bg-white hover:border-stone-400'}`}>
                          <div className={`mt-0.5 w-4 h-4 rounded border-2 flex-shrink-0 flex items-center justify-center ${checked ? 'border-emerald-600 bg-emerald-600' : 'border-stone-300'}`}>
                            {checked && <Check size={11} className="text-white" />}
                          </div>
                          <span className="text-sm text-stone-900">{labelForTarget(t)}</span>
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
              <div className="mt-3">
                <label className="text-xs uppercase tracking-wider font-mono text-stone-500 block mb-1">Notes (optional)</label>
                <textarea value={notes} onChange={(e) => setNotes(e.target.value)}
                  rows={2} placeholder="Anything the owner should know about this recheck…"
                  className="w-full px-3 py-2 rounded-xl border border-stone-300 bg-white text-stone-900 text-sm focus:outline-none focus:border-stone-900" />
              </div>
            </div>
          )}
        </div>
        {targets.length > 0 && (
          <div className="p-5 border-t border-stone-200 space-y-2">
            {error && (
              <div className="p-2 rounded-lg bg-red-50 border border-red-200 text-red-700 text-xs flex items-start gap-2">
                <AlertCircle size={14} className="flex-shrink-0 mt-0.5" /> {error}
              </div>
            )}
            <div className="text-xs text-stone-600 text-center">
              {selected.size} item{selected.size === 1 ? '' : 's'} selected
            </div>
            <button onClick={submit} disabled={busy || selected.size === 0}
              className="w-full py-3 rounded-2xl bg-stone-900 text-stone-50 font-medium disabled:opacity-50">
              {busy ? 'Submitting…' : `Submit recheck request${selected.size > 0 ? ` (${selected.size})` : ''}`}
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

function PortalAssignmentDetail({ property, assignment, portalUser, onBack, onEdit }) {
  const [busy, setBusy] = useState(false);
  const canEdit = assignment.pm_status === 'draft' || assignment.pm_status === 'rejected';
  const canDelete = canEdit;
  // Recheck modal — only relevant when the assignment is APPROVED
  // (visible to cleaners) and has at least one item not yet passed.
  // PM uses this to tell us "the tenant did this part themselves, you
  // don't need to clean it anymore."
  const [recheckOpen, setRecheckOpen] = useState(false);
  const [pendingRecheck, setPendingRecheck] = useState(null); // existing pending request, if any

  // Pull existing pending recheck request for this assignment so we
  // can show "you already submitted a recheck — waiting for owner".
  useEffect(() => {
    if (assignment.pm_status !== 'approved') return;
    (async () => {
      const { data } = await supabase.from('recheck_requests')
        .select('id, created_at, pm_status, items:recheck_request_items(id)')
        .eq('assignment_id', assignment.id)
        .eq('pm_status', 'pending')
        .limit(1).maybeSingle();
      setPendingRecheck(data || null);
    })();
  }, [assignment.id, assignment.pm_status]);

  const submit = async () => {
    setBusy(true);
    const { error } = await supabase.from('assignments')
      .update({ pm_status: 'pending', pm_rejection_reason: null })
      .eq('id', assignment.id);
    setBusy(false);
    if (error) { alert('Could not submit: ' + error.message); return; }
    onBack();
  };

  const remove = async () => {
    if (!confirm('Delete this assignment? This cannot be undone.')) return;
    setBusy(true);
    if (assignment.file_path) await deletePmFile(assignment.file_path);
    await supabase.from('assignments').delete().eq('id', assignment.id);
    setBusy(false);
    onBack();
  };

  const statusLabels = {
    draft: { text: 'Draft', color: 'bg-stone-200 text-stone-700' },
    pending: { text: 'Pending approval', color: 'bg-amber-100 text-amber-800' },
    approved: { text: 'Approved — visible to team', color: 'bg-emerald-100 text-emerald-800' },
    rejected: { text: 'Needs changes', color: 'bg-red-100 text-red-700' },
  };
  const s = statusLabels[assignment.pm_status] || statusLabels.draft;

  return (
    <div className="min-h-screen bg-stone-50 pb-12">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div className="flex-1 min-w-0">
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono truncate">{property.name}</div>
          <div className="font-serif text-xl text-stone-900 truncate">{assignment.title}</div>
        </div>
      </div>
      {(assignment.assignment_type || assignment.scheduled_date) && (
        <div className="flex gap-2 flex-wrap px-5 pt-3">
          <AssignmentTypeChip type={assignment.assignment_type} />
          {assignment.scheduled_date && (
            <span className="inline-flex items-center gap-1 px-2.5 py-1 rounded-full bg-stone-200 text-stone-800 text-xs font-mono">
              <Calendar size={11} /> {fmtDateWithDay(assignment.scheduled_date)}
            </span>
          )}
        </div>
      )}
      <div className="px-5 pt-4 space-y-2">
        <SpanishTranslationPanel assignment={assignment} viewerRole="pm" />
        <TranslateButton texts={
          assignment.extracted_text && assignment.extracted_text.trim()
            ? [assignment.title, assignment.notes, assignment.extracted_text].filter(Boolean)
            : [assignment.title, assignment.notes].filter(Boolean)
        } />
      </div>
      <div className="px-5 pt-4 space-y-5">
        <div className={`p-3 rounded-xl text-sm flex items-center gap-2 ${s.color}`}>
          <Check size={14} /> {s.text}
        </div>

        {assignment.pm_rejection_reason && (
          <div className="p-4 rounded-2xl bg-red-50 border border-red-200">
            <div className="text-xs uppercase tracking-wider font-mono text-red-700 mb-1">Owner's note</div>
            <div className="text-sm text-red-900 whitespace-pre-wrap">{assignment.pm_rejection_reason}</div>
          </div>
        )}

        {assignment.file_url && (
          <div className="p-4 rounded-2xl bg-white border border-stone-200">
            <div className="flex items-center gap-3 mb-3">
              {assignment.file_kind === 'pdf'
                ? <FileText size={20} className="text-stone-600" />
                : <ImageIcon size={20} className="text-stone-600" />}
              <div className="flex-1">
                <div className="font-serif text-base text-stone-900">Attached file</div>
                <div className="text-xs text-stone-500 font-mono">{assignment.file_kind?.toUpperCase()}</div>
              </div>
            </div>
            {assignment.file_kind === 'image' && (
              <img loading="lazy" src={assignment.file_url} alt="" className="w-full max-h-[60vh] object-contain rounded-xl mb-3 bg-stone-100" />
            )}
            <a href={assignment.file_url} target="_blank" rel="noreferrer"
              className="w-full inline-flex items-center justify-center gap-2 py-2.5 rounded-xl bg-stone-900 text-stone-50 text-sm font-medium">
              <Eye size={14} /> Open
            </a>
          </div>
        )}

        {assignment.notes && (
          <div className="p-4 rounded-2xl bg-amber-50 border border-amber-200">
            <div className="text-xs uppercase tracking-wider font-mono text-amber-700 mb-1">Notes</div>
            <div className="text-sm text-stone-800 whitespace-pre-wrap">{assignment.notes}</div>
          </div>
        )}

        {canEdit ? (
          <div className="space-y-2 pt-2">
            <button onClick={submit} disabled={busy}
              className="w-full py-4 rounded-2xl bg-stone-900 text-stone-50 font-medium disabled:opacity-50">
              {busy ? 'Working…' : 'Submit for approval'}
            </button>
            <button onClick={onEdit} disabled={busy}
              className="w-full py-3 rounded-2xl bg-stone-100 text-stone-700 text-sm font-medium flex items-center justify-center gap-2">
              <Edit2 size={14} /> Edit
            </button>
            {canDelete && (
              <button onClick={remove} disabled={busy}
                className="w-full py-3 rounded-2xl border-2 border-red-200 text-red-700 text-sm font-medium flex items-center justify-center gap-2">
                <Trash2 size={14} /> Delete
              </button>
            )}
          </div>
        ) : assignment.pm_status === 'pending' ? (
          <div className="p-4 rounded-2xl bg-amber-50 border border-amber-200 text-sm text-stone-700">
            This assignment is locked while waiting for the owner to review. You'll be able to edit again if changes are requested.
          </div>
        ) : (
          // Approved (active) — PM can now submit a recheck if the
          // tenant fixed some items themselves between the original
          // submission and the cleaner arriving.
          <div className="space-y-3">
            <div className="p-4 rounded-2xl bg-emerald-50 border border-emerald-200 text-sm text-stone-700">
              This assignment is active and visible to the cleaning team. It can't be edited from here.
            </div>
            {pendingRecheck ? (
              <div className="p-4 rounded-2xl bg-amber-50 border border-amber-200">
                <div className="text-xs uppercase tracking-wider font-mono text-amber-800 mb-1">Recheck pending review</div>
                <div className="text-sm text-stone-700">
                  You submitted a recheck request with {pendingRecheck.items?.length || 0} item{(pendingRecheck.items?.length || 0) === 1 ? '' : 's'}. The owner will approve or reject it.
                </div>
              </div>
            ) : (
              <button onClick={() => setRecheckOpen(true)} disabled={busy}
                className="w-full py-3 rounded-2xl bg-stone-100 border border-stone-300 text-stone-800 text-sm font-medium flex items-center justify-center gap-2 disabled:opacity-50 hover:bg-stone-200">
                <Check size={14} /> Request recheck — tenant passed some items
              </button>
            )}
          </div>
        )}
      </div>

      {recheckOpen && (
        <RecheckRequestModal
          assignment={assignment}
          property={property}
          portalUser={portalUser}
          onClose={() => setRecheckOpen(false)}
          onSaved={() => {
            setRecheckOpen(false);
            // Reload the pending banner state
            (async () => {
              const { data } = await supabase.from('recheck_requests')
                .select('id, created_at, pm_status, items:recheck_request_items(id)')
                .eq('assignment_id', assignment.id)
                .eq('pm_status', 'pending')
                .limit(1).maybeSingle();
              setPendingRecheck(data || null);
            })();
          }} />
      )}
    </div>
  );
}

// ReviewRecheckModal — owner approves or rejects a PM recheck
// request. Approving marks every listed item done + recheck_passed,
// which removes them from the cleaning team's workflow. Rejecting
// leaves the items where they are (still pending for cleaners).
function ReviewRecheckModal({ recheck, employee, onDone, onClose }) {
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');
  const [rejecting, setRejecting] = useState(false);
  const [rejectionReason, setRejectionReason] = useState('');

  const items = recheck.items || [];

  const approve = async () => {
    setBusy(true); setError('');
    try {
      const nowISO = new Date().toISOString();
      const targetIds = items.map(i => i.target?.id).filter(Boolean);
      // 1) Mark every listed target as done + recheck_passed.
      //    completed_by stays null (no cleaner did this work) — the
      //    recheck_passed_at column distinguishes from a normal close.
      if (targetIds.length > 0) {
        const { error: e1 } = await supabase.from('assignment_targets')
          .update({
            status: 'done',
            completed_at: nowISO,
            recheck_passed_at: nowISO,
            recheck_passed_by: recheck.created_by || null,
          })
          .in('id', targetIds);
        if (e1) throw e1;
      }
      // 2) Stamp the recheck request as approved
      const { error: e2 } = await supabase.from('recheck_requests')
        .update({
          pm_status: 'approved',
          approved_by: employee.id,
          approved_at: nowISO,
        }).eq('id', recheck.id);
      if (e2) throw e2;
      onDone();
    } catch (e) {
      setError(e.message || String(e));
    }
    setBusy(false);
  };

  const reject = async () => {
    if (!rejectionReason.trim()) {
      setError('Please give a reason so the PM knows what to change.');
      return;
    }
    setBusy(true); setError('');
    try {
      const nowISO = new Date().toISOString();
      const { error: e1 } = await supabase.from('recheck_requests')
        .update({
          pm_status: 'rejected',
          rejected_by: employee.id,
          rejected_at: nowISO,
          rejection_reason: rejectionReason.trim(),
        }).eq('id', recheck.id);
      if (e1) throw e1;
      onDone();
    } catch (e) {
      setError(e.message || String(e));
    }
    setBusy(false);
  };

  // Group items by bedroom for display
  const grouped = (() => {
    const m = new Map();
    items.forEach(i => {
      const t = i.target;
      if (!t) return;
      const k = `${t.unit?.label || ''}::${t.party?.label || ''}`;
      if (!m.has(k)) m.set(k, { unitLabel: t.unit?.label || '', partyLabel: t.party?.label || '', list: [] });
      m.get(k).list.push(t);
    });
    return Array.from(m.values());
  })();

  const labelForTarget = (t) => {
    if (t.status_notes && (t.template_item_key?.startsWith?.('requested:') || t.template_item_key?.startsWith?.('custom_'))) return t.status_notes;
    const key = t.template_item_key || '';
    if (!key) return 'Item';
    return key.replace(/^[a-z]+:/, '').replace(/_/g, ' ').replace(/^./, c => c.toUpperCase());
  };

  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-lg sm:rounded-3xl rounded-t-3xl flex flex-col max-h-[90vh]">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 mb-0.5">
              <span className="text-[9px] uppercase tracking-wider px-1.5 py-0.5 rounded-full bg-purple-100 text-purple-700 font-mono">RECHECK</span>
              <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">Review request</div>
            </div>
            <div className="font-serif text-xl text-stone-900 truncate">{recheck.assignment?.title}</div>
            <div className="text-xs text-stone-500 font-mono mt-0.5">{recheck.assignment?.property?.name}</div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100 flex-shrink-0">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-5">
          <div className="text-sm text-stone-700 mb-4">
            The PM is asking you to confirm the tenant passed the following items on recheck. Approving removes them from the cleaning team's workflow.
          </div>
          {recheck.notes && (
            <div className="p-3 rounded-xl bg-stone-100 text-sm text-stone-700 mb-4 whitespace-pre-wrap">
              <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-1">PM notes</div>
              {recheck.notes}
            </div>
          )}
          {grouped.length === 0 ? (
            <div className="text-center py-8 text-stone-400 text-sm">No items in this request.</div>
          ) : (
            <div className="space-y-3">
              {grouped.map((g, idx) => (
                <div key={idx} className="rounded-2xl bg-white border-2 border-emerald-200 p-3">
                  <div className="text-xs uppercase tracking-wider font-mono text-emerald-700 mb-2">
                    {g.unitLabel}{g.partyLabel && ` · ${g.partyLabel}`} <span className="text-stone-400">({g.list.length})</span>
                  </div>
                  <ul className="space-y-1">
                    {g.list.map(t => (
                      <li key={t.id} className="flex items-start gap-2 text-sm">
                        <Check size={14} className="text-emerald-600 flex-shrink-0 mt-0.5" />
                        <span>{labelForTarget(t)}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          )}
        </div>
        <div className="p-5 border-t border-stone-200 space-y-2">
          {error && (
            <div className="p-2 rounded-lg bg-red-50 border border-red-200 text-red-700 text-xs flex items-start gap-2">
              <AlertCircle size={14} className="flex-shrink-0 mt-0.5" /> {error}
            </div>
          )}
          {rejecting ? (
            <>
              <textarea value={rejectionReason} onChange={(e) => setRejectionReason(e.target.value)}
                rows={2} placeholder="Reason — e.g. 'tenant didn't actually clean, the photo shows dust'"
                className="w-full px-3 py-2 rounded-xl border border-stone-300 bg-white text-stone-900 text-sm focus:outline-none focus:border-stone-900" />
              <div className="flex gap-2">
                <button onClick={() => setRejecting(false)} disabled={busy}
                  className="flex-1 py-3 rounded-2xl bg-stone-100 text-stone-700 font-medium text-sm">
                  Back
                </button>
                <button onClick={reject} disabled={busy}
                  className="flex-1 py-3 rounded-2xl bg-red-600 text-white font-medium text-sm disabled:opacity-50">
                  {busy ? 'Sending…' : 'Send back to PM'}
                </button>
              </div>
            </>
          ) : (
            <div className="flex gap-2">
              <button onClick={() => setRejecting(true)} disabled={busy}
                className="flex-1 py-3 rounded-2xl border-2 border-red-200 text-red-700 font-medium text-sm flex items-center justify-center gap-1.5">
                <X size={14} /> Send back
              </button>
              <button onClick={approve} disabled={busy}
                className="flex-1 py-3 rounded-2xl bg-emerald-600 text-white font-medium text-sm disabled:opacity-50 flex items-center justify-center gap-1.5">
                <Check size={14} /> {busy ? 'Approving…' : `Approve (${items.length})`}
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// =================================================================
// INBOX VIEW — owner/manager review of PM uploads
// Two tabs: Pending assignments + New photos
// =================================================================
function InboxView({ employee, onBack }) {
  const [tab, setTab] = useState('assignments');
  const [pendingAssignments, setPendingAssignments] = useState([]);
  const [reviewedAssignments, setReviewedAssignments] = useState([]);
  const [pendingRechecks, setPendingRechecks] = useState([]); // PM recheck requests waiting for owner
  const [reviewRecheck, setReviewRecheck] = useState(null);   // currently-open recheck in review modal
  const [newPhotos, setNewPhotos] = useState([]);
  const [reviewedPhotos, setReviewedPhotos] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [reviewAssignment, setReviewAssignment] = useState(null);
  const [reviewPhoto, setReviewPhoto] = useState(null);
  const [togglingAssignmentId, setTogglingAssignmentId] = useState(null);
  // Queue review mode — when on, the inbox auto-opens the first pending
  // assignment as a review modal. After approve / send-back, we
  // immediately advance to the next pending one. When the queue empties
  // we show an "all caught up" prompt + the owner confirms to leave.
  const [queueMode, setQueueMode] = useState(false);
  const [queueDone, setQueueDone] = useState(false);

  // Flip priority on every target of an assignment from the inbox row.
  // Sweep mode: if ANY target is priority, turn all off; otherwise turn
  // all on. Lets owners flag urgent PM submissions without opening the
  // review modal.
  const togglePmAssignmentPriority = async (assignment) => {
    if (togglingAssignmentId) return;
    const targetIds = (assignment.targets || []).map(t => t.id);
    if (targetIds.length === 0) return;
    const anyPriority = (assignment.targets || []).some(t => t.priority);
    const newPriority = !anyPriority;
    setTogglingAssignmentId(assignment.id);
    // Optimistic update across both lists (might appear in either)
    const flip = list => list.map(a => a.id === assignment.id ? {
      ...a,
      targets: (a.targets || []).map(t => ({ ...t, priority: newPriority }))
    } : a);
    setPendingAssignments(prev => flip(prev));
    setReviewedAssignments(prev => flip(prev));
    const { error } = await supabase.from('assignment_targets')
      .update({ priority: newPriority }).in('id', targetIds);
    setTogglingAssignmentId(null);
    if (error) {
      alert('Could not update priority: ' + error.message);
      load();
    }
  };

  const load = async () => {
    setLoaded(false);
    // Pending assignments
    const { data: aData } = await supabase.from('assignments')
      .select('*, property:customers(id, name, property_type), targets:assignment_targets(id, priority, unit:units(label), party:parties(label))')
      .eq('source', 'pm').eq('pm_status', 'pending')
      .order('created_at', { ascending: false });
    setPendingAssignments(aData || []);

    // Pending recheck requests — PM submissions saying "tenant passed
    // these items on recheck, don't need cleaning anymore". Pull the
    // item rows + assignment context for the review modal.
    const { data: rcData } = await supabase.from('recheck_requests')
      .select(`
        id, assignment_id, created_at, pm_status, notes,
        assignment:assignments(id, title, customer_id, property:customers(id, name, property_type)),
        items:recheck_request_items(
          id,
          target:assignment_targets(id, status, template_section, template_item_key, status_notes, unit:units(label), party:parties(label))
        )
      `)
      .eq('pm_status', 'pending')
      .order('created_at', { ascending: false });
    setPendingRechecks(rcData || []);

    // Already-reviewed PM assignments (approved or rejected) — for the "Reviewed" tab
    const { data: rData } = await supabase.from('assignments')
      .select('*, property:customers(id, name, property_type), targets:assignment_targets(id, priority, unit:units(label), party:parties(label))')
      .eq('source', 'pm').in('pm_status', ['approved', 'rejected'])
      .order('approved_at', { ascending: false, nullsFirst: false })
      .limit(50);
    setReviewedAssignments(rData || []);

    // New photos
    const { data: pData } = await supabase.from('pm_photos')
      .select('*, property:customers(id, name), unit:units(label), party:parties(label)')
      .eq('status', 'new')
      .order('created_at', { ascending: false });
    setNewPhotos(pData || []);

    // Reviewed photos (seen or archived)
    const { data: rpData } = await supabase.from('pm_photos')
      .select('*, property:customers(id, name), unit:units(label), party:parties(label)')
      .in('status', ['seen', 'archived'])
      .order('reviewed_at', { ascending: false, nullsFirst: false })
      .limit(50);
    setReviewedPhotos(rpData || []);

    setLoaded(true);
  };
  useEffect(() => { load(); }, []);
  useAssignmentSync(load, 'inbox-sync');

  // When in queue mode and no modal open, pick the next pending
  // assignment to review. When the list drains, flip to "done" so the
  // owner sees the all-caught-up screen instead of looping.
  useEffect(() => {
    if (!queueMode || reviewAssignment) return;
    if (!loaded) return;
    if (pendingAssignments.length > 0) {
      setReviewAssignment(pendingAssignments[0]);
    } else {
      setQueueDone(true);
    }
  }, [queueMode, reviewAssignment, pendingAssignments, loaded]);

  const markPhotoSeen = async (photo) => {
    await supabase.from('pm_photos').update({
      status: 'seen',
      reviewed_by: employee.id,
      reviewed_at: new Date().toISOString()
    }).eq('id', photo.id);
    load();
  };
  const archivePhoto = async (photo) => {
    if (!confirm('Archive this photo? It will no longer appear in your inbox.')) return;
    await supabase.from('pm_photos').update({
      status: 'archived',
      reviewed_by: employee.id,
      reviewed_at: new Date().toISOString()
    }).eq('id', photo.id);
    load();
  };
  const restorePhoto = async (photo) => {
    await supabase.from('pm_photos').update({
      status: 'new',
      reviewed_by: null,
      reviewed_at: null
    }).eq('id', photo.id);
    load();
  };
  const deletePhoto = async (photo) => {
    if (!confirm('Permanently delete this photo? This cannot be undone.')) return;
    if (photo.photo_path) await supabase.storage.from(PM_UPLOAD_BUCKET).remove([photo.photo_path]);
    await supabase.from('pm_photos').delete().eq('id', photo.id);
    load();
  };

  return (
    <div className="pb-24">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div>
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">From property managers</div>
          <div className="font-serif text-xl text-stone-900">Inbox</div>
        </div>
      </div>

      <div className="px-5 pt-4">
        <div className="flex gap-1 bg-stone-100 p-1 rounded-xl mb-5 overflow-x-auto">
          <button onClick={() => setTab('assignments')}
            className={`flex-1 py-2 px-2 rounded-lg text-xs font-medium whitespace-nowrap ${tab === 'assignments' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
            Assignments ({pendingAssignments.length})
          </button>
          <button onClick={() => setTab('photos')}
            className={`flex-1 py-2 px-2 rounded-lg text-xs font-medium whitespace-nowrap ${tab === 'photos' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
            Photos ({newPhotos.length})
          </button>
          <button onClick={() => setTab('reviewed')}
            className={`flex-1 py-2 px-2 rounded-lg text-xs font-medium whitespace-nowrap ${tab === 'reviewed' ? 'bg-white shadow-sm text-stone-900' : 'text-stone-500'}`}>
            Reviewed
          </button>
        </div>

        {!loaded ? <Splash text="Loading…" /> : tab === 'assignments' ? (
          (pendingAssignments.length === 0 && pendingRechecks.length === 0) ? (
            <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
              No assignments waiting for review.
            </div>
          ) : (
            <>
              {/* Pending recheck requests from PMs — these are
                 "tenant passed items X, Y, Z" submissions. Approve
                 marks those items done + recheck_passed_at so the
                 cleaning team stops seeing them. Shown above new
                 assignment submissions so they're easy to spot. */}
              {pendingRechecks.length > 0 && (
                <div className="mb-4">
                  <div className="text-[10px] uppercase tracking-wider font-mono text-stone-500 mb-2">
                    Recheck requests ({pendingRechecks.length})
                  </div>
                  <div className="space-y-2">
                    {pendingRechecks.map(rc => (
                      <div key={rc.id} onClick={() => setReviewRecheck(rc)}
                        tabIndex={0}
                        role="button"
                        onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setReviewRecheck(rc); } }}
                        className="w-full text-left p-4 rounded-2xl bg-white border-2 border-purple-200 hover:border-purple-500 transition-colors cursor-pointer">
                        <div className="flex items-start justify-between gap-2">
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-1 flex-wrap">
                              <span className="text-[9px] uppercase tracking-wider px-1.5 py-0.5 rounded-full bg-purple-100 text-purple-700 font-mono">RECHECK</span>
                              <span className="font-serif text-base text-stone-900 truncate">{rc.assignment?.title || 'Recheck request'}</span>
                            </div>
                            <div className="text-xs text-stone-600 font-mono mt-0.5">
                              {rc.assignment?.property?.name}
                              {' · '}{rc.items?.length || 0} {(rc.items?.length || 0) === 1 ? 'item' : 'items'} the PM says passed
                            </div>
                            <div className="text-xs text-stone-400 font-mono mt-1">
                              Submitted {fmtDate(rc.created_at)}
                            </div>
                          </div>
                          <ChevronRight size={16} className="text-stone-400 flex-shrink-0" />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Queue mode CTA — owner taps once, then walks through
                 every pending review one at a time. Approve / send back
                 → auto-advances. When the queue empties we show a
                 confirmation before leaving the queue screen. */}
              {pendingAssignments.length > 0 && (
              <button onClick={() => { setQueueDone(false); setQueueMode(true); }}
                className="w-full mb-3 py-3.5 rounded-2xl bg-stone-900 hover:bg-stone-800 text-stone-50 font-medium text-sm flex items-center justify-center gap-2 active:scale-98">
                <Play size={14} /> Review all {pendingAssignments.length} in queue
              </button>
              )}
              <div className="space-y-2">
              {pendingAssignments.map(a => {
                const anyPriority = (a.targets || []).some(t => t.priority);
                const isToggling = togglingAssignmentId === a.id;
                return (
                  <div key={a.id} onClick={() => setReviewAssignment(a)}
                    tabIndex={0}
                    role="button"
                    onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setReviewAssignment(a); } }}
                    className="w-full text-left p-4 rounded-2xl bg-white border-2 border-amber-200 hover:border-amber-500 transition-colors cursor-pointer">
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1 flex-wrap">
                          {a.file_kind === 'pdf'
                            ? <FileText size={14} className="text-stone-500 flex-shrink-0" />
                            : <ImageIcon size={14} className="text-stone-500 flex-shrink-0" />}
                          <span className="font-serif text-base text-stone-900 truncate">{a.title}</span>
                        </div>
                        {/* Priority + cleaning-type chips. Priority is a
                           click-to-toggle button right on the capsule —
                           owners can flag urgent PM submissions without
                           opening the review modal. */}
                        <div className="flex items-center gap-1.5 flex-wrap mb-1">
                          <button
                            onClick={(e) => { e.stopPropagation(); togglePmAssignmentPriority(a); }}
                            disabled={isToggling}
                            className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full border inline-flex items-center gap-1 transition-colors disabled:opacity-50 ${anyPriority
                                ? 'bg-red-100 text-red-800 border-red-300 font-bold hover:bg-red-200'
                                : 'bg-stone-100 text-stone-500 border-stone-200 hover:bg-stone-200'}`}>
                            <AlertCircle size={10} /> {anyPriority ? 'Priority' : 'Mark priority'}
                          </button>
                          <AssignmentTypeChip type={a.assignment_type} />
                        </div>
                        <div className="text-xs text-stone-600 font-mono mb-1 flex items-center gap-1.5">
                          <Building2 size={11} /> {a.property?.name}
                        </div>
                        {a.targets?.[0] && (a.targets[0].unit?.label || a.targets[0].party?.label) && (
                          <div className="text-xs text-stone-500 font-mono">
                            {a.targets[0].unit?.label}{a.targets[0].party?.label && ` · ${a.targets[0].party.label}`}
                          </div>
                        )}
                        <div className="text-xs text-stone-400 font-mono mt-1 flex items-center gap-2">
                          Submitted {fmtDate(a.created_at)}
                          {a.actor_kind === 'pm_staff' && (
                            <span className="text-[9px] uppercase tracking-wider px-1.5 py-0.5 rounded-full bg-stone-100 text-stone-600">PM staff</span>
                          )}
                        </div>
                      </div>
                      <ChevronRight size={16} className="text-stone-400 flex-shrink-0" />
                    </div>
                  </div>
                );
              })}
            </div>
            </>
          )
        ) : tab === 'photos' ? (
          newPhotos.length === 0 ? (
            <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
              No new photos.
            </div>
          ) : (
            <div className="space-y-3">
              {newPhotos.map(p => (
                <div key={p.id} className="p-4 rounded-2xl bg-white border-2 border-amber-200">
                  <div className="text-xs text-stone-600 font-mono mb-2 flex items-center gap-1.5">
                    <Building2 size={11} /> {p.property?.name}
                    {p.unit?.label && <span>· {p.unit.label}</span>}
                    {p.party?.label && <span>· {p.party.label}</span>}
                  </div>
                  {p.title && <div className="font-serif text-base text-stone-900 mb-1">{p.title}</div>}
                  {p.notes && <div className="text-sm text-stone-700 mb-2 whitespace-pre-wrap">{p.notes}</div>}
                  <button onClick={() => setReviewPhoto(p)} className="block w-full rounded-xl overflow-hidden bg-stone-100 mb-3">
                    <img loading="lazy" src={p.photo_url} alt={p.title || ''} className="w-full max-h-96 object-contain" />
                  </button>
                  <div className="text-[10px] text-stone-400 font-mono mb-3 flex items-center gap-2">
                    Sent {fmtDate(p.created_at)}
                    {p.actor_kind === 'pm_staff' && (
                      <span className="text-[9px] uppercase tracking-wider px-1.5 py-0.5 rounded-full bg-stone-100 text-stone-600">PM staff</span>
                    )}
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => markPhotoSeen(p)}
                      className="flex-1 py-2 rounded-xl bg-stone-900 text-stone-50 text-sm font-medium flex items-center justify-center gap-2">
                      <Check size={14} /> Mark seen
                    </button>
                    <button onClick={() => archivePhoto(p)}
                      className="py-2 px-3 rounded-xl border border-stone-300 text-stone-600 text-sm font-medium flex items-center justify-center gap-1">
                      <X size={14} /> Archive
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )
        ) : (
          /* Reviewed tab — combines reviewed photos and reviewed assignments */
          <div className="space-y-6">
            {reviewedPhotos.length === 0 && reviewedAssignments.length === 0 ? (
              <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
                Nothing reviewed yet. Once you review photos or approve/reject assignments they show up here.
              </div>
            ) : (
              <>
                {reviewedAssignments.length > 0 && (
                  <div>
                    <div className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-3">
                      Reviewed assignments ({reviewedAssignments.length})
                    </div>
                    <div className="space-y-2">
                      {reviewedAssignments.map(a => {
                        const isApproved = a.pm_status === 'approved';
                        return (
                          <div key={a.id} className={`p-4 rounded-2xl border ${isApproved ? 'bg-emerald-50 border-emerald-200' : 'bg-red-50 border-red-200'}`}>
                            <div className="flex items-center gap-2 mb-1 flex-wrap">
                              {a.file_kind === 'pdf'
                                ? <FileText size={14} className="text-stone-600 flex-shrink-0" />
                                : <ImageIcon size={14} className="text-stone-600 flex-shrink-0" />}
                              <span className="font-serif text-base text-stone-900 truncate flex-1">{a.title}</span>
                              <span className={`text-[10px] uppercase tracking-wider font-mono px-2 py-0.5 rounded-full ${isApproved ? 'bg-emerald-100 text-emerald-800' : 'bg-red-100 text-red-700'}`}>
                                {isApproved ? 'Approved' : 'Rejected'}
                              </span>
                            </div>
                            <div className="text-xs text-stone-600 font-mono mb-1 flex items-center gap-1.5">
                              <Building2 size={11} /> {a.property?.name}
                            </div>
                            {a.pm_rejection_reason && (
                              <div className="text-xs text-red-700 italic mt-1">"{a.pm_rejection_reason}"</div>
                            )}
                            <div className="flex gap-2 mt-2">
                              {a.file_url && (
                                <a href={a.file_url} target="_blank" rel="noreferrer"
                                  className="px-3 py-1.5 rounded-lg bg-stone-100 hover:bg-stone-200 text-stone-700 text-xs font-medium flex items-center gap-1">
                                  <Eye size={12} /> Open file
                                </a>
                              )}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}

                {reviewedPhotos.length > 0 && (
                  <div>
                    <div className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-3">
                      Reviewed photos ({reviewedPhotos.length})
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                      {reviewedPhotos.map(p => (
                        <div key={p.id} className="relative">
                          <button onClick={() => setReviewPhoto(p)}
                            className="block w-full aspect-square rounded-xl overflow-hidden bg-stone-100">
                            <img loading="lazy" src={p.photo_url} alt={p.title || ''} className="w-full h-full object-cover" />
                          </button>
                          <div className="absolute bottom-1 left-1 right-1 flex items-center justify-between">
                            <span className={`text-[9px] uppercase tracking-wider font-mono px-1.5 py-0.5 rounded-full ${p.status === 'seen' ? 'bg-emerald-600 text-white' : 'bg-stone-700 text-white'}`}>
                              {p.status}
                            </span>
                          </div>
                          <div className="mt-1 px-1 text-[10px] font-mono text-stone-500 truncate">
                            {p.property?.name}{p.unit?.label && ` · ${p.unit.label}`}
                          </div>
                          <div className="px-1 flex gap-2 mt-1">
                            <button onClick={() => restorePhoto(p)}
                              className="text-[10px] font-mono text-stone-600 hover:text-stone-900">
                              Restore
                            </button>
                            <button onClick={() => deletePhoto(p)}
                              className="text-[10px] font-mono text-red-600 hover:text-red-800">
                              Delete
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </>
            )}
          </div>
        )}
      </div>

      {reviewAssignment && (
        <ReviewAssignmentModal assignment={reviewAssignment} employee={employee}
          onDone={() => {
            // CRITICAL — optimistically drop the just-handled assignment
            // from local state BEFORE clearing reviewAssignment. The
            // queue-advance useEffect runs the moment reviewAssignment
            // flips to null, and at that instant pendingAssignments is
            // still the stale list including the one we just approved
            // (load() is in flight, hasn't returned yet). Without this
            // optimistic prune, the useEffect picks the same row at
            // index 0 and re-opens the modal with the assignment the
            // user thought they just finished — every other "approve"
            // click ends up being a no-op database update on an
            // already-approved row. End result: 48 clicks → maybe 20
            // real approvals, the rest invisible to cleaners because
            // they were never actually advanced through the queue.
            const id = reviewAssignment.id;
            setPendingAssignments(prev => prev.filter(a => a.id !== id));
            setReviewAssignment(null);
            load();
          }}
          onClose={() => {
            // Closing the modal mid-queue also exits queue mode (the
            // owner chose to stop). They can re-enter from the button.
            if (queueMode) setQueueMode(false);
            setReviewAssignment(null);
          }} />
      )}
      {reviewRecheck && (
        <ReviewRecheckModal recheck={reviewRecheck} employee={employee}
          onDone={() => { setReviewRecheck(null); load(); }}
          onClose={() => setReviewRecheck(null)} />
      )}
      {/* "All caught up" overlay — shown when the queue empties.
         Owner taps to confirm and exits queue mode. */}
      {queueDone && (
        <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-stone-50 w-full sm:max-w-md sm:rounded-3xl rounded-t-3xl p-6 text-center">
            <div className="w-16 h-16 rounded-full bg-emerald-100 text-emerald-700 flex items-center justify-center mx-auto mb-3">
              <Check size={32} />
            </div>
            <div className="font-serif text-2xl text-stone-900 mb-1">All caught up</div>
            <div className="text-sm text-stone-600 mb-5">
              No more PM submissions waiting for your review.
            </div>
            <button onClick={() => { setQueueDone(false); setQueueMode(false); }}
              className="w-full py-3 rounded-2xl bg-stone-900 text-stone-50 font-medium">
              Got it
            </button>
          </div>
        </div>
      )}
      {reviewPhoto && (
        <div className="fixed inset-0 bg-stone-900/95 z-50 flex flex-col">
          <div className="flex items-center justify-between p-4 text-stone-50 bg-stone-900 flex-shrink-0">
            <div className="text-sm font-mono truncate flex-1">{reviewPhoto.title || 'Photo from PM'}</div>
            <button onClick={() => setReviewPhoto(null)} className="p-2 rounded-full bg-stone-800 ml-2 flex-shrink-0">
              <X size={20} />
            </button>
          </div>
          <div className="flex-1 overflow-auto p-4">
            <img loading="lazy" src={reviewPhoto.photo_url} alt="" className="w-full h-auto rounded-xl" />
            {reviewPhoto.notes && (
              <div className="mt-3 p-3 rounded-xl bg-stone-800 text-stone-200 text-sm whitespace-pre-wrap">
                {reviewPhoto.notes}
              </div>
            )}
          </div>
          <div className="p-3 bg-stone-900 flex-shrink-0">
            <a href={reviewPhoto.photo_url} target="_blank" rel="noreferrer"
              className="block w-full text-center py-3 rounded-xl bg-stone-50 text-stone-900 text-sm font-medium">
              Open full-size in new tab
            </a>
          </div>
        </div>
      )}
    </div>
  );
}

// Modal for owner/manager to approve or reject a PM assignment
function ReviewAssignmentModal({ assignment, employee, onDone, onClose }) {
  const [rejectMode, setRejectMode] = useState(false);
  const [rejectReason, setRejectReason] = useState('');
  const [editedType, setEditedType] = useState(assignment.assignment_type || 'standard');
  const [editedDate, setEditedDate] = useState(assignment.scheduled_date || '');
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  const approve = async () => {
    setBusy(true); setError('');
    const { error: e } = await supabase.from('assignments').update({
      pm_status: 'approved',
      approved_by: employee.id,
      approved_at: new Date().toISOString(),
      pm_rejection_reason: null,
      // Apply any edits owner/manager made during review
      assignment_type: editedType,
      scheduled_date: editedDate || null,
    }).eq('id', assignment.id);
    setBusy(false);
    if (e) { setError(e.message); return; }
    onDone();
  };

  const reject = async () => {
    if (!rejectReason.trim()) { setError('Please tell the PM what to change.'); return; }
    setBusy(true); setError('');
    const { error: e } = await supabase.from('assignments').update({
      pm_status: 'rejected',
      pm_rejection_reason: rejectReason.trim()
    }).eq('id', assignment.id);
    setBusy(false);
    if (e) { setError(e.message); return; }
    onDone();
  };

  return (
    <div className="fixed inset-0 bg-stone-900/80 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-stone-50 w-full sm:max-w-lg sm:rounded-3xl rounded-t-3xl max-h-[90vh] flex flex-col">
        <div className="flex items-center justify-between p-5 border-b border-stone-200">
          <div className="flex-1 min-w-0">
            <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">Review submission</div>
            <div className="font-serif text-xl text-stone-900 truncate">{assignment.title}</div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-stone-100">
            <X size={20} className="text-stone-600" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {!rejectMode && (
            <div className="p-3 rounded-xl bg-amber-50 border border-amber-200 space-y-3">
              <div className="text-[10px] uppercase tracking-wider font-mono text-amber-700">
                Adjust before approving
              </div>
              <div>
                <label className="text-xs text-stone-700 font-mono mb-1 block">Type</label>
                <select value={editedType} onChange={(e) => setEditedType(e.target.value)}
                  className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm">
                  {ASSIGNMENT_TYPES.map(t => (
                    <option key={t.value} value={t.value}>{t.label}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="text-xs text-stone-700 font-mono mb-1 block">Scheduled for</label>
                <input type="date" value={editedDate} onChange={(e) => setEditedDate(e.target.value)}
                  className="w-full px-3 py-2 rounded-lg border border-stone-300 bg-white text-sm" />
                {editedDate !== (assignment.scheduled_date || '') && (
                  <div className="text-[11px] text-amber-700 mt-1">
                    PM requested: {assignment.scheduled_date ? fmtDateWithDay(assignment.scheduled_date) : 'no date'}
                  </div>
                )}
              </div>
            </div>
          )}
          {assignment.notes && (
            <div className="p-3 rounded-xl bg-stone-100 text-sm text-stone-800 whitespace-pre-wrap">
              {assignment.notes}
            </div>
          )}
          {assignment.file_url && (
            <div>
              {assignment.file_kind === 'image' ? (
                <img loading="lazy" src={assignment.file_url} alt="" className="w-full max-h-[60vh] object-contain rounded-xl bg-stone-100" />
              ) : (
                <a href={assignment.file_url} target="_blank" rel="noreferrer"
                  className="block p-4 rounded-xl bg-white border border-stone-200 hover:border-stone-400">
                  <div className="flex items-center gap-2">
                    <FileText size={18} className="text-stone-600" />
                    <span className="text-sm text-stone-800 flex-1">Open PDF</span>
                    <Eye size={14} className="text-stone-500" />
                  </div>
                </a>
              )}
            </div>
          )}

          {rejectMode && (
            <div>
              <label className="text-xs uppercase tracking-wider text-stone-500 font-mono mb-2 block">
                Tell the PM what needs to change
              </label>
              <textarea value={rejectReason} onChange={(e) => setRejectReason(e.target.value)} rows={4}
                placeholder="e.g. Wrong apartment — should be B3-205 instead of B3-105"
                className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white resize-none" />
            </div>
          )}

          {error && (
            <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-start gap-2">
              <AlertCircle size={16} className="flex-shrink-0 mt-0.5" /><span>{error}</span>
            </div>
          )}
        </div>
        <div className="p-5 border-t border-stone-200 space-y-2">
          {rejectMode ? (
            <>
              <button onClick={reject} disabled={busy}
                className="w-full py-3 rounded-2xl bg-red-600 text-white font-medium disabled:opacity-50">
                {busy ? 'Sending…' : 'Send back to PM with note'}
              </button>
              <button onClick={() => { setRejectMode(false); setError(''); }} disabled={busy}
                className="w-full py-2 rounded-2xl text-stone-600 text-sm font-medium">
                Cancel
              </button>
            </>
          ) : (
            <>
              <button onClick={approve} disabled={busy}
                className="w-full py-4 rounded-2xl bg-emerald-600 text-white font-medium flex items-center justify-center gap-2 disabled:opacity-50">
                <Check size={16} /> {busy ? 'Approving…' : 'Approve & make visible to cleaners'}
              </button>
              <button onClick={() => setRejectMode(true)} disabled={busy}
                className="w-full py-3 rounded-2xl border-2 border-red-200 text-red-700 text-sm font-medium">
                Send back for changes
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

// =================================================================
// MESSAGING — Deploy 1
//
// - Staff DMs (1-to-1 between staff)
// - Property threads (PM ↔ owners/managers, one per portal-enabled property)
// - Photo attachments
// - Realtime delivery via Supabase Realtime
// - Owners can read any DM for oversight; managers cannot
// =================================================================

// ---- Hook: unread message count ----
function useUnreadCount({ employee = null, customer = null, refreshKey = 0 }) {
  const [count, setCount] = useState(0);
  useEffect(() => {
    let cancelled = false;
    const load = async () => {
      try {
        if (employee) {
          // Staff: count unread across all conversations they're in
          // For owners: also include property threads (they implicitly see all)
          // For everyone: count DMs they're a participant in
          const { data: parts } = await supabase
            .from('conversation_participants')
            .select('conversation_id, last_read_at')
            .eq('employee_id', employee.id);
          if (!parts || cancelled) return;
          let unread = 0;
          for (const p of parts) {
            const since = p.last_read_at || '1970-01-01';
            const { count: c } = await supabase
              .from('messages')
              .select('id', { count: 'exact', head: true })
              .eq('conversation_id', p.conversation_id)
              .gt('created_at', since)
              .neq('sender_employee_id', employee.id);
            unread += c || 0;
          }
          // For owners and managers, also count unread property threads.
          // Per-thread read state uses conversation_participants — if no row
          // exists for this employee, treat the thread as fully unread.
          if (employee.role === 'owner' || employee.role === 'manager') {
            const { data: convs } = await supabase
              .from('conversations')
              .select('id, last_message_at')
              .eq('kind', 'property_thread');
            for (const c of (convs || [])) {
              if (!c.last_message_at) continue;
              const { data: myRead } = await supabase
                .from('conversation_participants')
                .select('last_read_at')
                .eq('conversation_id', c.id)
                .eq('employee_id', employee.id)
                .maybeSingle();
              const since = myRead?.last_read_at || '1970-01-01';
              if (c.last_message_at > since) {
                const { count: cc } = await supabase
                  .from('messages')
                  .select('id', { count: 'exact', head: true })
                  .eq('conversation_id', c.id)
                  .gt('created_at', since)
                  .eq('sender_is_pm', true);
                unread += cc || 0;
              }
            }
          }
          if (!cancelled) setCount(unread);
        } else if (customer) {
          // PM: their property thread
          const { data: conv } = await supabase
            .from('conversations')
            .select('id, last_message_at')
            .eq('customer_id', customer.id)
            .eq('kind', 'property_thread')
            .maybeSingle();
          if (!conv) { if (!cancelled) setCount(0); return; }
          const since = customer.pm_last_read_at || '1970-01-01';
          const { count: c } = await supabase
            .from('messages')
            .select('id', { count: 'exact', head: true })
            .eq('conversation_id', conv.id)
            .gt('created_at', since)
            .eq('sender_is_pm', false);
          if (!cancelled) setCount(c || 0);
        }
      } catch (e) { console.error('[unread]', e); }
    };
    load();
    const interval = setInterval(load, 20000); // poll every 20s as a backup to realtime
    return () => { cancelled = true; clearInterval(interval); };
  }, [employee?.id, customer?.id, refreshKey]);
  return count;
}


// ---- Main Messages tab (staff side) ----
function StaffMessagesTab({ employee, onClose }) {
  const [view, setView] = useState({ kind: 'list' });

  if (view.kind === 'thread') {
    return <MessageThread
      conversationId={view.conversationId}
      otherName={view.otherName}
      asEmployee={employee}
      isPropertyThread={view.isPropertyThread}
      propertyName={view.propertyName}
      onBack={() => setView({ kind: 'list' })} />;
  }

  if (view.kind === 'new-dm') {
    return <NewDmPicker employee={employee}
      onBack={() => setView({ kind: 'list' })}
      onPicked={(conversationId, otherName) =>
        setView({ kind: 'thread', conversationId, otherName, isPropertyThread: false })} />;
  }

  if (view.kind === 'new-property-thread') {
    return <NewPropertyThreadPicker employee={employee}
      onBack={() => setView({ kind: 'list' })}
      onPicked={(conversationId, propertyName) =>
        setView({ kind: 'thread', conversationId, otherName: propertyName, isPropertyThread: true, propertyName })} />;
  }

  return <ConversationList employee={employee}
    onOpen={(c) => setView({ kind: 'thread', ...c })}
    onNewDm={() => setView({ kind: 'new-dm' })}
    onNewPropertyThread={() => setView({ kind: 'new-property-thread' })}
    onClose={onClose} />;
}

function ConversationList({ employee, onOpen, onNewDm, onNewPropertyThread, onClose }) {
  const [dms, setDms] = useState([]);
  const [threads, setThreads] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [showNewMenu, setShowNewMenu] = useState(false);
  const canSeeThreads = employee.role === 'owner' || employee.role === 'manager';

  const load = async () => {
    setLoaded(false);
    // DMs the employee is a participant in
    const { data: parts } = await supabase
      .from('conversation_participants')
      .select('conversation_id, last_read_at, conversation:conversations!inner(id, kind, last_message_at, last_message_preview)')
      .eq('employee_id', employee.id);
    const dmConvs = (parts || []).filter(p => p.conversation?.kind === 'staff_dm');
    // For each, find the OTHER participant's name
    const dmList = [];
    for (const p of dmConvs) {
      const { data: others } = await supabase
        .from('conversation_participants')
        .select('employee:employees(id, name)')
        .eq('conversation_id', p.conversation_id)
        .neq('employee_id', employee.id);
      const other = others?.[0]?.employee;
      if (other) {
        // Compute unread for this convo
        const since = p.last_read_at || '1970-01-01';
        const { count: unread } = await supabase
          .from('messages')
          .select('id', { count: 'exact', head: true })
          .eq('conversation_id', p.conversation_id)
          .gt('created_at', since)
          .neq('sender_employee_id', employee.id);
        dmList.push({
          conversationId: p.conversation_id,
          otherId: other.id,
          otherName: other.name,
          lastMessageAt: p.conversation.last_message_at,
          preview: p.conversation.last_message_preview,
          unread: unread || 0
        });
      }
    }
    // Sort: unread first (highest count), then by recency
    dmList.sort((a, b) => {
      if ((a.unread > 0) !== (b.unread > 0)) return a.unread > 0 ? -1 : 1;
      return (b.lastMessageAt || '').localeCompare(a.lastMessageAt || '');
    });
    setDms(dmList);

    // Property threads (only owners/managers see these)
    if (canSeeThreads) {
      const { data: convs } = await supabase
        .from('conversations')
        .select('id, customer_id, last_message_at, last_message_preview, customer:customers(name)')
        .eq('kind', 'property_thread')
        .order('last_message_at', { ascending: false, nullsFirst: false });
      // Per-thread unread tracking via conversation_participants
      const threadList = [];
      for (const c of (convs || [])) {
        let unread = 0;
        if (c.last_message_at) {
          const { data: myRead } = await supabase
            .from('conversation_participants')
            .select('last_read_at')
            .eq('conversation_id', c.id)
            .eq('employee_id', employee.id)
            .maybeSingle();
          const since = myRead?.last_read_at || '1970-01-01';
          if (c.last_message_at > since) {
            const { count: cc } = await supabase
              .from('messages')
              .select('id', { count: 'exact', head: true })
              .eq('conversation_id', c.id)
              .gt('created_at', since)
              .eq('sender_is_pm', true);
            unread = cc || 0;
          }
        }
        threadList.push({
          conversationId: c.id,
          customerId: c.customer_id,
          propertyName: c.customer?.name || 'Unknown',
          lastMessageAt: c.last_message_at,
          preview: c.last_message_preview,
          unread
        });
      }
      // Sort: unread first, then by recency
      threadList.sort((a, b) => {
        if ((a.unread > 0) !== (b.unread > 0)) return a.unread > 0 ? -1 : 1;
        return (b.lastMessageAt || '').localeCompare(a.lastMessageAt || '');
      });
      setThreads(threadList);
    }
    setLoaded(true);
  };

  useEffect(() => { load(); }, [employee.id]);

  // Realtime: refresh on any new message
  useEffect(() => {
    const channel = supabase.channel('msg-list-' + employee.id)
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'messages' }, () => load())
      .on('postgres_changes', { event: 'DELETE', schema: 'public', table: 'messages' }, () => load())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [employee.id]);

  return (
    <div className="pb-24">
      {onClose ? (
        <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200 bg-white">
          <button onClick={onClose} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
            <ArrowLeft size={20} className="text-stone-700" />
          </button>
          <div className="font-serif text-xl text-stone-900">Messages</div>
        </div>
      ) : (
        <Header name={employee.name} onSignOut={() => {}} role={employee.role} />
      )}
      <div className="px-5 pt-6 max-w-2xl mx-auto w-full">
        <div className="flex items-center justify-between mb-4">
          {!onClose && <h2 className="font-serif text-2xl text-stone-900">Messages</h2>}
          <div className={`relative ${onClose ? 'ml-auto' : ''}`}>
            <button onClick={() => canSeeThreads ? setShowNewMenu(s => !s) : onNewDm()}
              className="px-3 py-2 rounded-full bg-stone-900 text-stone-50 text-xs font-mono flex items-center gap-1.5">
              <Plus size={14} /> New
            </button>
            {canSeeThreads && showNewMenu && (
              <>
                <div className="fixed inset-0 z-40" onClick={() => setShowNewMenu(false)} />
                <div className="absolute right-0 top-full mt-1 z-50 w-56 rounded-2xl bg-white border border-stone-200 shadow-lg overflow-hidden">
                  <button onClick={() => { setShowNewMenu(false); onNewDm(); }}
                    className="w-full text-left px-4 py-3 hover:bg-stone-50 flex items-start gap-2.5 border-b border-stone-100">
                    <User size={16} className="text-stone-500 mt-0.5 flex-shrink-0" />
                    <div>
                      <div className="text-sm font-medium text-stone-900">Message a teammate</div>
                      <div className="text-[11px] text-stone-500">Direct message to cleaners, managers</div>
                    </div>
                  </button>
                  <button onClick={() => { setShowNewMenu(false); onNewPropertyThread && onNewPropertyThread(); }}
                    className="w-full text-left px-4 py-3 hover:bg-stone-50 flex items-start gap-2.5">
                    <Building2 size={16} className="text-amber-700 mt-0.5 flex-shrink-0" />
                    <div>
                      <div className="text-sm font-medium text-stone-900">Message a property</div>
                      <div className="text-[11px] text-stone-500">Reach PMs and owners at a property</div>
                    </div>
                  </button>
                </div>
              </>
            )}
          </div>
        </div>

        {!loaded ? <Splash text="Loading…" /> : (
          <>
            {canSeeThreads && threads.length > 0 && (
              <div className="mb-6">
                <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-2">
                  Property threads
                </div>
                <div className="space-y-2">
                  {threads.map(t => (
                    <button key={t.conversationId}
                      onClick={() => onOpen({ conversationId: t.conversationId, otherName: t.propertyName, isPropertyThread: true, propertyName: t.propertyName })}
                      className="w-full text-left p-3 rounded-2xl bg-white border border-stone-200 hover:border-stone-400 transition-colors">
                      <div className="flex items-center justify-between gap-2">
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            <Building2 size={14} className="text-amber-700 flex-shrink-0" />
                            <span className={`font-serif text-base text-stone-900 truncate ${t.unread > 0 ? 'font-bold' : ''}`}>{t.propertyName}</span>
                            {t.unread > 0 && (
                              <span className="w-2 h-2 rounded-full bg-amber-600 flex-shrink-0" title={`${t.unread} unread`} />
                            )}
                          </div>
                          {t.preview && (
                            <div className={`text-xs truncate mt-1 ${t.unread > 0 ? 'text-stone-900 font-medium' : 'text-stone-600'}`}>{t.preview}</div>
                          )}
                          {t.lastMessageAt && (
                            <div className="text-[10px] font-mono text-stone-400 mt-0.5">{fmtDate(t.lastMessageAt)}</div>
                          )}
                        </div>
                        <ChevronRight size={14} className="text-stone-400 flex-shrink-0" />
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div>
              <div className="text-xs uppercase tracking-wider font-mono text-stone-500 mb-2">
                Direct messages
              </div>
              {dms.length === 0 ? (
                <div className="text-center py-10 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
                  No direct messages yet. Tap "New" to start one.
                </div>
              ) : (
                <div className="space-y-2">
                  {dms.map(d => (
                    <button key={d.conversationId}
                      onClick={() => onOpen({ conversationId: d.conversationId, otherName: d.otherName, isPropertyThread: false })}
                      className="w-full text-left p-3 rounded-2xl bg-white border border-stone-200 hover:border-stone-400 transition-colors">
                      <div className="flex items-center justify-between gap-2">
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            <User size={14} className="text-stone-500 flex-shrink-0" />
                            <span className={`font-serif text-base text-stone-900 truncate ${d.unread > 0 ? 'font-bold' : ''}`}>{d.otherName}</span>
                            {d.unread > 0 && (
                              <span className="w-2 h-2 rounded-full bg-amber-600 flex-shrink-0" title={`${d.unread} unread`} />
                            )}
                          </div>
                          {d.preview && (
                            <div className={`text-xs truncate mt-1 ${d.unread > 0 ? 'text-stone-900 font-medium' : 'text-stone-600'}`}>{d.preview}</div>
                          )}
                          {d.lastMessageAt && (
                            <div className="text-[10px] font-mono text-stone-400 mt-0.5">{fmtDate(d.lastMessageAt)}</div>
                          )}
                        </div>
                        <ChevronRight size={14} className="text-stone-400 flex-shrink-0" />
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
}

function NewDmPicker({ employee, onBack, onPicked }) {
  const [staff, setStaff] = useState([]);
  const [search, setSearch] = useState('');
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    (async () => {
      const { data } = await supabase.from('employees')
        .select('id, name, role, active')
        .eq('active', true)
        .neq('id', employee.id)
        .order('name');
      setStaff(data || []);
    })();
  }, [employee.id]);

  const startDm = async (other) => {
    setBusy(true);
    try {
      // See if a DM already exists between these two
      const { data: myParts } = await supabase.from('conversation_participants')
        .select('conversation_id, conversation:conversations!inner(kind)')
        .eq('employee_id', employee.id);
      const myDmConvIds = (myParts || []).filter(p => p.conversation?.kind === 'staff_dm').map(p => p.conversation_id);
      let foundConvId = null;
      if (myDmConvIds.length > 0) {
        const { data: theirParts } = await supabase.from('conversation_participants')
          .select('conversation_id')
          .eq('employee_id', other.id)
          .in('conversation_id', myDmConvIds);
        if (theirParts && theirParts.length > 0) foundConvId = theirParts[0].conversation_id;
      }
      if (foundConvId) {
        onPicked(foundConvId, other.name);
        return;
      }
      // Create a new conversation
      const { data: conv, error } = await supabase.from('conversations')
        .insert({ kind: 'staff_dm' })
        .select().single();
      if (error) throw error;
      await supabase.from('conversation_participants').insert([
        { conversation_id: conv.id, employee_id: employee.id },
        { conversation_id: conv.id, employee_id: other.id }
      ]);
      onPicked(conv.id, other.name);
    } catch (e) {
      alert('Could not start DM: ' + e.message);
    } finally {
      setBusy(false);
    }
  };

  const filtered = search
    ? staff.filter(s => s.name.toLowerCase().includes(search.toLowerCase()))
    : staff;

  return (
    <div className="pb-24">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div className="font-serif text-xl text-stone-900">New direct message</div>
      </div>
      <div className="px-5 pt-4">
        <input type="text" value={search} onChange={(e) => setSearch(e.target.value)}
          placeholder="Search staff…"
          className="w-full px-4 py-3 rounded-xl border border-stone-300 bg-white mb-4" />
        <div className="space-y-1">
          {filtered.map(s => (
            <button key={s.id} disabled={busy} onClick={() => startDm(s)}
              className="w-full text-left px-4 py-3 rounded-xl hover:bg-stone-50 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-9 h-9 rounded-full bg-stone-100 flex items-center justify-center text-sm font-medium text-stone-700">
                  {s.name.charAt(0).toUpperCase()}
                </div>
                <div>
                  <div className="font-medium text-stone-900">{s.name}</div>
                  <div className="text-xs text-stone-500 font-mono uppercase tracking-wider">{s.role}</div>
                </div>
              </div>
              <ChevronRight size={16} className="text-stone-400" />
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

// =================================================================
// NEW PROPERTY THREAD PICKER — owner/manager picks a property to
// start a property_thread conversation. If a thread already exists
// for that property, opens it; otherwise creates a fresh one.
// =================================================================
function NewPropertyThreadPicker({ employee, onBack, onPicked }) {
  const [properties, setProperties] = useState([]);
  const [search, setSearch] = useState('');
  const [busy, setBusy] = useState(false);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      const { data } = await supabase.from('customers')
        .select('id, name, address')
        .eq('active', true)
        .order('name');
      setProperties(visibleProps(data, employee));
      setLoaded(true);
    })();
  }, []);

  const startThread = async (property) => {
    setBusy(true);
    try {
      // Check if a property_thread already exists for this property
      const { data: existing } = await supabase.from('conversations')
        .select('id')
        .eq('kind', 'property_thread')
        .eq('customer_id', property.id)
        .maybeSingle();
      let convId = existing?.id;
      if (!convId) {
        // Create a new property_thread conversation
        const { data: conv, error } = await supabase.from('conversations')
          .insert({ kind: 'property_thread', customer_id: property.id })
          .select().single();
        if (error) throw error;
        convId = conv.id;
        // Add the current employee as a participant (so last_read_at tracks for them)
        await supabase.from('conversation_participants').insert({
          conversation_id: convId,
          employee_id: employee.id,
        });
      } else {
        // Make sure the current employee is a participant
        const { data: part } = await supabase.from('conversation_participants')
          .select('id')
          .eq('conversation_id', convId)
          .eq('employee_id', employee.id)
          .maybeSingle();
        if (!part) {
          await supabase.from('conversation_participants').insert({
            conversation_id: convId,
            employee_id: employee.id,
          });
        }
      }
      onPicked(convId, property.name);
    } catch (e) {
      alert('Could not start thread: ' + e.message);
    } finally {
      setBusy(false);
    }
  };

  const filtered = search
    ? properties.filter(p => p.name.toLowerCase().includes(search.toLowerCase()))
    : properties;

  return (
    <div className="min-h-screen bg-stone-50 pb-24">
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100" disabled={busy}>
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div>
          <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">New thread</div>
          <div className="font-serif text-xl text-stone-900">Pick a property</div>
        </div>
      </div>

      <div className="px-5 pt-6 max-w-2xl mx-auto w-full">
        {properties.length >= 6 && (
          <input type="text" value={search} onChange={(e) => setSearch(e.target.value)}
            placeholder={`Search ${properties.length} properties…`}
            className="w-full mb-4 px-4 py-3 rounded-xl border border-stone-300 bg-white focus:outline-none focus:border-stone-900 text-stone-900 text-sm" />
        )}

        {!loaded ? <Splash text="Loading…" /> : filtered.length === 0 ? (
          <div className="text-center py-12 text-stone-400 text-sm border-2 border-dashed border-stone-200 rounded-2xl">
            {search ? `No properties match "${search}".` : 'No properties yet.'}
          </div>
        ) : (
          <div className="space-y-2">
            {filtered.map(p => (
              <button key={p.id} onClick={() => startThread(p)} disabled={busy}
                className="w-full text-left p-4 rounded-2xl bg-white border border-stone-200 hover:border-amber-500 transition-colors active:scale-[0.99] disabled:opacity-50 flex items-center gap-3">
                <Building2 size={18} className="text-amber-700 flex-shrink-0" />
                <div className="flex-1 min-w-0">
                  <div className="font-serif text-base text-stone-900 truncate">{p.name}</div>
                  {p.address && <div className="text-xs text-stone-500"><AddressLink address={p.address} /></div>}
                </div>
                <ChevronRight size={16} className="text-stone-400 flex-shrink-0" />
              </button>
            ))}
          </div>
        )}

        <p className="text-xs text-stone-500 mt-6 text-center">
          Messages here are visible to all PMs &amp; property owners assigned to this property.
        </p>
      </div>
    </div>
  );
}


// ---- The conversation/thread view ----
function MessageThread({ conversationId, otherName, asEmployee = null, asPmCustomer = null, pmActorKind = null, isPropertyThread = false, propertyName, onBack }) {
  const [messages, setMessages] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [text, setText] = useState('');
  const [photoFile, setPhotoFile] = useState(null);
  const [sending, setSending] = useState(false);
  const [error, setError] = useState('');
  const [zoomPhoto, setZoomPhoto] = useState(null);
  const [urgent, setUrgent] = useState(false); // urgent flag for next message
  const scrollRef = useRef(null);

  const load = async () => {
    const { data } = await supabase.from('messages')
      .select('*, sender:employees(id, name)')
      .eq('conversation_id', conversationId)
      .order('created_at', { ascending: true });
    setMessages(data || []);
    setLoaded(true);
    // Mark conversation as read for this person
    if (asEmployee) {
      // For DMs they're already a participant. For property threads, owners/managers
      // may not have a row yet — upsert so the read state actually persists.
      const nowIso = new Date().toISOString();
      const { error: updErr } = await supabase.from('conversation_participants')
        .update({ last_read_at: nowIso })
        .eq('conversation_id', conversationId)
        .eq('employee_id', asEmployee.id);
      // If no row was updated (property thread, first time opening), insert one
      if (isPropertyThread) {
        await supabase.from('conversation_participants')
          .upsert({ conversation_id: conversationId, employee_id: asEmployee.id, last_read_at: nowIso },
                  { onConflict: 'conversation_id,employee_id' });
      }
    } else if (asPmCustomer) {
      await supabase.from('customers')
        .update({ pm_last_read_at: new Date().toISOString() })
        .eq('id', asPmCustomer.id);
    }
    setTimeout(() => scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' }), 50);
  };

  useEffect(() => { load(); }, [conversationId]);

  // Realtime subscription for new messages in this conversation
  useEffect(() => {
    const channel = supabase.channel('msg-' + conversationId)
      .on('postgres_changes', {
        event: 'INSERT', schema: 'public', table: 'messages',
        filter: `conversation_id=eq.${conversationId}`
      }, () => load())
      .on('postgres_changes', {
        event: 'DELETE', schema: 'public', table: 'messages',
        filter: `conversation_id=eq.${conversationId}`
      }, () => load())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [conversationId]);

  const send = async () => {
    if (sending) return;
    if (!text.trim() && !photoFile) { setError('Type a message or attach a photo.'); return; }
    setError('');
    setSending(true);
    try {
      let photoUrl = null, photoPath = null;
      if (photoFile) {
        const r = await uploadMessagePhoto(photoFile, conversationId);
        photoUrl = r.publicUrl; photoPath = r.path;
      }
      const insert = {
        conversation_id: conversationId,
        content: text.trim() || null,
        photo_url: photoUrl,
        photo_path: photoPath,
        urgent: !!urgent,
      };
      if (asEmployee) {
        insert.sender_employee_id = asEmployee.id;
        insert.sender_is_pm = false;
      } else {
        insert.sender_employee_id = null;
        insert.sender_is_pm = true;
        insert.pm_actor_kind = pmActorKind || 'pm';
      }
      const { error: e } = await supabase.from('messages').insert(insert);
      if (e) throw e;
      setText(''); setPhotoFile(null); setUrgent(false);
      // load() will be triggered by realtime, but call it anyway for instant response
      load();
    } catch (e) {
      setError(e.message || String(e));
    } finally {
      setSending(false);
    }
  };

  const deleteMessage = async (m) => {
    if (!confirm('Delete this message? This cannot be undone.')) return;
    if (m.photo_path) await deleteMessagePhoto(m.photo_path);
    await supabase.from('messages').delete().eq('id', m.id);
    // Realtime will refresh
  };

  // Decide who counts as "me" for bubble alignment
  const isMine = (m) => {
    if (asEmployee) return m.sender_employee_id === asEmployee.id;
    if (asPmCustomer) return m.sender_is_pm === true;
    return false;
  };

  // Decide the displayed sender name
  const senderName = (m) => {
    if (m.sender_is_pm) {
      return m.pm_actor_kind === 'pm_staff' ? 'Property manager · staff' : 'Property manager';
    }
    if (!isPropertyThread) return m.sender?.name || 'Unknown';
    // Property thread + staff sender → show as Summit Clean to the PM
    if (asPmCustomer) return 'Summit Clean';
    // Property thread + viewing as staff → show real name
    return m.sender?.name || 'Summit Clean';
  };

  return (
    <div className="flex flex-col bg-stone-50" style={{ height: '100dvh', maxHeight: '100dvh' }}>
      <div className="flex items-center gap-3 px-5 py-4 border-b border-stone-200 bg-white flex-shrink-0">
        <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-stone-100">
          <ArrowLeft size={20} className="text-stone-700" />
        </button>
        <div className="flex-1 min-w-0">
          {isPropertyThread && <div className="text-xs uppercase tracking-wider text-stone-500 font-mono">Property thread</div>}
          <div className="font-serif text-xl text-stone-900 truncate">{otherName}</div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto" style={{ minHeight: 0 }}>
        <div className="max-w-2xl mx-auto px-4 py-4 space-y-2">
        {!loaded ? <div className="text-center text-stone-400 text-sm">Loading…</div> : messages.length === 0 ? (
          <div className="text-center text-stone-400 text-sm py-12">No messages yet. Say hi!</div>
        ) : messages.map(m => {
          const mine = isMine(m);
          const isUrgent = !!m.urgent;
          const bubbleClass = isUrgent
            ? (mine ? 'bg-amber-600 text-white border border-amber-700' : 'bg-amber-50 border-2 border-amber-400 text-amber-950')
            : (mine ? 'bg-stone-900 text-stone-50' : 'bg-white border border-stone-200 text-stone-900');
          return (
            <div key={m.id} className={`flex ${mine ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] ${mine ? 'items-end' : 'items-start'} flex flex-col`}>
                {!mine && (
                  <div className="text-[10px] font-mono text-stone-500 mb-0.5 px-1">{senderName(m)}</div>
                )}
                {isUrgent && (
                  <div className={`flex items-center gap-1 mb-0.5 px-1 text-[10px] font-mono uppercase tracking-wider ${mine ? 'text-amber-700' : 'text-amber-700'}`}>
                    <AlertCircle size={10} /> Urgent
                  </div>
                )}
                <div className={`px-3 py-2 rounded-2xl ${bubbleClass}`}>
                  {m.photo_url && (
                    <button onClick={() => setZoomPhoto(m.photo_url)} className="block mb-1">
                      <img src={m.photo_url} alt="" loading="lazy"
                        className="rounded-xl max-w-full max-h-60 object-cover" />
                    </button>
                  )}
                  {m.content && <div className="text-sm whitespace-pre-wrap break-words">{m.content}</div>}
                </div>
                <div className="flex items-center gap-2 mt-0.5 px-1">
                  <div className="text-[10px] font-mono text-stone-400">{fmtClock(m.created_at)}</div>
                  {mine && (
                    <button onClick={() => deleteMessage(m)}
                      className="text-[10px] font-mono text-stone-400 hover:text-red-600">
                      Delete
                    </button>
                  )}
                </div>
              </div>
            </div>
          );
        })}
        </div>
      </div>

      {error && (
        <div className="px-4 py-2 bg-red-50 border-t border-red-200 text-red-700 text-sm flex items-center gap-2 flex-shrink-0">
          <AlertCircle size={16} /><span>{error}</span>
        </div>
      )}

      {photoFile && (
        <div className="px-4 py-2 bg-stone-100 border-t border-stone-200 flex items-center gap-2 flex-shrink-0">
          <ImageIcon size={16} className="text-stone-600" />
          <span className="text-xs text-stone-700 flex-1 truncate">{photoFile.name}</span>
          <button onClick={() => setPhotoFile(null)} className="p-1 rounded-full hover:bg-stone-200">
            <X size={14} className="text-stone-600" />
          </button>
        </div>
      )}

      <div className="border-t border-stone-200 bg-white flex-shrink-0" style={{ paddingBottom: 'max(0.75rem, env(safe-area-inset-bottom))' }}>
        {urgent && (
          <div className="px-4 py-2 bg-amber-100 border-t border-amber-200 flex items-center gap-2 flex-shrink-0">
            <AlertCircle size={14} className="text-amber-700 flex-shrink-0" />
            <span className="text-xs text-amber-900 flex-1">This message will be sent as <span className="font-bold">urgent</span>.</span>
            <button onClick={() => setUrgent(false)}
              className="text-[10px] text-amber-700 hover:text-amber-900 font-mono uppercase tracking-wider">
              Cancel
            </button>
          </div>
        )}
        <div className="px-4 py-3 max-w-2xl mx-auto flex items-end gap-2">
        <label className="p-2 rounded-full hover:bg-stone-100 cursor-pointer flex-shrink-0">
          <Camera size={20} className="text-stone-600" />
          <input type="file" accept="image/*" className="hidden"
            onChange={(e) => { const f = e.target.files?.[0]; if (f) setPhotoFile(f); }} />
        </label>
        <button onClick={() => setUrgent(u => !u)} type="button"
          title={urgent ? 'Urgent flag enabled — tap to turn off' : 'Mark this message as urgent'}
          className={`p-2 rounded-full flex-shrink-0 transition-colors ${urgent ? 'bg-amber-600 hover:bg-amber-700 text-white' : 'hover:bg-stone-100 text-stone-600'}`}>
          <AlertCircle size={20} />
        </button>
        <textarea value={text} onChange={(e) => setText(e.target.value)} rows={1}
          placeholder={urgent ? 'Type your urgent message…' : 'Type a message…'} disabled={sending}
          onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); } }}
          onFocus={(e) => {
            // Scroll the input into view after the iOS keyboard animation
            setTimeout(() => { try { e.target.scrollIntoView({ block: 'end', behavior: 'smooth' }); } catch {} }, 300);
          }}
          style={{ fontSize: 16 }}
          className={`flex-1 px-3 py-2 rounded-xl border bg-white resize-none max-h-32 ${urgent ? 'border-amber-400 focus:border-amber-600' : 'border-stone-300'}`} />
        <button onClick={send} disabled={sending || (!text.trim() && !photoFile)}
          className={`p-2.5 rounded-full text-stone-50 disabled:opacity-40 flex-shrink-0 ${urgent ? 'bg-amber-600 hover:bg-amber-700' : 'bg-stone-900'}`}>
          {sending ? <div className="w-4 h-4 border-2 border-stone-50 border-t-transparent rounded-full animate-spin" /> : <ChevronRight size={16} />}
        </button>
        </div>
      </div>

      {zoomPhoto && (
        <div className="fixed inset-0 bg-stone-900/95 z-50 flex flex-col" onClick={() => setZoomPhoto(null)}>
          <div className="flex justify-end p-4">
            <button className="p-2 rounded-full bg-stone-800">
              <X size={20} className="text-stone-50" />
            </button>
          </div>
          <div className="flex-1 overflow-auto p-4">
            <img src={zoomPhoto} alt="" className="w-full h-auto rounded-xl" />
          </div>
        </div>
      )}
    </div>
  );
}


// ---- PM-side Messages tab ----
function PortalMessagesTab({ property, portalKind, onClose, onPropertyRefresh }) {
  const [conversationId, setConversationId] = useState(null);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      // Find or create the property thread for this property
      const { data: existing } = await supabase.from('conversations')
        .select('id').eq('customer_id', property.id).eq('kind', 'property_thread').maybeSingle();
      if (existing) {
        setConversationId(existing.id);
      } else {
        const { data: created } = await supabase.from('conversations')
          .insert({ kind: 'property_thread', customer_id: property.id })
          .select().single();
        if (created) setConversationId(created.id);
      }
      setLoaded(true);
    })();
  }, [property.id]);

  if (!loaded) return <div className="px-5 pt-6"><Splash text="Loading…" /></div>;
  if (!conversationId) return <div className="px-5 pt-6 text-stone-400">Could not load messages.</div>;

  const handleBack = onClose || (() => onPropertyRefresh && onPropertyRefresh());

  return <MessageThread
    conversationId={conversationId}
    otherName="Summit Clean team"
    asPmCustomer={property}
    pmActorKind={portalKind || 'pm'}
    isPropertyThread={true}
    propertyName={property.name}
    onBack={handleBack} />;
}
